static void *cheng_seed_xmalloc(size_t size) {
    void *ptr = malloc(size);
    if (!ptr) {
        fprintf(stderr, "[cheng_seed] out of memory size=%zu\n", size);
        exit(1);
    }
    return ptr;
}

static char (*cheng_seed_alloc_call_arg_scratch(void))[4096] {
    return (char (*)[4096])cheng_seed_xmalloc(sizeof(char[CHENG_MAX_CALL_ARGS][4096]));
}

static void *cheng_seed_xrealloc(void *ptr, size_t size) {
    void *next = realloc(ptr, size);
    if (!next) {
        fprintf(stderr, "[cheng_seed] out of memory resize=%zu\n", size);
        exit(1);
    }
    return next;
}

static char *cheng_seed_strdup(const char *text) {
    size_t len = strlen(text);
    char *out = (char *)cheng_seed_xmalloc(len + 1);
    memcpy(out, text, len + 1);
    return out;
}

static char *cheng_seed_trim_inplace(char *text) {
    char *start = text;
    char *end;
    while (*start != '\0' && isspace((unsigned char)*start)) {
        start++;
    }
    end = start + strlen(start);
    while (end > start && isspace((unsigned char)end[-1])) {
        end--;
    }
    *end = '\0';
    return start;
}

static bool cheng_seed_streq(const char *a, const char *b) {
    return strcmp(a, b) == 0;
}

static void cheng_seed_owned_string_vec_init(ChengSeedOwnedStringVec *vec) {
    vec->items = NULL;
    vec->len = 0U;
    vec->cap = 0U;
}

static void cheng_seed_owned_string_vec_push_dup(ChengSeedOwnedStringVec *vec, const char *text) {
    if (vec->len + 1U > vec->cap) {
        size_t next_cap = vec->cap == 0U ? 16U : vec->cap * 2U;
        vec->items = (char **)cheng_seed_xrealloc(vec->items, next_cap * sizeof(char *));
        vec->cap = next_cap;
    }
    vec->items[vec->len++] = cheng_seed_strdup(text);
}

static char *cheng_seed_owned_string_vec_pop(ChengSeedOwnedStringVec *vec) {
    if (vec->len == 0U) {
        return NULL;
    }
    vec->len -= 1U;
    return vec->items[vec->len];
}

static void cheng_seed_owned_string_vec_free(ChengSeedOwnedStringVec *vec) {
    size_t i;
    for (i = 0U; i < vec->len; ++i) {
        free(vec->items[i]);
    }
    free(vec->items);
    vec->items = NULL;
    vec->len = 0U;
    vec->cap = 0U;
}

static void cheng_seed_forbidden_hit_vec_init(ChengSeedForbiddenHitVec *vec) {
    vec->items = NULL;
    vec->len = 0U;
    vec->cap = 0U;
}

static void cheng_seed_forbidden_hit_vec_push(ChengSeedForbiddenHitVec *vec,
                                      const char *path,
                                      const char *label) {
    if (vec->len + 1U > vec->cap) {
        size_t next_cap = vec->cap == 0U ? 16U : vec->cap * 2U;
        vec->items = (ChengSeedForbiddenHit *)cheng_seed_xrealloc(vec->items,
                                                   next_cap * sizeof(ChengSeedForbiddenHit));
        vec->cap = next_cap;
    }
    vec->items[vec->len].path = cheng_seed_strdup(path);
    vec->items[vec->len].label = label;
    vec->len += 1U;
}

static void cheng_seed_forbidden_hit_vec_free(ChengSeedForbiddenHitVec *vec) {
    size_t i;
    for (i = 0U; i < vec->len; ++i) {
        free(vec->items[i].path);
    }
    free(vec->items);
    vec->items = NULL;
    vec->len = 0U;
    vec->cap = 0U;
}

static bool cheng_seed_has_csv_token(const char *csv, const char *needle) {
    size_t needle_len = strlen(needle);
    const char *cursor = csv;
    while (*cursor != '\0') {
        while (*cursor == ' ' || *cursor == '\t' || *cursor == ',') {
            cursor++;
        }
        if (*cursor == '\0') {
            return false;
        }
        const char *stop = cursor;
        while (*stop != '\0' && *stop != ',') {
            stop++;
        }
        while (stop > cursor && (stop[-1] == ' ' || stop[-1] == '\t')) {
            stop--;
        }
        if ((size_t)(stop - cursor) == needle_len && strncmp(cursor, needle, needle_len) == 0) {
            return true;
        }
        cursor = stop;
        if (*cursor == ',') {
            cursor++;
        }
    }
    return false;
}

static uint64_t cheng_seed_fnv1a64(const char *text) {
    uint64_t hash = 1469598103934665603ULL;
    const unsigned char *cursor = (const unsigned char *)text;
    while (*cursor != '\0') {
        hash ^= (uint64_t)(*cursor);
        hash *= 1099511628211ULL;
        cursor++;
    }
    return hash;
}

