static bool cheng_seed_bootstrap_artifacts_ready(const ChengSeedBootstrapPaths *paths) {
    struct stat st;
    return access(paths->stage2, X_OK) == 0 &&
           access(paths->stage3, X_OK) == 0 &&
           stat(paths->env_path, &st) == 0 &&
           S_ISREG(st.st_mode) &&
           st.st_size > 0 &&
           stat(paths->snapshot_path, &st) == 0 &&
           S_ISREG(st.st_mode) &&
           st.st_size > 0;
}

static bool cheng_seed_stat_mtime_ns(const char *path, uint64_t *out_ns) {
    struct stat st;
    uint64_t sec = 0;
    uint64_t nsec = 0;
    if (path == NULL || path[0] == '\0' || out_ns == NULL) {
        return false;
    }
    if (stat(path, &st) != 0) {
        return false;
    }
#if defined(__APPLE__)
    sec = (uint64_t)st.st_mtimespec.tv_sec;
    nsec = (uint64_t)st.st_mtimespec.tv_nsec;
#else
    sec = (uint64_t)st.st_mtime;
    nsec = 0;
#endif
    *out_ns = sec * 1000000000ULL + nsec;
    return true;
}

static bool cheng_seed_output_is_fresh_against_inputs(const char *output_path,
                                              const char *const *input_paths,
                                              size_t input_count) {
    uint64_t output_ns = 0;
    size_t i;
    if (!cheng_seed_stat_mtime_ns(output_path, &output_ns)) {
        return false;
    }
    for (i = 0; i < input_count; ++i) {
        uint64_t input_ns = 0;
        if (input_paths[i] == NULL || input_paths[i][0] == '\0') {
            continue;
        }
        if (!cheng_seed_stat_mtime_ns(input_paths[i], &input_ns)) {
            return false;
        }
        if (output_ns < input_ns) {
            return false;
        }
    }
    return true;
}

static bool cheng_seed_binary_contains_marker_checked(const char *path,
                                               const char *needle,
                                               bool *read_ok_out) {
    enum { ChengSeed_BINARY_SCAN_CHUNK = 8192 };
    FILE *fp;
    unsigned char buffer[ChengSeed_BINARY_SCAN_CHUNK + 256];
    size_t needle_len;
    size_t carry = 0U;
    size_t read_len;
    bool found = false;
    if (read_ok_out != NULL) {
        *read_ok_out = false;
    }
    if (path == NULL || path[0] == '\0' || needle == NULL || needle[0] == '\0') {
        return false;
    }
    needle_len = strlen(needle);
    if (needle_len + 1U > sizeof(buffer)) {
        return false;
    }
    fp = fopen(path, "rb");
    if (fp == NULL) {
        return false;
    }
    while ((read_len = fread(buffer + carry, 1U, ChengSeed_BINARY_SCAN_CHUNK, fp)) > 0U) {
        size_t scan_len = carry + read_len;
        size_t i;
        if (scan_len >= needle_len) {
            for (i = 0U; i + needle_len <= scan_len; ++i) {
                if (memcmp(buffer + i, needle, needle_len) == 0) {
                    found = true;
                    break;
                }
            }
        }
        if (found) {
            break;
        }
        if (needle_len > 1U) {
            carry = scan_len < needle_len - 1U ? scan_len : needle_len - 1U;
            memmove(buffer, buffer + scan_len - carry, carry);
        } else {
            carry = 0U;
        }
    }
    if (read_ok_out != NULL) {
        *read_ok_out = ferror(fp) == 0;
    }
    fclose(fp);
    return found;
}

static const char *cheng_seed_backend_driver_forbidden_identity_marker(const char *path) {
    static const char *const marker_parts[][5] = {
        { "cheng_", "v", "3_", "", "" },
        { "cheng_", "v", "3c", "", "" },
        { "CHENG_", "V", "3_", "", "" },
        { "pkg://cheng/", "v", "3", "", "" },
        { "cheng/", "v", "3", "", "" },
        { "artifacts/", "v", "3_", "", "" },
        { "v", "3", "/src", "", "" },
        { "v", "3", ".compiler", "", "" },
        { "v", "3", "_selfhost", "", "" },
        { "module_prefix = \"", "v", "3", "\"", "" },
        { "core_runtime_", "v", "3", "", "" },
        { "compiler_runtime_", "v", "3", "", "" },
        { "program_support_", "v", "3", "", "" },
        { "provider_root_", "v", "3", "", "" },
        { "v", "3", "Mobile", "", "" },
        { "v", "3", "Browser", "", "" },
        { "v", "3", "R2c", "", "" }
    };
    static char marker[128];
    size_t i;
    if (!cheng_seed_path_exists_nonempty(path)) {
        return "missing-output";
    }
    for (i = 0U; i < sizeof(marker_parts) / sizeof(marker_parts[0]); ++i) {
        bool read_ok = false;
        snprintf(marker,
                 sizeof(marker),
                 "%s%s%s%s%s",
                 marker_parts[i][0],
                 marker_parts[i][1],
                 marker_parts[i][2],
                 marker_parts[i][3],
                 marker_parts[i][4]);
        if (cheng_seed_binary_contains_marker_checked(path, marker, &read_ok)) {
            return marker;
        }
        if (!read_ok) {
            return "unreadable-output";
        }
    }
    return NULL;
}

static bool cheng_seed_bootstrap_artifacts_fresh(const ChengSeedBootstrapPaths *paths) {
    const char *inputs[6];
    if (!cheng_seed_bootstrap_artifacts_ready(paths)) {
        return false;
    }
    inputs[0] = paths->seed_source;
    inputs[1] = paths->stage1_source;
    inputs[2] = paths->compiler_entry_source;
    inputs[3] = paths->compiler_runtime_source;
    inputs[4] = paths->compiler_request_source;
    inputs[5] = paths->tooling_gate_source;
    return cheng_seed_output_is_fresh_against_inputs(paths->stage2, inputs, 6U) &&
           cheng_seed_output_is_fresh_against_inputs(paths->stage3, inputs, 6U) &&
           cheng_seed_output_is_fresh_against_inputs(paths->env_path, inputs, 6U) &&
           cheng_seed_output_is_fresh_against_inputs(paths->snapshot_path, inputs, 6U);
}

static bool cheng_seed_backend_driver_ready(const ChengSeedBootstrapPaths *paths) {
    const char *inputs[34];
    char map_path[PATH_MAX];
    if (paths == NULL || access(paths->backend_driver_out, X_OK) != 0) {
        return false;
    }
    snprintf(map_path, sizeof(map_path), "%s.map", paths->backend_driver_out);
    if (access(map_path, R_OK) != 0) {
        return false;
    }
    if (!cheng_seed_bootstrap_artifacts_fresh(paths)) {
        return false;
    }
    if (cheng_seed_backend_driver_forbidden_identity_marker(paths->backend_driver_out) != NULL) {
        return false;
    }
    inputs[0] = paths->env_path;
    inputs[1] = paths->stage2;
    inputs[2] = paths->stage3;
    inputs[3] = paths->backend_driver_entry_source;
    inputs[4] = paths->compiler_runtime_source;
    inputs[5] = paths->compiler_request_source;
    inputs[6] = paths->compiler_world_source;
    inputs[7] = paths->compiler_csg_source;
    inputs[8] = paths->compiler_world_libp2p_source;
    inputs[9] = paths->compiler_equivalence_source;
    inputs[10] = paths->compiler_publish_gate_source;
    inputs[11] = paths->lang_parser_source;
    inputs[12] = paths->backend_system_link_plan_source;
    inputs[13] = paths->backend_lowering_plan_source;
    inputs[14] = paths->backend_primary_object_plan_source;
    inputs[15] = paths->backend_object_plan_source;
    inputs[16] = paths->backend_native_link_plan_source;
    inputs[17] = paths->backend_system_link_exec_source;
    inputs[18] = paths->runtime_core_runtime_source;
    inputs[19] = paths->runtime_compiler_runtime_source;
    inputs[20] = paths->runtime_debug_runtime_source;
    inputs[21] = paths->tooling_bootstrap_contract_source;
    inputs[22] = paths->backend_build_plan_source;
    inputs[23] = paths->runtime_core_provider_source;
    inputs[24] = paths->runtime_compiler_program_provider_source;
    inputs[25] = paths->runtime_compiler_tooling_provider_source;
    inputs[26] = paths->runtime_program_support_provider_source;
    inputs[27] = paths->runtime_program_support_host_provider_source;
    inputs[28] = paths->runtime_debug_provider_source;
    inputs[29] = paths->tooling_host_ops_source;
    inputs[30] = paths->tooling_path_source;
    inputs[31] = paths->tooling_world_receipt_gate_source;
    inputs[32] = paths->std_os_host_process_source;
    inputs[33] = paths->std_os_source;
    return cheng_seed_output_is_fresh_against_inputs(paths->backend_driver_out, inputs, 34U) &&
           cheng_seed_output_is_fresh_against_inputs(map_path, inputs, 34U);
}

static int cheng_seed_cmd_bootstrap_bridge(int argc, char **argv);
static int cheng_seed_cmd_build_backend_driver(int argc, char **argv);

static bool cheng_seed_ensure_backend_driver_ready(ChengSeedBootstrapPaths *paths,
                                           const char *context) {
    if (paths == NULL) {
        return false;
    }
    if (!cheng_seed_bootstrap_artifacts_fresh(paths) &&
        cheng_seed_cmd_bootstrap_bridge(0, NULL) != 0) {
        if (context != NULL && context[0] != '\0') {
            fprintf(stderr,
                    "[cheng_seed] %s bootstrap-bridge failed\n",
                    context);
        }
        return false;
    }
    if (cheng_seed_backend_driver_ready(paths)) {
        return true;
    }
    if (cheng_seed_cmd_build_backend_driver(0, NULL) != 0) {
        if (context != NULL && context[0] != '\0') {
            fprintf(stderr,
                    "[cheng_seed] %s build-backend-driver failed\n",
                    context);
        }
        return false;
    }
    if (access(paths->backend_driver_out, X_OK) != 0) {
        if (context != NULL && context[0] != '\0') {
            fprintf(stderr,
                    "[cheng_seed] %s missing backend driver: %s\n",
                    context,
                    paths->backend_driver_out);
        }
        return false;
    }
    return true;
}

static bool cheng_seed_lock_holder_alive(const char *lock_path, bool *alive_out) {
    char pid_text[64];
    ssize_t pid_len;
    char *end = NULL;
    long pid = 0;
    if (alive_out == NULL) {
        return false;
    }
    *alive_out = false;
    pid_len = readlink(lock_path, pid_text, sizeof(pid_text) - 1);
    if (pid_len < 0) {
        if (errno == ENOENT) {
            return true;
        }
        perror("readlink");
        return false;
    }
    pid_text[pid_len] = '\0';
    errno = 0;
    pid = strtol(pid_text, &end, 10);
    if (errno != 0 || end == pid_text || *end != '\0' || pid <= 0) {
        return true;
    }
    if (kill((pid_t)pid, 0) == 0 || errno == EPERM) {
        *alive_out = true;
        return true;
    }
    if (errno == ESRCH) {
        *alive_out = false;
        return true;
    }
    perror("kill");
    return false;
}

static bool cheng_seed_acquire_pid_lock(const char *lock_path,
                                bool *held_out,
                                ChengSeedReadyCheckFn ready_fn,
                                const void *ready_ctx,
                                const char *label) {
    char pid_text[64];
    if (held_out != NULL) {
        *held_out = false;
    }
    snprintf(pid_text, sizeof(pid_text), "%ld", (long)getpid());
    for (;;) {
        if (symlink(pid_text, lock_path) == 0) {
            if (held_out != NULL) {
                *held_out = true;
            }
            return true;
        }
        if (errno != EEXIST) {
            fprintf(stderr, "[cheng_seed] %s lock create failed: %s\n", label, lock_path);
            perror("symlink");
            return false;
        }
        if (ready_fn != NULL && ready_fn(ready_ctx)) {
            return true;
        }
        {
            bool alive = false;
            if (!cheng_seed_lock_holder_alive(lock_path, &alive)) {
                return false;
            }
            if (!alive) {
                if (unlink(lock_path) != 0 && errno != ENOENT) {
                    fprintf(stderr, "[cheng_seed] %s lock cleanup failed: %s\n", label, lock_path);
                    perror("unlink");
                    return false;
                }
                continue;
            }
        }
        usleep(50000);
    }
}

static void cheng_seed_release_pid_lock(const char *lock_path, bool *held_io) {
    if (held_io == NULL || !*held_io) {
        return;
    }
    if (unlink(lock_path) != 0 && errno != ENOENT) {
        perror("unlink");
    }
    *held_io = false;
}

static bool cheng_seed_bootstrap_ready_check(const void *ctx) {
    return cheng_seed_bootstrap_artifacts_fresh((const ChengSeedBootstrapPaths *)ctx);
}

static bool cheng_seed_backend_driver_ready_check(const void *ctx) {
    return cheng_seed_backend_driver_ready((const ChengSeedBootstrapPaths *)ctx);
}

static bool cheng_seed_file_text_equal(const char *left_path, const char *right_path) {
    char *left = cheng_seed_read_file(left_path);
    char *right = cheng_seed_read_file(right_path);
    bool same = false;
    if (left != NULL && right != NULL) {
        same = strcmp(left, right) == 0;
    }
    free(left);
    free(right);
    return same;
}

static bool cheng_seed_build_plan_line_relevant(const char *line) {
    return strncmp(line, "target=", 7U) == 0 ||
           strncmp(line, "linker=", 7U) == 0 ||
           strncmp(line, "stage2_compiler=", 16U) == 0 ||
           strncmp(line, "entry=", 6U) == 0 ||
           strncmp(line, "output=", 7U) == 0 ||
           strncmp(line, "source[", 7U) == 0;
}

static char *cheng_seed_build_plan_comparable_text(const char *text) {
    size_t cap;
    char *out;
    size_t out_len = 0U;
    const char *cursor;
    if (text == NULL) {
        return NULL;
    }
    cap = strlen(text) + 1U;
    out = (char *)cheng_seed_xmalloc(cap);
    out[0] = '\0';
    cursor = text;
    while (*cursor != '\0') {
        const char *end = strchr(cursor, '\n');
        size_t len = end != NULL ? (size_t)(end - cursor) : strlen(cursor);
        char line[PATH_MAX * 4U];
        if (len >= sizeof(line)) {
            len = sizeof(line) - 1U;
        }
        memcpy(line, cursor, len);
        line[len] = '\0';
        if (cheng_seed_build_plan_line_relevant(line)) {
            if (out_len + len + 2U > cap) {
                size_t next_cap = cap * 2U + len + 2U;
                char *grown = (char *)realloc(out, next_cap);
                if (grown == NULL) {
                    free(out);
                    fprintf(stderr, "[cheng_seed] out of memory\n");
                    exit(1);
                }
                out = grown;
                cap = next_cap;
            }
            memcpy(out + out_len, line, len);
            out_len += len;
            out[out_len++] = '\n';
            out[out_len] = '\0';
        }
        cursor = end != NULL ? end + 1 : cursor + len;
    }
    return out;
}

static bool cheng_seed_build_plan_files_equal(const char *left_path, const char *right_path) {
    char *left = cheng_seed_read_file(left_path);
    char *right = cheng_seed_read_file(right_path);
    char *left_cmp = NULL;
    char *right_cmp = NULL;
    bool same = false;
    if (left != NULL && right != NULL) {
        left_cmp = cheng_seed_build_plan_comparable_text(left);
        right_cmp = cheng_seed_build_plan_comparable_text(right);
        same = left_cmp != NULL && right_cmp != NULL && strcmp(left_cmp, right_cmp) == 0;
    }
    free(left);
    free(right);
    free(left_cmp);
    free(right_cmp);
    return same;
}

static bool cheng_seed_run_shell_command_logged(const char *command,
                                        const char *log_path,
                                        const char *label) {
    const char *argv_local[4];
    if (command == NULL || command[0] == '\0') {
        return false;
    }
    argv_local[0] = "/bin/sh";
    argv_local[1] = "-lc";
    argv_local[2] = command;
    argv_local[3] = NULL;
    return cheng_seed_run_command_logged_argv(3U, argv_local, log_path, label);
}

static bool cheng_seed_waitpid_nointr_silent(pid_t pid, int *status_out) {
    int status = 0;
    for (;;) {
        if (waitpid(pid, &status, 0) >= 0) {
            if (status_out != NULL) {
                *status_out = status;
            }
            return true;
        }
        if (errno == EINTR) {
            continue;
        }
        return false;
    }
}

static bool cheng_seed_waitpid_nointr(pid_t pid, int *status_out) {
    if (cheng_seed_waitpid_nointr_silent(pid, status_out)) {
        return true;
    }
    perror("waitpid");
    return false;
}

static const char *cheng_seed_signal_name(int signal_code) {
    switch (signal_code) {
        case SIGHUP: return "SIGHUP";
        case SIGINT: return "SIGINT";
        case SIGQUIT: return "SIGQUIT";
        case SIGILL: return "SIGILL";
        case SIGTRAP: return "SIGTRAP";
        case SIGABRT: return "SIGABRT";
        case SIGBUS: return "SIGBUS";
        case SIGFPE: return "SIGFPE";
        case SIGKILL: return "SIGKILL";
        case SIGUSR1: return "SIGUSR1";
        case SIGSEGV: return "SIGSEGV";
        case SIGUSR2: return "SIGUSR2";
        case SIGPIPE: return "SIGPIPE";
        case SIGALRM: return "SIGALRM";
        case SIGTERM: return "SIGTERM";
        default: return NULL;
    }
}

static void cheng_seed_report_child_status(const char *label,
                                   int status,
                                   const char *log_path) {
    const char *safe_label = (label != NULL && label[0] != '\0') ? label : "<unknown>";
    const char *safe_log = (log_path != NULL && log_path[0] != '\0') ? log_path : "-";
    if (WIFEXITED(status)) {
        fprintf(stderr,
                "[cheng_seed] %s failed exit=%d log=%s\n",
                safe_label,
                WEXITSTATUS(status),
                safe_log);
        return;
    }
    if (WIFSIGNALED(status)) {
        int signal_code = WTERMSIG(status);
        const char *signal_name = cheng_seed_signal_name(signal_code);
        const char *signal_text = strsignal(signal_code);
        fprintf(stderr,
                "[cheng_seed] %s failed signal=%d",
                safe_label,
                signal_code);
        if (signal_name != NULL && signal_name[0] != '\0') {
            fprintf(stderr, " name=%s", signal_name);
        }
        if (signal_text != NULL && signal_text[0] != '\0') {
            fprintf(stderr, " detail=%s", signal_text);
        }
        fprintf(stderr, " log=%s\n", safe_log);
        return;
    }
    fprintf(stderr,
            "[cheng_seed] %s failed status=%d log=%s\n",
            safe_label,
            status,
            safe_log);
}

static bool cheng_seed_env_key_matches(const char *entry, const char *key) {
    size_t key_len;
    if (entry == NULL || key == NULL || key[0] == '\0') {
        return false;
    }
    key_len = strlen(key);
    return strncmp(entry, key, key_len) == 0 && entry[key_len] == '=';
}

static char *cheng_seed_env_override_entry(const char *key, const char *value) {
    size_t key_len;
    size_t value_len;
    char *out;
    if (key == NULL || value == NULL || key[0] == '\0') {
        return NULL;
    }
    key_len = strlen(key);
    value_len = strlen(value);
    out = (char *)cheng_seed_xmalloc(key_len + value_len + 2U);
    memcpy(out, key, key_len);
    out[key_len] = '=';
    memcpy(out + key_len + 1U, value, value_len);
    out[key_len + value_len + 1U] = '\0';
    return out;
}

static char **cheng_seed_copy_environ_with_overrides(const char *env_key_a,
                                             const char *env_value_a,
                                             const char *env_key_b,
                                             const char *env_value_b) {
    size_t count = 0U;
    size_t out_len = 0U;
    size_t i;
    char *override_a = cheng_seed_env_override_entry(env_key_a, env_value_a);
    char *override_b = cheng_seed_env_override_entry(env_key_b, env_value_b);
    char **out;
    bool same_key = false;
    if (override_a != NULL && override_b != NULL &&
        env_key_a != NULL && env_key_b != NULL &&
        strcmp(env_key_a, env_key_b) == 0) {
        same_key = true;
        free(override_a);
        override_a = NULL;
    }
    while (environ != NULL && environ[count] != NULL) {
        count += 1U;
    }
    out = (char **)cheng_seed_xmalloc(sizeof(char *) * (count + 3U));
    for (i = 0U; i < count; ++i) {
        const char *entry = environ[i];
        if (override_a != NULL && cheng_seed_env_key_matches(entry, env_key_a)) {
            continue;
        }
        if (override_b != NULL && cheng_seed_env_key_matches(entry, env_key_b)) {
            continue;
        }
        out[out_len++] = cheng_seed_strdup(entry);
    }
    if (override_a != NULL) {
        out[out_len++] = override_a;
    }
    if (override_b != NULL) {
        out[out_len++] = override_b;
    } else if (same_key) {
        out[out_len++] = cheng_seed_env_override_entry(env_key_b, env_value_b);
    }
    out[out_len] = NULL;
    return out;
}

static void cheng_seed_free_spawn_env(char **envp) {
    size_t i = 0U;
    if (envp == NULL) {
        return;
    }
    while (envp[i] != NULL) {
        free(envp[i]);
        i += 1U;
    }
    free(envp);
}

static void cheng_seed_write_spawn_error_log(const char *log_path,
                                     const char *program,
                                     int spawn_rc) {
    FILE *log_file;
    if (log_path == NULL || log_path[0] == '\0' || !cheng_seed_ensure_parent_dir(log_path)) {
        return;
    }
    log_file = fopen(log_path, "wb");
    if (log_file == NULL) {
        return;
    }
    fprintf(log_file,
            "spawn failed: %s rc=%d errno=%d (%s)\n",
            program != NULL ? program : "",
            spawn_rc,
            spawn_rc,
            strerror(spawn_rc));
    fclose(log_file);
}

static size_t cheng_seed_argv_count(char *const argv_local[]) {
    size_t count = 0U;
    if (argv_local == NULL) {
        return 0U;
    }
    while (argv_local[count] != NULL) {
        count += 1U;
    }
    return count;
}

static bool cheng_seed_spawn_argv_common(size_t arg_count,
                                 const char **args,
                                 const char *stdin_path,
                                 bool stdin_devnull,
                                 const char *stdout_path,
                                 bool merge_stderr,
                                 bool search_path,
                                 bool own_process_group,
                                 char *const envp[],
                                 pid_t *pid_out) {
    size_t i;
    char **exec_argv;
    posix_spawn_file_actions_t actions;
    posix_spawn_file_actions_t *actions_ptr = NULL;
    posix_spawnattr_t attr;
    posix_spawnattr_t *attr_ptr = NULL;
    pid_t pid = -1;
    int spawn_rc;
    bool actions_ready = false;
    bool attr_ready = false;
    short flags = 0;
    if (pid_out != NULL) {
        *pid_out = -1;
    }
    if (arg_count == 0U ||
        args == NULL ||
        args[0] == NULL ||
        args[0][0] == '\0' ||
        (stdin_path != NULL && stdin_path[0] == '\0')) {
        return false;
    }
    if (stdout_path != NULL && stdout_path[0] != '\0' && !cheng_seed_ensure_parent_dir(stdout_path)) {
        return false;
    }
    exec_argv = (char **)cheng_seed_xmalloc(sizeof(char *) * (arg_count + 1U));
    for (i = 0U; i < arg_count; ++i) {
        exec_argv[i] = (char *)(args[i] != NULL ? args[i] : "");
    }
    exec_argv[arg_count] = NULL;
    if (stdin_path != NULL || stdin_devnull || (stdout_path != NULL && stdout_path[0] != '\0') || merge_stderr) {
        if (posix_spawn_file_actions_init(&actions) != 0) {
            free(exec_argv);
            return false;
        }
        actions_ready = true;
        actions_ptr = &actions;
        if ((stdin_path != NULL &&
             posix_spawn_file_actions_addopen(&actions, STDIN_FILENO, stdin_path, O_RDONLY, 0) != 0) ||
            (stdin_path == NULL &&
             stdin_devnull &&
             posix_spawn_file_actions_addopen(&actions, STDIN_FILENO, "/dev/null", O_RDONLY, 0) != 0) ||
            ((stdout_path != NULL && stdout_path[0] != '\0') &&
             posix_spawn_file_actions_addopen(&actions,
                                              STDOUT_FILENO,
                                              stdout_path,
                                              O_WRONLY | O_CREAT | O_TRUNC,
                                              0644) != 0) ||
            (merge_stderr &&
             posix_spawn_file_actions_adddup2(&actions, STDOUT_FILENO, STDERR_FILENO) != 0)) {
            goto done;
        }
    }
    if (own_process_group) {
        if (posix_spawnattr_init(&attr) != 0) {
            goto done;
        }
        attr_ready = true;
        flags = (short)(flags | POSIX_SPAWN_SETPGROUP);
        if (posix_spawnattr_setflags(&attr, flags) != 0 ||
            posix_spawnattr_setpgroup(&attr, 0) != 0) {
            goto done;
        }
        attr_ptr = &attr;
    }
    spawn_rc = search_path
        ? posix_spawnp(&pid, exec_argv[0], actions_ptr, attr_ptr, exec_argv, envp != NULL ? envp : environ)
        : posix_spawn(&pid, exec_argv[0], actions_ptr, attr_ptr, exec_argv, envp != NULL ? envp : environ);
    if (spawn_rc != 0) {
        if (stdout_path != NULL && stdout_path[0] != '\0') {
            cheng_seed_write_spawn_error_log(stdout_path, exec_argv[0], spawn_rc);
        }
        errno = spawn_rc;
        perror(search_path ? "posix_spawnp" : "posix_spawn");
        goto done;
    }
    if (pid_out != NULL) {
        *pid_out = pid;
    }
    if (attr_ready) {
        posix_spawnattr_destroy(&attr);
    }
    if (actions_ready) {
        posix_spawn_file_actions_destroy(&actions);
    }
    free(exec_argv);
    return true;
done:
    if (attr_ready) {
        posix_spawnattr_destroy(&attr);
    }
    if (actions_ready) {
        posix_spawn_file_actions_destroy(&actions);
    }
    free(exec_argv);
    return false;
}

static bool cheng_seed_spawn_logged_argv(size_t arg_count,
                                 const char **args,
                                 const char *log_path,
                                 bool search_path,
                                 bool stdin_devnull,
                                 bool own_process_group,
                                 pid_t *pid_out) {
    return cheng_seed_spawn_argv_common(arg_count,
                                args,
                                NULL,
                                stdin_devnull,
                                log_path,
                                true,
                                search_path,
                                own_process_group,
                                NULL,
                                pid_out);
}

