static bool cheng_seed_run_command_status_argv(size_t arg_count,
                                       const char **args,
                                       bool search_path,
                                       const char *label) {
    pid_t pid = -1;
    int status = 0;
    if (!cheng_seed_spawn_argv_with_env(arg_count, args, search_path, false, NULL, &pid)) {
        return false;
    }
    if (!cheng_seed_waitpid_nointr(pid, &status)) {
        return false;
    }
    if (WIFEXITED(status) && WEXITSTATUS(status) == 0) {
        return true;
    }
    fprintf(stderr,
            "[cheng_seed] %s failed status=%d program=%s\n",
            label != NULL ? label : "command",
            status,
            args != NULL && arg_count > 0U && args[0] != NULL ? args[0] : "");
    return false;
}

static bool cheng_seed_run_shell_command_status(const char *command, const char *label) {
    const char *argv_local[4];
    if (command == NULL || command[0] == '\0') {
        return false;
    }
    argv_local[0] = "/bin/sh";
    argv_local[1] = "-lc";
    argv_local[2] = command;
    argv_local[3] = NULL;
    return cheng_seed_run_command_status_argv(3U, argv_local, false, label);
}

static bool cheng_seed_run_command_logged_argv(size_t arg_count,
                                       const char **args,
                                       const char *log_path,
                                       const char *label) {
    pid_t pid;
    int status = 0;
    if (arg_count == 0U || args == NULL) {
        fprintf(stderr, "[cheng_seed] %s missing argv\n", label);
        return false;
    }
    if (!cheng_seed_spawn_logged_argv(arg_count, args, log_path, true, true, false, &pid)) {
        return false;
    }
    if (!cheng_seed_waitpid_nointr(pid, &status)) {
        return false;
    }
    if (!cheng_seed_status_is_exit_code(status, 0)) {
        cheng_seed_report_child_status(label, status, log_path);
        return false;
    }
    return true;
}

static void cheng_seed_echo_progress_line(const char *line, size_t len) {
    static const char prefix[] = "compile_progress ";
    if (line == NULL || len + 1U < sizeof(prefix)) {
        return;
    }
    if (memcmp(line, prefix, sizeof(prefix) - 1U) != 0) {
        return;
    }
    fwrite(line, 1U, len, stderr);
    fputc('\n', stderr);
    fflush(stderr);
}

static void cheng_seed_echo_progress_chunk(const char *data,
                                   size_t len,
                                   char *line,
                                   size_t line_cap,
                                   size_t *line_len) {
    size_t i;
    if (data == NULL || line == NULL || line_len == NULL || line_cap == 0U) {
        return;
    }
    for (i = 0U; i < len; ++i) {
        char ch = data[i];
        if (ch == '\n') {
            cheng_seed_echo_progress_line(line, *line_len);
            *line_len = 0U;
            continue;
        }
        if (*line_len + 1U < line_cap) {
            line[*line_len] = ch;
            *line_len += 1U;
            line[*line_len] = '\0';
        } else {
            *line_len = 0U;
        }
    }
}

static bool cheng_seed_run_command_logged_argv_live(size_t arg_count,
                                            const char **args,
                                            const char *log_path,
                                            const char *label) {
    char **exec_argv = NULL;
    posix_spawn_file_actions_t actions;
    bool actions_ready = false;
    int pipe_fds[2] = { -1, -1 };
    int flags;
    int spawn_rc;
    pid_t pid = -1;
    int status = 0;
    bool running = true;
    bool pipe_open = true;
    FILE *log = NULL;
    char buffer[8192];
    char progress_line[1024];
    size_t progress_len = 0U;
    size_t i;
    if (arg_count == 0U || args == NULL || log_path == NULL || log_path[0] == '\0') {
        fprintf(stderr, "[cheng_seed] %s missing argv/log\n", label);
        return false;
    }
    if (!cheng_seed_ensure_parent_dir(log_path)) {
        return false;
    }
    log = fopen(log_path, "wb");
    if (log == NULL) {
        perror("fopen");
        return false;
    }
    exec_argv = (char **)cheng_seed_xmalloc(sizeof(char *) * (arg_count + 1U));
    for (i = 0U; i < arg_count; ++i) {
        exec_argv[i] = (char *)args[i];
    }
    exec_argv[arg_count] = NULL;
    if (pipe(pipe_fds) != 0) {
        perror("pipe");
        goto fail;
    }
    if (posix_spawn_file_actions_init(&actions) != 0) {
        goto fail;
    }
    actions_ready = true;
    if (posix_spawn_file_actions_addclose(&actions, pipe_fds[0]) != 0 ||
        posix_spawn_file_actions_adddup2(&actions, pipe_fds[1], STDOUT_FILENO) != 0 ||
        posix_spawn_file_actions_adddup2(&actions, pipe_fds[1], STDERR_FILENO) != 0 ||
        (pipe_fds[1] != STDOUT_FILENO &&
         pipe_fds[1] != STDERR_FILENO &&
         posix_spawn_file_actions_addclose(&actions, pipe_fds[1]) != 0)) {
        goto fail;
    }
    spawn_rc = posix_spawnp(&pid, exec_argv[0], &actions, NULL, exec_argv, environ);
    if (spawn_rc != 0) {
        errno = spawn_rc;
        perror("posix_spawnp");
        goto fail;
    }
    close(pipe_fds[1]);
    pipe_fds[1] = -1;
    flags = fcntl(pipe_fds[0], F_GETFL, 0);
    if (flags >= 0) {
        (void)fcntl(pipe_fds[0], F_SETFL, flags | O_NONBLOCK);
    }
    while (running || pipe_open) {
        ssize_t n = read(pipe_fds[0], buffer, sizeof(buffer));
        if (n > 0) {
            fwrite(buffer, 1U, (size_t)n, log);
            fflush(log);
            cheng_seed_echo_progress_chunk(buffer,
                                   (size_t)n,
                                   progress_line,
                                   sizeof(progress_line),
                                   &progress_len);
            continue;
        }
        if (n == 0) {
            pipe_open = false;
        } else if (errno != EAGAIN && errno != EWOULDBLOCK && errno != EINTR) {
            pipe_open = false;
        }
        if (running) {
            pid_t wait_rc = waitpid(pid, &status, WNOHANG);
            if (wait_rc == pid) {
                running = false;
            } else if (wait_rc < 0 && errno != EINTR) {
                running = false;
                status = 127 << 8;
            }
        }
        if (running || pipe_open) {
            usleep(20000U);
        }
    }
    if (progress_len > 0U) {
        cheng_seed_echo_progress_line(progress_line, progress_len);
    }
    fclose(log);
    log = NULL;
    if (pipe_fds[0] >= 0) {
        close(pipe_fds[0]);
    }
    if (actions_ready) {
        posix_spawn_file_actions_destroy(&actions);
    }
    free(exec_argv);
    if (!cheng_seed_status_is_exit_code(status, 0)) {
        cheng_seed_report_child_status(label, status, log_path);
        return false;
    }
    return true;
fail:
    if (pid > 0) {
        kill(pid, SIGTERM);
    }
    if (pipe_fds[0] >= 0) {
        close(pipe_fds[0]);
    }
    if (pipe_fds[1] >= 0) {
        close(pipe_fds[1]);
    }
    if (actions_ready) {
        posix_spawn_file_actions_destroy(&actions);
    }
    if (log != NULL) {
        fclose(log);
    }
    free(exec_argv);
    return false;
}

static bool cheng_seed_run_command_logged_argv_quiet(size_t arg_count,
                                             const char **args,
                                             const char *log_path,
                                             const char *label) {
    pid_t pid;
    int status = 0;
    if (arg_count == 0U || args == NULL) {
        return false;
    }
    (void)label;
    if (!cheng_seed_spawn_logged_argv(arg_count, args, log_path, true, true, false, &pid)) {
        return false;
    }
    if (!cheng_seed_waitpid_nointr(pid, &status)) {
        return false;
    }
    return status == 0;
}

static bool cheng_seed_run_command_logged_argv_with_input_file(size_t arg_count,
                                                       const char **args,
                                                       const char *stdin_path,
                                                       const char *log_path,
                                                       const char *label,
                                                       bool quiet_failures) {
    pid_t pid = -1;
    int status = 0;
    if (arg_count == 0U || args == NULL || stdin_path == NULL || stdin_path[0] == '\0') {
        return false;
    }
    if (!cheng_seed_spawn_logged_argv_with_input_file(arg_count,
                                              args,
                                              stdin_path,
                                              log_path,
                                              true,
                                              false,
                                              &pid)) {
        return false;
    }
    if (!cheng_seed_waitpid_nointr(pid, &status)) {
        return false;
    }
    if (status != 0 && !quiet_failures) {
        cheng_seed_report_child_status(label, status, log_path);
    }
    return status == 0;
}

static bool cheng_seed_bootstrap_write_env_and_snapshot(const ChengSeedBootstrapPaths *paths) {
    char *env_text;
    char *snapshot_text;
    size_t env_cap = 8192U;
    size_t snapshot_cap = 12288U;
    env_text = (char *)cheng_seed_xmalloc(env_cap);
    snapshot_text = (char *)cheng_seed_xmalloc(snapshot_cap);
    snprintf(env_text,
             env_cap,
             "ChengSeed_ROOT=%s\n"
             "ChengSeed_TARGET=%s\n"
             "CHENG_BOOTSTRAP_KIND=selfhost\n"
             "CHENG_BOOTSTRAP_STAGE1_SOURCE=%s\n"
             "ChengSeed_COMPILER_ENTRY_SOURCE=%s\n"
             "ChengSeed_COMPILER_RUNTIME_SOURCE=%s\n"
             "ChengSeed_COMPILER_REQUEST_SOURCE=%s\n"
             "CHENG_BOOTSTRAP_STAGE0=%s\n"
             "CHENG_BOOTSTRAP_STAGE1=%s\n"
             "CHENG_BOOTSTRAP_STAGE2=%s\n"
             "CHENG_BOOTSTRAP_STAGE3=%s\n"
             "CHENG_BOOTSTRAP_ENV=%s\n"
             "CHENG_BOOTSTRAP_SNAPSHOT=%s\n"
             "CHENG_BOOTSTRAP_STAGE1_REPORT=%s\n"
             "CHENG_BOOTSTRAP_STAGE2_REPORT=%s\n"
             "CHENG_BOOTSTRAP_STAGE3_REPORT=%s\n",
             paths->root,
             paths->target,
             paths->stage1_source,
             paths->compiler_entry_source,
             paths->compiler_runtime_source,
             paths->compiler_request_source,
             paths->stage0,
             paths->stage1,
             paths->stage2,
             paths->stage3,
             paths->env_path,
             paths->snapshot_path,
             paths->stage1_report,
             paths->stage2_report,
             paths->stage3_report);
    snprintf(snapshot_text,
             snapshot_cap,
             "target=%s\n"
             "bootstrap_kind=selfhost\n"
             "stage1_source=%s\n"
             "compiler_entry_source=%s\n"
             "compiler_runtime_source=%s\n"
             "compiler_request_source=%s\n"
             "tooling_gate_source=%s\n"
             "stage0=%s\n"
             "stage1=%s\n"
             "stage2=%s\n"
             "stage3=%s\n"
             "stage1_report=%s\n"
             "stage2_report=%s\n"
             "stage3_report=%s\n"
             "stage0_build_log=%s\n"
             "stage0_self_check_log=%s\n"
             "stage1_build_log=%s\n"
             "stage1_self_check_log=%s\n"
             "stage2_build_log=%s\n"
             "stage2_self_check_log=%s\n"
             "stage3_build_log=%s\n"
             "stage3_self_check_log=%s\n"
             "stage2_contract_log=%s\n"
             "stage3_contract_log=%s\n"
             "fixed_point=stage2_stage3_contract_match\n",
             paths->target,
             paths->stage1_source,
             paths->compiler_entry_source,
             paths->compiler_runtime_source,
             paths->compiler_request_source,
             paths->tooling_gate_source,
             paths->stage0,
             paths->stage1,
             paths->stage2,
             paths->stage3,
             paths->stage1_report,
             paths->stage2_report,
             paths->stage3_report,
             paths->stage0_build_log,
             paths->stage0_self_check_log,
             paths->stage1_build_log,
             paths->stage1_self_check_log,
             paths->stage2_build_log,
             paths->stage2_self_check_log,
             paths->stage3_build_log,
             paths->stage3_self_check_log,
             paths->stage2_contract_log,
             paths->stage3_contract_log);
    if (!cheng_seed_ensure_parent_dir(paths->env_path) ||
        !cheng_seed_write_text_file(paths->env_path, env_text) ||
        !cheng_seed_write_text_file(paths->snapshot_path, snapshot_text)) {
        free(env_text);
        free(snapshot_text);
        return false;
    }
    free(env_text);
    free(snapshot_text);
    return true;
}

static const char *cheng_seed_flag_value(int argc, char **argv, const char *flag) {
    size_t flag_len = strlen(flag);
    int i;
    for (i = 2; i < argc; ++i) {
        const char *arg = argv[i];
        if (strncmp(arg, flag, flag_len) == 0) {
            if (arg[flag_len] == ':') {
                return arg + flag_len + 1;
            }
            if (arg[flag_len] == '=') {
                return arg + flag_len + 1;
            }
            if (arg[flag_len] == '\0' && (i + 1) < argc) {
                return argv[i + 1];
            }
        }
    }
    return NULL;
}

