static bool cheng_seed_lowering_plan_reserve_functions(ChengSeedLoweringPlanStub *lowering,
                                               size_t needed) {
    size_t old_cap;
    size_t new_cap;
    ChengSeedLoweredFunctionStub *grown;
    if (lowering == NULL) {
        return false;
    }
    if (needed <= lowering->function_cap) {
        return true;
    }
    if (needed > CHENG_MAX_PLAN_FUNCTIONS) {
        return false;
    }
    new_cap = lowering->function_cap > 0U ? lowering->function_cap : 64U;
    while (new_cap < needed) {
        if (new_cap >= CHENG_MAX_PLAN_FUNCTIONS) {
            new_cap = CHENG_MAX_PLAN_FUNCTIONS;
            break;
        }
        new_cap *= 2U;
        if (new_cap > CHENG_MAX_PLAN_FUNCTIONS) {
            new_cap = CHENG_MAX_PLAN_FUNCTIONS;
        }
    }
    if (new_cap < needed) {
        return false;
    }
    old_cap = lowering->function_cap;
    grown = (ChengSeedLoweredFunctionStub *)realloc(lowering->functions,
                                             sizeof(ChengSeedLoweredFunctionStub) * new_cap);
    if (grown == NULL) {
        return false;
    }
    if (new_cap > old_cap) {
        memset(grown + old_cap,
               0,
               sizeof(ChengSeedLoweredFunctionStub) * (new_cap - old_cap));
    }
    lowering->functions = grown;
    lowering->function_cap = new_cap;
    return true;
}

