static bool cheng_seed_target_is_darwin_arm64(const char *target_triple) {
    return target_triple != NULL &&
           (strcmp(target_triple, "arm64-apple-darwin") == 0 ||
            strcmp(target_triple, "aarch64-apple-ios") == 0 ||
            strcmp(target_triple, "arm64-apple-ios") == 0);
}

static long long cheng_seed_bft_monotime_ms(void);

static long long cheng_seed_phase_elapsed_ms(long long start_ms, long long end_ms) {
    if (start_ms <= 0LL || end_ms <= 0LL || end_ms < start_ms) {
        return 0LL;
    }
    return end_ms - start_ms;
}

static bool cheng_seed_target_is_android_aarch64(const char *target_triple) {
    return target_triple != NULL && strcmp(target_triple, "aarch64-linux-android") == 0;
}

static bool cheng_seed_target_is_linux_x86_64(const char *target_triple);
static bool cheng_seed_target_is_linux_generic_aarch64(const char *target_triple);
static bool cheng_seed_target_is_linux_riscv64(const char *target_triple);
static bool cheng_seed_target_is_windows_aarch64(const char *target_triple);
