static ChengSeedImportAliasCacheEntry g_cheng_import_alias_cache[CHENG_MAX_IMPORT_ALIAS_CACHE];
static size_t g_cheng_import_alias_cache_count = 0U;
static ChengSeedTopLevelVarDeclCacheEntry g_cheng_top_level_var_cache[CHENG_MAX_TOP_LEVEL_VAR_CACHE];
static size_t g_cheng_top_level_var_cache_count = 0U;
static ChengSeedImportcTargetCacheEntry g_cheng_importc_target_cache[CHENG_MAX_IMPORTC_TARGET_CACHE];
static size_t g_cheng_importc_target_cache_count = 0U;

static bool cheng_seed_copy_import_aliases(ChengSeedImportAlias *aliases_out,
                                   size_t *alias_count_out,
                                   size_t alias_cap,
                                   const ChengSeedImportAlias *aliases,
                                   size_t alias_count) {
    if (alias_count_out != NULL) {
        *alias_count_out = 0U;
    }
    if (alias_count > alias_cap) {
        return false;
    }
    if (alias_count > 0U && aliases_out == NULL) {
        return false;
    }
    if (alias_count > 0U) {
        memcpy(aliases_out, aliases, sizeof(*aliases_out) * alias_count);
    }
    if (alias_count_out != NULL) {
        *alias_count_out = alias_count;
    }
    return true;
}

static bool cheng_seed_import_alias_cache_get(const char *source_path,
                                      ChengSeedImportAlias *aliases_out,
                                      size_t *alias_count_out,
                                      size_t alias_cap) {
    size_t i;
    if (source_path == NULL || source_path[0] == '\0') {
        return false;
    }
    for (i = 0U; i < g_cheng_import_alias_cache_count; ++i) {
        if (strcmp(g_cheng_import_alias_cache[i].source_path, source_path) != 0) {
            continue;
        }
        return cheng_seed_copy_import_aliases(aliases_out,
                                      alias_count_out,
                                      alias_cap,
                                      g_cheng_import_alias_cache[i].aliases,
                                      g_cheng_import_alias_cache[i].alias_count);
    }
    return false;
}

static void cheng_seed_import_alias_cache_store(const char *source_path,
                                        const ChengSeedImportAlias *aliases,
                                        size_t alias_count) {
    ChengSeedImportAlias *copy = NULL;
    ChengSeedImportAliasCacheEntry *entry = NULL;
    size_t i;
    if (source_path == NULL || source_path[0] == '\0') {
        return;
    }
    for (i = 0U; i < g_cheng_import_alias_cache_count; ++i) {
        if (strcmp(g_cheng_import_alias_cache[i].source_path, source_path) == 0) {
            return;
        }
    }
    if (g_cheng_import_alias_cache_count >= CHENG_MAX_IMPORT_ALIAS_CACHE) {
        return;
    }
    if (alias_count > 0U) {
        copy = (ChengSeedImportAlias *)malloc(sizeof(*copy) * alias_count);
        if (copy == NULL) {
            return;
        }
        memcpy(copy, aliases, sizeof(*copy) * alias_count);
    }
    entry = &g_cheng_import_alias_cache[g_cheng_import_alias_cache_count++];
    memset(entry, 0, sizeof(*entry));
    snprintf(entry->source_path, sizeof(entry->source_path), "%s", source_path);
    entry->alias_count = alias_count;
    entry->aliases = copy;
}

static bool cheng_seed_top_level_var_cache_get(const char *source_path,
                                       const ChengSeedTopLevelVarDecl **decls_out,
                                       size_t *decl_count_out) {
    size_t i;
    if (decls_out != NULL) {
        *decls_out = NULL;
    }
    if (decl_count_out != NULL) {
        *decl_count_out = 0U;
    }
    if (source_path == NULL || source_path[0] == '\0') {
        return false;
    }
    for (i = 0U; i < g_cheng_top_level_var_cache_count; ++i) {
        if (strcmp(g_cheng_top_level_var_cache[i].source_path, source_path) != 0) {
            continue;
        }
        if (decls_out != NULL) {
            *decls_out = g_cheng_top_level_var_cache[i].decls;
        }
        if (decl_count_out != NULL) {
            *decl_count_out = g_cheng_top_level_var_cache[i].decl_count;
        }
        return true;
    }
    return false;
}

static void cheng_seed_top_level_var_cache_store(const char *source_path,
                                         ChengSeedTopLevelVarDecl *decls,
                                         size_t decl_count) {
    ChengSeedTopLevelVarDeclCacheEntry *entry = NULL;
    size_t i;
    if (source_path == NULL || source_path[0] == '\0') {
        free(decls);
        return;
    }
    for (i = 0U; i < g_cheng_top_level_var_cache_count; ++i) {
        if (strcmp(g_cheng_top_level_var_cache[i].source_path, source_path) == 0) {
            free(decls);
            return;
        }
    }
    if (g_cheng_top_level_var_cache_count >= CHENG_MAX_TOP_LEVEL_VAR_CACHE) {
        free(decls);
        return;
    }
    entry = &g_cheng_top_level_var_cache[g_cheng_top_level_var_cache_count++];
    memset(entry, 0, sizeof(*entry));
    snprintf(entry->source_path, sizeof(entry->source_path), "%s", source_path);
    entry->decl_count = decl_count;
    entry->decls = decls;
}

static bool cheng_seed_collect_top_level_var_decls_from_lines(char **lines,
                                                      size_t line_count,
                                                      ChengSeedTopLevelVarDecl **decls_out,
                                                      size_t *decl_count_out) {
    ChengSeedTopLevelVarDecl *decls = NULL;
    size_t decl_count = 0U;
    size_t decl_cap = 0U;
    bool in_var_block = false;
    size_t i;
    if (decls_out == NULL || decl_count_out == NULL) {
        return false;
    }
    *decls_out = NULL;
    *decl_count_out = 0U;
    for (i = 0U; i < line_count; ++i) {
        char line_copy[4096];
        char name[128];
        char raw_type[256];
        char expr[4096];
        bool has_init = false;
        int32_t indent;
        char *trimmed;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        indent = cheng_seed_line_indent(line_copy);
        trimmed = cheng_seed_trim_inplace(line_copy);
        if (*trimmed == '\0' || *trimmed == '#') {
            continue;
        }
        if (indent <= 0 && strcmp(trimmed, "var") == 0) {
            in_var_block = true;
            continue;
        }
        if (indent <= 0 && !cheng_seed_startswith(trimmed, "var ")) {
            in_var_block = false;
        }
        if (indent <= 0 && cheng_seed_startswith(trimmed, "var ")) {
            trimmed += 4;
        } else if (!in_var_block || indent <= 0) {
            continue;
        }
        if (!cheng_seed_parse_top_level_var_binding_text(trimmed,
                                                 name,
                                                 sizeof(name),
                                                 raw_type,
                                                 sizeof(raw_type),
                                                 &has_init,
                                                 expr,
                                                 sizeof(expr))) {
            continue;
        }
        if (decl_count >= decl_cap) {
            size_t next_cap = decl_cap <= 0U ? 16U : decl_cap * 2U;
            ChengSeedTopLevelVarDecl *grown =
                (ChengSeedTopLevelVarDecl *)realloc(decls, sizeof(*grown) * next_cap);
            if (grown == NULL) {
                free(decls);
                return false;
            }
            decls = grown;
            decl_cap = next_cap;
        }
        memset(&decls[decl_count], 0, sizeof(decls[decl_count]));
        snprintf(decls[decl_count].name, sizeof(decls[decl_count].name), "%s", name);
        snprintf(decls[decl_count].raw_type, sizeof(decls[decl_count].raw_type), "%s", raw_type);
        decls[decl_count].has_init = has_init;
        decl_count += 1U;
    }
    *decls_out = decls;
    *decl_count_out = decl_count;
    return true;
}

static bool cheng_seed_load_top_level_var_decls_from_source_path(const char *source_path,
                                                         const ChengSeedTopLevelVarDecl **decls_out,
                                                         size_t *decl_count_out) {
    char **lines = NULL;
    char *owned = NULL;
    size_t line_count = 0U;
    ChengSeedTopLevelVarDecl *decls = NULL;
    size_t decl_count = 0U;
    ChengSeedImportAlias aliases[CHENG_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    if (decls_out != NULL) {
        *decls_out = NULL;
    }
    if (decl_count_out != NULL) {
        *decl_count_out = 0U;
    }
    if (source_path == NULL || source_path[0] == '\0' ||
        decls_out == NULL || decl_count_out == NULL) {
        return false;
    }
    if (cheng_seed_top_level_var_cache_get(source_path, decls_out, decl_count_out)) {
        return true;
    }
    if (!cheng_seed_load_source_lines(source_path, &lines, &owned, &line_count)) {
        return false;
    }
    if (!cheng_seed_collect_top_level_var_decls_from_lines(lines, line_count, &decls, &decl_count)) {
        free(lines);
        free(owned);
        return false;
    }
    cheng_seed_parse_import_aliases_from_lines(lines,
                                       line_count,
                                       aliases,
                                       &alias_count,
                                       CHENG_MAX_IMPORT_ALIASES);
    cheng_seed_import_alias_cache_store(source_path, aliases, alias_count);
    free(lines);
    free(owned);
    cheng_seed_top_level_var_cache_store(source_path, decls, decl_count);
    return cheng_seed_top_level_var_cache_get(source_path, decls_out, decl_count_out);
}

static bool cheng_seed_importc_target_cache_lookup(const char *source_path,
                                           const char *callee,
                                           ChengSeedAsmCallTarget *target_out,
                                           bool *found_out) {
    size_t i;
    if (found_out != NULL) {
        *found_out = false;
    }
    if (source_path == NULL || source_path[0] == '\0' ||
        callee == NULL || callee[0] == '\0') {
        return false;
    }
    for (i = 0U; i < g_cheng_importc_target_cache_count; ++i) {
        if (strcmp(g_cheng_importc_target_cache[i].source_path, source_path) != 0 ||
            strcmp(g_cheng_importc_target_cache[i].callee, callee) != 0) {
            continue;
        }
        if (found_out != NULL) {
            *found_out = g_cheng_importc_target_cache[i].found;
        }
        if (g_cheng_importc_target_cache[i].found &&
            target_out != NULL &&
            g_cheng_importc_target_cache[i].target != NULL) {
            memcpy(target_out,
                   g_cheng_importc_target_cache[i].target,
                   sizeof(*target_out));
        }
        return true;
    }
    return false;
}

static void cheng_seed_importc_target_cache_store(const char *source_path,
                                          const char *callee,
                                          const ChengSeedAsmCallTarget *target,
                                          bool found) {
    ChengSeedImportcTargetCacheEntry *entry = NULL;
    size_t i;
    if (source_path == NULL || source_path[0] == '\0' ||
        callee == NULL || callee[0] == '\0') {
        return;
    }
    for (i = 0U; i < g_cheng_importc_target_cache_count; ++i) {
        if (strcmp(g_cheng_importc_target_cache[i].source_path, source_path) == 0 &&
            strcmp(g_cheng_importc_target_cache[i].callee, callee) == 0) {
            return;
        }
    }
    if (g_cheng_importc_target_cache_count >= CHENG_MAX_IMPORTC_TARGET_CACHE) {
        return;
    }
    entry = &g_cheng_importc_target_cache[g_cheng_importc_target_cache_count++];
    memset(entry, 0, sizeof(*entry));
    snprintf(entry->source_path, sizeof(entry->source_path), "%s", source_path);
    snprintf(entry->callee, sizeof(entry->callee), "%s", callee);
    entry->found = found;
    if (found && target != NULL) {
        entry->target = (ChengSeedAsmCallTarget *)malloc(sizeof(*entry->target));
        if (entry->target == NULL) {
            entry->found = false;
            return;
        }
        memcpy(entry->target, target, sizeof(*entry->target));
    }
}

