static bool cheng_seed_startswith(const char *text, const char *prefix) {
    size_t n = strlen(prefix);
    return strncmp(text, prefix, n) == 0;
}

static void cheng_seed_copy_text(char *dst, size_t cap, const char *src) {
    if (!src) {
        dst[0] = '\0';
        return;
    }
    snprintf(dst, cap, "%s", src);
}

static bool cheng_seed_symbol_has_cheng_internal_abi_prefix(const char *name) {
    return cheng_seed_startswith(name, "driver_c_") ||
           cheng_seed_startswith(name, "__cheng_") ||
           cheng_seed_startswith(name, "cheng_") ||
           cheng_seed_startswith(name, "cheng_str_") ||
           cheng_seed_startswith(name, "cheng_seq_") ||
           cheng_seed_startswith(name, "cheng_rawbytes_") ||
           cheng_seed_startswith(name, "cheng_rawmem_") ||
           cheng_seed_startswith(name, "cheng_pty_") ||
           cheng_seed_startswith(name, "cheng_fd_") ||
           cheng_seed_startswith(name, "cheng_pipe_") ||
           cheng_seed_startswith(name, "cheng_exec_") ||
           cheng_seed_startswith(name, "cheng_epoch_") ||
           cheng_seed_startswith(name, "cheng_monotime_") ||
           cheng_seed_startswith(name, "cheng_system_") ||
           cheng_seed_startswith(name, "cheng_tailnet_") ||
           cheng_seed_startswith(name, "cheng_tcp_") ||
           cheng_seed_startswith(name, "rawmem") ||
           cheng_seed_streq(name, "alloc") ||
           cheng_seed_streq(name, "copyMem") ||
           cheng_seed_streq(name, "setMem") ||
           cheng_seed_streq(name, "ptr_add") ||
           cheng_seed_streq(name, "paramCount") ||
           cheng_seed_streq(name, "paramStr") ||
           cheng_seed_streq(name, "cmdCountFromRuntime") ||
           cheng_seed_streq(name, "cheng_cmd_ready_compat") ||
           cheng_seed_streq(name, "store");
}

static bool cheng_seed_symbol_uses_cheng_internal_abi(const char *symbol_name) {
    const char *name = symbol_name != NULL ? symbol_name : "";
    if (cheng_seed_symbol_has_cheng_internal_abi_prefix(name)) {
        return true;
    }
    return name[0] == '_' && cheng_seed_symbol_has_cheng_internal_abi_prefix(name + 1);
}

static bool cheng_seed_compiler_normalize_channel(const char *raw, char *out, size_t out_cap) {
    char copy[32];
    char *trimmed;
    if (!raw || *raw == '\0') {
        cheng_seed_copy_text(out, out_cap, "stable");
        return true;
    }
    cheng_seed_copy_text(copy, sizeof(copy), raw);
    trimmed = cheng_seed_trim_inplace(copy);
    if (*trimmed == '\0') {
        cheng_seed_copy_text(out, out_cap, "stable");
        return true;
    }
    if (!cheng_seed_streq(trimmed, "stable") && !cheng_seed_streq(trimmed, "edge")) {
        fprintf(stderr, "cheng compiler world: unsupported channel: %s\n", trimmed);
        return false;
    }
    cheng_seed_copy_text(out, out_cap, trimmed);
    return true;
}

static void cheng_seed_strip_trailing_comment_inplace(char *text) {
    bool in_string = false;
    size_t i;
    if (!text) {
        return;
    }
    for (i = 0; text[i] != '\0'; ++i) {
        if (text[i] == '"' && !cheng_seed_quote_is_escaped(text, i)) {
            in_string = !in_string;
            continue;
        }
        if (!in_string && text[i] == '#') {
            text[i] = '\0';
            break;
        }
    }
    cheng_seed_trim_inplace(text);
}

static void cheng_seed_const_value_init(ChengSeedConstValue *value) {
    memset(value, 0, sizeof(*value));
    value->kind = ChengSeed_CONST_INVALID;
}

static void cheng_seed_const_value_free(ChengSeedConstValue *value);

static void cheng_seed_const_record_free(ChengSeedConstRecord *record) {
    size_t i;
    if (!record) {
        return;
    }
    for (i = 0; i < record->field_count; ++i) {
        cheng_seed_const_value_free(&record->field_values[i]);
    }
    free(record);
}

static void cheng_seed_const_value_free(ChengSeedConstValue *value) {
    if (!value) {
        return;
    }
    if ((value->kind == ChengSeed_CONST_STR || value->kind == ChengSeed_CONST_SYMBOL) &&
        value->text_value != NULL) {
        free(value->text_value);
    }
    if (value->kind == ChengSeed_CONST_RECORD && value->record_value != NULL) {
        cheng_seed_const_record_free(value->record_value);
    }
    cheng_seed_const_value_init(value);
}

static bool cheng_seed_const_value_set_str_kind(ChengSeedConstValue *value,
                                        ChengSeedConstKind kind,
                                        const char *text) {
    cheng_seed_const_value_free(value);
    value->kind = kind;
    value->text_value = cheng_seed_strdup(text ? text : "");
    return true;
}

static bool cheng_seed_const_value_set_bool(ChengSeedConstValue *value, bool bool_value) {
    cheng_seed_const_value_free(value);
    value->kind = ChengSeed_CONST_BOOL;
    value->bool_value = bool_value;
    return true;
}

static bool cheng_seed_const_value_set_i32(ChengSeedConstValue *value, int32_t i32_value) {
    cheng_seed_const_value_free(value);
    value->kind = ChengSeed_CONST_I32;
    value->i32_value = i32_value;
    return true;
}

static bool cheng_seed_const_value_set_f64(ChengSeedConstValue *value, double f64_value) {
    cheng_seed_const_value_free(value);
    value->kind = ChengSeed_CONST_F64;
    value->f64_value = f64_value;
    return true;
}

static bool cheng_seed_const_value_truthy(const ChengSeedConstValue *value, bool *out) {
    if (value == NULL || out == NULL) {
        return false;
    }
    if (value->kind == ChengSeed_CONST_BOOL) {
        *out = value->bool_value;
        return true;
    }
    if (value->kind == ChengSeed_CONST_I32) {
        *out = value->i32_value != 0;
        return true;
    }
    if (value->kind == ChengSeed_CONST_F64) {
        *out = value->f64_value != 0.0;
        return true;
    }
    return false;
}

static bool cheng_seed_const_value_as_i32(const ChengSeedConstValue *value, int32_t *out) {
    if (value == NULL || out == NULL) {
        return false;
    }
    if (value->kind == ChengSeed_CONST_I32) {
        *out = value->i32_value;
        return true;
    }
    if (value->kind == ChengSeed_CONST_BOOL) {
        *out = value->bool_value ? 1 : 0;
        return true;
    }
    if (value->kind == ChengSeed_CONST_F64) {
        if (value->f64_value < (double)INT32_MIN ||
            value->f64_value > (double)INT32_MAX) {
            return false;
        }
        *out = (int32_t)value->f64_value;
        return true;
    }
    return false;
}

static bool cheng_seed_const_value_as_f64(const ChengSeedConstValue *value, double *out) {
    if (value == NULL || out == NULL) {
        return false;
    }
    if (value->kind == ChengSeed_CONST_F64) {
        *out = value->f64_value;
        return true;
    }
    if (value->kind == ChengSeed_CONST_I32) {
        *out = (double)value->i32_value;
        return true;
    }
    if (value->kind == ChengSeed_CONST_BOOL) {
        *out = value->bool_value ? 1.0 : 0.0;
        return true;
    }
    return false;
}

static bool cheng_seed_const_value_clone(const ChengSeedConstValue *src, ChengSeedConstValue *dst) {
    size_t i;
    cheng_seed_const_value_free(dst);
    dst->kind = src->kind;
    dst->bool_value = src->bool_value;
    dst->i32_value = src->i32_value;
    dst->f64_value = src->f64_value;
    if ((src->kind == ChengSeed_CONST_STR || src->kind == ChengSeed_CONST_SYMBOL) &&
        src->text_value != NULL) {
        dst->text_value = cheng_seed_strdup(src->text_value);
        return true;
    }
    if (src->kind == ChengSeed_CONST_RECORD && src->record_value != NULL) {
        ChengSeedConstRecord *record = (ChengSeedConstRecord *)cheng_seed_xmalloc(sizeof(ChengSeedConstRecord));
        memset(record, 0, sizeof(*record));
        record->field_count = src->record_value->field_count;
        for (i = 0; i < src->record_value->field_count; ++i) {
            snprintf(record->field_names[i], sizeof(record->field_names[i]), "%s",
                     src->record_value->field_names[i]);
            cheng_seed_const_value_init(&record->field_values[i]);
            if (!cheng_seed_const_value_clone(&src->record_value->field_values[i],
                                      &record->field_values[i])) {
                cheng_seed_const_record_free(record);
                return false;
            }
        }
        dst->record_value = record;
    }
    return true;
}

static const ChengSeedConstValue *cheng_seed_const_record_field(const ChengSeedConstValue *record_value,
                                                 const char *field_name) {
    size_t i;
    if (!record_value || record_value->kind != ChengSeed_CONST_RECORD || record_value->record_value == NULL) {
        return NULL;
    }
    for (i = 0; i < record_value->record_value->field_count; ++i) {
        if (strcmp(record_value->record_value->field_names[i], field_name) == 0) {
            return &record_value->record_value->field_values[i];
        }
    }
    return NULL;
}

static bool cheng_seed_const_value_index(const ChengSeedConstValue *base,
                                 int32_t index,
                                 ChengSeedConstValue *out) {
    char field_name[128];
    const ChengSeedConstValue *field = NULL;
    if (base == NULL ||
        out == NULL ||
        index < 0 ||
        base->kind != ChengSeed_CONST_RECORD ||
        base->record_value == NULL) {
        return false;
    }
    field = cheng_seed_const_record_field(base, "len");
    if (field != NULL) {
        const ChengSeedConstValue *buffer = cheng_seed_const_record_field(base, "buffer");
        int32_t len = 0;
        if (buffer == NULL ||
            !cheng_seed_const_value_as_i32(field, &len) ||
            index >= len ||
            buffer->kind != ChengSeed_CONST_RECORD ||
            buffer->record_value == NULL) {
            return false;
        }
        snprintf(field_name, sizeof(field_name), "%d", index);
        field = cheng_seed_const_record_field(buffer, field_name);
        return field != NULL && cheng_seed_const_value_clone(field, out);
    }
    snprintf(field_name, sizeof(field_name), "%d", index);
    field = cheng_seed_const_record_field(base, field_name);
    return field != NULL && cheng_seed_const_value_clone(field, out);
}

static bool cheng_seed_const_env_set(ChengSeedConstEnv *env, const char *name, const ChengSeedConstValue *value) {
    size_t i;
    for (i = 0; i < env->binding_count; ++i) {
        if (strcmp(env->bindings[i].name, name) == 0) {
            return cheng_seed_const_value_clone(value, &env->bindings[i].value);
        }
    }
    if (env->binding_count >= CHENG_CONST_MAX_BINDINGS) {
        return false;
    }
    snprintf(env->bindings[env->binding_count].name,
             sizeof(env->bindings[env->binding_count].name),
             "%s",
             name);
    cheng_seed_const_value_init(&env->bindings[env->binding_count].value);
    if (!cheng_seed_const_value_clone(value, &env->bindings[env->binding_count].value)) {
        return false;
    }
    env->binding_count += 1U;
    return true;
}

static const ChengSeedConstValue *cheng_seed_const_env_get(const ChengSeedConstEnv *env, const char *name) {
    size_t i;
    for (i = 0; i < env->binding_count; ++i) {
        if (strcmp(env->bindings[i].name, name) == 0) {
            return &env->bindings[i].value;
        }
    }
    return NULL;
}

static void cheng_seed_const_env_free(ChengSeedConstEnv *env) {
    size_t i;
    for (i = 0; i < env->binding_count; ++i) {
        cheng_seed_const_value_free(&env->bindings[i].value);
    }
    env->binding_count = 0U;
}

static void cheng_seed_trim_copy_text(const char *src, char *dst, size_t cap) {
    const char *start = src;
    const char *end;
    size_t copy_len;
    if (cap == 0U) {
        return;
    }
    while (*start != '\0' && isspace((unsigned char)*start)) {
        start++;
    }
    end = start + strlen(start);
    while (end > start && isspace((unsigned char)end[-1])) {
        end--;
    }
    copy_len = (size_t)(end - start);
    if (copy_len + 1U > cap) {
        copy_len = cap - 1U;
    }
    if (copy_len > 0U) {
        memmove(dst, start, copy_len);
    }
    dst[copy_len] = '\0';
}

static int32_t cheng_seed_find_top_level_binary_op(const char *text, const char *op) {
    bool in_string = false;
    int32_t depth = 0;
    int32_t bracket_depth = 0;
    bool alpha_op = false;
    size_t op_len = strlen(op);
    size_t len = strlen(text);
    size_t i;
    if (op_len > 0U) {
        alpha_op = true;
        for (i = 0U; i < op_len; ++i) {
            if (!isalpha((unsigned char)op[i])) {
                alpha_op = false;
                break;
            }
        }
    }
    for (i = 0; text[i] != '\0'; ++i) {
        if (text[i] == '"' && !cheng_seed_quote_is_escaped(text, i)) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (text[i] == '(') {
            depth += 1;
            continue;
        }
        if (text[i] == ')') {
            depth -= 1;
            continue;
        }
        if (text[i] == '[') {
            bracket_depth += 1;
            continue;
        }
        if (text[i] == ']') {
            bracket_depth -= 1;
            continue;
        }
        if (depth == 0 &&
            bracket_depth == 0 &&
            strncmp(text + i, op, op_len) == 0) {
            if (alpha_op) {
                char prev = i > 0U ? text[i - 1U] : '\0';
                char next = i + op_len < len ? text[i + op_len] : '\0';
                if (!(i > 0U && isspace((unsigned char)prev)) ||
                    !(i + op_len < len && isspace((unsigned char)next))) {
                    continue;
                }
            }
            if (op_len == 1U) {
                char prev = i > 0U ? text[i - 1U] : '\0';
                char next = i + 1U < len ? text[i + 1U] : '\0';
                if ((op[0] == '<' && (prev == '<' || next == '<' || next == '=')) ||
                    (op[0] == '>' && (prev == '>' || next == '>' || next == '=' || prev == '-')) ||
                    (op[0] == '&' && (prev == '&' || next == '&')) ||
                    (op[0] == '|' && (prev == '|' || next == '|')) ||
                    (op[0] == '-' && (next == '>' || prev == '-')) ||
                    (op[0] == '+' && (prev == '+' || next == '+'))) {
                    continue;
                }
            }
            return (int32_t)i;
        }
    }
    return -1;
}

static int32_t cheng_seed_find_top_level_char(const char *text, char target) {
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t brace_depth = 0;
    size_t i;
    if (!text) {
        return -1;
    }
    for (i = 0; text[i] != '\0'; ++i) {
        char ch = text[i];
        if (ch == '"' && !cheng_seed_quote_is_escaped(text, i)) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            continue;
        }
        if (ch == '[') {
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            continue;
        }
        if (ch == '{') {
            brace_depth += 1;
            continue;
        }
        if (ch == '}') {
            brace_depth -= 1;
            continue;
        }
        if (paren_depth == 0 &&
            bracket_depth == 0 &&
            brace_depth == 0 &&
            ch == target) {
            return (int32_t)i;
        }
    }
    return -1;
}

static bool cheng_seed_split_top_level_args(const char *text,
                                    char items[][4096],
                                    size_t *item_count,
                                    size_t item_cap) {
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t brace_depth = 0;
    const char *start = text;
    size_t i;
    *item_count = 0U;
    for (i = 0; ; ++i) {
        const char ch = text[i];
        if (ch == '"' && !cheng_seed_quote_is_escaped(text, i)) {
            in_string = !in_string;
        } else if (!in_string && ch == '(') {
            paren_depth += 1;
        } else if (!in_string && ch == ')') {
            paren_depth -= 1;
        } else if (!in_string && ch == '[') {
            bracket_depth += 1;
        } else if (!in_string && ch == ']') {
            bracket_depth -= 1;
        } else if (!in_string && ch == '{') {
            brace_depth += 1;
        } else if (!in_string && ch == '}') {
            brace_depth -= 1;
        }
        if ((!in_string &&
             paren_depth == 0 &&
             bracket_depth == 0 &&
             brace_depth == 0 &&
             ch == ',') || ch == '\0') {
            if (*item_count >= item_cap) {
                return false;
            }
            snprintf(items[*item_count], sizeof(items[*item_count]), "%.*s", (int)(text + i - start), start);
            cheng_seed_trim_copy_text(items[*item_count], items[*item_count], sizeof(items[*item_count]));
            *item_count += 1U;
            start = text + i + 1;
        }
        if (ch == '\0') {
            break;
        }
    }
    if (*item_count == 1U && items[0][0] == '\0') {
        *item_count = 0U;
    }
    return true;
}

static bool cheng_seed_count_top_level_args(const char *text,
                                    size_t *item_count_out) {
    bool in_string = false;
    bool in_char = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t brace_depth = 0;
    const char *start = text;
    size_t item_count = 0U;
    size_t i;
    if (item_count_out == NULL) {
        return false;
    }
    for (i = 0U; ; ++i) {
        char ch = text[i];
        if (!in_char && ch == '"' && !cheng_seed_quote_is_escaped(text, i)) {
            in_string = !in_string;
        } else if (!in_string && ch == '\'' && !cheng_seed_quote_is_escaped(text, i)) {
            in_char = !in_char;
        } else if (!in_string && !in_char && ch == '(') {
            paren_depth += 1;
        } else if (!in_string && !in_char && ch == ')') {
            paren_depth -= 1;
        } else if (!in_string && !in_char && ch == '[') {
            bracket_depth += 1;
        } else if (!in_string && !in_char && ch == ']') {
            bracket_depth -= 1;
        } else if (!in_string && !in_char && ch == '{') {
            brace_depth += 1;
        } else if (!in_string && !in_char && ch == '}') {
            brace_depth -= 1;
        }
        if ((!in_string &&
             !in_char &&
             paren_depth == 0 &&
             bracket_depth == 0 &&
             brace_depth == 0 &&
             ch == ',') || ch == '\0') {
            char piece[4096];
            snprintf(piece, sizeof(piece), "%.*s", (int)(text + i - start), start);
            cheng_seed_trim_copy_text(piece, piece, sizeof(piece));
            item_count += 1U;
            start = text + i + 1U;
        }
        if (ch == '\0') {
            break;
        }
    }
    if (item_count == 1U) {
        char only_item[4096];
        snprintf(only_item, sizeof(only_item), "%s", text);
        cheng_seed_trim_copy_text(only_item, only_item, sizeof(only_item));
        if (only_item[0] == '\0') {
            item_count = 0U;
        }
    }
    *item_count_out = item_count;
    return !in_string &&
           !in_char &&
           paren_depth == 0 &&
           bracket_depth == 0 &&
           brace_depth == 0;
}

static bool cheng_seed_parse_list_literal_text_alloc(const char *text,
                                             char (**items_out)[4096],
                                             size_t *item_count_out) {
    char trimmed[8192];
    char inner[8192];
    char (*items)[4096];
    size_t item_count = 0U;
    size_t alloc_count = 0U;
    size_t len;
    if (items_out == NULL || item_count_out == NULL) {
        return false;
    }
    *items_out = NULL;
    *item_count_out = 0U;
    cheng_seed_trim_copy_text(text, trimmed, sizeof(trimmed));
    len = strlen(trimmed);
    if (len < 2U || trimmed[0] != '[' || trimmed[len - 1U] != ']') {
        return false;
    }
    snprintf(inner, sizeof(inner), "%.*s", (int)(len - 2U), trimmed + 1);
    if (!cheng_seed_count_top_level_args(inner, &item_count)) {
        return false;
    }
    alloc_count = item_count > 0U ? item_count : 1U;
    items = (char (*)[4096])cheng_seed_xmalloc(alloc_count * sizeof(char[4096]));
    if (!cheng_seed_split_top_level_args(inner, items, &item_count, alloc_count)) {
        free(items);
        return false;
    }
    *items_out = items;
    *item_count_out = item_count;
    return true;
}

static bool cheng_seed_parse_prefix_single_arg_call(const char *expr_text,
                                            char *callee,
                                            size_t callee_cap,
                                            char *arg_text,
                                            size_t arg_cap);

static bool cheng_seed_parse_call_text_parts(const char *text,
                                     char *callee,
                                     size_t callee_cap,
                                     char *inner_out,
                                     size_t inner_cap) {
    char trimmed[8192];
    const char *open_paren = NULL;
    const char *close_paren = NULL;
    bool in_string = false;
    int32_t bracket_depth = 0;
    int32_t paren_depth = 0;
    size_t i;
    cheng_seed_trim_copy_text(text, trimmed, sizeof(trimmed));
    for (i = 0; trimmed[i] != '\0'; ++i) {
        char ch = trimmed[i];
        if (ch == '"' && !cheng_seed_quote_is_escaped(trimmed, i)) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '[') {
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            continue;
        }
        if (ch == '(' && bracket_depth == 0) {
            if (!open_paren) {
                open_paren = trimmed + i;
            }
            paren_depth += 1;
            continue;
        }
        if (ch == ')' && bracket_depth == 0) {
            paren_depth -= 1;
            if (paren_depth == 0) {
                close_paren = trimmed + i;
            }
            continue;
        }
    }
    if (!open_paren || !close_paren || close_paren <= open_paren || paren_depth != 0 || bracket_depth != 0) {
        return false;
    }
    if (trimmed[strlen(trimmed) - 1U] != ')') {
        return false;
    }
    snprintf(callee, callee_cap, "%.*s", (int)(open_paren - trimmed), trimmed);
    cheng_seed_trim_copy_text(callee, callee, callee_cap);
    {
        int32_t callee_bracket_depth = 0;
        if (callee[0] == '\0') {
            return false;
        }
        for (i = 0; callee[i] != '\0'; ++i) {
            char ch = callee[i];
            if (ch == '[') {
                callee_bracket_depth += 1;
                continue;
            }
            if (ch == ']') {
                callee_bracket_depth -= 1;
                if (callee_bracket_depth < 0) {
                    return false;
                }
                continue;
            }
            if (callee_bracket_depth == 0 &&
                (isspace((unsigned char)ch) ||
                 ch == '&' || ch == '|' || ch == '+' || ch == '-' ||
                 ch == '*' || ch == '/' || ch == '%' || ch == '!' ||
                 ch == '<' || ch == '>' || ch == '=' || ch == '?')) {
                return false;
            }
        }
        if (callee_bracket_depth != 0) {
            return false;
        }
    }
    snprintf(inner_out, inner_cap, "%.*s", (int)(close_paren - open_paren - 1), open_paren + 1);
    return true;
}

static bool cheng_seed_parse_call_text(const char *text,
                               char *callee,
                               size_t callee_cap,
                               char args[][4096],
                               size_t *arg_count,
                               size_t arg_cap) {
    char inner[8192];
    if (!cheng_seed_parse_call_text_parts(text,
                                  callee,
                                  callee_cap,
                                  inner,
                                  sizeof(inner))) {
        return false;
    }
    return cheng_seed_split_top_level_args(inner, args, arg_count, arg_cap);
}

static bool cheng_seed_parse_list_literal_text(const char *text,
                                       char items[][4096],
                                       size_t *item_count,
                                       size_t item_cap) {
    char trimmed[8192];
    char inner[8192];
    size_t len;
    cheng_seed_trim_copy_text(text, trimmed, sizeof(trimmed));
    len = strlen(trimmed);
    if (len < 2U || trimmed[0] != '[' || trimmed[len - 1U] != ']') {
        return false;
    }
    snprintf(inner, sizeof(inner), "%.*s", (int)(len - 2U), trimmed + 1);
    return cheng_seed_split_top_level_args(inner, items, item_count, item_cap);
}

static bool cheng_seed_is_list_literal_text(const char *text, bool *nonempty_out) {
    char trimmed[8192];
    size_t len;
    cheng_seed_trim_copy_text(text, trimmed, sizeof(trimmed));
    len = strlen(trimmed);
    if (len < 2U || trimmed[0] != '[' || trimmed[len - 1U] != ']') {
        return false;
    }
    if (nonempty_out) {
        *nonempty_out = len > 2U;
    }
    return true;
}

static bool cheng_seed_parse_ternary_expr(const char *text,
                                  char *cond_out,
                                  size_t cond_cap,
                                  char *true_out,
                                  size_t true_cap,
                                  char *false_out,
                                  size_t false_cap) {
    char trimmed[8192];
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t brace_depth = 0;
    int32_t q_index = -1;
    int32_t colon_index = -1;
    size_t i;
    cheng_seed_trim_copy_text(text, trimmed, sizeof(trimmed));
    for (i = 0; trimmed[i] != '\0'; ++i) {
        char ch = trimmed[i];
        if (ch == '"' && !cheng_seed_quote_is_escaped(trimmed, i)) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            continue;
        }
        if (ch == '[') {
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            continue;
        }
        if (ch == '{') {
            brace_depth += 1;
            continue;
        }
        if (ch == '}') {
            brace_depth -= 1;
            continue;
        }
        if (paren_depth == 0 && bracket_depth == 0 && brace_depth == 0) {
            if (ch == '?' && q_index < 0) {
                q_index = (int32_t)i;
                continue;
            }
            if (ch == ':' && q_index >= 0) {
                colon_index = (int32_t)i;
                break;
            }
        }
    }
    if (q_index <= 0 || colon_index <= q_index + 1) {
        return false;
    }
    snprintf(cond_out, cond_cap, "%.*s", q_index, trimmed);
    snprintf(true_out, true_cap, "%.*s", colon_index - q_index - 1, trimmed + q_index + 1);
    snprintf(false_out, false_cap, "%s", trimmed + colon_index + 1);
    cheng_seed_trim_copy_text(cond_out, cond_out, cond_cap);
    cheng_seed_trim_copy_text(true_out, true_out, true_cap);
    cheng_seed_trim_copy_text(false_out, false_out, false_cap);
    return cond_out[0] != '\0' && true_out[0] != '\0' && false_out[0] != '\0';
}

static int32_t cheng_seed_find_top_level_colon(const char *text);
static int32_t cheng_seed_find_top_level_else_expr_index(const char *text, size_t start_index) {
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t brace_depth = 0;
    int32_t if_expr_depth = 0;
    size_t i;
    if (text == NULL) {
        return -1;
    }
    for (i = start_index; text[i] != '\0'; ++i) {
        char ch = text[i];
        if (ch == '"' && !cheng_seed_quote_is_escaped(text, i)) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            continue;
        }
        if (ch == '[') {
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            continue;
        }
        if (ch == '{') {
            brace_depth += 1;
            continue;
        }
        if (ch == '}') {
            brace_depth -= 1;
            continue;
        }
        if (paren_depth == 0 &&
            bracket_depth == 0 &&
            brace_depth == 0) {
            if (cheng_seed_startswith(text + i, "if ") &&
                (i == 0U ||
                 isspace((unsigned char)text[i - 1U]) ||
                 text[i - 1U] == ':')) {
                if_expr_depth += 1;
                continue;
            }
            if (cheng_seed_startswith(text + i, "else:") &&
                (i == 0U || isspace((unsigned char)text[i - 1U]))) {
                if (if_expr_depth > 0) {
                    if_expr_depth -= 1;
                    continue;
                }
                return (int32_t)i;
            }
        }
    }
    return -1;
}

static bool cheng_seed_parse_if_expr(const char *text,
                             char *cond_out,
                             size_t cond_cap,
                             char *true_out,
                             size_t true_cap,
                             char *false_out,
                             size_t false_cap) {
    char trimmed[8192];
    int32_t colon_index;
    int32_t else_index;
    cheng_seed_trim_copy_text(text, trimmed, sizeof(trimmed));
    if (!cheng_seed_startswith(trimmed, "if ")) {
        return false;
    }
    colon_index = cheng_seed_find_top_level_colon(trimmed);
    if (colon_index <= 3) {
        return false;
    }
    else_index = cheng_seed_find_top_level_else_expr_index(trimmed, (size_t)colon_index + 1U);
    if (else_index < 0 || else_index <= colon_index + 1) {
        return false;
    }
    snprintf(cond_out, cond_cap, "%.*s", colon_index - 3, trimmed + 3);
    snprintf(true_out,
             true_cap,
             "%.*s",
             else_index - colon_index - 1,
             trimmed + colon_index + 1);
    snprintf(false_out, false_cap, "%s", trimmed + else_index + 5);
    cheng_seed_trim_copy_text(cond_out, cond_out, cond_cap);
    cheng_seed_trim_copy_text(true_out, true_out, true_cap);
    cheng_seed_trim_copy_text(false_out, false_out, false_cap);
    return cond_out[0] != '\0' && true_out[0] != '\0' && false_out[0] != '\0';
}

static bool cheng_seed_trim_outer_parens(const char *expr_text, char *out, size_t cap);
static ChengSeedResultIntrinsicKind cheng_seed_result_intrinsic_kind_from_name(const char *function_name);

static bool cheng_seed_parse_range_expr(const char *text,
                                char *start_expr_out,
                                size_t start_expr_cap,
                                char *end_expr_out,
                                size_t end_expr_cap,
                                bool *end_inclusive_out) {
    char trimmed[8192];
    int32_t range_sep = -1;
    size_t range_op_len = 0U;
    cheng_seed_trim_copy_text(text, trimmed, sizeof(trimmed));
    range_sep = cheng_seed_find_top_level_binary_op(trimmed, "..<");
    if (range_sep >= 0) {
        range_op_len = 3U;
        if (end_inclusive_out) {
            *end_inclusive_out = false;
        }
    } else {
        range_sep = cheng_seed_find_top_level_binary_op(trimmed, "..");
        if (range_sep >= 0) {
            range_op_len = 2U;
            if (end_inclusive_out) {
                *end_inclusive_out = true;
            }
        }
    }
    if (range_sep <= 0 || range_op_len == 0U) {
        return false;
    }
    snprintf(start_expr_out, start_expr_cap, "%.*s", range_sep, trimmed);
    snprintf(end_expr_out, end_expr_cap, "%s", trimmed + range_sep + (int32_t)range_op_len);
    cheng_seed_trim_copy_text(start_expr_out, start_expr_out, start_expr_cap);
    cheng_seed_trim_copy_text(end_expr_out, end_expr_out, end_expr_cap);
    return start_expr_out[0] != '\0' && end_expr_out[0] != '\0';
}

static void cheng_seed_expr_surface_init(ChengSeedExprSurface *surface) {
    if (surface == NULL) {
        return;
    }
    memset(surface, 0, sizeof(*surface));
    surface->kind = ChengSeed_EXPR_SURFACE_ATOM;
    surface->result_hint = ChengSeed_RESULT_INTRINSIC_NONE;
}

static ChengSeedExprSurfaceCacheEntry g_cheng_expr_surface_cache[CHENG_MAX_EXPR_SURFACE_CACHE];
static size_t g_cheng_expr_surface_cache_count = 0U;
static ChengSeedExprTypeCacheEntry g_cheng_expr_type_cache[CHENG_MAX_EXPR_TYPE_CACHE];

static uint64_t cheng_seed_hash_combine64(uint64_t hash, uint64_t value) {
    return hash ^ (value + 0x9e3779b97f4a7c15ULL + (hash << 6) + (hash >> 2));
}

static uint64_t cheng_seed_expr_type_cache_key_hash(const ChengSeedLoweredFunctionStub *current_function,
                                            size_t source_line,
                                            size_t local_count,
                                            const char *expr_text) {
    uint64_t hash = 0xcbf29ce484222325ULL;
    if (current_function == NULL || expr_text == NULL || expr_text[0] == '\0') {
        return 0ULL;
    }
    hash = cheng_seed_hash_combine64(hash, cheng_seed_fnv1a64(current_function->symbol_text));
    hash = cheng_seed_hash_combine64(hash, cheng_seed_fnv1a64(expr_text));
    hash = cheng_seed_hash_combine64(hash, (uint64_t)source_line);
    hash = cheng_seed_hash_combine64(hash, (uint64_t)local_count);
    return hash;
}

static bool cheng_seed_expr_type_cache_get(const ChengSeedLoweredFunctionStub *current_function,
                                   size_t source_line,
                                   size_t local_count,
                                   const char *expr_text,
                                   char *type_out,
                                   size_t type_cap,
                                   char *abi_out,
                                   size_t abi_cap) {
    uint64_t hash;
    size_t probe;
    size_t mask = CHENG_MAX_EXPR_TYPE_CACHE - 1U;
    if (current_function == NULL ||
        expr_text == NULL || expr_text[0] == '\0' ||
        type_out == NULL || abi_out == NULL) {
        return false;
    }
    hash = cheng_seed_expr_type_cache_key_hash(current_function, source_line, local_count, expr_text);
    if (hash == 0ULL) {
        return false;
    }
    for (probe = 0U; probe < CHENG_MAX_EXPR_TYPE_CACHE; ++probe) {
        size_t index = ((size_t)hash + probe) & mask;
        const ChengSeedExprTypeCacheEntry *entry = &g_cheng_expr_type_cache[index];
        if (!entry->occupied) {
            return false;
        }
        if (entry->key_hash != hash ||
            entry->source_line != source_line ||
            entry->local_count != local_count ||
            strcmp(entry->function_symbol, current_function->symbol_text) != 0 ||
            strcmp(entry->expr_text, expr_text) != 0) {
            continue;
        }
        snprintf(type_out, type_cap, "%s", entry->type_text);
        snprintf(abi_out, abi_cap, "%s", entry->abi_class);
        return true;
    }
    return false;
}

static void cheng_seed_expr_type_cache_store(const ChengSeedLoweredFunctionStub *current_function,
                                     size_t source_line,
                                     size_t local_count,
                                     const char *expr_text,
                                     const char *type_text,
                                     const char *abi_class) {
    uint64_t hash;
    size_t probe;
    size_t mask = CHENG_MAX_EXPR_TYPE_CACHE - 1U;
    size_t replace_index;
    ChengSeedExprTypeCacheEntry *entry = NULL;
    if (current_function == NULL ||
        expr_text == NULL || expr_text[0] == '\0' ||
        type_text == NULL || type_text[0] == '\0' ||
        abi_class == NULL || abi_class[0] == '\0') {
        return;
    }
    hash = cheng_seed_expr_type_cache_key_hash(current_function, source_line, local_count, expr_text);
    if (hash == 0ULL) {
        return;
    }
    replace_index = (size_t)hash & mask;
    for (probe = 0U; probe < CHENG_MAX_EXPR_TYPE_CACHE; ++probe) {
        size_t index = ((size_t)hash + probe) & mask;
        entry = &g_cheng_expr_type_cache[index];
        if (!entry->occupied ||
            (entry->key_hash == hash &&
             entry->source_line == source_line &&
             entry->local_count == local_count &&
             strcmp(entry->function_symbol, current_function->symbol_text) == 0 &&
             strcmp(entry->expr_text, expr_text) == 0)) {
            replace_index = index;
            break;
        }
    }
    entry = &g_cheng_expr_type_cache[replace_index];
    memset(entry, 0, sizeof(*entry));
    entry->occupied = true;
    entry->key_hash = hash;
    entry->source_line = source_line;
    entry->local_count = local_count;
    snprintf(entry->function_symbol, sizeof(entry->function_symbol), "%s", current_function->symbol_text);
    snprintf(entry->expr_text, sizeof(entry->expr_text), "%s", expr_text);
    snprintf(entry->type_text, sizeof(entry->type_text), "%s", type_text);
    snprintf(entry->abi_class, sizeof(entry->abi_class), "%s", abi_class);
}

static bool cheng_seed_expr_surface_cache_get(const char *expr_text,
                                      ChengSeedExprSurface *surface_out) {
    uint64_t hash;
    size_t i;
    if (expr_text == NULL || expr_text[0] == '\0' || surface_out == NULL) {
        return false;
    }
    hash = cheng_seed_fnv1a64(expr_text);
    for (i = 0U; i < g_cheng_expr_surface_cache_count; ++i) {
        if (g_cheng_expr_surface_cache[i].key_hash != hash ||
            strcmp(g_cheng_expr_surface_cache[i].expr_text, expr_text) != 0) {
            continue;
        }
        memcpy(surface_out, &g_cheng_expr_surface_cache[i].surface, sizeof(*surface_out));
        return true;
    }
    return false;
}

static void cheng_seed_expr_surface_cache_store(const char *expr_text,
                                        const ChengSeedExprSurface *surface) {
    ChengSeedExprSurfaceCacheEntry *entry = NULL;
    uint64_t hash;
    size_t i;
    if (expr_text == NULL || expr_text[0] == '\0' || surface == NULL) {
        return;
    }
    hash = cheng_seed_fnv1a64(expr_text);
    for (i = 0U; i < g_cheng_expr_surface_cache_count; ++i) {
        if (g_cheng_expr_surface_cache[i].key_hash == hash &&
            strcmp(g_cheng_expr_surface_cache[i].expr_text, expr_text) == 0) {
            return;
        }
    }
    if (g_cheng_expr_surface_cache_count >= CHENG_MAX_EXPR_SURFACE_CACHE) {
        return;
    }
    entry = &g_cheng_expr_surface_cache[g_cheng_expr_surface_cache_count++];
    memset(entry, 0, sizeof(*entry));
    entry->key_hash = hash;
    snprintf(entry->expr_text, sizeof(entry->expr_text), "%s", expr_text);
    memcpy(&entry->surface, surface, sizeof(entry->surface));
}

static bool cheng_seed_classify_expr_surface(const char *expr_text,
                                     ChengSeedExprSurface *surface,
                                     char *error_out,
                                     size_t error_cap) {
    char current[8192];
    char cache_key[8192];
    char rewritten[32768];
    char outer[8192];
    char fmt_error[256];
    char start_expr[4096];
    char end_expr[4096];
    char callee[PATH_MAX];
    char arg_text[4096] = {0};
    bool fmt_changed = false;
    size_t i;
    if (surface == NULL) {
        return false;
    }
    cheng_seed_expr_surface_init(surface);
    if (error_out && error_cap > 0U) {
        error_out[0] = '\0';
    }
    if (expr_text == NULL) {
        if (error_out && error_cap > 0U) {
            snprintf(error_out, error_cap, "%s", "expr_missing");
        }
        return false;
    }
    cheng_seed_trim_copy_text(expr_text, current, sizeof(current));
    if (current[0] == '\0') {
        if (error_out && error_cap > 0U) {
            snprintf(error_out, error_cap, "%s", "expr_empty");
        }
        return false;
    }
    if (cheng_seed_expr_surface_cache_get(current, surface)) {
        return true;
    }
    snprintf(cache_key, sizeof(cache_key), "%s", current);
    for (i = 0U; i < 16U; ++i) {
        if (!cheng_seed_expand_strformat_fmt_expr(current,
                                          rewritten,
                                          sizeof(rewritten),
                                          &fmt_changed,
                                          fmt_error,
                                          sizeof(fmt_error))) {
            if (error_out && error_cap > 0U) {
                snprintf(error_out, error_cap, "%s", fmt_error[0] != '\0' ? fmt_error : "fmt_invalid");
            }
            return false;
        }
        if (fmt_changed) {
            surface->rewritten = true;
            cheng_seed_trim_copy_text(rewritten, current, sizeof(current));
            continue;
        }
        if (cheng_seed_trim_outer_parens(current, outer, sizeof(outer))) {
            surface->rewritten = true;
            cheng_seed_trim_copy_text(outer, current, sizeof(current));
            continue;
        }
        break;
    }
    snprintf(surface->text, sizeof(surface->text), "%s", current);
    if (cheng_seed_parse_if_expr(surface->text,
                         surface->cond,
                         sizeof(surface->cond),
                         surface->when_true,
                         sizeof(surface->when_true),
                         surface->when_false,
                         sizeof(surface->when_false))) {
        surface->kind = ChengSeed_EXPR_SURFACE_IF;
        cheng_seed_expr_surface_cache_store(cache_key, surface);
        return true;
    }
    if (cheng_seed_parse_ternary_expr(surface->text,
                              surface->cond,
                              sizeof(surface->cond),
                              surface->when_true,
                              sizeof(surface->when_true),
                              surface->when_false,
                              sizeof(surface->when_false))) {
        surface->kind = ChengSeed_EXPR_SURFACE_TERNARY;
        cheng_seed_expr_surface_cache_store(cache_key, surface);
        return true;
    }
    if (cheng_seed_parse_range_expr(surface->text,
                            start_expr,
                            sizeof(start_expr),
                            end_expr,
                            sizeof(end_expr),
                            &surface->range_end_inclusive)) {
        surface->kind = ChengSeed_EXPR_SURFACE_RANGE;
        snprintf(surface->when_true, sizeof(surface->when_true), "%s", start_expr);
        snprintf(surface->when_false, sizeof(surface->when_false), "%s", end_expr);
        cheng_seed_expr_surface_cache_store(cache_key, surface);
        return true;
    }
    if (cheng_seed_parse_call_text_parts(surface->text,
                                 callee,
                                 sizeof(callee),
                                 surface->call_args_text,
                                 sizeof(surface->call_args_text))) {
        if (!cheng_seed_count_top_level_args(surface->call_args_text, &surface->call_arg_count)) {
            if (error_out && error_cap > 0U) {
                snprintf(error_out, error_cap, "%s", "call_args_invalid");
            }
            return false;
        }
        snprintf(surface->call_callee, sizeof(surface->call_callee), "%s", callee);
        surface->call_prefix_style = false;
        surface->kind = ChengSeed_EXPR_SURFACE_CALL;
    } else if (cheng_seed_parse_prefix_single_arg_call(surface->text,
                                               callee,
                                               sizeof(callee),
                                               arg_text,
                                               sizeof(arg_text))) {
        const char *base = strrchr(callee, '.');
        if (base != NULL) {
            base += 1;
        } else {
            base = callee;
            {
                const char *scope = strrchr(base, ':');
                if (scope && scope != base && scope[-1] == ':') {
                    base = scope + 1;
                }
            }
        }
        snprintf(surface->call_callee, sizeof(surface->call_callee), "%s", callee);
        snprintf(surface->call_args_text, sizeof(surface->call_args_text), "%s", arg_text);
        surface->call_prefix_style = true;
        surface->call_arg_count = 1U;
        surface->kind = ChengSeed_EXPR_SURFACE_CALL;
        surface->result_hint = cheng_seed_result_intrinsic_kind_from_name(base);
        cheng_seed_expr_surface_cache_store(cache_key, surface);
        return true;
    }
    if (surface->kind == ChengSeed_EXPR_SURFACE_CALL) {
        const char *base = strrchr(surface->call_callee, '.');
        if (base != NULL) {
            base += 1;
        } else {
            base = surface->call_callee;
            {
                const char *scope = strrchr(base, ':');
                if (scope && scope != base && scope[-1] == ':') {
                    base = scope + 1;
                }
            }
        }
        surface->result_hint = cheng_seed_result_intrinsic_kind_from_name(base);
        cheng_seed_expr_surface_cache_store(cache_key, surface);
        return true;
    }
    cheng_seed_expr_surface_cache_store(cache_key, surface);
    return true;
}

static bool cheng_seed_split_expr_surface_call_args(const ChengSeedExprSurface *surface,
                                            char args[][4096],
                                            size_t *arg_count,
                                            size_t arg_cap) {
    if (arg_count != NULL) {
        *arg_count = 0U;
    }
    if (surface == NULL || surface->kind != ChengSeed_EXPR_SURFACE_CALL ||
        args == NULL || arg_count == NULL) {
        return false;
    }
    if (surface->call_arg_count == 0U) {
        return surface->call_args_text[0] == '\0';
    }
    if (arg_cap < surface->call_arg_count) {
        return false;
    }
    if (surface->call_prefix_style || surface->call_arg_count == 1U) {
        snprintf(args[0], sizeof(args[0]), "%s", surface->call_args_text);
        *arg_count = 1U;
        return true;
    }
    return cheng_seed_split_top_level_args(surface->call_args_text, args, arg_count, arg_cap);
}

static bool cheng_seed_statement_has_incomplete_if_expr(const char *statement) {
    char trimmed[8192];
    char expr[8192];
    char cond[4096];
    char if_true[4096];
    char if_false[4096];
    cheng_seed_trim_copy_text(statement, trimmed, sizeof(trimmed));
    if (cheng_seed_startswith(trimmed, "return ")) {
        cheng_seed_trim_copy_text(trimmed + 7, expr, sizeof(expr));
    } else {
        const char *rhs = strstr(trimmed, "= if ");
        if (!rhs) {
            return false;
        }
        cheng_seed_trim_copy_text(rhs + 2, expr, sizeof(expr));
    }
    if (!cheng_seed_startswith(expr, "if ")) {
        return false;
    }
    if (cheng_seed_parse_if_expr(expr,
                         cond,
                         sizeof(cond),
                         if_true,
                         sizeof(if_true),
                         if_false,
                         sizeof(if_false))) {
        return false;
    }
    return cheng_seed_find_top_level_colon(expr) >= 0;
}

static int32_t cheng_seed_next_expr_label_id(void) {
    static int32_t next_id = 0;
    next_id += 1;
    return next_id;
}

#define CHENG_MAX_LOOP_LABEL_DEPTH 64

static char cheng_loop_continue_labels[CHENG_MAX_LOOP_LABEL_DEPTH][128];
static char cheng_loop_break_labels[CHENG_MAX_LOOP_LABEL_DEPTH][128];
static size_t cheng_loop_label_depth = 0U;

static void cheng_seed_reset_loop_labels(void) {
    cheng_loop_label_depth = 0U;
}

static bool cheng_seed_push_loop_labels(const char *continue_label, const char *break_label) {
    if (cheng_loop_label_depth >= CHENG_MAX_LOOP_LABEL_DEPTH) {
        return false;
    }
    snprintf(cheng_loop_continue_labels[cheng_loop_label_depth],
             sizeof(cheng_loop_continue_labels[cheng_loop_label_depth]),
             "%s",
             continue_label ? continue_label : "");
    snprintf(cheng_loop_break_labels[cheng_loop_label_depth],
             sizeof(cheng_loop_break_labels[cheng_loop_label_depth]),
             "%s",
             break_label ? break_label : "");
    cheng_loop_label_depth += 1U;
    return true;
}

static void cheng_seed_pop_loop_labels(void) {
    if (cheng_loop_label_depth > 0U) {
        cheng_loop_label_depth -= 1U;
    }
}

static const char *cheng_seed_current_continue_label(void) {
    if (cheng_loop_label_depth <= 0U) {
        return NULL;
    }
    return cheng_loop_continue_labels[cheng_loop_label_depth - 1U][0] != '\0'
               ? cheng_loop_continue_labels[cheng_loop_label_depth - 1U]
               : NULL;
}

static const char *cheng_seed_current_break_label(void) {
    if (cheng_loop_label_depth <= 0U) {
        return NULL;
    }
    return cheng_loop_break_labels[cheng_loop_label_depth - 1U][0] != '\0'
               ? cheng_loop_break_labels[cheng_loop_label_depth - 1U]
               : NULL;
}

