static ChengSeedCopyKind cheng_seed_result_intrinsic_projection_copy_kind(const ChengSeedLoweringPlanStub *lowering,
                                                           ChengSeedResultIntrinsicKind kind,
                                                           const char *result_type) {
    char field_type[256];
    char field_abi[32];
    char err_type[256];
    char err_abi[32];
    char msg_type[256];
    char msg_abi[32];
    int32_t field_offset = 0;
    int32_t err_offset = 0;
    int32_t msg_offset = 0;
    if (lowering == NULL || result_type == NULL || result_type[0] == '\0') {
        return ChengSeed_COPY_KIND_VALUE;
    }
    if (kind == ChengSeed_RESULT_INTRINSIC_VALUE) {
        if (cheng_seed_resolve_field_meta(lowering,
                                  result_type,
                                  "value",
                                  field_type,
                                  sizeof(field_type),
                                  field_abi,
                                  sizeof(field_abi),
                                  &field_offset) &&
            cheng_seed_type_copies_by_region(field_type, field_abi)) {
            return ChengSeed_COPY_KIND_REGION;
        }
        return ChengSeed_COPY_KIND_VALUE;
    }
    if (kind == ChengSeed_RESULT_INTRINSIC_ERROR_INFO_OF) {
        if (cheng_seed_resolve_field_meta(lowering,
                                  result_type,
                                  "err",
                                  field_type,
                                  sizeof(field_type),
                                  field_abi,
                                  sizeof(field_abi),
                                  &field_offset) &&
            cheng_seed_type_copies_by_region(field_type, field_abi)) {
            return ChengSeed_COPY_KIND_REGION;
        }
        return ChengSeed_COPY_KIND_VALUE;
    }
    if (kind != ChengSeed_RESULT_INTRINSIC_ERROR &&
        kind != ChengSeed_RESULT_INTRINSIC_ERROR_TEXT) {
        return ChengSeed_COPY_KIND_VALUE;
    }
    if (cheng_seed_resolve_field_meta(lowering,
                              result_type,
                              "err",
                              err_type,
                              sizeof(err_type),
                              err_abi,
                              sizeof(err_abi),
                              &err_offset) &&
        cheng_seed_type_copies_by_region(err_type, err_abi) &&
        cheng_seed_resolve_field_meta(lowering,
                              err_type,
                              "msg",
                              msg_type,
                              sizeof(msg_type),
                              msg_abi,
                              sizeof(msg_abi),
                              &msg_offset) &&
        cheng_seed_type_copies_by_region(msg_type, msg_abi)) {
        return ChengSeed_COPY_KIND_REGION;
    }
    return ChengSeed_COPY_KIND_VALUE;
}

static bool cheng_seed_result_intrinsic_projection_copies_by_region(const ChengSeedLoweringPlanStub *lowering,
                                                            ChengSeedResultIntrinsicKind kind,
                                                            const char *result_type) {
    return cheng_seed_result_intrinsic_projection_copy_kind(lowering, kind, result_type) ==
           ChengSeed_COPY_KIND_REGION;
}

static bool cheng_seed_function_return_prefers_address(const ChengSeedLoweredFunctionStub *function) {
    if (function == NULL) {
        return false;
    }
    return cheng_seed_value_signature_prefers_address(function->return_type,
                                              function->return_abi_class);
}

static ChengSeedReturnPassKind cheng_seed_function_return_pass_kind(const ChengSeedLoweredFunctionStub *function) {
    if (cheng_seed_function_return_prefers_address(function)) {
        return ChengSeed_RETURN_PASS_ADDRESS;
    }
    return ChengSeed_RETURN_PASS_VALUE;
}

static bool cheng_seed_function_return_passes_by_address(const ChengSeedLoweredFunctionStub *function) {
    return cheng_seed_function_return_pass_kind(function) == ChengSeed_RETURN_PASS_ADDRESS;
}

static ChengSeedCallResultKind cheng_seed_function_call_result_kind(const ChengSeedLoweredFunctionStub *function) {
    return cheng_seed_function_return_passes_by_address(function)
        ? ChengSeed_CALL_RESULT_ADDRESS
        : ChengSeed_CALL_RESULT_VALUE;
}

static void cheng_seed_native_function_lowering_rule_init(ChengSeedNativeFunctionLoweringRule *rule) {
    if (rule == NULL) {
        return;
    }
    memset(rule, 0, sizeof(*rule));
    rule->supported = false;
}

static bool cheng_seed_build_native_function_lowering_rule(const ChengSeedLoweredFunctionStub *function,
                                                   ChengSeedNativeFunctionLoweringRule *rule) {
    if (function == NULL || rule == NULL) {
        return false;
    }
    cheng_seed_native_function_lowering_rule_init(rule);
    rule->return_pass_kind = cheng_seed_function_return_pass_kind(function);
    rule->result_kind = cheng_seed_function_call_result_kind(function);
    rule->supported = true;
    return true;
}

static bool cheng_seed_native_function_rule_result_uses_address(const ChengSeedNativeFunctionLoweringRule *rule) {
    return rule != NULL && rule->supported &&
           rule->result_kind == ChengSeed_CALL_RESULT_ADDRESS;
}

static ChengSeedCallTargetReturnKind cheng_seed_call_target_return_kind(const ChengSeedAsmCallTarget *target) {
    if (target == NULL) {
        return ChengSeed_CALL_TARGET_RETURN_VALUE;
    }
    if (target->ffi_handle_enabled && target->ffi_handle_return_is_handle) {
        return ChengSeed_CALL_TARGET_RETURN_FFI_HANDLE_REGISTER;
    }
    return cheng_seed_value_signature_prefers_address(target->return_type, target->return_abi_class)
        ? ChengSeed_CALL_TARGET_RETURN_ADDRESS
        : ChengSeed_CALL_TARGET_RETURN_VALUE;
}

static bool cheng_seed_call_target_return_prefers_address(const ChengSeedAsmCallTarget *target) {
    return cheng_seed_call_target_return_kind(target) == ChengSeed_CALL_TARGET_RETURN_ADDRESS;
}

static ChengSeedReturnPassKind cheng_seed_call_target_return_pass_kind(const ChengSeedAsmCallTarget *target) {
    if (cheng_seed_call_target_return_prefers_address(target)) {
        return ChengSeed_RETURN_PASS_ADDRESS;
    }
    return ChengSeed_RETURN_PASS_VALUE;
}

static bool cheng_seed_call_target_return_passes_by_address(const ChengSeedAsmCallTarget *target) {
    return cheng_seed_call_target_return_pass_kind(target) == ChengSeed_RETURN_PASS_ADDRESS;
}

static ChengSeedCallResultKind cheng_seed_call_target_result_kind(const ChengSeedAsmCallTarget *target) {
    return cheng_seed_call_target_return_passes_by_address(target)
        ? ChengSeed_CALL_RESULT_ADDRESS
        : ChengSeed_CALL_RESULT_VALUE;
}

static void cheng_seed_native_call_lowering_rule_init(ChengSeedNativeCallLoweringRule *rule) {
    if (rule == NULL) {
        return;
    }
    memset(rule, 0, sizeof(*rule));
    rule->supported = false;
}

static ChengSeedNativeImportKind cheng_seed_native_call_target_import_kind(const ChengSeedAsmCallTarget *target) {
    ChengSeedCallResultKind result_kind;
    if (target == NULL || !target->external || !target->c_abi) {
        return ChengSeed_NATIVE_IMPORT_NONE;
    }
    result_kind = cheng_seed_call_target_result_kind(target);
    return result_kind == ChengSeed_CALL_RESULT_ADDRESS
        ? ChengSeed_NATIVE_IMPORT_C_ABI_ADDRESS
        : ChengSeed_NATIVE_IMPORT_C_ABI_VALUE;
}

static bool cheng_seed_build_native_call_lowering_rule(const ChengSeedAsmCallTarget *target,
                                               ChengSeedNativeCallLoweringRule *rule) {
    size_t i;
    if (target == NULL || rule == NULL || target->param_count > CHENG_MAX_CALL_ARGS) {
        return false;
    }
    cheng_seed_native_call_lowering_rule_init(rule);
    rule->param_count = target->param_count;
    for (i = 0U; i < target->param_count; ++i) {
        rule->arg_kinds[i] = cheng_seed_call_target_arg_kind(target, i);
    }
    rule->return_kind = cheng_seed_call_target_return_kind(target);
    rule->return_pass_kind = cheng_seed_call_target_return_pass_kind(target);
    rule->result_kind = cheng_seed_call_target_result_kind(target);
    rule->import_kind = cheng_seed_native_call_target_import_kind(target);
    rule->supported = true;
    return true;
}

static void cheng_seed_snapshot_call_target_param_signature(const ChengSeedAsmCallTarget *target,
                                                    char type_out[][256],
                                                    char abi_out[][32]) {
    size_t i;
    if (target == NULL || type_out == NULL || abi_out == NULL) {
        return;
    }
    for (i = 0U; i < CHENG_MAX_CALL_ARGS; ++i) {
        type_out[i][0] = '\0';
        abi_out[i][0] = '\0';
    }
    for (i = 0U; i < target->param_count && i < CHENG_MAX_CALL_ARGS; ++i) {
        snprintf(type_out[i], 256, "%s", target->param_types[i]);
        snprintf(abi_out[i], 32, "%s", target->param_abi_classes[i]);
    }
}

static bool cheng_seed_native_call_rule_result_uses_address(const ChengSeedNativeCallLoweringRule *rule) {
    return rule != NULL && rule->result_kind == ChengSeed_CALL_RESULT_ADDRESS;
}

static void cheng_seed_native_composite_call_lowering_rule_init(ChengSeedNativeCompositeCallLoweringRule *rule) {
    if (rule == NULL) {
        return;
    }
    memset(rule, 0, sizeof(*rule));
    rule->supported = false;
}

static ChengSeedNativeCompositeResultKind cheng_seed_native_composite_result_kind_for_call_rule(const ChengSeedNativeCallLoweringRule *rule) {
    if (rule == NULL || !rule->supported || !cheng_seed_native_call_rule_result_uses_address(rule)) {
        return ChengSeed_NATIVE_COMPOSITE_RESULT_UNSUPPORTED;
    }
    return rule->import_kind == ChengSeed_NATIVE_IMPORT_C_ABI_ADDRESS
        ? ChengSeed_NATIVE_COMPOSITE_RESULT_IMPORT_BUFFER
        : ChengSeed_NATIVE_COMPOSITE_RESULT_DEST_ADDRESS;
}

static bool cheng_seed_build_native_composite_call_lowering_rule(const ChengSeedAsmCallTarget *target,
                                                         ChengSeedNativeCompositeCallLoweringRule *rule) {
    if (rule == NULL) {
        return false;
    }
    cheng_seed_native_composite_call_lowering_rule_init(rule);
    if (!cheng_seed_build_native_call_lowering_rule(target, &rule->call_rule)) {
        return false;
    }
    rule->composite_result_kind =
        cheng_seed_native_composite_result_kind_for_call_rule(&rule->call_rule);
    rule->supported = rule->composite_result_kind != ChengSeed_NATIVE_COMPOSITE_RESULT_UNSUPPORTED;
    return rule->supported;
}

static const char *cheng_seed_native_call_rule_arg_load_abi(const ChengSeedAsmCallTarget *target,
                                                    const ChengSeedNativeCallLoweringRule *rule,
                                                    size_t arg_index) {
    ChengSeedCallTargetArgKind kind;
    if (target == NULL || rule == NULL ||
        arg_index >= CHENG_MAX_CALL_ARGS ||
        arg_index >= target->param_count ||
        arg_index >= rule->param_count) {
        abort();
    }
    kind = rule->arg_kinds[arg_index];
    if (cheng_seed_call_target_arg_kind_uses_indirect_slot(kind)) {
        return "ptr";
    }
    return target->param_abi_classes[arg_index];
}

static bool cheng_seed_prepare_native_call_lowering_rule_with_args(const ChengSeedSystemLinkPlanStub *plan,
                                                           const ChengSeedLoweringPlanStub *lowering,
                                                           const ChengSeedLoweredFunctionStub *current_function,
                                                           const ChengSeedImportAlias *aliases,
                                                           size_t alias_count,
                                                           const ChengSeedAsmLocalSlot *locals,
                                                           size_t local_count,
                                                           char *callee,
                                                           size_t callee_cap,
                                                           char args[][4096],
                                                           size_t *arg_count_io,
                                                           const ChengSeedAsmCallTarget *preferred_target,
                                                           ChengSeedAsmCallTarget *target,
                                                           ChengSeedNativeCallLoweringRule *rule,
                                                           bool *resolved_out) {
    size_t arg_count = 0U;
    bool call_rewritten = false;
    if (plan == NULL || lowering == NULL || current_function == NULL ||
        callee == NULL || callee_cap == 0U || arg_count_io == NULL ||
        target == NULL || rule == NULL) {
        return false;
    }
    if (resolved_out != NULL) {
        *resolved_out = false;
    }
    memset(target, 0, sizeof(*target));
    memset(rule, 0, sizeof(*rule));
    arg_count = *arg_count_io;
    if (!cheng_seed_canonicalize_static_str_join_call(current_function->owner_module_path,
                                              aliases,
                                              alias_count,
                                              callee,
                                              callee_cap,
                                              (const char (*)[4096])args,
                                              &arg_count,
                                              &call_rewritten)) {
        return false;
    }
    *arg_count_io = arg_count;
    if (preferred_target != NULL && !call_rewritten) {
        memcpy(target, preferred_target, sizeof(*target));
    } else if (!cheng_seed_resolve_call_target_with_args(plan,
                                                 lowering,
                                                 current_function,
                                                 aliases,
                                                 alias_count,
                                                 locals,
                                                 local_count,
                                                 callee,
                                                 (const char (*)[4096])args,
                                                 arg_count,
                                                 target)) {
        return resolved_out != NULL;
    }
    if (!cheng_seed_build_native_call_lowering_rule(target, rule)) {
        return false;
    }
    if (resolved_out != NULL) {
        *resolved_out = true;
    }
    return true;
}

static bool cheng_seed_prepare_native_composite_call_lowering_rule_with_args(const ChengSeedSystemLinkPlanStub *plan,
                                                                     const ChengSeedLoweringPlanStub *lowering,
                                                                     const ChengSeedLoweredFunctionStub *current_function,
                                                                     const ChengSeedImportAlias *aliases,
                                                                     size_t alias_count,
                                                                     const ChengSeedAsmLocalSlot *locals,
                                                                     size_t local_count,
                                                                     char *callee,
                                                                     size_t callee_cap,
                                                                     char args[][4096],
                                                                     size_t *arg_count_io,
                                                                     ChengSeedAsmCallTarget *target,
                                                                     ChengSeedNativeCompositeCallLoweringRule *rule,
                                                                     bool *resolved_out) {
    size_t arg_count = 0U;
    if (plan == NULL || lowering == NULL || current_function == NULL ||
        callee == NULL || callee_cap == 0U || arg_count_io == NULL ||
        target == NULL || rule == NULL || resolved_out == NULL) {
        return false;
    }
    *resolved_out = false;
    arg_count = *arg_count_io;
    if (!cheng_seed_canonicalize_static_str_join_call(current_function->owner_module_path,
                                              aliases,
                                              alias_count,
                                              callee,
                                              callee_cap,
                                              (const char (*)[4096])args,
                                              &arg_count,
                                              NULL)) {
        return false;
    }
    *arg_count_io = arg_count;
    memset(target, 0, sizeof(*target));
    memset(rule, 0, sizeof(*rule));
    if (!cheng_seed_resolve_call_target_with_args(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          callee,
                                          (const char (*)[4096])args,
                                          arg_count,
                                          target)) {
        return true;
    }
    if (!cheng_seed_build_native_composite_call_lowering_rule(target, rule)) {
        return false;
    }
    *resolved_out = true;
    return true;
}

static bool cheng_seed_is_internal_ref_type(const char *type_text) {
    return type_text != NULL && cheng_seed_startswith(type_text, "ref@");
}

static void cheng_seed_strip_internal_ref_type(const char *type_text, char *out, size_t cap) {
    if (cap == 0U) {
        return;
    }
    if (cheng_seed_is_internal_ref_type(type_text)) {
        snprintf(out, cap, "%s", type_text + 4);
        return;
    }
    snprintf(out, cap, "%s", type_text ? type_text : "");
}

static void cheng_seed_write_type_def_normalized(const ChengSeedTypeDefStub *type_def, char *out, size_t cap) {
    if (cap == 0U) {
        return;
    }
    if (type_def == NULL) {
        out[0] = '\0';
        return;
    }
    if (type_def->ref_object) {
        snprintf(out, cap, "ref@%s::%s", type_def->owner_module_path, type_def->type_name);
        return;
    }
    snprintf(out, cap, "%s::%s", type_def->owner_module_path, type_def->type_name);
}

static void cheng_seed_text_appendf(char *out, size_t cap, const char *fmt, ...);
static bool cheng_seed_abi_class_scalar_or_ptr(const char *abi_class);

static const char *cheng_seed_canonical_scalar_type_name(const char *type_text) {
    if (type_text == NULL) {
        return "";
    }
    if (strcmp(type_text, "int") == 0) {
        return "int32";
    }
    return type_text;
}

static bool cheng_seed_scalar_type_is_unsigned(const char *type_text) {
    const char *canonical = cheng_seed_canonical_scalar_type_name(type_text);
    return strcmp(canonical, "uint8") == 0 ||
           strcmp(canonical, "uint16") == 0 ||
           strcmp(canonical, "uint32") == 0 ||
           strcmp(canonical, "uint64") == 0;
}

static bool cheng_seed_text_case_equal(const char *lhs, const char *rhs) {
    size_t i = 0U;
    if (!lhs || !rhs) {
        return false;
    }
    while (lhs[i] != '\0' && rhs[i] != '\0') {
        if (tolower((unsigned char)lhs[i]) != tolower((unsigned char)rhs[i])) {
            return false;
        }
        i += 1U;
    }
    return lhs[i] == '\0' && rhs[i] == '\0';
}

static bool cheng_seed_emit_scalar_cast_reg(char *out,
                                    size_t cap,
                                    const char *src_type_text,
                                    const char *src_abi,
                                    const char *dst_type_text,
                                    const char *dst_abi,
                                    int reg_index) {
    const char *src_type = cheng_seed_canonical_scalar_type_name(src_type_text);
    const char *dst_type = cheng_seed_canonical_scalar_type_name(dst_type_text);
    if (!cheng_seed_abi_class_scalar_or_ptr(src_abi) || !cheng_seed_abi_class_scalar_or_ptr(dst_abi)) {
        return false;
    }
    if (strcmp(dst_abi, "bool") == 0) {
        if (cheng_seed_active_target_is_linux_x86_64()) {
            cheng_seed_emit_x64_cmp_zero_set_bool(out,
                                          cap,
                                          reg_index,
                                          reg_index,
                                          strcmp(src_abi, "i64") == 0 || strcmp(src_abi, "ptr") == 0,
                                          "ne");
        } else {
            cheng_seed_text_appendf(out, cap, "  cmp %c%d, #0\n  cset w%d, ne\n",
                            strcmp(src_abi, "i64") == 0 || strcmp(src_abi, "ptr") == 0 ? 'x' : 'w',
                            reg_index,
                            reg_index);
        }
        return true;
    }
    if (strcmp(src_abi, dst_abi) == 0 &&
        strcmp(src_type, dst_type) == 0) {
        return true;
    }
    if (cheng_seed_active_target_is_linux_x86_64()) {
        if (strcmp(dst_abi, "i64") == 0 || strcmp(dst_abi, "ptr") == 0) {
            if (strcmp(src_abi, "bool") == 0 || strcmp(src_abi, "u8") == 0) {
                cheng_seed_text_appendf(out, cap, "  movzbl %s, %s\n",
                                cheng_seed_x64_breg_name(reg_index),
                                cheng_seed_x64_dreg_name(reg_index));
                return true;
            }
            if (strcmp(src_abi, "i8") == 0) {
                cheng_seed_text_appendf(out, cap, "  movsbq %s, %s\n",
                                cheng_seed_x64_breg_name(reg_index),
                                cheng_seed_x64_qreg_name(reg_index));
                return true;
            }
            if (strcmp(src_abi, "u16") == 0) {
                cheng_seed_text_appendf(out, cap, "  movzwl %s, %s\n",
                                cheng_seed_x64_hreg_name(reg_index),
                                cheng_seed_x64_dreg_name(reg_index));
                return true;
            }
            if (strcmp(src_abi, "i16") == 0) {
                cheng_seed_text_appendf(out, cap, "  movswq %s, %s\n",
                                cheng_seed_x64_hreg_name(reg_index),
                                cheng_seed_x64_qreg_name(reg_index));
                return true;
            }
            if (strcmp(src_abi, "i32") == 0) {
                cheng_seed_text_appendf(out, cap, "  movslq %s, %s\n",
                                cheng_seed_x64_dreg_name(reg_index),
                                cheng_seed_x64_qreg_name(reg_index));
                return true;
            }
            if (strcmp(src_abi, "i64") == 0 || strcmp(src_abi, "ptr") == 0) {
                return true;
            }
            return false;
        }
        if (strcmp(dst_abi, "i32") == 0) {
            if (strcmp(src_abi, "i64") == 0 || strcmp(src_abi, "ptr") == 0) {
                cheng_seed_text_appendf(out, cap, "  movl %s, %s\n",
                                cheng_seed_x64_dreg_name(reg_index),
                                cheng_seed_x64_dreg_name(reg_index));
            }
            return true;
        }
        if (strcmp(dst_abi, "i16") == 0) {
            cheng_seed_text_appendf(out,
                            cap,
                            cheng_seed_scalar_type_is_unsigned(dst_type) ? "  movzwl %s, %s\n" : "  movswl %s, %s\n",
                            cheng_seed_x64_hreg_name(reg_index),
                            cheng_seed_x64_dreg_name(reg_index));
            return true;
        }
        if (strcmp(dst_abi, "u16") == 0) {
            cheng_seed_text_appendf(out, cap, "  movzwl %s, %s\n",
                            cheng_seed_x64_hreg_name(reg_index),
                            cheng_seed_x64_dreg_name(reg_index));
            return true;
        }
        if (strcmp(dst_abi, "i8") == 0) {
            cheng_seed_text_appendf(out,
                            cap,
                            cheng_seed_scalar_type_is_unsigned(dst_type) ? "  movzbl %s, %s\n" : "  movsbl %s, %s\n",
                            cheng_seed_x64_breg_name(reg_index),
                            cheng_seed_x64_dreg_name(reg_index));
            return true;
        }
        if (strcmp(dst_abi, "u8") == 0) {
            cheng_seed_text_appendf(out, cap, "  movzbl %s, %s\n",
                            cheng_seed_x64_breg_name(reg_index),
                            cheng_seed_x64_dreg_name(reg_index));
            return true;
        }
        return false;
    }
    if (strcmp(dst_abi, "i64") == 0 || strcmp(dst_abi, "ptr") == 0) {
        if (strcmp(src_abi, "bool") == 0 ||
            strcmp(src_abi, "i8") == 0 ||
            strcmp(src_abi, "u8") == 0 ||
            strcmp(src_abi, "i16") == 0 ||
            strcmp(src_abi, "u16") == 0 ||
            strcmp(src_abi, "i32") == 0) {
            if (cheng_seed_scalar_type_is_unsigned(src_type) ||
                strcmp(src_abi, "bool") == 0 ||
                strcmp(src_abi, "u8") == 0 ||
                strcmp(src_abi, "u16") == 0) {
                cheng_seed_text_appendf(out, cap, "  uxtw x%d, w%d\n", reg_index, reg_index);
            } else {
                cheng_seed_text_appendf(out, cap, "  sxtw x%d, w%d\n", reg_index, reg_index);
            }
            return true;
        }
        if (strcmp(src_abi, "i64") == 0 || strcmp(src_abi, "ptr") == 0) {
            return true;
        }
        return false;
    }
    if (strcmp(dst_abi, "i32") == 0) {
        if (strcmp(src_abi, "i64") == 0 || strcmp(src_abi, "ptr") == 0) {
            cheng_seed_text_appendf(out, cap, "  mov w%d, w%d\n", reg_index, reg_index);
            return true;
        }
        if (strcmp(src_abi, "bool") == 0 ||
            strcmp(src_abi, "i8") == 0 ||
            strcmp(src_abi, "u8") == 0 ||
            strcmp(src_abi, "i16") == 0 ||
            strcmp(src_abi, "u16") == 0 ||
            strcmp(src_abi, "i32") == 0) {
            return true;
        }
        return false;
    }
    if (strcmp(dst_abi, "i16") == 0) {
        cheng_seed_text_appendf(out,
                        cap,
                        cheng_seed_scalar_type_is_unsigned(dst_type) ? "  uxth w%d, w%d\n" : "  sxth w%d, w%d\n",
                        reg_index,
                        reg_index);
        return true;
    }
    if (strcmp(dst_abi, "u16") == 0) {
        cheng_seed_text_appendf(out, cap, "  uxth w%d, w%d\n", reg_index, reg_index);
        return true;
    }
    if (strcmp(dst_abi, "i8") == 0) {
        cheng_seed_text_appendf(out,
                        cap,
                        cheng_seed_scalar_type_is_unsigned(dst_type) ? "  uxtb w%d, w%d\n" : "  sxtb w%d, w%d\n",
                        reg_index,
                        reg_index);
        return true;
    }
    if (strcmp(dst_abi, "u8") == 0) {
        cheng_seed_text_appendf(out, cap, "  uxtb w%d, w%d\n", reg_index, reg_index);
        return true;
    }
    return false;
}

static bool cheng_seed_strip_var_type_text(const char *type_text,
                                   char *out,
                                   size_t cap) {
    char trimmed[256];
    if (!type_text || !out || cap == 0U) {
        return false;
    }
    cheng_seed_trim_copy_text(type_text, trimmed, sizeof(trimmed));
    if (!cheng_seed_startswith(trimmed, "var ")) {
        snprintf(out, cap, "%s", trimmed);
        return false;
    }
    cheng_seed_trim_copy_text(trimmed + 4, out, cap);
    return out[0] != '\0';
}

static bool cheng_seed_parse_top_level_const_binding(const char *statement,
                                             char *name_out,
                                             size_t name_cap,
                                             char *type_out,
                                             size_t type_cap,
                                             char *expr_out,
                                             size_t expr_cap) {
    const char *eq = strchr(statement, '=');
    char left[256];
    char right[4096];
    char *colon;
    if (!eq) {
        return false;
    }
    snprintf(left, sizeof(left), "%.*s", (int)(eq - statement), statement);
    snprintf(right, sizeof(right), "%s", eq + 1);
    cheng_seed_trim_copy_text(left, left, sizeof(left));
    cheng_seed_trim_copy_text(right, expr_out, expr_cap);
    if (left[0] == '\0' || expr_out[0] == '\0') {
        return false;
    }
    colon = strchr(left, ':');
    if (colon) {
        *colon = '\0';
        snprintf(type_out, type_cap, "%s", colon + 1);
        cheng_seed_trim_copy_text(type_out, type_out, type_cap);
    } else {
        type_out[0] = '\0';
    }
    cheng_seed_trim_copy_text(left, name_out, name_cap);
    return name_out[0] != '\0';
}

static int32_t cheng_seed_find_top_level_const_index_by_symbol(const ChengSeedLoweringPlanStub *lowering,
                                                       const char *symbol_text) {
    size_t i;
    for (i = 0; i < lowering->const_count; ++i) {
        if (strcmp(lowering->consts[i].symbol_text, symbol_text) == 0) {
            return (int32_t)i;
        }
    }
    return -1;
}

static bool cheng_seed_parse_string_literal_text(const char *expr_text,
                                         char *literal_out,
                                         size_t literal_cap);
static bool cheng_seed_parse_int_literal_text(const char *expr_text, int64_t *value_out);
static int32_t cheng_seed_find_top_level_binary_op_last(const char *text, const char *op);
static bool cheng_seed_parse_top_level_var_binding_text(const char *statement,
                                                char *name_out,
                                                size_t name_cap,
                                                char *type_out,
                                                size_t type_cap,
                                                bool *has_init_out,
                                                char *expr_out,
                                                size_t expr_cap);

static bool cheng_seed_try_resolve_i64_top_level_const_expr(const char *expr_text,
                                                    const ChengSeedLoweringPlanStub *lowering,
                                                    const char *owner_module_path,
                                                    const ChengSeedImportAlias *aliases,
                                                    size_t alias_count,
                                                    int64_t *value_out) {
    char expr[4096];
    int64_t literal = 0;
    int32_t shl_index = -1;
    int32_t plus_index = -1;
    int32_t minus_index = -1;
    int64_t lhs = 0;
    int64_t rhs = 0;
    char left[4096];
    char right[4096];
    char symbol_text[PATH_MAX];
    int32_t index = -1;
    const ChengSeedTopLevelConstStub *existing = NULL;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return false;
    }
    if (cheng_seed_parse_int_literal_text(expr, &literal)) {
        *value_out = literal;
        return true;
    }
    shl_index = cheng_seed_find_top_level_binary_op_last(expr, "<<");
    if (shl_index > 0) {
        snprintf(left, sizeof(left), "%.*s", shl_index, expr);
        snprintf(right, sizeof(right), "%s", expr + shl_index + 2);
        cheng_seed_trim_copy_text(left, left, sizeof(left));
        cheng_seed_trim_copy_text(right, right, sizeof(right));
        return cheng_seed_try_resolve_i64_top_level_const_expr(left,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &lhs) &&
               cheng_seed_try_resolve_i64_top_level_const_expr(right,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &rhs) &&
               rhs >= 0 &&
               rhs < 63 &&
               ((*value_out = (int64_t)((uint64_t)lhs << (uint32_t)rhs)), true);
    }
    plus_index = cheng_seed_find_top_level_binary_op_last(expr, "+");
    if (plus_index > 0) {
        snprintf(left, sizeof(left), "%.*s", plus_index, expr);
        snprintf(right, sizeof(right), "%s", expr + plus_index + 1);
        cheng_seed_trim_copy_text(left, left, sizeof(left));
        cheng_seed_trim_copy_text(right, right, sizeof(right));
        return cheng_seed_try_resolve_i64_top_level_const_expr(left,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &lhs) &&
               cheng_seed_try_resolve_i64_top_level_const_expr(right,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &rhs) &&
               ((*value_out = lhs + rhs), true);
    }
    minus_index = cheng_seed_find_top_level_binary_op_last(expr, "-");
    if (minus_index > 0) {
        snprintf(left, sizeof(left), "%.*s", minus_index, expr);
        snprintf(right, sizeof(right), "%s", expr + minus_index + 1);
        cheng_seed_trim_copy_text(left, left, sizeof(left));
        cheng_seed_trim_copy_text(right, right, sizeof(right));
        return cheng_seed_try_resolve_i64_top_level_const_expr(left,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &lhs) &&
               cheng_seed_try_resolve_i64_top_level_const_expr(right,
                                                       lowering,
                                                       owner_module_path,
                                                       aliases,
                                                       alias_count,
                                                       &rhs) &&
               ((*value_out = lhs - rhs), true);
    }
    if (strchr(expr, '.') != NULL) {
        char alias_text[128];
        char const_name[128];
        char expr_copy[4096];
        char *dot;
        const char *module_path;
        snprintf(expr_copy, sizeof(expr_copy), "%s", expr);
        dot = strchr(expr_copy, '.');
        *dot = '\0';
        snprintf(alias_text, sizeof(alias_text), "%s", expr_copy);
        snprintf(const_name, sizeof(const_name), "%s", dot + 1);
        module_path = cheng_seed_alias_module_path_exported_member(aliases,
                                                           alias_count,
                                                           owner_module_path,
                                                           alias_text,
                                                           const_name,
                                                           sizeof(const_name));
        if (!module_path) {
            return false;
        }
        snprintf(symbol_text, sizeof(symbol_text), "%s::%s", module_path, const_name);
    } else {
        snprintf(symbol_text, sizeof(symbol_text), "%s::%s", owner_module_path, expr);
    }
    index = cheng_seed_find_top_level_const_index_by_symbol(lowering, symbol_text);
    if (index < 0) {
        return false;
    }
    existing = &lowering->consts[index];
    if (strcmp(existing->abi_class, "i32") != 0 &&
        strcmp(existing->abi_class, "i64") != 0 &&
        strcmp(existing->abi_class, "bool") != 0) {
        return false;
    }
    *value_out = existing->i64_value;
    return true;
}

static bool cheng_seed_try_parse_scalar_const_literal(const char *expr_text,
                                              const char *declared_type,
                                              const ChengSeedLoweringPlanStub *lowering,
                                              const char *owner_module_path,
                                              const ChengSeedImportAlias *aliases,
                                              size_t alias_count,
                                              ChengSeedTopLevelConstStub *out) {
    char expr[4096];
    char literal[8192];
    char *end = NULL;
    const char *declared_abi = cheng_seed_type_abi_class(declared_type);
    int64_t resolved_i64 = 0;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return false;
    }
    memset(out, 0, sizeof(*out));
    if (strcmp(expr, "true") == 0 || strcmp(expr, "false") == 0) {
        snprintf(out->abi_class, sizeof(out->abi_class), "%s", "bool");
        out->bool_value = strcmp(expr, "true") == 0;
        out->i64_value = out->bool_value ? 1 : 0;
        return true;
    }
    if ((expr[0] >= '0' && expr[0] <= '9') ||
        (expr[0] == '-' && ((expr[1] >= '0' && expr[1] <= '9') || expr[1] == '0'))) {
        long long value = strtoll(expr, &end, 0);
        if (end && *cheng_seed_trim_inplace(end) == '\0') {
            snprintf(out->abi_class,
                     sizeof(out->abi_class),
                     "%s",
                     strcmp(declared_abi, "i64") == 0 ? "i64" : "i32");
            out->i64_value = (int64_t)value;
            return true;
        }
    }
    if ((declared_type[0] == '\0' ||
         strcmp(declared_abi, "i32") == 0 ||
         strcmp(declared_abi, "i64") == 0 ||
         strcmp(declared_abi, "bool") == 0) &&
        cheng_seed_try_resolve_i64_top_level_const_expr(expr,
                                                lowering,
                                                owner_module_path,
                                                aliases,
                                                alias_count,
                                                &resolved_i64)) {
        snprintf(out->abi_class,
                 sizeof(out->abi_class),
                 "%s",
                 strcmp(declared_abi, "i64") == 0 ? "i64" :
                 (strcmp(declared_abi, "bool") == 0 ? "bool" : "i32"));
        out->i64_value = resolved_i64;
        out->bool_value = resolved_i64 != 0;
        return true;
    }
    if (cheng_seed_parse_string_literal_text(expr, literal, sizeof(literal))) {
        if (declared_type[0] != '\0' &&
            strcmp(declared_type, "str") != 0 &&
            strcmp(declared_type, "cstring") != 0) {
            return false;
        }
        snprintf(out->abi_class, sizeof(out->abi_class), "%s", cheng_seed_type_abi_class("str"));
        snprintf(out->str_value, sizeof(out->str_value), "%s", literal);
        out->has_str_value = true;
        return true;
    }
    if (strchr(expr, '(') == NULL && strchr(expr, '[') == NULL && strchr(expr, ' ') == NULL) {
        char symbol_text[PATH_MAX];
        const ChengSeedTopLevelConstStub *existing = NULL;
        if (strchr(expr, '.') != NULL) {
            char alias_text[128];
            char const_name[128];
            char expr_copy[4096];
            char *dot;
            const char *module_path;
            snprintf(expr_copy, sizeof(expr_copy), "%s", expr);
            dot = strchr(expr_copy, '.');
            *dot = '\0';
            snprintf(alias_text, sizeof(alias_text), "%s", expr_copy);
            snprintf(const_name, sizeof(const_name), "%s", dot + 1);
            module_path = cheng_seed_alias_module_path_exported_member(aliases,
                                                               alias_count,
                                                               owner_module_path,
                                                               alias_text,
                                                               const_name,
                                                               sizeof(const_name));
            if (!module_path) {
                return false;
            }
            snprintf(symbol_text, sizeof(symbol_text), "%s::%s", module_path, const_name);
        } else {
            snprintf(symbol_text, sizeof(symbol_text), "%s::%s", owner_module_path, expr);
        }
        {
            int32_t index = cheng_seed_find_top_level_const_index_by_symbol(lowering, symbol_text);
            if (index < 0) {
                return false;
            }
            existing = &lowering->consts[index];
        }
        snprintf(out->abi_class, sizeof(out->abi_class), "%s", existing->abi_class);
        snprintf(out->str_value, sizeof(out->str_value), "%s", existing->str_value);
        out->has_str_value = existing->has_str_value;
        out->i64_value = existing->i64_value;
        out->bool_value = existing->bool_value;
        if (strcmp(declared_abi, "i64") == 0 && strcmp(out->abi_class, "i32") == 0) {
            snprintf(out->abi_class, sizeof(out->abi_class), "%s", "i64");
        }
        if (declared_type[0] != '\0' &&
            cheng_seed_abi_class_is_composite(out->abi_class) &&
            strcmp(declared_type, "str") != 0 &&
            strcmp(declared_type, "cstring") != 0) {
            return false;
        }
        return out->abi_class[0] != '\0';
    }
    return false;
}

static bool cheng_seed_collect_top_level_consts_from_source(const ChengSeedSystemLinkPlanStub *plan,
                                                    const char *source_path,
                                                    ChengSeedLoweringPlanStub *lowering) {
    char owner_module_path[PATH_MAX];
    ChengSeedImportAlias aliases[CHENG_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    char *owned;
    char **lines;
    size_t line_count = 0U;
    size_t i;
    bool in_const_block = false;
    cheng_seed_source_path_to_module_path(plan->workspace_root,
                                  plan->package_root,
                                  plan->package_id,
                                  source_path,
                                  owner_module_path,
                                  sizeof(owner_module_path));
    if (!cheng_seed_load_source_lines(source_path, &lines, &owned, &line_count)) {
        fprintf(stderr, "[cheng_seed] type scan read failed: %s\n", source_path);
        return false;
    }
    cheng_seed_parse_import_aliases_from_lines(lines,
                                       line_count,
                                       aliases,
                                       &alias_count,
                                       CHENG_MAX_IMPORT_ALIASES);
    for (i = 0; i < line_count; ++i) {
        char line_copy[4096];
        char name[128];
        char type_text[CHENG_MAX_TYPE_TEXT];
        char expr_text[4096];
        ChengSeedTopLevelConstStub value;
        int32_t indent;
        char *trimmed;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        indent = cheng_seed_line_indent(line_copy);
        trimmed = cheng_seed_trim_inplace(line_copy);
        if (*trimmed == '\0') {
            continue;
        }
        if (indent <= 0 &&
            cheng_seed_startswith(trimmed, "const ") &&
            cheng_seed_parse_top_level_const_binding(trimmed + 6,
                                             name,
                                             sizeof(name),
                                             type_text,
                                             sizeof(type_text),
                                             expr_text,
                                             sizeof(expr_text))) {
            if (!cheng_seed_try_parse_scalar_const_literal(expr_text,
                                                   type_text,
                                                   lowering,
                                                   owner_module_path,
                                                   aliases,
                                                   alias_count,
                                                   &value)) {
                continue;
            }
            if (!cheng_seed_lowering_plan_reserve_consts(lowering, lowering->const_count + 1U)) {
                free(lines);
                free(owned);
                return false;
            }
            snprintf(lowering->consts[lowering->const_count].owner_module_path,
                     sizeof(lowering->consts[lowering->const_count].owner_module_path),
                     "%s",
                     owner_module_path);
            snprintf(lowering->consts[lowering->const_count].const_name,
                     sizeof(lowering->consts[lowering->const_count].const_name),
                     "%s",
                     name);
            snprintf(lowering->consts[lowering->const_count].symbol_text,
                     sizeof(lowering->consts[lowering->const_count].symbol_text),
                     "%s::%s",
                     owner_module_path,
                     name);
            snprintf(lowering->consts[lowering->const_count].type_text,
                     sizeof(lowering->consts[lowering->const_count].type_text),
                     "%s",
                     type_text[0] != '\0' ? type_text : "int32");
            snprintf(lowering->consts[lowering->const_count].abi_class,
                     sizeof(lowering->consts[lowering->const_count].abi_class),
                     "%s",
                     value.abi_class);
            snprintf(lowering->consts[lowering->const_count].str_value,
                     sizeof(lowering->consts[lowering->const_count].str_value),
                     "%s",
                     value.str_value);
            lowering->consts[lowering->const_count].has_str_value = value.has_str_value;
            lowering->consts[lowering->const_count].i64_value = value.i64_value;
            lowering->consts[lowering->const_count].bool_value = value.bool_value;
            lowering->const_count += 1U;
            continue;
        }
        if (indent <= 0 && strcmp(trimmed, "const") == 0) {
            in_const_block = true;
            continue;
        }
        if (!in_const_block) {
            continue;
        }
        if (indent <= 0) {
            in_const_block = false;
            continue;
        }
        if (!cheng_seed_parse_top_level_const_binding(trimmed,
                                              name,
                                              sizeof(name),
                                              type_text,
                                              sizeof(type_text),
                                              expr_text,
                                              sizeof(expr_text))) {
            continue;
        }
        if (!cheng_seed_try_parse_scalar_const_literal(expr_text,
                                               type_text,
                                               lowering,
                                               owner_module_path,
                                               aliases,
                                               alias_count,
                                               &value)) {
            continue;
        }
        if (!cheng_seed_lowering_plan_reserve_consts(lowering, lowering->const_count + 1U)) {
            free(lines);
            free(owned);
            return false;
        }
        snprintf(lowering->consts[lowering->const_count].symbol_text,
                 sizeof(lowering->consts[lowering->const_count].symbol_text),
                 "%s::%s",
                 owner_module_path,
                 name);
        snprintf(lowering->consts[lowering->const_count].owner_module_path,
                 sizeof(lowering->consts[lowering->const_count].owner_module_path),
                 "%s",
                 owner_module_path);
        snprintf(lowering->consts[lowering->const_count].const_name,
                 sizeof(lowering->consts[lowering->const_count].const_name),
                 "%s",
                 name);
        snprintf(lowering->consts[lowering->const_count].type_text,
                 sizeof(lowering->consts[lowering->const_count].type_text),
                 "%s",
                 type_text[0] != '\0' ? type_text :
                 (cheng_seed_abi_class_is_composite(value.abi_class) && value.has_str_value ? "str" :
                 (strcmp(value.abi_class, "i64") == 0 ? "int64" :
                  (strcmp(value.abi_class, "bool") == 0 ? "bool" : "int32"))));
        snprintf(lowering->consts[lowering->const_count].abi_class,
                 sizeof(lowering->consts[lowering->const_count].abi_class),
                 "%s",
                 value.abi_class);
        snprintf(lowering->consts[lowering->const_count].str_value,
                 sizeof(lowering->consts[lowering->const_count].str_value),
                 "%s",
                 value.str_value);
        lowering->consts[lowering->const_count].has_str_value = value.has_str_value;
        lowering->consts[lowering->const_count].i64_value = value.i64_value;
        lowering->consts[lowering->const_count].bool_value = value.bool_value;
        lowering->const_count += 1U;
    }
    free(owned);
    return true;
}

static const ChengSeedTopLevelConstStub *cheng_seed_find_expr_top_level_const(const ChengSeedLoweringPlanStub *lowering,
                                                               const char *owner_module_path,
                                                               const ChengSeedImportAlias *aliases,
                                                               size_t alias_count,
                                                               const char *expr_text) {
    char expr[4096];
    char symbol_text[PATH_MAX];
    int32_t index;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0' || strchr(expr, '(') != NULL || strchr(expr, '[') != NULL) {
        return NULL;
    }
    if (strchr(expr, '.') != NULL) {
        char alias_text[128];
        char const_name[128];
        char expr_copy[4096];
        char *dot;
        const char *module_path;
        snprintf(expr_copy, sizeof(expr_copy), "%s", expr);
        dot = strchr(expr_copy, '.');
        *dot = '\0';
        snprintf(alias_text, sizeof(alias_text), "%s", expr_copy);
        snprintf(const_name, sizeof(const_name), "%s", dot + 1);
        module_path = cheng_seed_alias_module_path_exported_member(aliases,
                                                           alias_count,
                                                           owner_module_path,
                                                           alias_text,
                                                           const_name,
                                                           sizeof(const_name));
        if (!module_path) {
            return NULL;
        }
        snprintf(symbol_text, sizeof(symbol_text), "%s::%s", module_path, const_name);
        index = cheng_seed_find_top_level_const_index_by_symbol(lowering, symbol_text);
        return index >= 0 ? &lowering->consts[index] : NULL;
    }
    snprintf(symbol_text, sizeof(symbol_text), "%s::%s", owner_module_path, expr);
    index = cheng_seed_find_top_level_const_index_by_symbol(lowering, symbol_text);
    if (index >= 0) {
        return &lowering->consts[index];
    }
    {
        const ChengSeedTopLevelConstStub *match = NULL;
        size_t i;
        for (i = 0; i < alias_count; ++i) {
            snprintf(symbol_text, sizeof(symbol_text), "%s::%s", aliases[i].module_path, expr);
            index = cheng_seed_find_top_level_const_index_by_symbol(lowering, symbol_text);
            if (index < 0) {
                continue;
            }
            if (match != NULL) {
                return NULL;
            }
            match = &lowering->consts[index];
        }
        if (match != NULL) {
            return match;
        }
    }
    {
        const ChengSeedTopLevelConstStub *match = NULL;
        size_t i;
        for (i = 0; i < lowering->const_count; ++i) {
            if (strcmp(lowering->consts[i].const_name, expr) != 0) {
                continue;
            }
            if (match != NULL) {
                return NULL;
            }
            match = &lowering->consts[i];
        }
        return match;
    }
}

static int32_t cheng_seed_align_up_i32(int32_t value, int32_t align) {
    if (align <= 1) {
        return value;
    }
    return (value + align - 1) / align * align;
}

static void cheng_seed_strip_var_prefix(const char *type_text, char *out, size_t cap) {
    char scratch[256];
    cheng_seed_trim_copy_text(type_text, scratch, sizeof(scratch));
    if (cheng_seed_startswith(scratch, "var ")) {
        cheng_seed_trim_copy_text(scratch + 4, out, cap);
        return;
    }
    cheng_seed_copy_text(out, cap, scratch);
}

static bool cheng_seed_eval_type_int32_expr(const ChengSeedLoweringPlanStub *lowering,
                                    const char *owner_module_path,
                                    const ChengSeedImportAlias *aliases,
                                    size_t alias_count,
                                    const char *expr_text,
                                    int32_t *value_out) {
    char expr[256];
    char *end = NULL;
    long long parsed;
    const ChengSeedTopLevelConstStub *top_level_const;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return false;
    }
    parsed = strtoll(expr, &end, 0);
    if (end && *cheng_seed_trim_inplace(end) == '\0') {
        *value_out = (int32_t)parsed;
        return true;
    }
    top_level_const = cheng_seed_find_expr_top_level_const(lowering,
                                                   owner_module_path,
                                                   aliases,
                                                   alias_count,
                                                   expr);
    if (!top_level_const) {
        return false;
    }
    *value_out = (int32_t)top_level_const->i64_value;
    return true;
}

