static int32_t cheng_seed_incoming_stack_arg_offset_for_target(const ChengSeedSystemLinkPlanStub *plan,
                                                       int32_t frame_size,
                                                       int32_t stack_arg_index) {
    if (plan != NULL && cheng_seed_target_is_linux_x86_64(plan->target_triple)) {
        return frame_size + 56 + stack_arg_index * 8;
    }
    return frame_size + stack_arg_index * 8;
}

static const char *cheng_seed_x64_cond_suffix(const char *cond) {
    if (cond == NULL) {
        return "e";
    }
    if (strcmp(cond, "eq") == 0) return "e";
    if (strcmp(cond, "ne") == 0) return "ne";
    if (strcmp(cond, "lt") == 0) return "l";
    if (strcmp(cond, "le") == 0) return "le";
    if (strcmp(cond, "gt") == 0) return "g";
    if (strcmp(cond, "ge") == 0) return "ge";
    return "e";
}

static void cheng_seed_emit_x64_move_reg(char *out,
                                 size_t cap,
                                 int dst_reg,
                                 int src_reg,
                                 const char *abi_class) {
    if (cheng_seed_abi_class_word_reg(abi_class)) {
        if (dst_reg != src_reg) {
            cheng_seed_text_appendf(out, cap,
                            "  movl %s, %s\n",
                            cheng_seed_x64_dreg_name(src_reg),
                            cheng_seed_x64_dreg_name(dst_reg));
        }
        return;
    }
    if (dst_reg != src_reg) {
        cheng_seed_text_appendf(out, cap,
                        "  movq %s, %s\n",
                        cheng_seed_x64_qreg_name(src_reg),
                        cheng_seed_x64_qreg_name(dst_reg));
    }
}

static void cheng_seed_emit_move_reg_abi(char *out,
                                 size_t cap,
                                 int dst_reg,
                                 int src_reg,
                                 const char *abi_class) {
    if (cheng_seed_active_target_is_linux_x86_64()) {
        cheng_seed_emit_x64_move_reg(out, cap, dst_reg, src_reg, abi_class);
        return;
    }
    if (dst_reg == src_reg) {
        return;
    }
    if (cheng_seed_abi_class_word_reg(abi_class)) {
        cheng_seed_text_appendf(out, cap, "  mov w%d, w%d\n", dst_reg, src_reg);
    } else {
        cheng_seed_text_appendf(out, cap, "  mov x%d, x%d\n", dst_reg, src_reg);
    }
}

static void cheng_seed_emit_x64_cmp_zero_set_bool(char *out,
                                          size_t cap,
                                          int src_reg,
                                          int dst_reg,
                                          bool wide,
                                          const char *cond) {
    cheng_seed_text_appendf(out, cap,
                    "  cmp%s $0, %s\n"
                    "  movl $0, %s\n"
                    "  set%s %s\n",
                    wide ? "q" : "l",
                    wide ? cheng_seed_x64_qreg_name(src_reg) : cheng_seed_x64_dreg_name(src_reg),
                    cheng_seed_x64_dreg_name(dst_reg),
                    cheng_seed_x64_cond_suffix(cond),
                    cheng_seed_x64_breg_name(dst_reg));
}

static void cheng_seed_emit_x64_cmp_regs_set_bool(char *out,
                                          size_t cap,
                                          int left_reg,
                                          int right_reg,
                                          int dst_reg,
                                          bool wide,
                                          const char *cond) {
    cheng_seed_text_appendf(out, cap,
                    "  cmp%s %s, %s\n"
                    "  movl $0, %s\n"
                    "  set%s %s\n",
                    wide ? "q" : "l",
                    wide ? cheng_seed_x64_qreg_name(right_reg) : cheng_seed_x64_dreg_name(right_reg),
                    wide ? cheng_seed_x64_qreg_name(left_reg) : cheng_seed_x64_dreg_name(left_reg),
                    cheng_seed_x64_dreg_name(dst_reg),
                    cheng_seed_x64_cond_suffix(cond),
                    cheng_seed_x64_breg_name(dst_reg));
}

static void cheng_seed_emit_x64_branch_zero(char *out,
                                    size_t cap,
                                    int reg_index,
                                    bool wide,
                                    bool branch_if_zero,
                                    const char *label) {
    cheng_seed_text_appendf(out, cap,
                    "  cmp%s $0, %s\n"
                    "  j%s %s\n",
                    wide ? "q" : "l",
                    wide ? cheng_seed_x64_qreg_name(reg_index) : cheng_seed_x64_dreg_name(reg_index),
                    branch_if_zero ? "e" : "ne",
                    label);
}

static void cheng_seed_emit_branch_zero(char *out,
                                size_t cap,
                                int reg_index,
                                bool wide,
                                const char *label) {
    if (cheng_seed_active_target_is_linux_x86_64()) {
        cheng_seed_emit_x64_branch_zero(out, cap, reg_index, wide, true, label);
        return;
    }
    cheng_seed_text_appendf(out, cap,
                    "  cmp %c%d, #0\n"
                    "  b.eq %s\n",
                    wide ? 'x' : 'w',
                    reg_index,
                    label);
}

static void cheng_seed_emit_branch_nonzero(char *out,
                                   size_t cap,
                                   int reg_index,
                                   bool wide,
                                   const char *label) {
    if (cheng_seed_active_target_is_linux_x86_64()) {
        cheng_seed_emit_x64_branch_zero(out, cap, reg_index, wide, false, label);
        return;
    }
    cheng_seed_text_appendf(out, cap,
                    "  cmp %c%d, #0\n"
                    "  b.ne %s\n",
                    wide ? 'x' : 'w',
                    reg_index,
                    label);
}

static void cheng_seed_emit_jump_label(char *out,
                               size_t cap,
                               const char *label) {
    cheng_seed_text_appendf(out,
                    cap,
                    cheng_seed_active_target_is_linux_x86_64() ? "  jmp %s\n" : "  b %s\n",
                    label);
}

static bool cheng_seed_active_target_is_linux_x86_64(void) {
    return cheng_seed_target_is_linux_x86_64(cheng_seed_active_codegen_target_triple);
}

typedef struct ChengSeedPrimaryTextBuilder {
    char *data;
    size_t cap;
    size_t len;
    bool overflowed;
} ChengSeedPrimaryTextBuilder;
static void cheng_seed_primary_text_builder_init(ChengSeedPrimaryTextBuilder *builder, char *data, size_t cap);

static void cheng_seed_append_cstring_section_for_target(const ChengSeedSystemLinkPlanStub *plan,
                                                 char *out,
                                                 size_t cap) {
    if (cheng_seed_target_is_elf_aarch64(plan->target_triple) ||
        cheng_seed_target_is_linux_x86_64(plan->target_triple)) {
        cheng_seed_text_append(out, cap, ".section .rodata\n");
    } else {
        cheng_seed_text_append(out, cap, ".section __TEXT,__cstring,cstring_literals\n");
    }
}

static void cheng_seed_flush_cstring_literal_pool_for_target(const ChengSeedSystemLinkPlanStub *plan,
                                                     ChengSeedPrimaryTextBuilder *pool,
                                                     char *out,
                                                     size_t cap) {
    if (plan == NULL || pool == NULL || pool->data == NULL || pool->len == 0U) {
        return;
    }
    cheng_seed_append_cstring_section_for_target(plan, out, cap);
    cheng_seed_text_append(out, cap, pool->data);
    cheng_seed_text_append(out, cap, ".text\n.p2align 2\n");
    cheng_seed_primary_text_builder_init(pool, pool->data, pool->cap);
}

static void cheng_seed_append_const_section_for_target(const ChengSeedSystemLinkPlanStub *plan,
                                               char *out,
                                               size_t cap) {
    if (cheng_seed_target_is_elf_aarch64(plan->target_triple) ||
        cheng_seed_target_is_linux_x86_64(plan->target_triple)) {
        cheng_seed_text_append(out, cap, ".section .data.rel.ro\n.p2align 3\n");
    } else {
        cheng_seed_text_append(out, cap, ".section __DATA_CONST,__const\n.p2align 3\n");
    }
}

static void cheng_seed_append_symbol_trailer_for_target(const ChengSeedSystemLinkPlanStub *plan,
                                                char *out,
                                                size_t cap) {
    if (cheng_seed_target_is_darwin_arm64(plan->target_triple)) {
        cheng_seed_text_append(out, cap, ".subsections_via_symbols\n");
    }
}

static bool cheng_seed_symbol_name_looks_compiler_generated(const char *symbol_name) {
    return symbol_name != NULL && strstr(symbol_name, "__") != NULL;
}

static bool cheng_seed_symbol_address_needs_got(const ChengSeedSystemLinkPlanStub *plan,
                                        const char *symbol_name,
                                        bool local_label) {
    if (plan == NULL ||
        symbol_name == NULL ||
        symbol_name[0] == '\0' ||
        local_label ||
        !(cheng_seed_streq(plan->emit_kind, "shared") || cheng_seed_streq(plan->emit_kind, "obj"))) {
        return false;
    }
    if (cheng_seed_symbol_visibility_is_internal(plan) &&
        cheng_seed_symbol_name_looks_compiler_generated(symbol_name)) {
        return false;
    }
    return true;
}

static bool cheng_seed_emit_symbol_address_for_target(const ChengSeedSystemLinkPlanStub *plan,
                                              char *out,
                                              size_t cap,
                                              int reg_index,
                                              const char *symbol_name) {
    bool local_label = false;
    if (plan == NULL || symbol_name == NULL || symbol_name[0] == '\0') {
        return false;
    }
    local_label = cheng_seed_startswith(symbol_name, "L_");
    if (cheng_seed_target_is_elf_aarch64(plan->target_triple)) {
        if (cheng_seed_symbol_address_needs_got(plan, symbol_name, local_label)) {
            cheng_seed_text_appendf(out, cap,
                            "  adrp x%d, :got:%s\n"
                            "  ldr x%d, [x%d, #:got_lo12:%s]\n",
                            reg_index,
                            symbol_name,
                            reg_index,
                            reg_index,
                            symbol_name);
            return true;
        }
        cheng_seed_text_appendf(out, cap,
                        "  adrp x%d, %s\n"
                        "  add x%d, x%d, :lo12:%s\n",
                        reg_index,
                        symbol_name,
                        reg_index,
                        reg_index,
                        symbol_name);
        return true;
    }
    if (cheng_seed_target_is_linux_x86_64(plan->target_triple)) {
        if (cheng_seed_symbol_address_needs_got(plan, symbol_name, local_label)) {
            cheng_seed_text_appendf(out, cap,
                            "  movq %s@GOTPCREL(%%rip), %s\n",
                            symbol_name,
                            cheng_seed_x64_qreg_name(reg_index));
            return true;
        }
        cheng_seed_text_appendf(out, cap,
                        "  leaq %s(%%rip), %s\n",
                        symbol_name,
                        cheng_seed_x64_qreg_name(reg_index));
        return true;
    }
    cheng_seed_text_appendf(out, cap,
                    "  adrp x%d, %s@PAGE\n"
                    "  add x%d, x%d, %s@PAGEOFF\n",
                    reg_index,
                    symbol_name,
                    reg_index,
                    reg_index,
                    symbol_name);
    return true;
}

static void cheng_seed_emit_call_named_symbol(const ChengSeedSystemLinkPlanStub *plan,
                                      char *out,
                                      size_t cap,
                                      const char *symbol) {
    char target_symbol[PATH_MAX];
    cheng_seed_copy_target_symbol_name(plan, symbol, target_symbol, sizeof(target_symbol));
    if (plan != NULL && cheng_seed_target_is_linux_x86_64(plan->target_triple)) {
        cheng_seed_text_appendf(out, cap, "  call %s\n", target_symbol);
        return;
    }
    cheng_seed_text_appendf(out, cap, "  bl %s\n", target_symbol);
}

static void cheng_seed_emit_call_target_symbol_text(const ChengSeedSystemLinkPlanStub *plan,
                                            char *out,
                                            size_t cap,
                                            const char *target_symbol) {
    if (plan != NULL && cheng_seed_target_is_linux_x86_64(plan->target_triple)) {
        cheng_seed_text_appendf(out, cap, "  call %s\n", target_symbol);
        return;
    }
    cheng_seed_text_appendf(out, cap, "  bl %s\n", target_symbol);
}

static void cheng_seed_embedded_line_map_end_label(size_t ordinal,
                                           char *out,
                                           size_t cap) {
    snprintf(out, cap, "L_cheng_embedded_line_map_end_%zu", ordinal);
}

static void cheng_seed_embedded_line_map_function_name_label(size_t ordinal,
                                                     char *out,
                                                     size_t cap) {
    snprintf(out, cap, "L_cheng_embedded_line_map_fn_%zu", ordinal);
}

static void cheng_seed_embedded_line_map_source_path_label(size_t ordinal,
                                                   char *out,
                                                   size_t cap) {
    snprintf(out, cap, "L_cheng_embedded_line_map_src_%zu", ordinal);
}

static bool cheng_seed_append_embedded_line_map(char *text,
                                        size_t cap,
                                        const ChengSeedSystemLinkPlanStub *plan,
                                        const ChengSeedLoweringPlanStub *lowering,
                                        const ChengSeedLoweredFunctionStub *single_function) {
    const ChengSeedLoweredFunctionStub *entry_function = NULL;
    size_t function_entry_count = 0U;
    size_t bridge_ordinal = single_function != NULL ? 1U : lowering->function_count;
    size_t i;
    if (!cheng_seed_streq(plan->emit_kind, "exe")) {
        return true;
    }
    entry_function = single_function != NULL ? single_function : cheng_seed_find_entry_lowered_function(lowering);
    if (single_function != NULL) {
        function_entry_count = 1U;
    } else {
        for (i = 0; i < lowering->function_count; ++i) {
            if (cheng_seed_function_has_unbound_generics(lowering, &lowering->functions[i]) ||
                cheng_seed_function_has_obvious_template_text(&lowering->functions[i])) {
                continue;
            }
            function_entry_count += 1U;
        }
    }
    {
        size_t entry_count = function_entry_count + (entry_function != NULL ? 1U : 0U);
    if (entry_count == 0U) {
        return true;
    }
    cheng_seed_append_cstring_section_for_target(plan, text, cap);
    for (i = 0; single_function != NULL ? i < 1U : i < lowering->function_count; ++i) {
        const ChengSeedLoweredFunctionStub *function =
            single_function != NULL ? single_function : &lowering->functions[i];
        char fn_label[64];
        char src_label[64];
        char *escaped_function;
        char *escaped_source;
        if (single_function == NULL &&
            (cheng_seed_function_has_unbound_generics(lowering, function) ||
             cheng_seed_function_has_obvious_template_text(function))) {
            continue;
        }
        cheng_seed_embedded_line_map_function_name_label(i, fn_label, sizeof(fn_label));
        cheng_seed_embedded_line_map_source_path_label(i, src_label, sizeof(src_label));
        escaped_function = cheng_seed_c_escape(function->function_name);
        escaped_source = cheng_seed_c_escape(function->source_path);
        cheng_seed_text_appendf(text, cap,
                        "%s:\n"
                        "  .asciz \"%s\"\n"
                        "%s:\n"
                        "  .asciz \"%s\"\n",
                        fn_label,
                        escaped_function,
                        src_label,
                        escaped_source);
        free(escaped_function);
        free(escaped_source);
    }
    if (entry_function != NULL) {
        char fn_label[64];
        char src_label[64];
        char *escaped_function;
        char *escaped_source;
        cheng_seed_embedded_line_map_function_name_label(bridge_ordinal, fn_label, sizeof(fn_label));
        cheng_seed_embedded_line_map_source_path_label(bridge_ordinal, src_label, sizeof(src_label));
        escaped_function = cheng_seed_c_escape(entry_function->function_name);
        escaped_source = cheng_seed_c_escape(entry_function->source_path);
        cheng_seed_text_appendf(text, cap,
                        "%s:\n"
                        "  .asciz \"%s\"\n"
                        "%s:\n"
                        "  .asciz \"%s\"\n",
                        fn_label,
                        escaped_function,
                        src_label,
                        escaped_source);
        free(escaped_function);
        free(escaped_source);
    }
    cheng_seed_append_const_section_for_target(plan, text, cap);
    cheng_seed_text_append(text, cap, "L_cheng_embedded_line_map_entries:\n");
    for (i = 0; single_function != NULL ? i < 1U : i < lowering->function_count; ++i) {
        const ChengSeedLoweredFunctionStub *function =
            single_function != NULL ? single_function : &lowering->functions[i];
        char symbol_name[PATH_MAX];
        char end_label[64];
        char fn_label[64];
        char src_label[64];
        if (single_function == NULL &&
            (cheng_seed_function_has_unbound_generics(lowering, function) ||
             cheng_seed_function_has_obvious_template_text(function))) {
            continue;
        }
        cheng_seed_primary_symbol_name(plan, function, symbol_name, sizeof(symbol_name));
        cheng_seed_embedded_line_map_end_label(i, end_label, sizeof(end_label));
        cheng_seed_embedded_line_map_function_name_label(i, fn_label, sizeof(fn_label));
        cheng_seed_embedded_line_map_source_path_label(i, src_label, sizeof(src_label));
        cheng_seed_text_appendf(text, cap,
                        "  .quad %s\n"
                        "  .quad %s\n"
                        "  .quad %s\n"
                        "  .quad %s\n"
                        "  .long %zu\n"
                        "  .long %zu\n"
                        "  .long %zu\n"
                        "  .long 0\n",
                        symbol_name,
                        end_label,
                        fn_label,
                        src_label,
                        function->signature_line_number,
                        function->body_first_line_number,
                        function->body_last_line_number);
    }
    if (entry_function != NULL) {
        char bridge_symbol[PATH_MAX];
        char end_label[64];
        char fn_label[64];
        char src_label[64];
        cheng_seed_runtime_entry_bridge_symbol(plan, bridge_symbol, sizeof(bridge_symbol));
        cheng_seed_embedded_line_map_end_label(bridge_ordinal, end_label, sizeof(end_label));
        cheng_seed_embedded_line_map_function_name_label(bridge_ordinal, fn_label, sizeof(fn_label));
        cheng_seed_embedded_line_map_source_path_label(bridge_ordinal, src_label, sizeof(src_label));
        cheng_seed_text_appendf(text, cap,
                        "  .quad %s\n"
                        "  .quad %s\n"
                        "  .quad %s\n"
                        "  .quad %s\n"
                        "  .long %zu\n"
                        "  .long %zu\n"
                        "  .long %zu\n"
                        "  .long 0\n",
                        bridge_symbol,
                        end_label,
                        fn_label,
                        src_label,
                        entry_function->signature_line_number,
                        entry_function->body_first_line_number,
                        entry_function->body_last_line_number);
    }
    {
        char entries_getter_symbol[PATH_MAX];
        char count_getter_symbol[PATH_MAX];
        cheng_seed_copy_target_symbol_name(plan,
                                   "cheng_embedded_line_map_entries_get",
                                   entries_getter_symbol,
                                   sizeof(entries_getter_symbol));
        cheng_seed_copy_target_symbol_name(plan,
                                   "cheng_embedded_line_map_count_get",
                                   count_getter_symbol,
                                   sizeof(count_getter_symbol));
        cheng_seed_text_appendf(text, cap,
                        "L_cheng_embedded_line_map_count_value:\n"
                        "  .quad %zu\n"
                        ".text\n"
                        ".p2align 2\n"
                        ".globl %s\n"
                        "%s:\n",
                        entry_count,
                        entries_getter_symbol,
                        entries_getter_symbol);
        if (!cheng_seed_emit_symbol_address_for_target(plan, text, cap, 0, "L_cheng_embedded_line_map_entries")) {
            return false;
        }
        cheng_seed_text_appendf(text, cap,
                        "  ret\n"
                        ".globl %s\n"
                        "%s:\n",
                        count_getter_symbol,
                        count_getter_symbol);
        if (!cheng_seed_emit_symbol_address_for_target(plan, text, cap, 0, "L_cheng_embedded_line_map_count_value")) {
            return false;
        }
        if (cheng_seed_target_is_linux_x86_64(plan->target_triple)) {
            cheng_seed_text_append(text, cap,
                           "  movq 0(%rax), %rax\n"
                           "  retq\n");
        } else {
            cheng_seed_text_append(text, cap,
                           "  ldr x0, [x0]\n"
                           "  ret\n");
        }
    }
    }
    return true;
}

static void cheng_seed_line_map_path_for_output(const char *output_path,
                                        char *out,
                                        size_t cap) {
    snprintf(out, cap, "%s.map", output_path);
}

static char *cheng_seed_build_line_map_text(const ChengSeedSystemLinkPlanStub *plan,
                                    const ChengSeedLoweringPlanStub *lowering) {
    const ChengSeedLoweredFunctionStub *entry_function;
    size_t cap;
    char *text;
    size_t i;
    size_t entry_count = 0U;
    entry_function = cheng_seed_find_entry_lowered_function(lowering);
    cap = 256U + (lowering->function_count + 1U) * (PATH_MAX * 2U + 192U);
    text = (char *)cheng_seed_xmalloc(cap);
    text[0] = '\0';
    for (i = 0; i < lowering->function_count; ++i) {
        if (cheng_seed_function_has_unbound_generics(lowering, &lowering->functions[i]) ||
            cheng_seed_function_has_obvious_template_text(&lowering->functions[i])) {
            continue;
        }
        entry_count += 1U;
    }
    strncat(text, "cheng_line_map_v1\n", cap - strlen(text) - 1U);
    snprintf(text + strlen(text),
             cap - strlen(text),
             "entry_count=%zu\n",
             entry_count + (entry_function != NULL ? 1U : 0U));
    for (i = 0; i < lowering->function_count; ++i) {
        char primary_symbol[PATH_MAX];
        const ChengSeedLoweredFunctionStub *function = &lowering->functions[i];
        if (cheng_seed_function_has_unbound_generics(lowering, function)) {
            continue;
        }
        cheng_seed_primary_symbol_name(plan, function, primary_symbol, sizeof(primary_symbol));
        snprintf(text + strlen(text),
                 cap - strlen(text),
                 "entry\t%s\t%s\t%s\t%zu\t%zu\t%zu\n",
                 primary_symbol,
                 function->function_name,
                 function->source_path,
                 function->signature_line_number,
                 function->body_first_line_number,
                 function->body_last_line_number);
    }
    if (entry_function != NULL) {
        char bridge_symbol[PATH_MAX];
        cheng_seed_runtime_entry_bridge_symbol(plan, bridge_symbol, sizeof(bridge_symbol));
        snprintf(text + strlen(text),
                 cap - strlen(text),
                 "entry\t%s\t%s\t%s\t%zu\t%zu\t%zu\n",
                 bridge_symbol,
                 entry_function->function_name,
                 entry_function->source_path,
                 entry_function->signature_line_number,
                 entry_function->body_first_line_number,
                 entry_function->body_last_line_number);
    }
    return text;
}

static bool cheng_seed_write_executable_line_map(const ChengSeedSystemLinkPlanStub *plan,
                                         const ChengSeedLoweringPlanStub *lowering) {
    char map_path[PATH_MAX];
    char *text;
    if (!cheng_seed_streq(plan->emit_kind, "exe") || plan->output_path[0] == '\0') {
        return true;
    }
    cheng_seed_line_map_path_for_output(plan->output_path, map_path, sizeof(map_path));
    text = cheng_seed_build_line_map_text(plan, lowering);
    if (!cheng_seed_ensure_parent_dir(map_path) || !cheng_seed_write_text_file(map_path, text)) {
        free(text);
        return false;
    }
    free(text);
    return true;
}

static const ChengSeedLoweredFunctionStub *cheng_seed_find_entry_lowered_function(const ChengSeedLoweringPlanStub *lowering) {
    size_t i;
    for (i = 0; i < lowering->function_count; ++i) {
        if (lowering->functions[i].is_entry) {
            return &lowering->functions[i];
        }
    }
    return NULL;
}

static bool cheng_seed_abi_class_scalar_or_ptr(const char *abi_class) {
    ChengSeedAbiDescriptor desc = cheng_seed_abi_descriptor_from_class(abi_class);
    return desc.value_kind != ChengSeed_ABI_VALUE_COMPOSITE;
}

static bool cheng_seed_abi_class_is_composite(const char *abi_class) {
    ChengSeedAbiDescriptor desc = cheng_seed_abi_descriptor_from_class(abi_class);
    return desc.value_kind == ChengSeed_ABI_VALUE_COMPOSITE;
}

static bool cheng_seed_abi_class_word_reg(const char *abi_class) {
    return strcmp(abi_class, "i32") == 0 ||
           strcmp(abi_class, "i8") == 0 ||
           strcmp(abi_class, "u8") == 0 ||
           strcmp(abi_class, "i16") == 0 ||
           strcmp(abi_class, "u16") == 0 ||
           strcmp(abi_class, "bool") == 0;
}

static void cheng_seed_type_text_from_abi_class(const char *abi_class,
                                        char *type_out,
                                        size_t type_cap) {
    if (strcmp(abi_class, "i8") == 0) {
        snprintf(type_out, type_cap, "%s", "int8");
        return;
    }
    if (strcmp(abi_class, "u8") == 0) {
        snprintf(type_out, type_cap, "%s", "uint8");
        return;
    }
    if (strcmp(abi_class, "i16") == 0) {
        snprintf(type_out, type_cap, "%s", "int16");
        return;
    }
    if (strcmp(abi_class, "u16") == 0) {
        snprintf(type_out, type_cap, "%s", "uint16");
        return;
    }
    if (strcmp(abi_class, "i32") == 0) {
        snprintf(type_out, type_cap, "%s", "int32");
        return;
    }
    if (strcmp(abi_class, "i64") == 0) {
        snprintf(type_out, type_cap, "%s", "int64");
        return;
    }
    if (strcmp(abi_class, "bool") == 0) {
        snprintf(type_out, type_cap, "%s", "bool");
        return;
    }
    if (strcmp(abi_class, "ptr") == 0) {
        snprintf(type_out, type_cap, "%s", "ptr");
        return;
    }
    if (strcmp(abi_class, "void") == 0) {
        snprintf(type_out, type_cap, "%s", "void");
        return;
    }
    type_out[0] = '\0';
}

static bool cheng_seed_call_target_set_signature(ChengSeedAsmCallTarget *target,
                                         const char *return_type,
                                         size_t param_count,
                                         const char *const *param_types) {
    size_t i;
    if (target == NULL ||
        return_type == NULL || return_type[0] == '\0' ||
        param_count > CHENG_MAX_CALL_ARGS ||
        (param_count > 0U && param_types == NULL)) {
        return false;
    }
    target->param_count = param_count;
    snprintf(target->return_type, sizeof(target->return_type), "%s", return_type);
    snprintf(target->return_abi_class,
             sizeof(target->return_abi_class),
             "%s",
             cheng_seed_type_abi_class(target->return_type));
    for (i = 0; i < param_count; ++i) {
        if (param_types[i] == NULL || param_types[i][0] == '\0') {
            return false;
        }
        snprintf(target->param_types[i],
                 sizeof(target->param_types[i]),
                 "%s",
                 param_types[i]);
        snprintf(target->param_abi_classes[i],
                 sizeof(target->param_abi_classes[i]),
                 "%s",
                 cheng_seed_type_abi_class(target->param_types[i]));
    }
    return true;
}

static ChengSeedPrimaryTextBuilder *cheng_seed_active_primary_text_builder = NULL;
static ChengSeedPrimaryTextBuilder *g_cheng_active_cstring_literal_pool_builder = NULL;

static void cheng_seed_primary_text_builder_append(ChengSeedPrimaryTextBuilder *builder, const char *text);

static void cheng_seed_text_append(char *out, size_t cap, const char *text) {
    if (cheng_seed_active_primary_text_builder != NULL &&
        cheng_seed_active_primary_text_builder->data == out &&
        cheng_seed_active_primary_text_builder->cap == cap) {
        cheng_seed_primary_text_builder_append(cheng_seed_active_primary_text_builder, text);
        return;
    }
    strncat(out, text, cap - strlen(out) - 1U);
}

static void cheng_seed_text_appendf(char *out, size_t cap, const char *fmt, ...) {
    va_list ap;
    if (cheng_seed_active_primary_text_builder != NULL &&
        cheng_seed_active_primary_text_builder->data == out &&
        cheng_seed_active_primary_text_builder->cap == cap) {
        int written;
        size_t remaining;
        if (cheng_seed_active_primary_text_builder->len + 1U >= cheng_seed_active_primary_text_builder->cap) {
            cheng_seed_active_primary_text_builder->overflowed = true;
            return;
        }
        remaining = cheng_seed_active_primary_text_builder->cap - cheng_seed_active_primary_text_builder->len;
        va_start(ap, fmt);
        written = vsnprintf(cheng_seed_active_primary_text_builder->data + cheng_seed_active_primary_text_builder->len,
                            remaining,
                            fmt,
                            ap);
        va_end(ap);
        if (written < 0) {
            cheng_seed_active_primary_text_builder->data[cheng_seed_active_primary_text_builder->len] = '\0';
            return;
        }
        if ((size_t)written >= remaining) {
            cheng_seed_active_primary_text_builder->overflowed = true;
            cheng_seed_active_primary_text_builder->len = cheng_seed_active_primary_text_builder->cap - 1U;
        } else {
            cheng_seed_active_primary_text_builder->len += (size_t)written;
        }
        cheng_seed_active_primary_text_builder->data[cheng_seed_active_primary_text_builder->len] = '\0';
        return;
    }
    {
        size_t used = strlen(out);
        if (used + 1U >= cap) {
            return;
        }
        va_start(ap, fmt);
        vsnprintf(out + used, cap - used, fmt, ap);
        va_end(ap);
    }
}

static void cheng_seed_primary_text_builder_init(ChengSeedPrimaryTextBuilder *builder, char *data, size_t cap) {
    if (builder == NULL) {
        return;
    }
    builder->data = data;
    builder->cap = cap;
    builder->len = 0U;
    builder->overflowed = false;
    if (data != NULL && cap > 0U) {
        data[0] = '\0';
    }
}

static void cheng_seed_primary_text_builder_refresh(ChengSeedPrimaryTextBuilder *builder) {
    if (builder == NULL || builder->data == NULL || builder->cap == 0U) {
        return;
    }
    builder->len = strlen(builder->data);
    if (builder->len >= builder->cap) {
        builder->overflowed = true;
        builder->len = builder->cap - 1U;
        builder->data[builder->len] = '\0';
    }
}

static void cheng_seed_primary_text_builder_append(ChengSeedPrimaryTextBuilder *builder, const char *text) {
    size_t remaining;
    size_t want;
    if (builder == NULL || builder->data == NULL || builder->cap == 0U || text == NULL) {
        return;
    }
    if (builder->len + 1U >= builder->cap) {
        builder->overflowed = true;
        return;
    }
    remaining = builder->cap - builder->len - 1U;
    want = strlen(text);
    if (want > remaining) {
        builder->overflowed = true;
        want = remaining;
    }
    if (want > 0U) {
        memcpy(builder->data + builder->len, text, want);
        builder->len += want;
    }
    builder->data[builder->len] = '\0';
}

static void cheng_seed_primary_text_builder_append_n(ChengSeedPrimaryTextBuilder *builder, const char *text, size_t want) {
    size_t remaining;
    if (builder == NULL || builder->data == NULL || builder->cap == 0U || text == NULL) {
        return;
    }
    if (builder->len + 1U >= builder->cap) {
        builder->overflowed = true;
        return;
    }
    remaining = builder->cap - builder->len - 1U;
    if (want > remaining) {
        builder->overflowed = true;
        want = remaining;
    }
    if (want > 0U) {
        memcpy(builder->data + builder->len, text, want);
        builder->len += want;
    }
    builder->data[builder->len] = '\0';
}

static void cheng_seed_primary_text_builder_appendf(ChengSeedPrimaryTextBuilder *builder, const char *fmt, ...) {
    va_list ap;
    int written;
    size_t remaining;
    if (builder == NULL || builder->data == NULL || builder->cap == 0U || fmt == NULL) {
        return;
    }
    if (builder->len + 1U >= builder->cap) {
        builder->overflowed = true;
        return;
    }
    remaining = builder->cap - builder->len;
    va_start(ap, fmt);
    written = vsnprintf(builder->data + builder->len, remaining, fmt, ap);
    va_end(ap);
    if (written < 0) {
        builder->data[builder->len] = '\0';
        return;
    }
    if ((size_t)written >= remaining) {
        builder->overflowed = true;
        builder->len = builder->cap - 1U;
    } else {
        builder->len += (size_t)written;
    }
    builder->data[builder->len] = '\0';
}

static bool cheng_seed_primary_text_builder_ok(const ChengSeedPrimaryTextBuilder *builder) {
    if (builder == NULL) {
        return false;
    }
    return !builder->overflowed;
}

static bool cheng_seed_primary_text_builder_require_ok(const ChengSeedPrimaryTextBuilder *builder,
                                               const ChengSeedPrimaryTextBuilder *cstring_builder,
                                               const ChengSeedSystemLinkPlanStub *plan,
                                               const ChengSeedLoweringPlanStub *lowering,
                                               const char *phase,
                                               size_t cap) {
    if (cheng_seed_primary_text_builder_ok(builder) && cheng_seed_primary_text_builder_ok(cstring_builder)) {
        return true;
    }
    fprintf(stderr,
            "[cheng_seed] primary asm builder overflow phase=%s entry=%s functions=%zu source_closure=%zu cap=%zu asm_len=%zu cstring_len=%zu\n",
            phase != NULL ? phase : "-",
            (plan != NULL && plan->entry_path[0] != '\0') ? plan->entry_path : "-",
            lowering != NULL ? lowering->function_count : 0U,
            plan != NULL ? plan->source_closure_count : 0U,
            cap,
            builder != NULL ? builder->len : 0U,
            cstring_builder != NULL ? cstring_builder->len : 0U);
    return false;
}

static ChengSeedPrimaryTextBuilder *cheng_seed_primary_text_builder_push(ChengSeedPrimaryTextBuilder *builder) {
    ChengSeedPrimaryTextBuilder *previous = cheng_seed_active_primary_text_builder;
    cheng_seed_active_primary_text_builder = builder;
    return previous;
}

static void cheng_seed_primary_text_builder_pop(ChengSeedPrimaryTextBuilder *previous) {
    cheng_seed_active_primary_text_builder = previous;
}

static ChengSeedPrimaryTextBuilder *cheng_seed_cstring_literal_pool_push(ChengSeedPrimaryTextBuilder *builder) {
    ChengSeedPrimaryTextBuilder *previous = g_cheng_active_cstring_literal_pool_builder;
    g_cheng_active_cstring_literal_pool_builder = builder;
    return previous;
}

static void cheng_seed_cstring_literal_pool_pop(ChengSeedPrimaryTextBuilder *previous) {
    g_cheng_active_cstring_literal_pool_builder = previous;
}

static bool cheng_seed_trim_outer_parens(const char *expr_text, char *out, size_t cap) {
    char expr[8192];
    size_t len;
    int32_t depth = 0;
    bool in_string = false;
    size_t i;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    len = strlen(expr);
    if (len < 2U || expr[0] != '(' || expr[len - 1U] != ')') {
        return false;
    }
    for (i = 0; i < len - 1U; ++i) {
        char ch = expr[i];
        if (ch == '"' && !cheng_seed_quote_is_escaped(expr, i)) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            depth += 1;
        } else if (ch == ')') {
            depth -= 1;
            if (depth == 0 && i != len - 1U) {
                return false;
            }
        }
    }
    snprintf(out, cap, "%.*s", (int)(len - 2U), expr + 1);
    cheng_seed_trim_copy_text(out, out, cap);
    return true;
}

static bool cheng_seed_quote_is_escaped(const char *text, size_t index) {
    size_t backslash_count = 0U;
    if (!text) {
        return false;
    }
    while (index > 0U && text[index - 1U] == '\\') {
        backslash_count += 1U;
        index -= 1U;
    }
    return (backslash_count & 1U) != 0U;
}

static int32_t cheng_seed_find_top_level_binary_op_last(const char *text, const char *op) {
    bool in_string = false;
    bool in_char = false;
    int32_t depth = 0;
    int32_t bracket_depth = 0;
    bool alpha_op = false;
    size_t len = strlen(text);
    size_t op_len = strlen(op);
    size_t i;
    if (op_len > 0U) {
        alpha_op = true;
        for (i = 0U; i < op_len; ++i) {
            if (!isalpha((unsigned char)op[i])) {
                alpha_op = false;
                break;
            }
        }
    }
    if (len < op_len) {
        return -1;
    }
    for (i = len; i-- > 0U; ) {
        char ch = text[i];
        if (!in_char && ch == '"' && !cheng_seed_quote_is_escaped(text, i)) {
            in_string = !in_string;
            continue;
        }
        if (!in_string && ch == '\'' && !cheng_seed_quote_is_escaped(text, i)) {
            in_char = !in_char;
            continue;
        }
        if (in_string || in_char) {
            continue;
        }
        if (ch == ')') {
            depth += 1;
            continue;
        }
        if (ch == '(') {
            depth -= 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth += 1;
            continue;
        }
        if (ch == '[') {
            bracket_depth -= 1;
            continue;
        }
        if (depth == 0 &&
            bracket_depth == 0 &&
            i + op_len <= len &&
            strncmp(text + i, op, op_len) == 0) {
            if (alpha_op) {
                char prev = i > 0U ? text[i - 1U] : '\0';
                char next = i + op_len < len ? text[i + op_len] : '\0';
                if (!(i > 0U && isspace((unsigned char)prev)) ||
                    !(i + op_len < len && isspace((unsigned char)next))) {
                    continue;
                }
            }
            if (op_len == 1U) {
                char prev = i > 0U ? text[i - 1U] : '\0';
                char next = i + 1U < len ? text[i + 1U] : '\0';
                if ((op[0] == '<' && (prev == '<' || next == '<' || next == '=')) ||
                    (op[0] == '>' && (prev == '>' || next == '>' || next == '=' || prev == '-')) ||
                    (op[0] == '&' && (prev == '&' || next == '&')) ||
                    (op[0] == '|' && (prev == '|' || next == '|')) ||
                    (op[0] == '-' && (next == '>' || prev == '-')) ||
                    (op[0] == '+' && (prev == '+' || next == '+'))) {
                    continue;
                }
            }
            if (op_len == 1U && (op[0] == '+' || op[0] == '-' || op[0] == '*' || op[0] == '&')) {
                size_t prev = i;
                while (prev > 0U && isspace((unsigned char)text[prev - 1U])) {
                    prev -= 1U;
                }
                if (prev == 0U ||
                    text[prev - 1U] == '(' ||
                    text[prev - 1U] == '[' ||
                    text[prev - 1U] == '{' ||
                    text[prev - 1U] == ',' ||
                    text[prev - 1U] == ':' ||
                    text[prev - 1U] == '?' ||
                    text[prev - 1U] == '=' ||
                    text[prev - 1U] == '!' ||
                    text[prev - 1U] == '|' ||
                    text[prev - 1U] == '^' ||
                    text[prev - 1U] == '&' ||
                    text[prev - 1U] == '+' ||
                    text[prev - 1U] == '-' ||
                    text[prev - 1U] == '*' ||
                    text[prev - 1U] == '/' ||
                    text[prev - 1U] == '%' ||
                    text[prev - 1U] == '<' ||
                    text[prev - 1U] == '>') {
                    continue;
                }
            }
            return (int32_t)i;
        }
    }
    return -1;
}

static bool cheng_seed_parse_prefix_single_arg_call(const char *expr_text,
                                            char *callee,
                                            size_t callee_cap,
                                            char *arg_text,
                                            size_t arg_cap) {
    char expr[8192];
    bool in_string = false;
    bool in_char = false;
    int32_t depth = 0;
    size_t i;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    for (i = 0; expr[i] != '\0'; ++i) {
        char ch = expr[i];
        if (!in_char && ch == '"' && !cheng_seed_quote_is_escaped(expr, i)) {
            in_string = !in_string;
            continue;
        }
        if (!in_string && ch == '\'' && !cheng_seed_quote_is_escaped(expr, i)) {
            in_char = !in_char;
            continue;
        }
        if (in_string || in_char) {
            continue;
        }
        if (ch == '(') {
            depth += 1;
            continue;
        }
        if (ch == ')') {
            depth -= 1;
            continue;
        }
        if (depth == 0 && isspace((unsigned char)ch)) {
            snprintf(callee, callee_cap, "%.*s", (int)i, expr);
            snprintf(arg_text, arg_cap, "%s", expr + i + 1U);
            cheng_seed_trim_copy_text(callee, callee, callee_cap);
            cheng_seed_trim_copy_text(arg_text, arg_text, arg_cap);
            if (strchr(callee, '(') != NULL ||
                strchr(callee, ')') != NULL ||
                strchr(callee, '[') != NULL ||
                strchr(callee, ']') != NULL) {
                return false;
            }
            {
                size_t j = 0U;
                bool need_ident = true;
                for (j = 0U; callee[j] != '\0'; ++j) {
                    unsigned char cj = (unsigned char)callee[j];
                    if (need_ident) {
                        if (!(isalpha(cj) || cj == '_')) {
                            return false;
                        }
                        need_ident = false;
                        continue;
                    }
                    if (cj == '.') {
                        need_ident = true;
                        continue;
                    }
                    if (!(isalnum(cj) || cj == '_')) {
                        return false;
                    }
                }
                if (need_ident) {
                    return false;
                }
            }
            if (arg_text[0] == '<' ||
                arg_text[0] == '>' ||
                arg_text[0] == '+' ||
                arg_text[0] == '-' ||
                arg_text[0] == '*' ||
                arg_text[0] == '/' ||
                arg_text[0] == '%' ||
                arg_text[0] == '&' ||
                arg_text[0] == '|' ||
                arg_text[0] == '^' ||
                arg_text[0] == '=' ||
                arg_text[0] == '!' ||
                arg_text[0] == '?' ||
                arg_text[0] == ':') {
                return false;
            }
            return callee[0] != '\0' && arg_text[0] != '\0';
        }
    }
    {
        int32_t paren_depth = 0;
        int32_t bracket_depth = 0;
        int32_t brace_depth = 0;
        for (i = 0; expr[i] != '\0'; ++i) {
            char ch = expr[i];
            if (!in_char && ch == '"' && !cheng_seed_quote_is_escaped(expr, i)) {
                if (!in_string &&
                    paren_depth == 0 &&
                    bracket_depth == 0 &&
                    brace_depth == 0) {
                    size_t j;
                    snprintf(callee, callee_cap, "%.*s", (int)i, expr);
                    snprintf(arg_text, arg_cap, "%s", expr + i);
                    cheng_seed_trim_copy_text(callee, callee, callee_cap);
                    cheng_seed_trim_copy_text(arg_text, arg_text, arg_cap);
                    if (callee[0] == '\0' ||
                        arg_text[0] != '"' ||
                        arg_text[strlen(arg_text) - 1U] != '"') {
                        return false;
                    }
                    for (j = 0; callee[j] != '\0'; ++j) {
                        unsigned char cj = (unsigned char)callee[j];
                        if (!(isalnum(cj) || cj == '_' || cj == '.')) {
                            return false;
                        }
                    }
                    return true;
                }
                in_string = !in_string;
                continue;
            }
            if (!in_string && ch == '\'' && !cheng_seed_quote_is_escaped(expr, i)) {
                in_char = !in_char;
                continue;
            }
            if (in_string || in_char) {
                continue;
            }
            if (ch == '(') {
                paren_depth += 1;
            } else if (ch == ')') {
                paren_depth -= 1;
            } else if (ch == '[') {
                bracket_depth += 1;
            } else if (ch == ']') {
                bracket_depth -= 1;
            } else if (ch == '{') {
                brace_depth += 1;
            } else if (ch == '}') {
                brace_depth -= 1;
            }
        }
    }
    return false;
}

static bool cheng_seed_parse_address_of_expr(const char *expr_text,
                                     char *inner_out,
                                     size_t inner_cap) {
    static const char *OPS[] = {
        "||", "&&", "==", "!=", "<=", ">=", "<<", ">>", "<", ">", "|", "^", "xor", "&", "+", "-", "*", "/", "%"
    };
    char expr[4096];
    size_t i;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] != '&' || expr[1] == '\0') {
        return false;
    }
    for (i = 0; i < sizeof(OPS) / sizeof(OPS[0]); ++i) {
        int32_t op_index = cheng_seed_find_top_level_binary_op_last(expr, OPS[i]);
        if (op_index > 0) {
            return false;
        }
    }
    cheng_seed_trim_copy_text(expr + 1, inner_out, inner_cap);
    return inner_out[0] != '\0';
}

static bool cheng_seed_parse_deref_expr(const char *expr_text,
                                char *inner_out,
                                size_t inner_cap) {
    static const char *OPS[] = {
        "||", "&&", "==", "!=", "<=", ">=", "<<", ">>", "<", ">", "|", "^", "xor", "&", "+", "-", "*", "/", "%"
    };
    char expr[4096];
    size_t i;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] != '*' || expr[1] == '\0') {
        return false;
    }
    for (i = 0; i < sizeof(OPS) / sizeof(OPS[0]); ++i) {
        int32_t op_index = cheng_seed_find_top_level_binary_op_last(expr, OPS[i]);
        if (op_index > 0) {
            return false;
        }
    }
    cheng_seed_trim_copy_text(expr + 1, inner_out, inner_cap);
    return inner_out[0] != '\0';
}

static int32_t cheng_seed_find_top_level_assignment_eq(const char *text);

static bool cheng_seed_parse_binding_meta(const char *statement,
                                  const char *prefix,
                                  char *name_out,
                                  size_t name_cap,
                                  char *type_out,
                                  size_t type_cap,
                                  char *expr_out,
                                  size_t expr_cap) {
    const char *cursor = statement + strlen(prefix);
    int32_t eq_index = cheng_seed_find_top_level_assignment_eq(cursor);
    int32_t colon_index;
    char left[CHENG_MAX_TYPE_TEXT];
    if (eq_index < 0) {
        return false;
    }
    snprintf(left, sizeof(left), "%.*s", eq_index, cursor);
    cheng_seed_trim_copy_text(left, left, sizeof(left));
    colon_index = cheng_seed_find_top_level_char(left, ':');
    if (colon_index > 0) {
        snprintf(type_out, type_cap, "%s", left + colon_index + 1);
        cheng_seed_trim_copy_text(type_out, type_out, type_cap);
        left[colon_index] = '\0';
    } else {
        type_out[0] = '\0';
    }
    snprintf(name_out, name_cap, "%s", left);
    cheng_seed_trim_copy_text(name_out, name_out, name_cap);
    snprintf(expr_out, expr_cap, "%s", cursor + eq_index + 1);
    cheng_seed_trim_copy_text(expr_out, expr_out, expr_cap);
    return name_out[0] != '\0' && expr_out[0] != '\0';
}

static bool cheng_seed_parse_binding_decl_meta(const char *statement,
                                       const char *prefix,
                                       char *name_out,
                                       size_t name_cap,
                                       char *type_out,
                                       size_t type_cap) {
    const char *cursor = statement + strlen(prefix);
    char left[CHENG_MAX_TYPE_TEXT];
    int32_t colon_index;
    if (cheng_seed_find_top_level_assignment_eq(cursor) >= 0) {
        return false;
    }
    snprintf(left, sizeof(left), "%s", cursor);
    cheng_seed_trim_copy_text(left, left, sizeof(left));
    colon_index = cheng_seed_find_top_level_char(left, ':');
    if (colon_index <= 0) {
        return false;
    }
    left[colon_index] = '\0';
    snprintf(name_out, name_cap, "%s", left);
    cheng_seed_trim_copy_text(name_out, name_out, name_cap);
    snprintf(type_out, type_cap, "%s", left + colon_index + 1);
    cheng_seed_trim_copy_text(type_out, type_out, type_cap);
    return name_out[0] != '\0' && type_out[0] != '\0';
}

static int32_t cheng_seed_find_top_level_assignment_eq(const char *text) {
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t brace_depth = 0;
    size_t i;
    for (i = 0; text && text[i] != '\0'; ++i) {
        char ch = text[i];
        if (ch == '"' && !cheng_seed_quote_is_escaped(text, i)) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            continue;
        }
        if (ch == '[') {
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            continue;
        }
        if (ch == '{') {
            brace_depth += 1;
            continue;
        }
        if (ch == '}') {
            brace_depth -= 1;
            continue;
        }
        if (paren_depth == 0 && bracket_depth == 0 && brace_depth == 0 && ch == '=') {
            char prev = i > 0 ? text[i - 1] : '\0';
            char next = text[i + 1];
            if (prev == '=' || prev == '!' || prev == '<' || prev == '>' || next == '=') {
                continue;
            }
            return (int32_t)i;
        }
    }
    return -1;
}

static bool cheng_seed_parse_assignment_meta(const char *statement,
                                     char *lhs_out,
                                     size_t lhs_cap,
                                     char *rhs_out,
                                     size_t rhs_cap) {
    int32_t eq = cheng_seed_find_top_level_assignment_eq(statement);
    if (eq < 0) {
        return false;
    }
    snprintf(lhs_out, lhs_cap, "%.*s", eq, statement);
    cheng_seed_trim_copy_text(lhs_out, lhs_out, lhs_cap);
    snprintf(rhs_out, rhs_cap, "%s", statement + eq + 1);
    cheng_seed_trim_copy_text(rhs_out, rhs_out, rhs_cap);
    return lhs_out[0] != '\0' && rhs_out[0] != '\0';
}

static bool cheng_seed_parse_index_assignment_operands(const char *lhs_text,
                                               const char *rhs_text,
                                               char *base_out,
                                               size_t base_cap,
                                               char *index_out,
                                               size_t index_cap,
                                               char *value_out,
                                               size_t value_cap) {
    if (base_out && base_cap > 0U) {
        base_out[0] = '\0';
    }
    if (index_out && index_cap > 0U) {
        index_out[0] = '\0';
    }
    if (value_out && value_cap > 0U) {
        value_out[0] = '\0';
    }
    if (lhs_text == NULL ||
        rhs_text == NULL ||
        base_out == NULL ||
        index_out == NULL ||
        value_out == NULL ||
        !cheng_seed_parse_index_access_expr(lhs_text, base_out, base_cap, index_out, index_cap)) {
        return false;
    }
    cheng_seed_trim_copy_text(rhs_text, value_out, value_cap);
    return base_out[0] != '\0' &&
           index_out[0] != '\0' &&
           value_out[0] != '\0';
}

static int32_t cheng_seed_assignment_string_literal_count(const char *lhs_text,
                                                  const char *rhs_text) {
    char base_expr[4096];
    char index_expr[4096];
    char value_expr[4096];
    if (cheng_seed_parse_index_assignment_operands(lhs_text,
                                           rhs_text,
                                           base_expr,
                                           sizeof(base_expr),
                                           index_expr,
                                           sizeof(index_expr),
                                           value_expr,
                                           sizeof(value_expr))) {
        return cheng_seed_call_expr_string_literal_count(base_expr) +
               cheng_seed_call_expr_string_literal_count(index_expr) +
               cheng_seed_call_expr_string_literal_count(value_expr);
    }
    return cheng_seed_call_expr_string_literal_count(rhs_text);
}

static bool cheng_seed_load_source_lines(const char *source_path,
                                 char ***lines_out,
                                 char **owned_out,
                                 size_t *line_count_out) {
    char *owned;
    char *cursor;
    char *line;
    char **lines;
    size_t line_count = 0U;
    owned = cheng_seed_read_file(source_path);
    if (!owned) {
        return false;
    }
    lines = (char **)cheng_seed_xmalloc(sizeof(char *) * CHENG_MAX_SOURCE_LINES);
    cursor = owned;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        if (line_count >= CHENG_MAX_SOURCE_LINES) {
            free(lines);
            free(owned);
            return false;
        }
        lines[line_count++] = line;
    }
    *lines_out = lines;
    *owned_out = owned;
    *line_count_out = line_count;
    return true;
}

static bool cheng_seed_plan_path_list_contains(const ChengSeedPlanPath *items,
                                       size_t count,
                                       const char *text) {
    size_t i;
    if (items == NULL || text == NULL || text[0] == '\0') {
        return false;
    }
    for (i = 0U; i < count; ++i) {
        if (cheng_seed_streq(items[i].text, text)) {
            return true;
        }
    }
    return false;
}

static bool cheng_seed_collect_explicit_export_symbols_from_source(const char *source_path,
                                                           ChengSeedPlanPath *symbols_out,
                                                           size_t *symbol_count_out,
                                                           size_t symbol_cap) {
    char **lines = NULL;
    char *owned = NULL;
    size_t line_count = 0U;
    size_t i;
    if (symbol_count_out != NULL) {
        *symbol_count_out = 0U;
    }
    if (source_path == NULL || source_path[0] == '\0' ||
        symbols_out == NULL || symbol_count_out == NULL || symbol_cap == 0U) {
        return true;
    }
    if (!cheng_seed_load_source_lines(source_path, &lines, &owned, &line_count)) {
        return false;
    }
    for (i = 0U; i < line_count; ++i) {
        char line_copy[4096];
        char export_symbol[PATH_MAX];
        char *trimmed;
        snprintf(line_copy, sizeof(line_copy), "%s", lines[i]);
        trimmed = cheng_seed_trim_inplace(line_copy);
        if (cheng_seed_function_decl_prefix_len(trimmed) == 0U) {
            continue;
        }
        if (!cheng_seed_top_level_function_export_symbol_from_lines(lines,
                                                            line_count,
                                                            i,
                                                            export_symbol,
                                                            sizeof(export_symbol)) ||
            export_symbol[0] == '\0' ||
            cheng_seed_plan_path_list_contains(symbols_out, *symbol_count_out, export_symbol)) {
            continue;
        }
        if (*symbol_count_out >= symbol_cap) {
            free(lines);
            free(owned);
            return false;
        }
        snprintf(symbols_out[*symbol_count_out].text,
                 sizeof(symbols_out[*symbol_count_out].text),
                 "%s",
                 export_symbol);
        *symbol_count_out += 1U;
    }
    free(lines);
    free(owned);
    return true;
}

static bool cheng_seed_parse_top_level_var_binding_text(const char *statement,
                                                char *name_out,
                                                size_t name_cap,
                                                char *type_out,
                                                size_t type_cap,
                                                bool *has_init_out,
                                                char *expr_out,
                                                size_t expr_cap) {
    char synthetic[8192];
    snprintf(synthetic, sizeof(synthetic), "var %s", statement);
    if (cheng_seed_parse_binding_meta(synthetic,
                              "var ",
                              name_out,
                              name_cap,
                              type_out,
                              type_cap,
                              expr_out,
                              expr_cap)) {
        *has_init_out = true;
        return true;
    }
    expr_out[0] = '\0';
    if (cheng_seed_parse_binding_decl_meta(synthetic,
                                   "var ",
                                   name_out,
                                   name_cap,
                                   type_out,
                                   type_cap)) {
        *has_init_out = false;
        return true;
    }
    return false;
}

static void cheng_seed_global_var_symbol_name(const ChengSeedSystemLinkPlanStub *plan,
                                      const char *module_path,
                                      const char *var_name,
                                      char *out,
                                      size_t cap) {
    char raw[PATH_MAX];
    char sanitized[PATH_MAX];
    if (cap == 0U) {
        return;
    }
    snprintf(raw, sizeof(raw), "%s__%s", module_path, var_name);
    cheng_seed_sanitize_path_part(raw, sanitized, sizeof(sanitized));
    cheng_seed_copy_target_symbol_name(plan, sanitized, out, cap);
}

static void cheng_seed_module_init_symbol_name(const ChengSeedSystemLinkPlanStub *plan,
                                       const char *module_path,
                                       char *out,
                                       size_t cap) {
    char raw[PATH_MAX];
    char sanitized[PATH_MAX];
    if (cap == 0U) {
        return;
    }
    snprintf(raw, sizeof(raw), "%s::__cheng_module_init", module_path);
    cheng_seed_sanitize_path_part(raw, sanitized, sizeof(sanitized));
    cheng_seed_copy_target_symbol_name(plan, sanitized, out, cap);
}

static bool cheng_seed_is_bare_identifier_text(const char *text) {
    size_t i;
    if (!text || text[0] == '\0') {
        return false;
    }
    if (!(isalpha((unsigned char)text[0]) || text[0] == '_')) {
        return false;
    }
    for (i = 1U; text[i] != '\0'; ++i) {
        unsigned char ch = (unsigned char)text[i];
        if (!(isalnum(ch) || ch == '_')) {
            return false;
        }
    }
    return true;
}

static bool cheng_seed_find_top_level_var_decl(const ChengSeedSystemLinkPlanStub *plan,
                                       const ChengSeedLoweringPlanStub *lowering,
                                       const char *owner_module_path,
                                       const char *var_name,
                                       char *type_out,
                                       size_t type_cap,
                                       char *abi_out,
                                       size_t abi_cap) {
    char source_path[PATH_MAX];
    const ChengSeedTopLevelVarDecl *decls = NULL;
    size_t decl_count = 0U;
    ChengSeedImportAlias aliases[CHENG_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    size_t i;
    if (!plan || !lowering || !owner_module_path || !type_out || !abi_out ||
        !cheng_seed_is_bare_identifier_text(var_name)) {
        return false;
    }
    cheng_seed_module_path_to_source_path(plan->workspace_root,
                                  plan->package_root,
                                  plan->package_id,
                                  owner_module_path,
                                  source_path,
                                  sizeof(source_path));
    if (source_path[0] == '\0' ||
        !cheng_seed_path_exists_nonempty(source_path) ||
        !cheng_seed_load_top_level_var_decls_from_source_path(source_path, &decls, &decl_count) ||
        !cheng_seed_load_import_aliases_from_source_path(source_path,
                                                aliases,
                                                &alias_count,
                                                CHENG_MAX_IMPORT_ALIASES)) {
        return false;
    }
    for (i = 0U; i < decl_count; ++i) {
        char normalized_type[256];
        if (strcmp(decls[i].name, var_name) == 0 &&
            decls[i].raw_type[0] != '\0' &&
            cheng_seed_normalize_type_text(lowering,
                                   owner_module_path,
                                   aliases,
                                   alias_count,
                                   decls[i].raw_type,
                                   normalized_type,
                                   sizeof(normalized_type))) {
            snprintf(type_out, type_cap, "%s", normalized_type);
            snprintf(abi_out, abi_cap, "%s", cheng_seed_type_abi_class(normalized_type));
            return true;
        }
    }
    return false;
}

static bool cheng_seed_emit_owner_global_var_address(const ChengSeedSystemLinkPlanStub *plan,
                                             const ChengSeedLoweringPlanStub *lowering,
                                             const ChengSeedLoweredFunctionStub *current_function,
                                             const char *expr_text,
                                             char *type_out,
                                             size_t type_cap,
                                             char *abi_out,
                                             size_t abi_cap,
                                             int addr_reg,
                                             char *out,
                                             size_t cap) {
    char symbol_name[PATH_MAX];
    if (!cheng_seed_find_top_level_var_decl(plan,
                                    lowering,
                                    current_function->owner_module_path,
                                    expr_text,
                                    type_out,
                                    type_cap,
                                    abi_out,
                                    abi_cap)) {
        return false;
    }
    cheng_seed_global_var_symbol_name(plan,
                              current_function->owner_module_path,
                              expr_text,
                              symbol_name,
                              sizeof(symbol_name));
    return cheng_seed_emit_symbol_address_for_target(plan, out, cap, addr_reg, symbol_name);
}

static bool cheng_seed_append_module_global_storage(const ChengSeedSystemLinkPlanStub *plan,
                                            const ChengSeedLoweringPlanStub *lowering,
                                            const char *source_path,
                                            char *out,
                                            size_t cap) {
    char owner_module_path[PATH_MAX];
    const ChengSeedTopLevelVarDecl *decls = NULL;
    size_t decl_count = 0U;
    ChengSeedImportAlias aliases[CHENG_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    size_t i;
    bool emitted_any = false;
    cheng_seed_source_path_to_module_path(plan->workspace_root,
                                  plan->package_root,
                                  plan->package_id,
                                  source_path,
                                  owner_module_path,
                                  sizeof(owner_module_path));
    if (!cheng_seed_path_exists_nonempty(source_path) ||
        !cheng_seed_load_top_level_var_decls_from_source_path(source_path, &decls, &decl_count) ||
        !cheng_seed_load_import_aliases_from_source_path(source_path,
                                                aliases,
                                                &alias_count,
                                                CHENG_MAX_IMPORT_ALIASES)) {
        return false;
    }
    for (i = 0U; i < decl_count; ++i) {
        char normalized_type[256];
        char symbol_name[PATH_MAX];
        ChengSeedTypeLayoutStub layout;
        int32_t align_log2 = 0;
        if (decls[i].raw_type[0] == '\0' ||
            !cheng_seed_normalize_type_text(lowering,
                                    owner_module_path,
                                    aliases,
                                    alias_count,
                                    decls[i].raw_type,
                                    normalized_type,
                                    sizeof(normalized_type)) ||
            !cheng_seed_compute_type_layout_impl(lowering, normalized_type, &layout, 0U)) {
            continue;
        }
        while ((1 << align_log2) < layout.align && align_log2 < 15) {
            align_log2 += 1;
        }
        cheng_seed_global_var_symbol_name(plan,
                                  owner_module_path,
                                  decls[i].name,
                                  symbol_name,
                                  sizeof(symbol_name));
        if (!emitted_any) {
            cheng_seed_text_append(out, cap, ".data\n");
            emitted_any = true;
        }
        if (cheng_seed_internal_symbol_scaffold_should_be_global(plan)) {
            cheng_seed_text_appendf(out, cap, ".globl %s\n", symbol_name);
        }
        cheng_seed_text_appendf(out, cap,
                        ".p2align %d\n"
                        "%s:\n"
                        "  .space %d\n",
                        align_log2,
                        symbol_name,
                        layout.size > 0 ? layout.size : 1);
    }
    return true;
}

static bool cheng_seed_parse_string_literal_text(const char *expr_text,
                                         char *text_out,
                                         size_t text_cap) {
    char expr[4096];
    size_t len;
    size_t write_len = 0;
    size_t i = 0;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    len = strlen(expr);
    if (len < 2U || expr[0] != '"' || expr[len - 1U] != '"') {
        return false;
    }
    if (text_cap == 0U) {
        return false;
    }
    for (i = 1U; i + 1U < len; ++i) {
        unsigned char ch = (unsigned char)expr[i];
        bool escaped = false;
        if (ch == '\\') {
            unsigned char esc = 0;
            if (i + 2U >= len) {
                return false;
            }
            esc = (unsigned char)expr[++i];
            escaped = true;
            if (esc == 'n') {
                ch = '\n';
            } else if (esc == 'r') {
                ch = '\r';
            } else if (esc == 't') {
                ch = '\t';
            } else if (esc == '\\') {
                ch = '\\';
            } else if (esc == '"') {
                ch = '"';
            } else if (esc == '\'') {
                ch = '\'';
            } else if (esc == '0') {
                return false;
            } else {
                ch = esc;
            }
        }
        if (!escaped && ch == '"') {
            return false;
        }
        if (write_len + 1U >= text_cap) {
            return false;
        }
        text_out[write_len++] = (char)ch;
    }
    text_out[write_len] = '\0';
    return true;
}

static bool cheng_seed_str_append_text(char *out, size_t cap, const char *text) {
    size_t used;
    size_t need;
    if (!out || cap == 0U || !text) {
        return false;
    }
    used = strlen(out);
    need = strlen(text);
    if (used + need + 1U > cap) {
        return false;
    }
    memcpy(out + used, text, need + 1U);
    return true;
}

static bool cheng_seed_str_append_quoted_literal(char *out, size_t cap, const char *text) {
    size_t i;
    if (!cheng_seed_str_append_text(out, cap, "\"")) {
        return false;
    }
    for (i = 0; text && text[i] != '\0'; ++i) {
        unsigned char ch = (unsigned char)text[i];
        if (ch == '\n') {
            if (!cheng_seed_str_append_text(out, cap, "\\n")) {
                return false;
            }
            continue;
        }
        if (ch == '\r') {
            if (!cheng_seed_str_append_text(out, cap, "\\r")) {
                return false;
            }
            continue;
        }
        if (ch == '\t') {
            if (!cheng_seed_str_append_text(out, cap, "\\t")) {
                return false;
            }
            continue;
        }
        if (ch == '\\') {
            if (!cheng_seed_str_append_text(out, cap, "\\\\")) {
                return false;
            }
            continue;
        }
        if (ch == '"') {
            if (!cheng_seed_str_append_text(out, cap, "\\\"")) {
                return false;
            }
            continue;
        }
        {
            size_t used = strlen(out);
            if (used + 2U > cap) {
                return false;
            }
            out[used] = (char)ch;
            out[used + 1U] = '\0';
        }
    }
    return cheng_seed_str_append_text(out, cap, "\"");
}

static bool cheng_seed_strformat_fmt_append_piece(char *out,
                                          size_t cap,
                                          const char *piece_text,
                                          bool quoted,
                                          bool *has_piece_io,
                                          size_t *piece_count_io,
                                          char *single_piece_text,
                                          size_t single_piece_cap,
                                          bool *single_piece_quoted_io) {
    if (!piece_text || piece_text[0] == '\0') {
        return true;
    }
    if (*has_piece_io && !cheng_seed_str_append_text(out, cap, ", ")) {
        return false;
    }
    if (quoted) {
        if (!cheng_seed_str_append_quoted_literal(out, cap, piece_text)) {
            return false;
        }
    } else {
        if (!cheng_seed_str_append_text(out, cap, "(") ||
            !cheng_seed_str_append_text(out, cap, piece_text) ||
            !cheng_seed_str_append_text(out, cap, ")")) {
            return false;
        }
    }
    if (piece_count_io != NULL) {
        if (*piece_count_io == 0U &&
            single_piece_text != NULL &&
            single_piece_cap > 0U &&
            single_piece_quoted_io != NULL) {
            snprintf(single_piece_text, single_piece_cap, "%s", piece_text);
            *single_piece_quoted_io = quoted;
        }
        *piece_count_io += 1U;
    }
    *has_piece_io = true;
    return true;
}

static bool cheng_seed_trim_wrapping_parens_text(const char *text,
                                         char *out,
                                         size_t cap) {
    char trimmed[4096];
    bool changed = false;
    cheng_seed_trim_copy_text(text, trimmed, sizeof(trimmed));
    while (trimmed[0] == '(') {
        size_t len = strlen(trimmed);
        size_t i;
        int32_t paren_depth = 0;
        bool in_string = false;
        bool wraps = len > 1U && trimmed[len - 1U] == ')';
        if (!wraps) {
            break;
        }
        for (i = 0U; i < len; ++i) {
            char ch = trimmed[i];
            if (ch == '"' && !cheng_seed_quote_is_escaped(trimmed, i)) {
                in_string = !in_string;
                continue;
            }
            if (in_string) {
                continue;
            }
            if (ch == '(') {
                paren_depth += 1;
            } else if (ch == ')') {
                paren_depth -= 1;
                if (paren_depth == 0 && i + 1U < len) {
                    wraps = false;
                    break;
                }
            }
        }
        if (!wraps || paren_depth != 0) {
            break;
        }
        snprintf(trimmed, sizeof(trimmed), "%.*s", (int)(len - 2U), trimmed + 1);
        cheng_seed_trim_copy_text(trimmed, trimmed, sizeof(trimmed));
        changed = true;
    }
    snprintf(out, cap, "%s", trimmed);
    return changed || out[0] != '\0';
}

static bool cheng_seed_flatten_str_concat_terms(const char *expr_text,
                                        char terms[][4096],
                                        size_t *count_io,
                                        size_t term_cap) {
    char expr[4096];
    int32_t plus_index = -1;
    if (expr_text == NULL || terms == NULL || count_io == NULL || term_cap == 0U) {
        return false;
    }
    cheng_seed_trim_wrapping_parens_text(expr_text, expr, sizeof(expr));
    plus_index = cheng_seed_find_top_level_binary_op_last(expr, "+");
    if (plus_index < 0) {
        if (*count_io >= term_cap) {
            return false;
        }
        snprintf(terms[*count_io], 4096, "%s", expr);
        *count_io += 1U;
        return true;
    }
    {
        char left_expr[4096];
        char right_expr[4096];
        snprintf(left_expr, sizeof(left_expr), "%.*s", plus_index, expr);
        snprintf(right_expr, sizeof(right_expr), "%s", expr + plus_index + 1);
        cheng_seed_trim_copy_text(left_expr, left_expr, sizeof(left_expr));
        cheng_seed_trim_copy_text(right_expr, right_expr, sizeof(right_expr));
        return cheng_seed_flatten_str_concat_terms(left_expr, terms, count_io, term_cap) &&
               cheng_seed_flatten_str_concat_terms(right_expr, terms, count_io, term_cap);
    }
}

static bool cheng_seed_build_str_concat_fmt_call(const char *expr_text,
                                         char *rewritten_out,
                                         size_t rewritten_cap,
                                         char *error_out,
                                         size_t error_cap) {
    char terms[32][4096];
    size_t term_count = 0U;
    size_t i = 0U;
    if (rewritten_out != NULL && rewritten_cap > 0U) {
        rewritten_out[0] = '\0';
    }
    if (error_out != NULL && error_cap > 0U) {
        error_out[0] = '\0';
    }
    if (expr_text == NULL || rewritten_out == NULL || rewritten_cap == 0U) {
        return false;
    }
    if (!cheng_seed_flatten_str_concat_terms(expr_text,
                                     terms,
                                     &term_count,
                                     sizeof(terms) / sizeof(terms[0]))) {
        if (error_out != NULL && error_cap > 0U) {
            snprintf(error_out, error_cap, "str concat lowering failed");
        }
        return false;
    }
    if (term_count == 0U) {
        if (error_out != NULL && error_cap > 0U) {
            snprintf(error_out, error_cap, "str concat lowering produced no terms");
        }
        return false;
    }
    if (!cheng_seed_str_append_text(rewritten_out, rewritten_cap, "Fmt([")) {
        return false;
    }
    for (i = 0U; i < term_count; ++i) {
        if (i > 0U && !cheng_seed_str_append_text(rewritten_out, rewritten_cap, ", ")) {
            return false;
        }
        if (!cheng_seed_str_append_text(rewritten_out, rewritten_cap, terms[i])) {
            return false;
        }
    }
    return cheng_seed_str_append_text(rewritten_out, rewritten_cap, "])");
}

static bool cheng_seed_infer_expr_type(const ChengSeedSystemLinkPlanStub *plan,
                               const ChengSeedLoweringPlanStub *lowering,
                               const ChengSeedLoweredFunctionStub *current_function,
                               const ChengSeedImportAlias *aliases,
                               size_t alias_count,
                               const ChengSeedAsmLocalSlot *locals,
                               size_t local_count,
                               const char *expr_text,
                               char *type_out,
                               size_t type_cap,
                               char *abi_out,
                               size_t abi_cap);

static bool cheng_seed_expr_is_string_concat(const ChengSeedSystemLinkPlanStub *plan,
                                     const ChengSeedLoweringPlanStub *lowering,
                                     const ChengSeedLoweredFunctionStub *current_function,
                                     const ChengSeedImportAlias *aliases,
                                     size_t alias_count,
                                     const ChengSeedAsmLocalSlot *locals,
                                     size_t local_count,
                                     const char *expr_text) {
    char expr[8192];
    char left[4096];
    char right[4096];
    char left_type[256];
    char left_abi[32];
    char right_type[256];
    char right_abi[32];
    char normalized_left_type[256];
    char normalized_right_type[256];
    int32_t plus_index = -1;
    if (plan == NULL || lowering == NULL || current_function == NULL || expr_text == NULL) {
        return false;
    }
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    plus_index = cheng_seed_find_top_level_binary_op_last(expr, "+");
    if (plus_index < 0) {
        return false;
    }
    snprintf(left, sizeof(left), "%.*s", plus_index, expr);
    snprintf(right, sizeof(right), "%s", expr + plus_index + 1);
    cheng_seed_trim_copy_text(left, left, sizeof(left));
    cheng_seed_trim_copy_text(right, right, sizeof(right));
    if (!cheng_seed_infer_expr_type(plan,
                            lowering,
                            current_function,
                            aliases,
                            alias_count,
                            locals,
                            local_count,
                            left,
                            left_type,
                            sizeof(left_type),
                            left_abi,
                            sizeof(left_abi)) ||
        !cheng_seed_infer_expr_type(plan,
                            lowering,
                            current_function,
                            aliases,
                            alias_count,
                            locals,
                            local_count,
                            right,
                            right_type,
                            sizeof(right_type),
                            right_abi,
                            sizeof(right_abi)) ||
        !cheng_seed_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                left_type,
                                normalized_left_type,
                                sizeof(normalized_left_type)) ||
        !cheng_seed_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                right_type,
                                normalized_right_type,
                                sizeof(normalized_right_type))) {
        return false;
    }
    return strcmp(normalized_left_type, "str") == 0 ||
           strcmp(normalized_right_type, "str") == 0;
}

static bool cheng_seed_rewrite_expr_for_expected_str(const ChengSeedLoweringPlanStub *lowering,
                                             const ChengSeedLoweredFunctionStub *current_function,
                                             const ChengSeedImportAlias *aliases,
                                             size_t alias_count,
                                             const char *expected_type,
                                             const char *expr_text,
                                             char *rewritten_out,
                                             size_t rewritten_cap) {
    char normalized_expected[256];
    char concat_error[256];
    if (rewritten_out == NULL || rewritten_cap == 0U || expr_text == NULL) {
        return false;
    }
    rewritten_out[0] = '\0';
    if (lowering == NULL || current_function == NULL ||
        expected_type == NULL || expected_type[0] == '\0' ||
        !cheng_seed_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                expected_type,
                                normalized_expected,
                                sizeof(normalized_expected)) ||
        strcmp(normalized_expected, "str") != 0 ||
        cheng_seed_find_top_level_binary_op_last(expr_text, "+") < 0) {
        cheng_seed_trim_copy_text(expr_text, rewritten_out, rewritten_cap);
        return true;
    }
    return cheng_seed_build_str_concat_fmt_call(expr_text,
                                        rewritten_out,
                                        rewritten_cap,
                                        concat_error,
                                        sizeof(concat_error));
}

static bool cheng_seed_expand_strformat_fmt_expr(const char *expr_text,
                                         char *expanded_out,
                                         size_t expanded_cap,
                                         bool *changed_out,
                                         char *error_out,
                                         size_t error_cap) {
    char callee[PATH_MAX];
    char arg_text[4096];
    char literal[4096];
    char expr_buf[8192];
    char expr_piece[4096];
    char literal_piece[4096];
    char rewritten_pieces[8192];
    char single_piece[4096];
    char (*args)[4096] = NULL;
    size_t arg_count = 0U;
    size_t i = 0U;
    size_t literal_len = 0U;
    size_t piece_count = 0U;
    bool changed = false;
    bool has_piece = false;
    bool single_piece_quoted = false;
    const char *format_arg = NULL;
    const char *base = NULL;
    if (expanded_out && expanded_cap > 0U) {
        expanded_out[0] = '\0';
    }
    if (changed_out) {
        *changed_out = false;
    }
    if (error_out && error_cap > 0U) {
        error_out[0] = '\0';
    }
    if (!expr_text || !expanded_out || expanded_cap == 0U) {
        return false;
    }
    rewritten_pieces[0] = '\0';
    single_piece[0] = '\0';
    args = cheng_seed_alloc_call_arg_scratch();
    callee[0] = '\0';
    arg_text[0] = '\0';
    if (cheng_seed_parse_call_text(expr_text, callee, sizeof(callee), args, &arg_count, CHENG_MAX_CALL_ARGS)) {
        if (arg_count != 1U) {
            free(args);
            return true;
        }
        format_arg = args[0];
    } else if (cheng_seed_parse_prefix_single_arg_call(expr_text, callee, sizeof(callee), arg_text, sizeof(arg_text))) {
        format_arg = arg_text;
    } else {
        free(args);
        return true;
    }
    base = strrchr(callee, '.');
    base = base ? base + 1 : callee;
    if (!cheng_seed_is_strformat_fmt_name(base)) {
        free(args);
        return true;
    }
    if (!format_arg || !cheng_seed_parse_string_literal_text(format_arg, literal, sizeof(literal))) {
        free(args);
        return true;
    }
    for (i = 0U; literal[i] != '\0';) {
        char ch = literal[i];
        if (ch == '{') {
            if (literal[i + 1U] == '{') {
                changed = true;
                if (literal_len + 2U >= sizeof(literal_piece)) {
                    if (error_out && error_cap > 0U) {
                        snprintf(error_out, error_cap, "fmt literal too large");
                    }
                    free(args);
                    return false;
                }
                literal_piece[literal_len++] = '{';
                literal_piece[literal_len] = '\0';
                i += 2U;
                continue;
            }
            literal_piece[literal_len] = '\0';
            if (!cheng_seed_strformat_fmt_append_piece(rewritten_pieces,
                                               sizeof(rewritten_pieces),
                                               literal_piece,
                                               true,
                                               &has_piece,
                                               &piece_count,
                                               single_piece,
                                               sizeof(single_piece),
                                               &single_piece_quoted)) {
                if (error_out && error_cap > 0U) {
                    snprintf(error_out, error_cap, "fmt expansion too large");
                }
                free(args);
                return false;
            }
            literal_len = 0U;
            changed = true;
            {
                size_t start = i + 1U;
                int32_t paren_depth = 0;
                int32_t bracket_depth = 0;
                int32_t brace_depth = 0;
                bool in_string = false;
                bool in_char = false;
                i = start;
                while (literal[i] != '\0') {
                    char inner = literal[i];
                    if (inner == '"' && !in_char && !cheng_seed_quote_is_escaped(literal, i)) {
                        in_string = !in_string;
                        i += 1U;
                        continue;
                    }
                    if (inner == '\'' && !in_string && !cheng_seed_quote_is_escaped(literal, i)) {
                        in_char = !in_char;
                        i += 1U;
                        continue;
                    }
                    if (in_string || in_char) {
                        i += 1U;
                        continue;
                    }
                    if (inner == '(') {
                        paren_depth += 1;
                        i += 1U;
                        continue;
                    }
                    if (inner == ')') {
                        if (paren_depth > 0) {
                            paren_depth -= 1;
                        }
                        i += 1U;
                        continue;
                    }
                    if (inner == '[') {
                        bracket_depth += 1;
                        i += 1U;
                        continue;
                    }
                    if (inner == ']') {
                        if (bracket_depth > 0) {
                            bracket_depth -= 1;
                        }
                        i += 1U;
                        continue;
                    }
                    if (inner == '{') {
                        brace_depth += 1;
                        i += 1U;
                        continue;
                    }
                    if (inner == '}') {
                        if (paren_depth == 0 && bracket_depth == 0 && brace_depth == 0) {
                            break;
                        }
                        if (brace_depth > 0) {
                            brace_depth -= 1;
                        }
                        i += 1U;
                        continue;
                    }
                    i += 1U;
                }
                if (literal[i] != '}') {
                    if (error_out && error_cap > 0U) {
                        snprintf(error_out, error_cap, "fmt placeholder missing '}'");
                    }
                    free(args);
                    return false;
                }
                snprintf(expr_buf, sizeof(expr_buf), "%.*s", (int)(i - start), literal + start);
                cheng_seed_trim_copy_text(expr_buf, expr_piece, sizeof(expr_piece));
                if (expr_piece[0] == '\0') {
                    if (error_out && error_cap > 0U) {
                        snprintf(error_out, error_cap, "fmt placeholder empty");
                    }
                    free(args);
                    return false;
                }
                if (!cheng_seed_strformat_fmt_append_piece(rewritten_pieces,
                                                   sizeof(rewritten_pieces),
                                                   expr_piece,
                                                   false,
                                                   &has_piece,
                                                   &piece_count,
                                                   single_piece,
                                                   sizeof(single_piece),
                                                   &single_piece_quoted)) {
                    if (error_out && error_cap > 0U) {
                        snprintf(error_out, error_cap, "fmt expansion too large");
                    }
                    free(args);
                    return false;
                }
                i += 1U;
                continue;
            }
        }
        if (ch == '}') {
            if (literal[i + 1U] == '}') {
                changed = true;
                if (literal_len + 2U >= sizeof(literal_piece)) {
                    if (error_out && error_cap > 0U) {
                        snprintf(error_out, error_cap, "fmt literal too large");
                    }
                    free(args);
                    return false;
                }
                literal_piece[literal_len++] = '}';
                literal_piece[literal_len] = '\0';
                i += 2U;
                continue;
            }
            if (error_out && error_cap > 0U) {
                snprintf(error_out, error_cap, "fmt literal has unmatched '}'");
            }
            free(args);
            return false;
        }
        if (literal_len + 2U >= sizeof(literal_piece)) {
            if (error_out && error_cap > 0U) {
                snprintf(error_out, error_cap, "fmt literal too large");
            }
            free(args);
            return false;
        }
        literal_piece[literal_len++] = ch;
        literal_piece[literal_len] = '\0';
        i += 1U;
    }
    literal_piece[literal_len] = '\0';
    if (!cheng_seed_strformat_fmt_append_piece(rewritten_pieces,
                                       sizeof(rewritten_pieces),
                                       literal_piece,
                                       true,
                                       &has_piece,
                                       &piece_count,
                                       single_piece,
                                       sizeof(single_piece),
                                       &single_piece_quoted)) {
        if (error_out && error_cap > 0U) {
            snprintf(error_out, error_cap, "fmt expansion too large");
        }
        free(args);
        return false;
    }
    if (!changed) {
        free(args);
        return true;
    }
    if (piece_count == 0U) {
        if (!cheng_seed_str_append_text(expanded_out, expanded_cap, "\"\"")) {
            if (error_out && error_cap > 0U) {
                snprintf(error_out, error_cap, "fmt expansion too large");
            }
            free(args);
            return false;
        }
    } else if (piece_count == 1U) {
        if (single_piece_quoted) {
            if (!cheng_seed_str_append_quoted_literal(expanded_out, expanded_cap, single_piece)) {
                if (error_out && error_cap > 0U) {
                    snprintf(error_out, error_cap, "fmt expansion too large");
                }
                free(args);
                return false;
            }
        } else {
            if (!cheng_seed_str_append_text(expanded_out, expanded_cap, "(") ||
                !cheng_seed_str_append_text(expanded_out, expanded_cap, single_piece) ||
                !cheng_seed_str_append_text(expanded_out, expanded_cap, ")")) {
                if (error_out && error_cap > 0U) {
                    snprintf(error_out, error_cap, "fmt expansion too large");
                }
                free(args);
                return false;
            }
        }
    } else {
        if (!cheng_seed_str_append_text(expanded_out, expanded_cap, callee) ||
            !cheng_seed_str_append_text(expanded_out, expanded_cap, "([") ||
            !cheng_seed_str_append_text(expanded_out, expanded_cap, rewritten_pieces) ||
            !cheng_seed_str_append_text(expanded_out, expanded_cap, "])")) {
            if (error_out && error_cap > 0U) {
                snprintf(error_out, error_cap, "fmt expansion too large");
            }
            free(args);
            return false;
        }
    }
    if (changed_out) {
        *changed_out = true;
    }
    free(args);
    return true;
}

static bool cheng_seed_parse_char_literal_text(const char *expr_text, int32_t *value_out) {
    char expr[64];
    size_t len;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    len = strlen(expr);
    if (len < 3U || expr[0] != '\'' || expr[len - 1U] != '\'') {
        return false;
    }
    if (len == 3U) {
        if (value_out) {
            *value_out = (unsigned char)expr[1];
        }
        return true;
    }
    if (len == 4U && expr[1] == '\\') {
        int32_t value = 0;
        switch (expr[2]) {
            case 'n': value = '\n'; break;
            case 'r': value = '\r'; break;
            case 't': value = '\t'; break;
            case '0': value = '\0'; break;
            case '\\': value = '\\'; break;
            case '\'': value = '\''; break;
            case '"': value = '"'; break;
            default: return false;
        }
        if (value_out) {
            *value_out = value;
        }
        return true;
    }
    return false;
}

static bool cheng_seed_parse_int_literal_text(const char *expr_text, int64_t *value_out) {
    char expr[128];
    char *end = NULL;
    long long parsed;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return false;
    }
    parsed = strtoll(expr, &end, 0);
    if (!end || *cheng_seed_trim_inplace(end) != '\0') {
        return false;
    }
    if (value_out) {
        *value_out = (int64_t)parsed;
    }
    return true;
}

static bool cheng_seed_parse_member_access_expr(const char *expr_text,
                                        char *base_out,
                                        size_t base_cap,
                                        char *field_out,
                                        size_t field_cap);
static bool cheng_seed_parse_index_access_expr(const char *expr_text,
                                       char *base_out,
                                       size_t base_cap,
                                       char *index_out,
                                       size_t index_cap);
static bool cheng_seed_parse_named_arg_meta(const char *arg_text,
                                    char *field_out,
                                    size_t field_cap,
                                    char *expr_out,
                                    size_t expr_cap);

static int32_t cheng_seed_expr_string_literal_lexical_count(const char *expr_text) {
    const char *cursor = expr_text;
    bool in_string = false;
    bool escape = false;
    int32_t count = 0;
    if (!expr_text) {
        return 0;
    }
    while (*cursor) {
        char ch = *cursor;
        if (!in_string) {
            if (ch == '"') {
                in_string = true;
                escape = false;
                count += 1;
            }
            cursor += 1;
            continue;
        }
        if (escape) {
            escape = false;
            cursor += 1;
            continue;
        }
        if (ch == '\\') {
            escape = true;
            cursor += 1;
            continue;
        }
        if (ch == '"') {
            in_string = false;
        }
        cursor += 1;
    }
    return count;
}

static int32_t cheng_seed_call_expr_string_literal_count_slow(const char *expr_text, int32_t depth);

static int32_t cheng_seed_call_expr_string_literal_count_inner(const char *expr_text, int32_t depth) {
    if (!expr_text) {
        return 0;
    }
    if (depth >= 24) {
        return cheng_seed_expr_string_literal_lexical_count(expr_text);
    }
    if (strlen(expr_text) >= 4096U) {
        return cheng_seed_expr_string_literal_lexical_count(expr_text);
    }
    return cheng_seed_call_expr_string_literal_count_slow(expr_text, depth);
}

static int32_t cheng_seed_call_expr_string_literal_count_slow(const char *expr_text, int32_t depth) {
    static const char *OPS[] = {
        "||", "&&", "==", "!=", "<=", ">=", "<<", ">>", "<", ">", "|", "^", "xor", "&", "+", "-", "*", "/", "%"
    };
    char expr[4096];
    char named_field[256];
    char named_expr[4096];
    char base_name[4096];
    char field_name[256];
    char index_expr[4096];
    char callee[PATH_MAX];
    char arg_text[4096] = {0};
    char surface_error[256];
    size_t i;
    size_t expr_len = 0U;
    int32_t best = 0;
    ChengSeedExprSurface surface;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0') {
        return 0;
    }
    if (!cheng_seed_classify_expr_surface(expr, &surface, surface_error, sizeof(surface_error))) {
        return 0;
    }
    snprintf(expr, sizeof(expr), "%s", surface.text);
    expr_len = strlen(expr);
    if (cheng_seed_parse_named_arg_meta(expr,
                                named_field,
                                sizeof(named_field),
                                named_expr,
                                sizeof(named_expr))) {
        if (strcmp(named_expr, expr) == 0 || strlen(named_expr) >= expr_len) {
            return 0;
        }
        return cheng_seed_call_expr_string_literal_count_inner(named_expr, depth + 1);
    }
    if (expr[0] == '!') {
        return cheng_seed_call_expr_string_literal_count_inner(expr + 1, depth + 1);
    }
    if (expr[0] == '-' && expr[1] != '\0' &&
        !cheng_seed_parse_int_literal_text(expr, NULL)) {
        return cheng_seed_call_expr_string_literal_count_inner(expr + 1, depth + 1);
    }
    if (surface.kind == ChengSeed_EXPR_SURFACE_IF || surface.kind == ChengSeed_EXPR_SURFACE_TERNARY) {
        int32_t cond_count = cheng_seed_call_expr_string_literal_count_inner(surface.cond, depth + 1);
        int32_t true_count = cheng_seed_call_expr_string_literal_count_inner(surface.when_true, depth + 1);
        int32_t false_count = cheng_seed_call_expr_string_literal_count_inner(surface.when_false, depth + 1);
        best = cond_count > true_count ? cond_count : true_count;
        return best > false_count ? best : false_count;
    }
    if (surface.kind == ChengSeed_EXPR_SURFACE_RANGE) {
        int32_t start_count = cheng_seed_call_expr_string_literal_count_inner(surface.when_true, depth + 1);
        int32_t end_count = cheng_seed_call_expr_string_literal_count_inner(surface.when_false, depth + 1);
        return start_count > end_count ? start_count : end_count;
    }
    for (i = 0; i < sizeof(OPS) / sizeof(OPS[0]); ++i) {
        int32_t op_index = cheng_seed_find_top_level_binary_op_last(expr, OPS[i]);
        if (op_index >= 0) {
            char left[4096];
            char right[4096];
            int32_t left_count;
            int32_t right_count;
            snprintf(left, sizeof(left), "%.*s", op_index, expr);
            snprintf(right, sizeof(right), "%s", expr + op_index + strlen(OPS[i]));
            cheng_seed_trim_copy_text(left, left, sizeof(left));
            cheng_seed_trim_copy_text(right, right, sizeof(right));
            left_count = cheng_seed_call_expr_string_literal_count_inner(left, depth + 1);
            right_count = cheng_seed_call_expr_string_literal_count_inner(right, depth + 1);
            return left_count > right_count ? left_count : right_count;
        }
    }
    if (cheng_seed_parse_member_access_expr(expr, base_name, sizeof(base_name), field_name, sizeof(field_name))) {
        if (strcmp(base_name, expr) == 0 || strlen(base_name) >= expr_len) {
            return 0;
        }
        return cheng_seed_call_expr_string_literal_count_inner(base_name, depth + 1);
    }
    if (cheng_seed_parse_index_access_expr(expr, base_name, sizeof(base_name), index_expr, sizeof(index_expr))) {
        int32_t base_count = 0;
        int32_t index_count = 0;
        if (strcmp(base_name, expr) != 0 && strlen(base_name) < expr_len) {
            base_count = cheng_seed_call_expr_string_literal_count_inner(base_name, depth + 1);
        }
        if (strcmp(index_expr, expr) != 0 && strlen(index_expr) < expr_len) {
            index_count = cheng_seed_call_expr_string_literal_count_inner(index_expr, depth + 1);
        }
        return base_count > index_count ? base_count : index_count;
    }
    {
        char (*args)[4096] = NULL;
        size_t arg_count = 0U;
        if (cheng_seed_parse_list_literal_text_alloc(expr, &args, &arg_count)) {
            for (i = 0; i < arg_count; ++i) {
                int32_t arg_count_value = 0;
                if (strcmp(args[i], expr) != 0 && strlen(args[i]) < expr_len) {
                    arg_count_value = cheng_seed_call_expr_string_literal_count_inner(args[i], depth + 1);
                }
                if (arg_count_value > best) {
                    best = arg_count_value;
                }
            }
            free(args);
            return best;
        }
        free(args);
    }
    {
        char (*args)[4096] = cheng_seed_alloc_call_arg_scratch();
        size_t arg_count = 0U;
        if (cheng_seed_parse_call_text(expr, callee, sizeof(callee), args, &arg_count, CHENG_MAX_CALL_ARGS) ||
            cheng_seed_parse_prefix_single_arg_call(expr, callee, sizeof(callee), arg_text, sizeof(arg_text))) {
            int32_t top_level_count = 0;
            if (arg_count == 0U && arg_text[0] != '\0') {
                snprintf(args[0], sizeof(args[0]), "%s", arg_text);
                arg_count = 1U;
            }
            for (i = 0; i < arg_count; ++i) {
                char literal[4096];
                int32_t nested_count = 0;
                if (cheng_seed_parse_string_literal_text(args[i], literal, sizeof(literal))) {
                    top_level_count += 1;
                }
                if (strcmp(args[i], expr) != 0 && strlen(args[i]) < expr_len) {
                    nested_count = cheng_seed_call_expr_string_literal_count_inner(args[i], depth + 1);
                }
                if (nested_count > best) {
                    best = nested_count;
                }
            }
            free(args);
            return top_level_count > best ? top_level_count : best;
        }
        free(args);
    }
    return 0;
}

static int32_t cheng_seed_call_expr_string_literal_count(const char *expr_text) {
    return cheng_seed_call_expr_string_literal_count_inner(expr_text, 0);
}

static void cheng_seed_copy_expr_temp_key_text(const char *expr_text,
                                       char *out,
                                       size_t cap) {
    ChengSeedExprSurface surface;
    char surface_error[256];
    if (out == NULL || cap == 0U) {
        return;
    }
    out[0] = '\0';
    if (expr_text == NULL) {
        return;
    }
    if (!cheng_seed_classify_expr_surface(expr_text, &surface, surface_error, sizeof(surface_error))) {
        cheng_seed_trim_copy_text(expr_text, out, cap);
        return;
    }
    cheng_seed_trim_copy_text(surface.text, out, cap);
}

static bool cheng_seed_is_trivial_prepare_literal_text(const char *expr_text) {
    char trimmed[4096];
    char literal_text[4096];
    int32_t char_value = 0;
    if (!expr_text) {
        return false;
    }
    cheng_seed_trim_copy_text(expr_text, trimmed, sizeof(trimmed));
    return cheng_seed_parse_string_literal_text(trimmed, literal_text, sizeof(literal_text)) ||
           cheng_seed_parse_char_literal_text(trimmed, &char_value) ||
           cheng_seed_parse_int_literal_text(trimmed, NULL) ||
           strcmp(trimmed, "true") == 0 ||
           strcmp(trimmed, "false") == 0 ||
           strcmp(trimmed, "nil") == 0;
}

static void cheng_seed_call_arg_temp_name(const ChengSeedLoweredFunctionStub *function,
                                  const char *callee,
                                  size_t arg_index,
                                  const char *expr_text,
                                  char *out,
                                  size_t cap) {
    char canonical_expr[4096];
    char key[4608];
    uint64_t hash;
    cheng_seed_copy_expr_temp_key_text(expr_text, canonical_expr, sizeof(canonical_expr));
    snprintf(key,
             sizeof(key),
             "%s|%s|%zu|%s",
             function->symbol_text,
             callee,
             arg_index,
             canonical_expr);
    hash = cheng_seed_fnv1a64(key);
    snprintf(out, cap, "__cheng_calltmp_%016llx", (unsigned long long)hash);
}

static void cheng_seed_expr_temp_name(const ChengSeedLoweredFunctionStub *function,
                              const char *expr_text,
                              char *out,
                              size_t cap) {
    char canonical_expr[4096];
    char key[4608];
    uint64_t hash;
    cheng_seed_copy_expr_temp_key_text(expr_text, canonical_expr, sizeof(canonical_expr));
    snprintf(key,
             sizeof(key),
             "%s|expr|%s",
             function->symbol_text,
             canonical_expr);
    hash = cheng_seed_fnv1a64(key);
    snprintf(out, cap, "__cheng_exprtmp_%016llx", (unsigned long long)hash);
}

