static void cheng_seed_resolve_call_arg_preferred_signature(const ChengSeedLoweringPlanStub *lowering,
                                                    const char *owner_module_path,
                                                    const ChengSeedImportAlias *aliases,
                                                    size_t alias_count,
                                                    const char *callee,
                                                    const char **preferred_type_io,
                                                    const char **preferred_abi_io,
                                                    char *normalized_type_out,
                                                    size_t normalized_type_cap) {
    const char *preferred_type = preferred_type_io ? *preferred_type_io : NULL;
    const char *preferred_abi = preferred_abi_io ? *preferred_abi_io : NULL;
    const char *callee_base = NULL;
    if (normalized_type_out != NULL && normalized_type_cap > 0U) {
        normalized_type_out[0] = '\0';
    }
    if (lowering == NULL || callee == NULL || preferred_type_io == NULL || preferred_abi_io == NULL) {
        return;
    }
    callee_base = strrchr(callee, '.');
    callee_base = callee_base ? callee_base + 1 : callee;
    if ((preferred_type == NULL || preferred_type[0] == '\0') &&
        cheng_seed_is_strformat_join_name(callee_base)) {
        preferred_type = "str[]";
    }
    if (preferred_type != NULL && preferred_type[0] != '\0' &&
        (preferred_abi == NULL || preferred_abi[0] == '\0')) {
        preferred_abi = cheng_seed_resolved_type_abi_class(lowering,
                                                   owner_module_path,
                                                   aliases,
                                                   alias_count,
                                                   preferred_type,
                                                   normalized_type_out,
                                                   normalized_type_cap);
        if (normalized_type_out != NULL &&
            normalized_type_cap > 0U &&
            normalized_type_out[0] != '\0') {
            preferred_type = normalized_type_out;
        }
    }
    *preferred_type_io = preferred_type;
    *preferred_abi_io = preferred_abi;
}

static bool cheng_seed_prepare_composite_call_arg_temp(const ChengSeedSystemLinkPlanStub *plan,
                                               const ChengSeedLoweringPlanStub *lowering,
                                               const ChengSeedLoweredFunctionStub *current_function,
                                               const ChengSeedImportAlias *aliases,
                                               size_t alias_count,
                                               ChengSeedAsmLocalSlot *locals,
                                               size_t *local_count,
                                               size_t local_cap,
                                               int32_t *next_offset_io,
                                               const char *callee,
                                               size_t arg_index,
                                               const char *arg_expr,
                                               const char *preferred_type,
                                               const char *preferred_abi) {
    const char *trace_arg_kind = getenv("CHENG_TRACE_ARG_KIND");
    char named_field[128];
    char named_expr[4096];
    char temp_name[128];
    char inferred_type[256];
    char inferred_abi[32];
    char normalized_preferred_type[256];
    bool list_nonempty = false;
    char fixed_elem_type[256];
    char list_items[CHENG_MAX_CALL_ARGS][4096];
    size_t list_item_count = 0U;
    int32_t fixed_len = 0;
    const char *value_expr = arg_expr;
    normalized_preferred_type[0] = '\0';
    if (cheng_seed_parse_named_arg_meta(arg_expr,
                                named_field,
                                sizeof(named_field),
                                named_expr,
                                sizeof(named_expr))) {
        value_expr = named_expr;
    }
    if (cheng_seed_find_local_slot(locals, *local_count, value_expr) >= 0) {
        return true;
    }
    cheng_seed_call_arg_temp_name(current_function,
                          callee,
                          arg_index,
                          value_expr,
                          temp_name,
                          sizeof(temp_name));
    if (cheng_seed_find_local_slot(locals, *local_count, temp_name) >= 0) {
        return true;
    }
    cheng_seed_resolve_call_arg_preferred_signature(lowering,
                                            current_function->owner_module_path,
                                            aliases,
                                            alias_count,
                                            callee,
                                            &preferred_type,
                                            &preferred_abi,
                                            normalized_preferred_type,
                                            sizeof(normalized_preferred_type));
    if (preferred_type &&
        preferred_abi &&
        preferred_type[0] != '\0' &&
        preferred_abi[0] != '\0' &&
        cheng_seed_call_signature_needs_address_temp(preferred_type, preferred_abi)) {
        if (strlen(preferred_type) > 2U &&
            strcmp(preferred_type + strlen(preferred_type) - 2U, "[]") == 0 &&
            cheng_seed_is_list_literal_text(value_expr, &list_nonempty)) {
            snprintf(inferred_type, sizeof(inferred_type), "%s", preferred_type);
            snprintf(inferred_abi, sizeof(inferred_abi), "%s", preferred_abi);
        } else if (cheng_seed_parse_fixed_array_type(preferred_type,
                                             fixed_elem_type,
                                             sizeof(fixed_elem_type),
                                             &fixed_len) &&
                   cheng_seed_is_list_literal_text(value_expr, &list_nonempty)) {
            if (!cheng_seed_parse_list_literal_text(value_expr,
                                            list_items,
                                            &list_item_count,
                                            CHENG_MAX_CALL_ARGS) ||
                (int32_t)list_item_count != fixed_len) {
                fprintf(stderr,
                        "[cheng_seed] prepare composite arg fixed-list mismatch caller=%s callee=%s arg_index=%zu expr=%s preferred_type=%s list_items=%zu fixed_len=%d\n",
                        current_function->symbol_text,
                        callee,
                        arg_index,
                        arg_expr,
                        preferred_type,
                        list_item_count,
                        fixed_len);
                return false;
            }
            snprintf(inferred_type, sizeof(inferred_type), "%s", preferred_type);
            snprintf(inferred_abi, sizeof(inferred_abi), "%s", preferred_abi);
        } else {
            snprintf(inferred_type, sizeof(inferred_type), "%s", preferred_type);
            snprintf(inferred_abi, sizeof(inferred_abi), "%s", preferred_abi);
        }
    } else if (!cheng_seed_infer_expr_type(plan,
                                   lowering,
                                   current_function,
                                   aliases,
                                   alias_count,
                                   locals,
                                   *local_count,
                                   value_expr,
                                   inferred_type,
                                   sizeof(inferred_type),
                                   inferred_abi,
                                   sizeof(inferred_abi))) {
        fprintf(stderr,
                "[cheng_seed] prepare composite arg infer failed caller=%s callee=%s arg_index=%zu expr=%s preferred_type=%s preferred_abi=%s\n",
                current_function->symbol_text,
                callee,
                arg_index,
                arg_expr,
                preferred_type ? preferred_type : "",
                preferred_abi ? preferred_abi : "");
        return false;
    }
    if (!cheng_seed_expr_materializes_to_address(inferred_type, inferred_abi)) {
        return true;
    }
    if (!cheng_seed_add_local_slot_for_type(lowering,
                                    current_function->owner_module_path,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    local_cap,
                                    temp_name,
                                    inferred_type,
                                    inferred_abi,
                                    false,
                                    next_offset_io)) {
        fprintf(stderr,
                "[cheng_seed] prepare composite arg add-local failed caller=%s callee=%s arg_index=%zu expr=%s inferred_type=%s inferred_abi=%s\n",
                current_function->symbol_text,
                callee,
                arg_index,
                arg_expr,
                inferred_type,
                inferred_abi);
        return false;
    }
    if (trace_arg_kind != NULL &&
        trace_arg_kind[0] != '\0' &&
        (strcmp(trace_arg_kind, "1") == 0 ||
         strcmp(trace_arg_kind, callee) == 0 ||
         strstr(current_function->symbol_text, trace_arg_kind) != NULL)) {
        fprintf(stderr,
                "[cheng_seed] prepare composite arg temp caller=%s callee=%s arg_index=%zu temp=%s expr=%s inferred_type=%s inferred_abi=%s line=%zu\n",
                current_function->symbol_text,
                callee,
                arg_index,
                temp_name,
                arg_expr,
                inferred_type,
                inferred_abi,
                cheng_seed_current_source_line());
    }
    return true;
}

static bool cheng_seed_prepare_composite_expr_temp_known(const ChengSeedSystemLinkPlanStub *plan,
                                                 const ChengSeedLoweringPlanStub *lowering,
                                                 const ChengSeedLoweredFunctionStub *current_function,
                                                 const ChengSeedImportAlias *aliases,
                                                 size_t alias_count,
                                                 ChengSeedAsmLocalSlot *locals,
                                                 size_t *local_count,
                                                 size_t local_cap,
                                                 int32_t *next_offset_io,
                                                 const char *expr_text,
                                                 const char *known_type,
                                                 const char *known_abi,
                                                 char *canonical_expr_out,
                                                 size_t canonical_expr_cap,
                                                 char *temp_name_out,
                                                 size_t temp_name_cap) {
    char canonical_expr[8192];
    char temp_name[128];
    char inferred_type[256];
    char inferred_abi[32];
    const char *resolved_type = known_type;
    const char *resolved_abi = known_abi;
    char *canonical_expr_ptr = canonical_expr_out ? canonical_expr_out : canonical_expr;
    size_t canonical_expr_ptr_cap =
        canonical_expr_out && canonical_expr_cap > 0U ? canonical_expr_cap : sizeof(canonical_expr);
    char *temp_name_ptr = temp_name_out ? temp_name_out : temp_name;
    size_t temp_name_ptr_cap =
        temp_name_out && temp_name_cap > 0U ? temp_name_cap : sizeof(temp_name);
    if (expr_text == NULL || expr_text[0] == '\0' ||
        current_function == NULL || lowering == NULL ||
        locals == NULL || local_count == NULL ||
        canonical_expr_ptr_cap == 0U || temp_name_ptr_cap == 0U) {
        return false;
    }
    cheng_seed_copy_expr_temp_key_text(expr_text, canonical_expr_ptr, canonical_expr_ptr_cap);
    if (cheng_seed_find_local_slot(locals, *local_count, canonical_expr_ptr) >= 0) {
        return true;
    }
    cheng_seed_expr_temp_name(current_function, canonical_expr_ptr, temp_name_ptr, temp_name_ptr_cap);
    if (cheng_seed_find_local_slot(locals, *local_count, temp_name_ptr) >= 0) {
        return true;
    }
    if (resolved_type == NULL || resolved_type[0] == '\0' ||
        resolved_abi == NULL || resolved_abi[0] == '\0') {
        if (!cheng_seed_infer_expr_type(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                locals,
                                *local_count,
                                canonical_expr_ptr,
                                inferred_type,
                                sizeof(inferred_type),
                                inferred_abi,
                                sizeof(inferred_abi))) {
            return false;
        }
        resolved_type = inferred_type;
        resolved_abi = inferred_abi;
    }
    if (!cheng_seed_expr_materializes_to_address(resolved_type, resolved_abi)) {
        return true;
    }
    return cheng_seed_add_local_slot_for_type(lowering,
                                      current_function->owner_module_path,
                                      aliases,
                                      alias_count,
                                      locals,
                                      local_count,
                                      local_cap,
                                      temp_name_ptr,
                                      resolved_type,
                                      resolved_abi,
                                      false,
                                      next_offset_io);
}

static bool cheng_seed_prepare_composite_expr_temp(const ChengSeedSystemLinkPlanStub *plan,
                                           const ChengSeedLoweringPlanStub *lowering,
                                           const ChengSeedLoweredFunctionStub *current_function,
                                           const ChengSeedImportAlias *aliases,
                                           size_t alias_count,
                                           ChengSeedAsmLocalSlot *locals,
                                           size_t *local_count,
                                           size_t local_cap,
                                           int32_t *next_offset_io,
                                           const char *expr_text) {
    return cheng_seed_prepare_composite_expr_temp_known(plan,
                                                lowering,
                                                current_function,
                                                aliases,
                                                alias_count,
                                                locals,
                                                local_count,
                                                local_cap,
                                                next_offset_io,
                                                expr_text,
                                                NULL,
                                                NULL,
                                                NULL,
                                                0U,
                                                NULL,
                                                0U);
}

static bool cheng_seed_expr_surface_never_lvalue(const ChengSeedExprSurface *surface) {
    if (surface == NULL) {
        return false;
    }
    return surface->kind == ChengSeed_EXPR_SURFACE_IF ||
           surface->kind == ChengSeed_EXPR_SURFACE_TERNARY ||
           surface->kind == ChengSeed_EXPR_SURFACE_RANGE ||
           surface->kind == ChengSeed_EXPR_SURFACE_CALL;
}

static bool cheng_seed_emit_direct_composite_call_arg_address(const ChengSeedSystemLinkPlanStub *plan,
                                                      const ChengSeedLoweringPlanStub *lowering,
                                                      const ChengSeedLoweredFunctionStub *current_function,
                                                      const ChengSeedImportAlias *aliases,
                                                      size_t alias_count,
                                                      const ChengSeedAsmLocalSlot *locals,
                                                      size_t local_count,
                                                      const char *expr_text,
                                                      const char *expected_type,
                                                      const char *expected_abi,
                                                      int addr_reg,
                                                      int32_t call_arg_base,
                                                      int32_t string_temp_base,
                                                      int32_t string_temp_stride,
                                                      int call_depth,
                                                      char *out,
                                                      size_t cap) {
    char actual_type[256];
    char actual_abi[32];
    char normalized_expected[256];
    char normalized_actual[256];
    if (!plan || !lowering || !current_function || !expr_text ||
        !expected_type || !expected_abi ||
        expected_type[0] == '\0' ||
        !cheng_seed_call_signature_needs_address_temp(expected_type, expected_abi)) {
        return false;
    }
    if (!cheng_seed_emit_lvalue_address(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                locals,
                                local_count,
                                expr_text,
                                actual_type,
                                sizeof(actual_type),
                                actual_abi,
                                sizeof(actual_abi),
                                addr_reg,
                                call_arg_base,
                                string_temp_base,
                                string_temp_stride,
                                call_depth,
                                out,
                                cap) ||
        !cheng_seed_expr_materializes_to_address(actual_type, actual_abi) ||
        !cheng_seed_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                expected_type,
                                normalized_expected,
                                sizeof(normalized_expected)) ||
        !cheng_seed_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                actual_type,
                                normalized_actual,
                                sizeof(normalized_actual))) {
        return false;
    }
    return strcmp(normalized_expected, normalized_actual) == 0;
}

static void cheng_seed_note_emit_spill_call_depth(int call_depth);

static bool cheng_seed_emit_address_call_arg_spill(const ChengSeedSystemLinkPlanStub *plan,
                                           const ChengSeedLoweringPlanStub *lowering,
                                           const ChengSeedLoweredFunctionStub *current_function,
                                           const ChengSeedImportAlias *aliases,
                                           size_t alias_count,
                                           const ChengSeedAsmLocalSlot *locals,
                                           size_t local_count,
                                           const char *call_context,
                                           const char *callee,
                                           char args[][4096],
                                           const ChengSeedAsmCallTarget *target,
                                           size_t arg_index,
                                           int32_t call_arg_base,
                                           int32_t string_temp_base,
                                           int32_t string_temp_stride,
                                           int32_t *string_label_index_io,
                                           int call_depth,
                                           char *out,
                                           size_t cap) {
    const char *arg_expr = NULL;
    const char *param_type = NULL;
    const char *param_abi = NULL;
    int32_t local_index = -1;
    char temp_name[128];
    bool need_materialize = false;
    if (plan == NULL || lowering == NULL || current_function == NULL ||
        callee == NULL || args == NULL || target == NULL ||
        arg_index >= target->param_count || out == NULL) {
        return false;
    }
    arg_expr = args[arg_index];
    param_type = target->param_types[arg_index];
    param_abi = target->param_abi_classes[arg_index];
    if (!cheng_seed_call_signature_needs_address_temp(param_type, param_abi)) {
        return false;
    }
    if (getenv("CHENG_TRACE_ARG_KIND") != NULL) {
        fprintf(stderr,
                "[cheng_seed] %s arg kind caller=%s callee=%s arg_index=%zu param_type=%s param_abi=%s expr=%s\n",
                call_context ? call_context : "call",
                current_function->symbol_text,
                callee,
                arg_index,
                param_type,
                param_abi,
                arg_expr);
    }
    {
        char literal_text[4096];
        if (strcmp(param_type, "str") == 0 &&
            cheng_seed_parse_string_literal_text(arg_expr, literal_text, sizeof(literal_text))) {
            ChengSeedAsmLocalSlot scratch_slot;
            int32_t literal_slot = 0;
            size_t literal_i;
            for (literal_i = 0; literal_i <= arg_index; ++literal_i) {
                char prior_literal[4096];
                if (strcmp(target->param_types[literal_i], "str") == 0 &&
                    cheng_seed_parse_string_literal_text(args[literal_i], prior_literal, sizeof(prior_literal))) {
                    literal_slot += 1;
                }
            }
            literal_slot -= 1;
            if (literal_slot < 0 ||
                string_temp_stride < ((literal_slot + 2) * cheng_seed_active_target_str_size_i32())) {
                fprintf(stderr,
                        "[cheng_seed] %s str-arg scratch overflow caller=%s callee=%s arg_index=%zu expr=%s\n",
                        call_context ? call_context : "call",
                        current_function->symbol_text,
                        callee,
                        arg_index,
                        arg_expr);
                return false;
            }
            memset(&scratch_slot, 0, sizeof(scratch_slot));
            snprintf(scratch_slot.name, sizeof(scratch_slot.name), "%s", "__cheng_call_str_arg");
            snprintf(scratch_slot.type_text, sizeof(scratch_slot.type_text), "%s", "str");
            snprintf(scratch_slot.abi_class,
                     sizeof(scratch_slot.abi_class),
                     "%s",
                     cheng_seed_type_abi_class(scratch_slot.type_text));
            cheng_seed_note_emit_spill_call_depth(call_depth);
            scratch_slot.stack_offset =
                string_temp_base + call_depth * string_temp_stride +
                cheng_seed_active_target_str_size_i32() +
                literal_slot * cheng_seed_active_target_str_size_i32();
            scratch_slot.stack_size = cheng_seed_active_target_str_size_i32();
            scratch_slot.stack_align = cheng_seed_active_target_pointer_align_i32();
            if (!cheng_seed_emit_slot_address(out, cap, &scratch_slot, 15) ||
                !cheng_seed_materialize_composite_expr_into_address(plan,
                                                            lowering,
                                                            current_function,
                                                            aliases,
                                                            alias_count,
                                                            locals,
                                                            local_count,
                                                            arg_expr,
                                                            "str",
                                                            15,
                                                            call_arg_base,
                                                            string_temp_base,
                                                            string_temp_stride,
                                                            string_label_index_io,
                                                            call_depth + 1,
                                                            out,
                                                            cap)) {
                fprintf(stderr,
                        "[cheng_seed] %s str-arg materialize failed caller=%s callee=%s arg_index=%zu expr=%s\n",
                        call_context ? call_context : "call",
                        current_function->symbol_text,
                        callee,
                        arg_index,
                        arg_expr);
                return false;
            }
            cheng_seed_emit_call_arg_spill_store(out,
                                         cap,
                                         call_arg_base,
                                         call_depth,
                                         arg_index,
                                         "ptr",
                                         15);
            return true;
        }
    }
    local_index = cheng_seed_find_local_slot(locals, local_count, arg_expr);
    if (local_index < 0) {
        cheng_seed_call_arg_temp_name(current_function,
                              callee,
                              arg_index,
                              arg_expr,
                              temp_name,
                              sizeof(temp_name));
        local_index = cheng_seed_find_local_slot(locals, local_count, temp_name);
        need_materialize = true;
        if (local_index < 0) {
            cheng_seed_expr_temp_name(current_function,
                              arg_expr,
                              temp_name,
                              sizeof(temp_name));
            local_index = cheng_seed_find_local_slot(locals, local_count, temp_name);
        }
        if (local_index < 0) {
            if (cheng_seed_emit_direct_composite_call_arg_address(plan,
                                                          lowering,
                                                          current_function,
                                                          aliases,
                                                          alias_count,
                                                          locals,
                                                          local_count,
                                                          arg_expr,
                                                          param_type,
                                                          param_abi,
                                                          15,
                                                          call_arg_base,
                                                          string_temp_base,
                                                          string_temp_stride,
                                                          call_depth + 1,
                                                          out,
                                                          cap)) {
                cheng_seed_emit_call_arg_spill_store(out,
                                             cap,
                                             call_arg_base,
                                             call_depth,
                                             arg_index,
                                             "ptr",
                                             15);
                return true;
            }
            fprintf(stderr,
                    "[cheng_seed] %s composite-arg local missing caller=%s callee=%s arg_index=%zu expr=%s\n",
                    call_context ? call_context : "call",
                    current_function->symbol_text,
                    callee,
                    arg_index,
                    arg_expr);
            return false;
        }
    }
    if (need_materialize &&
        !cheng_seed_materialize_composite_expr_into_slot(plan,
                                                 lowering,
                                                 current_function,
                                                 aliases,
                                                 alias_count,
                                                 locals,
                                                 local_count,
                                                 callee,
                                                 arg_index,
                                                 arg_expr,
                                                 &locals[local_index],
                                                 call_arg_base,
                                                 string_temp_base,
                                                 string_temp_stride,
                                                 string_label_index_io,
                                                 call_depth + 1,
                                                 out,
                                                 cap)) {
        fprintf(stderr,
                "[cheng_seed] %s composite-arg materialize failed caller=%s callee=%s arg_index=%zu expr=%s\n",
                call_context ? call_context : "call",
                current_function->symbol_text,
                callee,
                arg_index,
                arg_expr);
        return false;
    }
    if (!cheng_seed_emit_local_value_address(out, cap, &locals[local_index], 15)) {
        fprintf(stderr,
                "[cheng_seed] %s composite-arg address failed caller=%s callee=%s arg_index=%zu local=%s\n",
                call_context ? call_context : "call",
                current_function->symbol_text,
                callee,
                arg_index,
                locals[local_index].name);
        return false;
    }
    cheng_seed_emit_call_arg_spill_store(out,
                                 cap,
                                 call_arg_base,
                                 call_depth,
                                 arg_index,
                                 "ptr",
                                 15);
    return true;
}

static void cheng_seed_update_max_i32(int32_t *value_io, int32_t candidate) {
    if (candidate > *value_io) {
        *value_io = candidate;
    }
}

static const char *cheng_seed_resolved_type_abi_class(const ChengSeedLoweringPlanStub *lowering,
                                              const char *owner_module_path,
                                              const ChengSeedImportAlias *aliases,
                                              size_t alias_count,
                                              const char *type_text,
                                              char *normalized_out,
                                              size_t normalized_cap) {
    if (normalized_out && normalized_cap > 0U) {
        normalized_out[0] = '\0';
    }
    if (!type_text || type_text[0] == '\0') {
        return "void";
    }
    if (lowering &&
        owner_module_path &&
        cheng_seed_normalize_type_text(lowering,
                               owner_module_path,
                               aliases,
                               alias_count,
                               type_text,
                               normalized_out,
                               normalized_cap)) {
        return cheng_seed_type_abi_class(normalized_out);
    }
    return cheng_seed_type_abi_class(type_text);
}

static int32_t cheng_seed_find_local_slot(const ChengSeedAsmLocalSlot *locals,
                                  size_t local_count,
                                  const char *name) {
    size_t i = local_count;
    size_t line_number = cheng_seed_current_source_line();
    while (i > 0U) {
        size_t index = i - 1U;
        if (strcmp(locals[index].name, name) == 0 &&
            locals[index].scope_start_line <= line_number &&
            line_number <= locals[index].scope_end_line) {
            return (int32_t)index;
        }
        i -= 1U;
    }
    return -1;
}

static void cheng_seed_limit_local_scope_end(ChengSeedAsmLocalSlot *locals,
                                     size_t start_index,
                                     size_t local_count,
                                     size_t end_line) {
    size_t i;
    for (i = start_index; i < local_count; ++i) {
        if (locals[i].scope_end_line > end_line) {
            locals[i].scope_end_line = end_line;
        }
    }
}

static bool cheng_seed_is_noop_local_reference_statement(const ChengSeedAsmLocalSlot *locals,
                                                 size_t local_count,
                                                 const char *statement) {
    char trimmed[256];
    if (!statement || statement[0] == '\0') {
        return false;
    }
    snprintf(trimmed, sizeof(trimmed), "%s", statement);
    cheng_seed_trim_inplace(trimmed);
    if (!cheng_seed_is_bare_identifier_text(trimmed)) {
        return false;
    }
    return cheng_seed_find_local_slot(locals, local_count, trimmed) >= 0;
}

static bool cheng_seed_add_local_slot_sized(ChengSeedAsmLocalSlot *locals,
                                    size_t *local_count,
                                    size_t local_cap,
                                    const char *name,
                                    const char *type_text,
                                    const char *abi_class,
                                    bool indirect_value,
                                    int32_t slot_size,
                                    int32_t slot_align,
                                    int32_t *next_offset_io) {
    int32_t align = slot_align > 0 ? slot_align : 1;
    int32_t size = slot_size > 0 ? slot_size : 8;
    if (*local_count >= local_cap) {
        fprintf(stderr,
                "[cheng_seed] asm local cap exceeded local_cap=%zu name=%s type=%s abi=%s\n",
                local_cap,
                name ? name : "",
                type_text ? type_text : "",
                abi_class ? abi_class : "");
        return false;
    }
    snprintf(locals[*local_count].name, sizeof(locals[*local_count].name), "%s", name);
    snprintf(locals[*local_count].type_text, sizeof(locals[*local_count].type_text), "%s", type_text);
    snprintf(locals[*local_count].abi_class, sizeof(locals[*local_count].abi_class), "%s", abi_class);
    locals[*local_count].indirect_value = indirect_value;
    locals[*local_count].stack_align = align;
    locals[*local_count].stack_size = size;
    locals[*local_count].scope_start_line = cheng_seed_current_source_line();
    locals[*local_count].scope_end_line = (size_t)-1;
    *next_offset_io = cheng_seed_align_up_i32(*next_offset_io, align);
    locals[*local_count].stack_offset = *next_offset_io;
    *next_offset_io += cheng_seed_align_up_i32(size, 8);
    *local_count += 1U;
    return true;
}

static bool cheng_seed_add_local_slot_for_type(const ChengSeedLoweringPlanStub *lowering,
                                       const char *owner_module_path,
                                       const ChengSeedImportAlias *aliases,
                                       size_t alias_count,
                                       ChengSeedAsmLocalSlot *locals,
                                       size_t *local_count,
                                       size_t local_cap,
                                       const char *name,
                                       const char *type_text,
                                       const char *abi_class,
                                       bool as_indirect_param,
                                       int32_t *next_offset_io) {
    ChengSeedTypeLayoutStub layout;
    char normalized_type[256];
    const char *resolved_abi_class;
    (void)abi_class;
    if (!cheng_seed_normalize_type_text(lowering,
                                owner_module_path,
                                aliases,
                                alias_count,
                                type_text,
                                normalized_type,
                                sizeof(normalized_type))) {
        fprintf(stderr,
                "[cheng_seed] normalize type failed owner=%s type=%s\n",
                owner_module_path,
                type_text);
        return false;
    }
    resolved_abi_class = cheng_seed_type_abi_class(normalized_type);
    if (strcmp(resolved_abi_class, "void") == 0) {
        return false;
    }
    if (!cheng_seed_expr_materializes_to_address(normalized_type, resolved_abi_class)) {
        return cheng_seed_add_local_slot_sized(locals,
                                       local_count,
                                       local_cap,
                                       name,
                                       normalized_type,
                                       resolved_abi_class,
                                       as_indirect_param,
                                       8,
                                       8,
                                       next_offset_io);
    }
    if (!cheng_seed_compute_type_layout_impl(lowering, normalized_type, &layout, 0U)) {
        fprintf(stderr,
                "[cheng_seed] layout failed owner=%s type=%s normalized=%s\n",
                owner_module_path,
                type_text,
                normalized_type);
        return false;
    }
    return cheng_seed_add_local_slot_sized(locals,
                                   local_count,
                                   local_cap,
                                   name,
                                   normalized_type,
                                   resolved_abi_class,
                                   as_indirect_param,
                                   as_indirect_param ? 8 : layout.size,
                                   as_indirect_param ? 8 : layout.align,
                                   next_offset_io);
}

