static bool g_cheng_current_frame_base_valid = false;
static int32_t g_cheng_current_frame_fp_to_base_offset = 0;
static bool g_cheng_emit_spill_depth_scope_active = false;
static int32_t g_cheng_emit_spill_depth_reserved_max_call_depth = 0;
static int32_t g_cheng_emit_spill_depth_used_max_call_depth = 0;
static char g_cheng_emit_spill_depth_symbol[PATH_MAX];

static void cheng_seed_begin_emit_spill_depth_scope(const char *symbol_text,
                                            int32_t reserved_max_call_depth) {
    if (reserved_max_call_depth < 0) {
        reserved_max_call_depth = 0;
    }
    g_cheng_emit_spill_depth_scope_active = true;
    g_cheng_emit_spill_depth_reserved_max_call_depth = reserved_max_call_depth;
    g_cheng_emit_spill_depth_used_max_call_depth = 0;
    snprintf(g_cheng_emit_spill_depth_symbol,
             sizeof(g_cheng_emit_spill_depth_symbol),
             "%s",
             symbol_text != NULL && symbol_text[0] != '\0' ? symbol_text : "-");
}

static void cheng_seed_note_emit_spill_call_depth(int call_depth) {
    if (!g_cheng_emit_spill_depth_scope_active || call_depth < 0) {
        return;
    }
    if (call_depth > g_cheng_emit_spill_depth_used_max_call_depth) {
        g_cheng_emit_spill_depth_used_max_call_depth = call_depth;
    }
}

static bool cheng_seed_validate_emit_spill_depth_scope(void) {
    int32_t prepared_spill_max_call_depth =
        g_cheng_emit_spill_depth_reserved_max_call_depth + 1;
    bool ok = true;
    if (g_cheng_emit_spill_depth_scope_active &&
        g_cheng_emit_spill_depth_used_max_call_depth >
            prepared_spill_max_call_depth) {
        fprintf(stderr,
                "[cheng_seed] emit spill depth exceeded prepared frame function=%s prepared_max_call_depth=%d prepared_spill_max_call_depth=%d emit_max_call_depth=%d\n",
                g_cheng_emit_spill_depth_symbol,
                g_cheng_emit_spill_depth_reserved_max_call_depth,
                prepared_spill_max_call_depth,
                g_cheng_emit_spill_depth_used_max_call_depth);
        ok = false;
    }
    g_cheng_emit_spill_depth_scope_active = false;
    g_cheng_emit_spill_depth_reserved_max_call_depth = 0;
    g_cheng_emit_spill_depth_used_max_call_depth = 0;
    g_cheng_emit_spill_depth_symbol[0] = '\0';
    return ok;
}

static bool cheng_seed_emit_frame_base_address(char *out,
                                       size_t cap,
                                       int reg_index) {
    if (!g_cheng_current_frame_base_valid) {
        return cheng_seed_emit_sp_offset_address(out, cap, reg_index, 0);
    }
    if (cheng_seed_active_target_is_linux_x86_64()) {
        if (reg_index != 29) {
            cheng_seed_text_appendf(out, cap,
                            "  movq %%rbp, %s\n",
                            cheng_seed_x64_qreg_name(reg_index));
        }
        return true;
    }
    if (g_cheng_current_frame_fp_to_base_offset == 0) {
        if (reg_index != 29) {
            cheng_seed_text_appendf(out, cap, "  mov x%d, x29\n", reg_index);
        }
        return true;
    }
    if (reg_index == 29) {
        return false;
    }
    if (g_cheng_current_frame_fp_to_base_offset <= 4095) {
        cheng_seed_text_appendf(out, cap,
                        "  sub x%d, x29, #%d\n",
                        reg_index,
                        g_cheng_current_frame_fp_to_base_offset);
        return true;
    }
    {
        int scratch_reg = reg_index == 17 ? 16 : 17;
        if (!cheng_seed_emit_mov_imm(out, cap, scratch_reg, g_cheng_current_frame_fp_to_base_offset)) {
            return false;
        }
        cheng_seed_text_appendf(out, cap,
                        "  sub x%d, x29, x%d\n",
                        reg_index,
                        scratch_reg);
    }
    return true;
}

static bool cheng_seed_emit_frame_offset_address(char *out,
                                         size_t cap,
                                         int dst_reg,
                                         int32_t offset) {
    if (offset < 0) {
        return false;
    }
    if (!g_cheng_current_frame_base_valid) {
        return cheng_seed_emit_sp_offset_address(out, cap, dst_reg, offset);
    }
    if (!cheng_seed_emit_frame_base_address(out, cap, dst_reg)) {
        return false;
    }
    if (offset == 0) {
        return true;
    }
    return cheng_seed_emit_add_address_offset(out, cap, dst_reg, dst_reg, offset);
}

static bool cheng_seed_emit_frame_store_reg(char *out,
                                    size_t cap,
                                    int32_t offset,
                                    const char *abi_class,
                                    int src_reg) {
    if (!cheng_seed_emit_frame_offset_address(out, cap, 16, offset)) {
        return false;
    }
    cheng_seed_emit_store_scalar_to_address(out, cap, 16, 0, abi_class, src_reg);
    return true;
}

static bool cheng_seed_emit_frame_load_reg(char *out,
                                   size_t cap,
                                   int32_t offset,
                                   const char *abi_class,
                                   int dst_reg) {
    if (!cheng_seed_emit_frame_offset_address(out, cap, 16, offset)) {
        return false;
    }
    cheng_seed_emit_load_scalar_from_address(out, cap, 16, 0, abi_class, dst_reg);
    return true;
}

static bool cheng_seed_emit_local_stack_address(char *out,
                                        size_t cap,
                                        const ChengSeedAsmLocalSlot *slot,
                                        int reg_index) {
    if (slot == NULL || slot->stack_offset < 0 ||
        !cheng_seed_emit_frame_base_address(out, cap, reg_index)) {
        return false;
    }
    if (slot->stack_offset == 0) {
        return true;
    }
    return cheng_seed_emit_add_address_offset(out, cap, reg_index, reg_index, slot->stack_offset);
}

static void cheng_seed_emit_load_slot(char *out,
                              size_t cap,
                              const ChengSeedAsmLocalSlot *slot,
                              int reg_index) {
    int addr_reg = reg_index == 16 ? 17 : 16;
    if (!slot || slot->stack_offset < 0 ||
        !cheng_seed_emit_local_stack_address(out, cap, slot, addr_reg)) {
        abort();
    }
    if (slot->indirect_value) {
        cheng_seed_emit_load_scalar_from_address(out, cap, addr_reg, 0, "ptr", addr_reg);
    }
    cheng_seed_emit_load_scalar_from_address(out, cap, addr_reg, 0, slot->abi_class, reg_index);
}

static void cheng_seed_emit_store_slot(char *out,
                               size_t cap,
                               const ChengSeedAsmLocalSlot *slot,
                               int reg_index) {
    int addr_reg = reg_index == 16 ? 17 : 16;
    if (!slot || slot->stack_offset < 0 ||
        !cheng_seed_emit_local_stack_address(out, cap, slot, addr_reg)) {
        abort();
    }
    if (slot->indirect_value) {
        cheng_seed_emit_load_scalar_from_address(out, cap, addr_reg, 0, "ptr", addr_reg);
    }
    cheng_seed_emit_store_scalar_to_address(out, cap, addr_reg, 0, slot->abi_class, reg_index);
}

static bool cheng_seed_emit_local_value_address(char *out,
                                        size_t cap,
                                        const ChengSeedAsmLocalSlot *slot,
                                        int reg_index) {
    if (slot == NULL) {
        return false;
    }
    return cheng_seed_emit_slot_address(out, cap, slot, reg_index);
}

static bool cheng_seed_emit_local_value_address_from_base(char *out,
                                                  size_t cap,
                                                  const ChengSeedAsmLocalSlot *slot,
                                                  int base_reg,
                                                  int reg_index) {
    if (slot == NULL || slot->stack_offset < 0) {
        return false;
    }
    if (cheng_seed_active_target_is_linux_x86_64()) {
        if (slot->indirect_value) {
            if (slot->stack_offset == 0) {
                cheng_seed_text_appendf(out, cap,
                                "  movq (%s), %s\n",
                                cheng_seed_x64_qreg_name(base_reg),
                                cheng_seed_x64_qreg_name(reg_index));
            } else {
                cheng_seed_text_appendf(out, cap,
                                "  movq %d(%s), %s\n",
                                slot->stack_offset,
                                cheng_seed_x64_qreg_name(base_reg),
                                cheng_seed_x64_qreg_name(reg_index));
            }
            return true;
        }
        if (slot->stack_offset == 0) {
            if (reg_index != base_reg) {
                cheng_seed_text_appendf(out, cap,
                                "  movq %s, %s\n",
                                cheng_seed_x64_qreg_name(base_reg),
                                cheng_seed_x64_qreg_name(reg_index));
            }
            return true;
        }
        cheng_seed_text_appendf(out, cap,
                        "  leaq %d(%s), %s\n",
                        slot->stack_offset,
                        cheng_seed_x64_qreg_name(base_reg),
                        cheng_seed_x64_qreg_name(reg_index));
        return true;
    }
    if (!cheng_seed_emit_add_address_offset(out, cap, reg_index, base_reg, slot->stack_offset)) {
        return false;
    }
    if (slot->indirect_value) {
        cheng_seed_text_appendf(out, cap, "  ldr x%d, [x%d]\n", reg_index, reg_index);
    }
    return true;
}

static const char *cheng_seed_param_pass_abi_class(const ChengSeedAsmLocalSlot *slot,
                                           const char *value_abi_class) {
    if (slot != NULL && slot->indirect_value) {
        return "ptr";
    }
    return value_abi_class;
}

static bool cheng_seed_external_call_signature(const ChengSeedSystemLinkPlanStub *plan,
                                       const char *name,
                                       ChengSeedAsmCallTarget *target) {
    static const struct {
        const char *name;
        const char *symbol;
        const char *ret_type;
        size_t argc;
        const char *arg_types[8];
    } TABLE[] = {
        {"rawmemAsVoidPtrBridge", "rawmemAsVoid", "ptr", 1U, {"ptr"}},
        {"rawmemAsVoidCStringBridge", "rawmemAsVoid", "ptr", 1U, {"ptr"}},
        {"rawmemCopyRaw", "copyMem", "void", 3U, {"ptr", "ptr", "int32"}},
        {"rawmemSet", "setMem", "void", 3U, {"ptr", "int32", "int32"}},
        {"rawmemPtrAdd", "ptr_add", "ptr", 2U, {"ptr", "int32"}},
        {"system_ptr_add", "ptr_add", "ptr", 2U, {"ptr", "int32"}},
        {"puts", "puts", "int32", 1U, {"ptr"}},
        {"c_puts", "c_puts", "int32", 1U, {"ptr"}},
        {"exit", "exit", "void", 1U, {"int32"}},
        {"c_strlen", "cheng_cstrlen", "int32", 1U, {"ptr"}},
        {"cheng_str_param_to_cstring_compat", "cheng_str_param_to_cstring_compat", "ptr", 1U, {"ptr"}},
        {"alloc", "alloc", "ptr", 1U, {"int32"}},
        {"cheng_seq_set_grow", "cheng_seq_set_grow", "ptr", 3U, {"ptr", "int32", "int32"}},
        {"cheng_seq_get", "cheng_seq_get", "ptr", 4U, {"ptr", "int32", "int32", "int32"}},
        {"cheng_seq_set", "cheng_seq_set", "ptr", 4U, {"ptr", "int32", "int32", "int32"}},
        {"cheng_seq_string_elem_bytes_compat_system", "cheng_seq_string_elem_bytes_compat", "int32", 0U, {0}},
        {"cheng_seq_header_len_get", "cheng_seq_header_len_get", "int32", 1U, {"ptr"}},
        {"cheng_seq_header_len_set", "cheng_seq_header_len_set", "void", 2U, {"ptr", "int32"}},
        {"cheng_seq_header_buffer_get", "cheng_seq_header_buffer_get", "ptr", 1U, {"ptr"}},
        {"cheng_seq_header_buffer_set", "cheng_seq_header_buffer_set", "void", 2U, {"ptr", "ptr"}},
        {"cheng_ptr_seq_get_compat", "cheng_ptr_seq_get_compat", "ptr", 2U, {"ChengSeqHeader", "int32"}},
        {"cheng_ptr_seq_set_compat", "cheng_ptr_seq_set_compat", "void", 3U, {"ptr", "int32", "ptr"}},
        {"ptrLoadCompat", "load_ptr", "ptr", 1U, {"ptr"}},
        {"ptrStoreCompat", "store_ptr", "void", 2U, {"ptr", "ptr"}},
        {"int32LoadCompat", "load_int32", "int32", 1U, {"ptr"}},
        {"int32StoreCompat", "store_int32", "void", 2U, {"ptr", "int32"}},
        {"chengStrBridgeLoadCompatInto", "cheng_str_bridge_load_into", "void", 2U, {"ptr", "ptr"}},
        {"chengStrBridgeStoreCompatRaw", "store", "void", 2U, {"ptr", "str"}},
        {"rawmemWriteI8Compat", "cheng_rawmem_write_i8", "void", 3U, {"ptr", "int32", "int8"}},
        {"memCopyCompat", "cheng_memcpy", "void", 3U, {"ptr", "ptr", "int32"}},
        {"memSetCompat", "cheng_memset", "void", 3U, {"ptr", "int32", "int32"}},
        {"memZeroCompat", "cheng_zero_mem_compat", "void", 2U, {"ptr", "int32"}},
        {"chengRawbytesGetAt", "cheng_rawbytes_get_at", "int32", 2U, {"ptr", "int32"}},
        {"chengRawbytesSetAt", "cheng_rawbytes_set_at", "void", 3U, {"ptr", "int32", "int32"}},
        {"driver_c_i32_to_str", "driver_c_i32_to_str", "ptr", 1U, {"int32"}},
        {"driver_c_i64_to_str", "driver_c_i64_to_str", "ptr", 1U, {"int64"}},
        {"driver_c_u64_to_str", "driver_c_u64_to_str", "ptr", 1U, {"int64"}},
        {"driver_c_i32_to_cstring", "driver_c_i32_to_str", "ptr", 1U, {"int32"}},
        {"driver_c_i64_to_cstring", "driver_c_i64_to_str", "ptr", 1U, {"int64"}},
        {"driver_c_u64_to_cstring", "driver_c_u64_to_str", "ptr", 1U, {"int64"}},
        {"intToStrRaw", "driver_c_i32_to_str", "ptr", 1U, {"int32"}},
        {"int64ToStrRaw", "driver_c_i64_to_str", "ptr", 1U, {"int64"}},
        {"uint64ToStrRaw", "driver_c_u64_to_str", "ptr", 1U, {"int64"}},
        {"cheng_epoch_time_seconds", "cheng_epoch_time_seconds", "int64", 0U, {0}},
        {"chengSystemEntropyFill", "cheng_system_entropy_fill", "int32", 2U, {"ptr", "int32"}}
    };
    const char *lookup = name;
    const char *dot = strrchr(name, '.');
    const char *scope = strstr(name, "::");
    size_t i;
    if (scope && (!dot || scope > dot)) {
        lookup = scope + 2;
    } else if (dot) {
        lookup = dot + 1;
    }
    for (i = 0; i < sizeof(TABLE) / sizeof(TABLE[0]); ++i) {
        if (strcmp(TABLE[i].name, lookup) != 0) {
            continue;
        }
        memset(target, 0, sizeof(*target));
        target->ffi_handle_consume_index = -1;
        target->external = true;
        snprintf(target->callee_name, sizeof(target->callee_name), "%s", lookup);
        cheng_seed_copy_target_symbol_name(plan, TABLE[i].symbol, target->symbol_name, sizeof(target->symbol_name));
        target->c_abi = !cheng_seed_symbol_uses_cheng_internal_abi(TABLE[i].symbol);
        return cheng_seed_call_target_set_signature(target,
                                            TABLE[i].ret_type,
                                            TABLE[i].argc,
                                            TABLE[i].arg_types);
    }
    return false;
}

static bool cheng_seed_parse_result_inner_type(const char *result_type,
                                       char *inner_type_out,
                                       size_t inner_type_cap);
