static bool cheng_seed_extract_function_generic_placeholder(const ChengSeedLoweringPlanStub *lowering,
                                                    const char *owner_module_path,
                                                    const char *type_text,
                                                    char *name_out,
                                                    size_t name_cap) {
    const char *tail;
    size_t i;
    if (!lowering ||
        !owner_module_path || owner_module_path[0] == '\0' ||
        !type_text || type_text[0] == '\0' ||
        !name_out || name_cap == 0U ||
        !cheng_seed_startswith(type_text, owner_module_path)) {
        return false;
    }
    tail = type_text + strlen(owner_module_path);
    if (tail[0] != ':' || tail[1] != ':') {
        return false;
    }
    tail += 2;
    if (!cheng_seed_ident_start_char(*tail)) {
        return false;
    }
    for (i = 0U; tail[i] != '\0'; ++i) {
        if (!cheng_seed_ident_char(tail[i])) {
            return false;
        }
    }
    if (cheng_seed_find_type_def_index_by_symbol(lowering, owner_module_path, tail) >= 0) {
        return false;
    }
    snprintf(name_out, name_cap, "%s", tail);
    return true;
}

static int32_t cheng_seed_find_generic_binding_index(const char generic_names[][128],
                                             size_t generic_count,
                                             const char *generic_name) {
    size_t i;
    for (i = 0U; i < generic_count; ++i) {
        if (strcmp(generic_names[i], generic_name) == 0) {
            return (int32_t)i;
        }
    }
    return -1;
}

static bool cheng_seed_normalize_type_text_for_function(const ChengSeedLoweringPlanStub *lowering,
                                                const ChengSeedLoweredFunctionStub *function,
                                                const ChengSeedImportAlias *aliases,
                                                size_t alias_count,
                                                const char *type_text,
                                                char *out,
                                                size_t cap) {
    char bound_type[CHENG_MAX_TYPE_TEXT];
    char generic_name[128];
    char inner[CHENG_MAX_TYPE_TEXT];
    int32_t fixed_len = 0;
    int32_t pointer_depth = 0;
    size_t i;
    if (!lowering || !function) {
        return false;
    }
    if (function->generic_binding_count > 0U) {
        cheng_seed_trim_copy_text(type_text, bound_type, sizeof(bound_type));
        if (cheng_seed_extract_function_generic_placeholder(lowering,
                                                    function->owner_module_path,
                                                    bound_type,
                                                    generic_name,
                                                    sizeof(generic_name))) {
            int32_t binding_index =
                cheng_seed_find_generic_binding_index(function->generic_binding_names,
                                              function->generic_binding_count,
                                              generic_name);
            if (binding_index >= 0) {
                snprintf(bound_type, sizeof(bound_type), "%s", function->generic_binding_types[binding_index]);
            }
        } else if (cheng_seed_parse_result_inner_type(bound_type, inner, sizeof(inner))) {
            if (!cheng_seed_normalize_type_text_for_function(lowering,
                                                     function,
                                                     aliases,
                                                     alias_count,
                                                     inner,
                                                     inner,
                                                     sizeof(inner))) {
                return false;
            }
            snprintf(bound_type, sizeof(bound_type), "Result[%s]", inner);
        } else if (strlen(bound_type) > 2U &&
                   strcmp(bound_type + strlen(bound_type) - 2U, "[]") == 0) {
            snprintf(inner, sizeof(inner), "%.*s", (int)(strlen(bound_type) - 2U), bound_type);
            if (!cheng_seed_normalize_type_text_for_function(lowering,
                                                     function,
                                                     aliases,
                                                     alias_count,
                                                     inner,
                                                     inner,
                                                     sizeof(inner))) {
                return false;
            }
            snprintf(bound_type, sizeof(bound_type), "%s[]", inner);
        } else if (cheng_seed_parse_fixed_array_type(bound_type, inner, sizeof(inner), &fixed_len)) {
            if (!cheng_seed_normalize_type_text_for_function(lowering,
                                                     function,
                                                     aliases,
                                                     alias_count,
                                                     inner,
                                                     inner,
                                                     sizeof(inner))) {
                return false;
            }
            snprintf(bound_type, sizeof(bound_type), "%s[%d]", inner, fixed_len);
        } else {
            pointer_depth = cheng_seed_type_text_pointer_depth(bound_type, inner, sizeof(inner));
            if (pointer_depth > 0) {
                if (!cheng_seed_normalize_type_text_for_function(lowering,
                                                         function,
                                                         aliases,
                                                         alias_count,
                                                         inner,
                                                         inner,
                                                         sizeof(inner))) {
                    return false;
                }
                snprintf(bound_type, sizeof(bound_type), "%s", inner);
                for (i = 0U; i < (size_t)pointer_depth; ++i) {
                    size_t used = strlen(bound_type);
                    if (used + 2U >= sizeof(bound_type)) {
                        return false;
                    }
                    snprintf(bound_type + used, sizeof(bound_type) - used, " *");
                }
            }
        }
        return cheng_seed_normalize_type_text_with_params(lowering,
                                                  function->owner_module_path,
                                                  aliases,
                                                  alias_count,
                                                  function->generic_binding_names,
                                                  function->generic_binding_types,
                                                  function->generic_binding_count,
                                                  bound_type,
                                                  out,
                                                  cap);
    }
    return cheng_seed_normalize_type_text(lowering,
                                  function->owner_module_path,
                                  aliases,
                                  alias_count,
                                  type_text,
                                  out,
                                  cap);
}

static bool cheng_seed_type_text_contains_function_placeholder(const ChengSeedLoweringPlanStub *lowering,
                                                       const char *owner_module_path,
                                                       const char *type_text,
                                                       unsigned depth) {
    char stripped[256];
    const char *cursor;
    if (!lowering || !owner_module_path || !type_text || depth > 16U) {
        return false;
    }
    cheng_seed_strip_var_prefix(type_text, stripped, sizeof(stripped));
    if (stripped[0] == '\0') {
        return false;
    }
    cursor = stripped;
    while ((cursor = strstr(cursor, owner_module_path)) != NULL) {
        const char *tail = cursor + strlen(owner_module_path);
        char ident[128];
        size_t ident_len = 0U;
        if (tail[0] != ':' || tail[1] != ':') {
            cursor += 1;
            continue;
        }
        tail += 2;
        if (!cheng_seed_ident_start_char(*tail)) {
            cursor += 1;
            continue;
        }
        while (tail[ident_len] != '\0' &&
               cheng_seed_ident_char(tail[ident_len]) &&
               ident_len + 1U < sizeof(ident)) {
            ident[ident_len] = tail[ident_len];
            ident_len += 1U;
        }
        ident[ident_len] = '\0';
        if (ident_len > 0U &&
            cheng_seed_find_type_def_index_by_symbol(lowering, owner_module_path, ident) < 0) {
            return true;
        }
        cursor = tail + ident_len;
    }
    return false;
}

static bool cheng_seed_function_has_unbound_generics(const ChengSeedLoweringPlanStub *lowering,
                                             const ChengSeedLoweredFunctionStub *function) {
    size_t i;
    if (!lowering || !function || function->generic_binding_count > 0U) {
        return false;
    }
    if (cheng_seed_type_text_contains_function_placeholder(lowering,
                                                   function->owner_module_path,
                                                   function->return_type,
                                                   0U)) {
        return true;
    }
    for (i = 0U; i < function->param_count; ++i) {
        if (cheng_seed_type_text_contains_function_placeholder(lowering,
                                                       function->owner_module_path,
                                                       function->param_types[i],
                                                       0U)) {
            return true;
        }
    }
    return false;
}

static bool cheng_seed_type_text_contains_obvious_template_ident(const char *type_text) {
    const char *cursor;
    if (!type_text || type_text[0] == '\0') {
        return false;
    }
    cursor = type_text;
    while ((cursor = strstr(cursor, "::")) != NULL) {
        const char *ident = cursor + 2;
        if ((ident[0] == 'T' || ident[0] == 'K' || ident[0] == 'V') &&
            !cheng_seed_ident_char(ident[1])) {
            return true;
        }
        cursor = ident;
        if (*cursor != '\0') {
            cursor += 1;
        }
    }
    return false;
}

static bool cheng_seed_function_has_obvious_template_text(const ChengSeedLoweredFunctionStub *function) {
    size_t i;
    if (!function) {
        return false;
    }
    if (function->generic_binding_count > 0U) {
        return false;
    }
    if (cheng_seed_type_text_contains_obvious_template_ident(function->return_type)) {
        return true;
    }
    for (i = 0U; i < function->param_count; ++i) {
        if (cheng_seed_type_text_contains_obvious_template_ident(function->param_types[i])) {
            return true;
        }
    }
    return false;
}

static bool cheng_seed_resolve_bound_elem_size_value(const ChengSeedLoweringPlanStub *lowering,
                                             const ChengSeedLoweredFunctionStub *current_function,
                                             const ChengSeedImportAlias *aliases,
                                             size_t alias_count,
                                             const char *callee_text,
                                             int32_t *size_out) {
    char base_name[PATH_MAX];
    char type_arg[CHENG_MAX_TYPE_TEXT];
    char normalized_type[CHENG_MAX_TYPE_TEXT];
    ChengSeedTypeLayoutStub layout;
    const char *base;
    if (!lowering || !current_function || !callee_text || !size_out) {
        return false;
    }
    cheng_seed_strip_trailing_type_args_text(callee_text, base_name, sizeof(base_name));
    base = strrchr(base_name, '.');
    base = base ? base + 1 : base_name;
    if (strcmp(base, "elemSize") != 0 ||
        !cheng_seed_extract_trailing_type_arg_text(callee_text, type_arg, sizeof(type_arg))) {
        return false;
    }
    if (!cheng_seed_normalize_type_text_for_function(lowering,
                                             current_function,
                                             aliases,
                                             alias_count,
                                             type_arg,
                                             normalized_type,
                                             sizeof(normalized_type)) ||
        !cheng_seed_compute_type_layout_impl(lowering, normalized_type, &layout, 0U)) {
        return false;
    }
    *size_out = layout.size;
    return true;
}

static void cheng_seed_specialized_function_name(const ChengSeedLoweredFunctionStub *function,
                                         const char generic_names[][128],
                                         const char generic_types[][256],
                                         size_t generic_count,
                                         char *out,
                                         size_t cap) {
    char key[4096];
    uint64_t hash;
    size_t i;
    snprintf(key, sizeof(key), "%s", function->symbol_text);
    for (i = 0U; i < generic_count; ++i) {
        size_t used = strlen(key);
        if (used + 4U >= sizeof(key)) {
            break;
        }
        snprintf(key + used,
                 sizeof(key) - used,
                 "|%s=%s",
                 generic_names[i],
                 generic_types[i]);
    }
    hash = cheng_seed_fnv1a64(key);
    snprintf(out, cap, "%s$g%016llx", function->function_name, (unsigned long long)hash);
}

static bool cheng_seed_ensure_specialized_function(const ChengSeedLoweringPlanStub *lowering,
                                           const ChengSeedLoweredFunctionStub *template_function,
                                           const char generic_names[][128],
                                           const char generic_types[][256],
                                           size_t generic_count,
                                           char *out_symbol,
                                           size_t out_symbol_cap) {
    ChengSeedLoweringPlanStub *mutable_lowering = (ChengSeedLoweringPlanStub *)lowering;
    char specialized_name[128];
    char specialized_symbol[PATH_MAX];
    size_t i;
    if (!mutable_lowering || !template_function || !out_symbol || out_symbol_cap == 0U) {
        return false;
    }
    if (generic_count == 0U) {
        snprintf(out_symbol, out_symbol_cap, "%s", template_function->symbol_text);
        return true;
    }
    cheng_seed_specialized_function_name(template_function,
                                 generic_names,
                                 generic_types,
                                 generic_count,
                                 specialized_name,
                                 sizeof(specialized_name));
    snprintf(specialized_symbol,
             sizeof(specialized_symbol),
             "%s::%s",
             template_function->owner_module_path,
             specialized_name);
    for (i = 0U; i < mutable_lowering->function_count; ++i) {
        if (strcmp(mutable_lowering->functions[i].symbol_text, specialized_symbol) == 0) {
            snprintf(out_symbol, out_symbol_cap, "%s", specialized_symbol);
            return true;
        }
    }
    if (!cheng_seed_lowering_plan_reserve_functions(mutable_lowering,
                                            mutable_lowering->function_count + 1U)) {
        return false;
    }
    mutable_lowering->functions[mutable_lowering->function_count] = *template_function;
    snprintf(mutable_lowering->functions[mutable_lowering->function_count].function_name,
             sizeof(mutable_lowering->functions[mutable_lowering->function_count].function_name),
             "%s",
             specialized_name);
    snprintf(mutable_lowering->functions[mutable_lowering->function_count].symbol_text,
             sizeof(mutable_lowering->functions[mutable_lowering->function_count].symbol_text),
             "%s",
             specialized_symbol);
    mutable_lowering->functions[mutable_lowering->function_count].generic_binding_count = generic_count;
    memset(mutable_lowering->functions[mutable_lowering->function_count].generic_binding_names,
           0,
           sizeof(mutable_lowering->functions[mutable_lowering->function_count].generic_binding_names));
    memset(mutable_lowering->functions[mutable_lowering->function_count].generic_binding_types,
           0,
           sizeof(mutable_lowering->functions[mutable_lowering->function_count].generic_binding_types));
    for (i = 0U; i < generic_count && i < CHENG_MAX_TYPE_PARAMS; ++i) {
        snprintf(mutable_lowering->functions[mutable_lowering->function_count].generic_binding_names[i],
                 sizeof(mutable_lowering->functions[mutable_lowering->function_count].generic_binding_names[i]),
                 "%s",
                 generic_names[i]);
        snprintf(mutable_lowering->functions[mutable_lowering->function_count].generic_binding_types[i],
                 sizeof(mutable_lowering->functions[mutable_lowering->function_count].generic_binding_types[i]),
                 "%s",
                 generic_types[i]);
    }
    mutable_lowering->functions[mutable_lowering->function_count].callee_count = 0U;
    mutable_lowering->functions[mutable_lowering->function_count].reachable = true;
    mutable_lowering->function_count += 1U;
    snprintf(out_symbol, out_symbol_cap, "%s", specialized_symbol);
    return true;
}

static bool cheng_seed_overload_match_type(const ChengSeedLoweringPlanStub *lowering,
                                   const char *candidate_owner_module_path,
                                   const char *param_type,
                                   const char *arg_type,
                                   char generic_names[][128],
                                   char generic_types[][256],
                                   size_t *generic_count_io,
                                   int32_t *score_io,
                                   unsigned depth) {
    char trimmed_param[256];
    char trimmed_arg[256];
    char generic_name[128];
    char param_inner[256];
    char arg_inner[256];
    char normalized_param[256];
    char normalized_arg[256];
    int32_t fixed_param_len = 0;
    int32_t fixed_arg_len = 0;
    int32_t pointer_depth_param = 0;
    int32_t pointer_depth_arg = 0;
    if (!lowering || !candidate_owner_module_path || !param_type || !arg_type ||
        !generic_count_io || !score_io || depth > 16U) {
        return false;
    }
    cheng_seed_trim_copy_text(param_type, trimmed_param, sizeof(trimmed_param));
    cheng_seed_trim_copy_text(arg_type, trimmed_arg, sizeof(trimmed_arg));
    if (trimmed_param[0] == '\0' || trimmed_arg[0] == '\0') {
        return false;
    }
    if (!cheng_seed_normalize_type_text(lowering,
                                candidate_owner_module_path,
                                NULL,
                                0U,
                                trimmed_param,
                                normalized_param,
                                sizeof(normalized_param))) {
        snprintf(normalized_param, sizeof(normalized_param), "%s", trimmed_param);
    }
    if (!cheng_seed_normalize_type_text(lowering,
                                candidate_owner_module_path,
                                NULL,
                                0U,
                                trimmed_arg,
                                normalized_arg,
                                sizeof(normalized_arg))) {
        snprintf(normalized_arg, sizeof(normalized_arg), "%s", trimmed_arg);
    }
    if (strcmp(normalized_param, "int") == 0) {
        snprintf(normalized_param, sizeof(normalized_param), "%s", "int32");
    } else if (strcmp(normalized_param, "uint") == 0) {
        snprintf(normalized_param, sizeof(normalized_param), "%s", "uint32");
    }
    if (strcmp(normalized_arg, "int") == 0) {
        snprintf(normalized_arg, sizeof(normalized_arg), "%s", "int32");
    } else if (strcmp(normalized_arg, "uint") == 0) {
        snprintf(normalized_arg, sizeof(normalized_arg), "%s", "uint32");
    }
    if (strcmp(trimmed_arg, "nil") == 0) {
        if (strcmp(normalized_param, "ptr") == 0 ||
            strcmp(normalized_param, "cstring") == 0 ||
            cheng_seed_type_text_pointer_depth(normalized_param, param_inner, sizeof(param_inner)) > 0 ||
            cheng_seed_is_internal_ref_type(normalized_param)) {
            *score_io += 1;
            return true;
        }
        return false;
    }
    if (strcmp(normalized_param, normalized_arg) == 0 ||
        strcmp(trimmed_param, trimmed_arg) == 0) {
        *score_io += 4;
        return true;
    }
    if (cheng_seed_extract_function_generic_placeholder(lowering,
                                                candidate_owner_module_path,
                                                trimmed_param,
                                                generic_name,
                                                sizeof(generic_name))) {
        int32_t binding_index = cheng_seed_find_generic_binding_index(generic_names,
                                                              *generic_count_io,
                                                              generic_name);
        if (binding_index >= 0) {
            return cheng_seed_overload_match_type(lowering,
                                          candidate_owner_module_path,
                                          generic_types[binding_index],
                                          trimmed_arg,
                                          generic_names,
                                          generic_types,
                                          generic_count_io,
                                          score_io,
                                          depth + 1U);
        }
        if (*generic_count_io >= CHENG_MAX_TYPE_PARAMS) {
            return false;
        }
        snprintf(generic_names[*generic_count_io], 128, "%s", generic_name);
        snprintf(generic_types[*generic_count_io], 256, "%s", trimmed_arg);
        *generic_count_io += 1U;
        *score_io += 1;
        return true;
    }
    if (cheng_seed_parse_result_inner_type(normalized_param, param_inner, sizeof(param_inner)) &&
        cheng_seed_parse_result_inner_type(normalized_arg, arg_inner, sizeof(arg_inner))) {
        *score_io += 1;
        return cheng_seed_overload_match_type(lowering,
                                      candidate_owner_module_path,
                                      param_inner,
                                      arg_inner,
                                      generic_names,
                                      generic_types,
                                      generic_count_io,
                                      score_io,
                                      depth + 1U);
    }
    if (strlen(normalized_param) > 2U &&
        strlen(normalized_arg) > 2U &&
        strcmp(normalized_param + strlen(normalized_param) - 2U, "[]") == 0 &&
        strcmp(normalized_arg + strlen(normalized_arg) - 2U, "[]") == 0) {
        snprintf(param_inner, sizeof(param_inner), "%.*s", (int)(strlen(normalized_param) - 2U), normalized_param);
        snprintf(arg_inner, sizeof(arg_inner), "%.*s", (int)(strlen(normalized_arg) - 2U), normalized_arg);
        *score_io += 1;
        return cheng_seed_overload_match_type(lowering,
                                      candidate_owner_module_path,
                                      param_inner,
                                      arg_inner,
                                      generic_names,
                                      generic_types,
                                      generic_count_io,
                                      score_io,
                                      depth + 1U);
    }
    if (cheng_seed_parse_fixed_array_type(normalized_param,
                                  param_inner,
                                  sizeof(param_inner),
                                  &fixed_param_len) &&
        cheng_seed_parse_fixed_array_type(normalized_arg,
                                  arg_inner,
                                  sizeof(arg_inner),
                                  &fixed_arg_len) &&
        fixed_param_len == fixed_arg_len) {
        *score_io += 1;
        return cheng_seed_overload_match_type(lowering,
                                      candidate_owner_module_path,
                                      param_inner,
                                      arg_inner,
                                      generic_names,
                                      generic_types,
                                      generic_count_io,
                                      score_io,
                                      depth + 1U);
    }
    pointer_depth_param = cheng_seed_type_text_pointer_depth(normalized_param, param_inner, sizeof(param_inner));
    pointer_depth_arg = cheng_seed_type_text_pointer_depth(normalized_arg, arg_inner, sizeof(arg_inner));
    if (pointer_depth_param > 0 && pointer_depth_param == pointer_depth_arg) {
        *score_io += 1;
        return cheng_seed_overload_match_type(lowering,
                                      candidate_owner_module_path,
                                      param_inner,
                                      arg_inner,
                                      generic_names,
                                      generic_types,
                                      generic_count_io,
                                      score_io,
                                      depth + 1U);
    }
    return false;
}

static bool cheng_seed_expr_matches_fixed_array_param_type(const ChengSeedSystemLinkPlanStub *plan,
                                                   const ChengSeedLoweringPlanStub *lowering,
                                                   const ChengSeedLoweredFunctionStub *current_function,
                                                   const ChengSeedImportAlias *aliases,
                                                   size_t alias_count,
                                                   const ChengSeedAsmLocalSlot *locals,
                                                   size_t local_count,
                                                   const char *expr_text,
                                                   const char *candidate_owner_module_path,
                                                   const char *param_type,
                                                   char generic_names[][128],
                                                   char generic_types[][256],
                                                   size_t *generic_count_io,
                                                   int32_t *score_io,
                                                   unsigned depth) {
    char normalized_param[256];
    char elem_type[256];
    char expr[4096];
    char surface_error[256];
    char (*items)[4096] = NULL;
    size_t item_count = 0U;
    int32_t fixed_len = 0;
    size_t i;
    ChengSeedExprSurface surface;
    if (plan == NULL || lowering == NULL || current_function == NULL ||
        expr_text == NULL || candidate_owner_module_path == NULL || param_type == NULL ||
        generic_count_io == NULL || score_io == NULL || depth > 16U) {
        return false;
    }
    if (!cheng_seed_normalize_type_text(lowering,
                                candidate_owner_module_path,
                                NULL,
                                0U,
                                param_type,
                                normalized_param,
                                sizeof(normalized_param))) {
        snprintf(normalized_param, sizeof(normalized_param), "%s", param_type);
    }
    if (!cheng_seed_parse_fixed_array_type(normalized_param,
                                   elem_type,
                                   sizeof(elem_type),
                                   &fixed_len)) {
        return false;
    }
    if (!cheng_seed_classify_expr_surface(expr_text, &surface, surface_error, sizeof(surface_error))) {
        return false;
    }
    snprintf(expr, sizeof(expr), "%s", surface.text);
    if (surface.kind == ChengSeed_EXPR_SURFACE_IF || surface.kind == ChengSeed_EXPR_SURFACE_TERNARY) {
        char temp_generic_names[CHENG_MAX_TYPE_PARAMS][128];
        char temp_generic_types[CHENG_MAX_TYPE_PARAMS][256];
        size_t temp_generic_count = *generic_count_io;
        int32_t temp_score = *score_io;
        memcpy(temp_generic_names, generic_names, sizeof(temp_generic_names));
        memcpy(temp_generic_types, generic_types, sizeof(temp_generic_types));
        if (!cheng_seed_expr_matches_fixed_array_param_type(plan,
                                                    lowering,
                                                    current_function,
                                                    aliases,
                                                    alias_count,
                                                    locals,
                                                    local_count,
                                                    surface.when_true,
                                                    candidate_owner_module_path,
                                                    normalized_param,
                                                    temp_generic_names,
                                                    temp_generic_types,
                                                    &temp_generic_count,
                                                    &temp_score,
                                                    depth + 1U) ||
            !cheng_seed_expr_matches_fixed_array_param_type(plan,
                                                    lowering,
                                                    current_function,
                                                    aliases,
                                                    alias_count,
                                                    locals,
                                                    local_count,
                                                    surface.when_false,
                                                    candidate_owner_module_path,
                                                    normalized_param,
                                                    temp_generic_names,
                                                    temp_generic_types,
                                                    &temp_generic_count,
                                                    &temp_score,
                                                    depth + 1U)) {
            return false;
        }
        memcpy(generic_names, temp_generic_names, sizeof(temp_generic_names));
        memcpy(generic_types, temp_generic_types, sizeof(temp_generic_types));
        *generic_count_io = temp_generic_count;
        *score_io = temp_score + 1;
        return true;
    }
    if (!cheng_seed_parse_list_literal_text_alloc(expr, &items, &item_count) ||
        item_count != (size_t)fixed_len) {
        free(items);
        return false;
    }
    for (i = 0U; i < item_count; ++i) {
        char nested_elem_type[256];
        int32_t nested_fixed_len = 0;
        if (cheng_seed_parse_fixed_array_type(elem_type,
                                      nested_elem_type,
                                      sizeof(nested_elem_type),
                                      &nested_fixed_len)) {
            if (!cheng_seed_expr_matches_fixed_array_param_type(plan,
                                                        lowering,
                                                        current_function,
                                                        aliases,
                                                        alias_count,
                                                        locals,
                                                        local_count,
                                                        items[i],
                                                        candidate_owner_module_path,
                                                        elem_type,
                                                        generic_names,
                                                        generic_types,
                                                        generic_count_io,
                                                        score_io,
                                                        depth + 1U)) {
                free(items);
                return false;
            }
            continue;
        }
        {
            char item_type[256];
            char item_abi[32];
            if (!cheng_seed_infer_expr_type(plan,
                                    lowering,
                                    current_function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    items[i],
                                    item_type,
                                    sizeof(item_type),
                                    item_abi,
                                    sizeof(item_abi)) ||
                !cheng_seed_overload_match_type(lowering,
                                        candidate_owner_module_path,
                                        elem_type,
                                        item_type,
                                        generic_names,
                                        generic_types,
                                        generic_count_io,
                                        score_io,
                                        depth + 1U)) {
                free(items);
                return false;
            }
        }
    }
    free(items);
    *score_io += 1;
    return true;
}

static bool cheng_seed_expr_can_bind_var_arg(const ChengSeedAsmLocalSlot *locals,
                                     size_t local_count,
                                     const char *expr_text) {
    char trimmed[4096];
    char base_expr[4096];
    char index_expr[4096];
    char field_name[256];
    if (!expr_text) {
        return false;
    }
    cheng_seed_trim_copy_text(expr_text, trimmed, sizeof(trimmed));
    if (trimmed[0] == '\0') {
        return false;
    }
    if (cheng_seed_find_local_slot(locals, local_count, trimmed) >= 0) {
        return true;
    }
    if (cheng_seed_parse_member_access_expr(trimmed,
                                    base_expr,
                                    sizeof(base_expr),
                                    field_name,
                                    sizeof(field_name)) ||
        cheng_seed_parse_index_access_expr(trimmed,
                                   base_expr,
                                   sizeof(base_expr),
                                   index_expr,
                                   sizeof(index_expr))) {
        return true;
    }
    return false;
}

static bool cheng_seed_select_overloaded_function_symbol(const ChengSeedSystemLinkPlanStub *plan,
                                                 const ChengSeedLoweringPlanStub *lowering,
                                                 const ChengSeedLoweredFunctionStub *current_function,
                                                 const ChengSeedImportAlias *aliases,
                                                 size_t alias_count,
                                                 const ChengSeedAsmLocalSlot *locals,
                                                 size_t local_count,
                                                 const char *module_path,
                                                 const char *function_name,
                                                 const char args[][4096],
                                                 size_t arg_count,
                                                 int32_t *selected_index_out,
                                                 char *out,
                                                 size_t cap) {
    int32_t best_index = -1;
    int32_t best_score = -1;
    int32_t best_exact_score = -1;
    bool ambiguous = false;
    const char *trace_overload = getenv("CHENG_TRACE_OVERLOAD");
    char best_generic_names[CHENG_MAX_TYPE_PARAMS][128];
    char best_generic_types[CHENG_MAX_TYPE_PARAMS][256];
    size_t best_generic_count = SIZE_MAX;
    size_t i;
    (void)plan;
    if (selected_index_out != NULL) {
        *selected_index_out = -1;
    }
    if (!lowering || !current_function || !module_path || module_path[0] == '\0' ||
        !function_name || function_name[0] == '\0' || !out || cap == 0U) {
        return false;
    }
    out[0] = '\0';
    for (i = 0U; i < lowering->function_count; ++i) {
        const ChengSeedLoweredFunctionStub *candidate = &lowering->functions[i];
        char generic_names[CHENG_MAX_TYPE_PARAMS][128];
        char generic_types[CHENG_MAX_TYPE_PARAMS][256];
        size_t generic_count = 0U;
        int32_t score = 0;
        int32_t exact_score = 0;
        size_t arg_index;
        if (strcmp(candidate->owner_module_path, module_path) != 0 ||
            strcmp(candidate->function_name, function_name) != 0 ||
            candidate->param_count != arg_count) {
            continue;
        }
        memset(generic_names, 0, sizeof(generic_names));
        memset(generic_types, 0, sizeof(generic_types));
        for (arg_index = 0U; arg_index < arg_count; ++arg_index) {
            char arg_type[256];
            char arg_abi[32];
            char normalized_arg_type[256];
            if (candidate->param_is_var[arg_index] &&
                !cheng_seed_expr_can_bind_var_arg(locals, local_count, args[arg_index])) {
                score = -1;
                break;
            }
            if (strcmp(args[arg_index], "nil") == 0) {
                snprintf(normalized_arg_type, sizeof(normalized_arg_type), "%s", "nil");
            } else if (cheng_seed_expr_matches_fixed_array_param_type(plan,
                                                              lowering,
                                                              current_function,
                                                              aliases,
                                                              alias_count,
                                                              locals,
                                                              local_count,
                                                              args[arg_index],
                                                              candidate->owner_module_path,
                                                              candidate->param_types[arg_index],
                                                              generic_names,
                                                              generic_types,
                                                              &generic_count,
                                                              &score,
                                                              0U)) {
                snprintf(normalized_arg_type,
                         sizeof(normalized_arg_type),
                         "%s",
                         candidate->param_types[arg_index]);
                exact_score += 1;
                continue;
            } else if (strcmp(args[arg_index], "[]") == 0) {
                snprintf(normalized_arg_type, sizeof(normalized_arg_type), "%s", "[]");
            } else if (!cheng_seed_infer_expr_type(plan,
                                           lowering,
                                           current_function,
                                           aliases,
                                           alias_count,
                                           locals,
                                           local_count,
                                           args[arg_index],
                                           arg_type,
                                           sizeof(arg_type),
                                           arg_abi,
                                           sizeof(arg_abi)) ||
                       !cheng_seed_normalize_type_text(lowering,
                                               current_function->owner_module_path,
                                               aliases,
                                               alias_count,
                                               arg_type,
                                               normalized_arg_type,
                                               sizeof(normalized_arg_type))) {
                score = -1;
                break;
            }
            if (strcmp(normalized_arg_type, "[]") == 0) {
                if (!(strlen(candidate->param_types[arg_index]) > 2U &&
                      strcmp(candidate->param_types[arg_index] + strlen(candidate->param_types[arg_index]) - 2U, "[]") == 0)) {
                    score = -1;
                    break;
                }
                score += 1;
                exact_score += 1;
                continue;
            }
            if (!cheng_seed_overload_match_type(lowering,
                                        candidate->owner_module_path,
                                        candidate->param_types[arg_index],
                                        normalized_arg_type,
                                        generic_names,
                                        generic_types,
                                        &generic_count,
                                        &score,
                                        0U)) {
                score = -1;
                break;
            }
            if (strcmp(candidate->param_types[arg_index], normalized_arg_type) == 0) {
                exact_score += 2;
            }
        }
            if (score < 0) {
                if (trace_overload &&
                    trace_overload[0] != '\0' &&
                    (strcmp(trace_overload, "1") == 0 ||
                     strstr(current_function->symbol_text, trace_overload) != NULL ||
                     strstr(function_name, trace_overload) != NULL)) {
                    size_t debug_i;
                    fprintf(stderr,
                        "[cheng_seed] overload reject caller=%s callee=%s candidate=%s params=%zu\n",
                        current_function->symbol_text,
                        function_name,
                        candidate->symbol_text,
                        candidate->param_count);
                    for (debug_i = 0U; debug_i < candidate->param_count; ++debug_i) {
                        fprintf(stderr,
                                "[cheng_seed] overload reject candidate_param[%zu]=%s%s\n",
                                debug_i,
                                candidate->param_is_var[debug_i] ? "var " : "",
                                candidate->param_types[debug_i]);
                    }
                    for (debug_i = 0U; debug_i < arg_count; ++debug_i) {
                        char debug_arg_type[256];
                        char debug_arg_abi[32];
                        char debug_normalized_arg[256];
                        debug_arg_type[0] = '\0';
                        debug_arg_abi[0] = '\0';
                        debug_normalized_arg[0] = '\0';
                        if (cheng_seed_infer_expr_type(plan,
                                               lowering,
                                               current_function,
                                               aliases,
                                               alias_count,
                                               locals,
                                               local_count,
                                               args[debug_i],
                                               debug_arg_type,
                                               sizeof(debug_arg_type),
                                               debug_arg_abi,
                                               sizeof(debug_arg_abi)) &&
                            cheng_seed_normalize_type_text(lowering,
                                                   current_function->owner_module_path,
                                                   aliases,
                                                   alias_count,
                                                   debug_arg_type,
                                                   debug_normalized_arg,
                                                   sizeof(debug_normalized_arg))) {
                            fprintf(stderr,
                                    "[cheng_seed] overload reject arg[%zu]=%s type=%s normalized=%s abi=%s\n",
                                    debug_i,
                                    args[debug_i],
                                    debug_arg_type,
                                    debug_normalized_arg,
                                    debug_arg_abi);
                        } else {
                            fprintf(stderr,
                                    "[cheng_seed] overload reject arg[%zu]=%s type=<infer-failed>\n",
                                    debug_i,
                                    args[debug_i]);
                        }
                    }
                }
                continue;
            }
        if (trace_overload &&
            trace_overload[0] != '\0' &&
            (strcmp(trace_overload, "1") == 0 ||
             strstr(current_function->symbol_text, trace_overload) != NULL ||
             strstr(function_name, trace_overload) != NULL)) {
            char signature[1024];
            size_t sig_used = 0U;
            size_t sig_i;
            signature[0] = '\0';
            sig_used = (size_t)snprintf(signature,
                                        sizeof(signature),
                                        "%s(",
                                        candidate->function_name);
            for (sig_i = 0U; sig_i < candidate->param_count && sig_used + 8U < sizeof(signature); ++sig_i) {
                sig_used += (size_t)snprintf(signature + sig_used,
                                             sizeof(signature) - sig_used,
                                             "%s%s%s",
                                             sig_i == 0U ? "" : ", ",
                                             candidate->param_is_var[sig_i] ? "var " : "",
                                             candidate->param_types[sig_i]);
            }
            if (sig_used + 8U < sizeof(signature)) {
                snprintf(signature + sig_used,
                         sizeof(signature) - sig_used,
                         "): %s",
                         candidate->return_type);
            }
            fprintf(stderr,
                    "[cheng_seed] overload match caller=%s callee=%s candidate=%s signature=%s source=%s:%zu score=%d exact=%d generic_count=%zu\n",
                    current_function->symbol_text,
                    function_name,
                    candidate->symbol_text,
                    signature,
                    candidate->source_path,
                    candidate->signature_line_number,
                    score,
                    exact_score,
                    generic_count);
        }
        if (score > best_score) {
            best_index = (int32_t)i;
            best_score = score;
            best_exact_score = exact_score;
            ambiguous = false;
            best_generic_count = generic_count;
            memcpy(best_generic_names, generic_names, sizeof(best_generic_names));
            memcpy(best_generic_types, generic_types, sizeof(best_generic_types));
        } else if (score == best_score && exact_score > best_exact_score) {
            best_index = (int32_t)i;
            best_exact_score = exact_score;
            ambiguous = false;
            best_generic_count = generic_count;
            memcpy(best_generic_names, generic_names, sizeof(best_generic_names));
            memcpy(best_generic_types, generic_types, sizeof(best_generic_types));
        } else if (score == best_score &&
                   exact_score == best_exact_score &&
                   generic_count < best_generic_count) {
            best_index = (int32_t)i;
            ambiguous = false;
            best_generic_count = generic_count;
            memcpy(best_generic_names, generic_names, sizeof(best_generic_names));
            memcpy(best_generic_types, generic_types, sizeof(best_generic_types));
        } else if (score == best_score && exact_score == best_exact_score) {
            ambiguous = true;
        }
    }
    if (best_index < 0 || ambiguous) {
        if (trace_overload &&
            trace_overload[0] != '\0' &&
            (strcmp(trace_overload, "1") == 0 ||
             strstr(current_function->symbol_text, trace_overload) != NULL ||
             strstr(function_name, trace_overload) != NULL)) {
            fprintf(stderr,
                    "[cheng_seed] overload unresolved caller=%s callee=%s best_index=%d ambiguous=%d\n",
                    current_function->symbol_text,
                    function_name,
                    best_index,
                    ambiguous ? 1 : 0);
        }
        return false;
    }
    if (trace_overload &&
        trace_overload[0] != '\0' &&
        (strcmp(trace_overload, "1") == 0 ||
         strstr(current_function->symbol_text, trace_overload) != NULL ||
         strstr(function_name, trace_overload) != NULL)) {
        fprintf(stderr,
                "[cheng_seed] overload pick caller=%s callee=%s winner=%s\n",
                current_function->symbol_text,
                function_name,
                lowering->functions[best_index].symbol_text);
    }
    if (trace_overload &&
        trace_overload[0] != '\0' &&
        (strcmp(trace_overload, "1") == 0 ||
         strstr(current_function->symbol_text, trace_overload) != NULL ||
         strstr(function_name, trace_overload) != NULL)) {
        fprintf(stderr,
                "[cheng_seed] overload pick caller=%s callee=%s winner=%s score=%d exact=%d\n",
                current_function->symbol_text,
                function_name,
                lowering->functions[best_index].symbol_text,
                best_score,
                best_exact_score);
    }
    if (!cheng_seed_ensure_specialized_function(lowering,
                                        &lowering->functions[best_index],
                                        best_generic_names,
                                        best_generic_types,
                                        best_generic_count,
                                        out,
                                        cap)) {
        return false;
    }
    if (selected_index_out != NULL) {
        int32_t resolved_index = cheng_seed_find_lowered_function_index_by_symbol(lowering, out);
        *selected_index_out = resolved_index >= 0 ? resolved_index : best_index;
    }
    return true;
}

static bool cheng_seed_select_visible_overloaded_function_symbol(const ChengSeedSystemLinkPlanStub *plan,
                                                         const ChengSeedLoweringPlanStub *lowering,
                                                         const ChengSeedLoweredFunctionStub *current_function,
                                                         const ChengSeedImportAlias *aliases,
                                                         size_t alias_count,
                                                         const ChengSeedAsmLocalSlot *locals,
                                                         size_t local_count,
                                                         const char *function_name,
                                                         const char args[][4096],
                                                         size_t arg_count,
                                                         int32_t *selected_index_out,
                                                         char *out,
                                                         size_t cap) {
    int32_t best_index = -1;
    int32_t best_score = -1;
    int32_t best_exact_score = -1;
    bool ambiguous = false;
    const char *trace_overload = getenv("CHENG_TRACE_OVERLOAD");
    char best_generic_names[CHENG_MAX_TYPE_PARAMS][128];
    char best_generic_types[CHENG_MAX_TYPE_PARAMS][256];
    size_t best_generic_count = SIZE_MAX;
    size_t i;
    (void)plan;
    if (selected_index_out != NULL) {
        *selected_index_out = -1;
    }
    if (!lowering || !current_function ||
        !function_name || function_name[0] == '\0' || !out || cap == 0U) {
        return false;
    }
    out[0] = '\0';
    for (i = 0U; i < lowering->function_count; ++i) {
        const ChengSeedLoweredFunctionStub *candidate = &lowering->functions[i];
        char generic_names[CHENG_MAX_TYPE_PARAMS][128];
        char generic_types[CHENG_MAX_TYPE_PARAMS][256];
        size_t generic_count = 0U;
        int32_t score = 0;
        int32_t exact_score = 0;
        size_t arg_index;
        if (strcmp(candidate->function_name, function_name) != 0 ||
            candidate->param_count != arg_count ||
            !cheng_seed_function_name_visible_from_module(current_function->owner_module_path,
                                                  aliases,
                                                  alias_count,
                                                  candidate->owner_module_path,
                                                  function_name)) {
            continue;
        }
        memset(generic_names, 0, sizeof(generic_names));
        memset(generic_types, 0, sizeof(generic_types));
        for (arg_index = 0U; arg_index < arg_count; ++arg_index) {
            char arg_type[256];
            char arg_abi[32];
            char normalized_arg_type[256];
            if (candidate->param_is_var[arg_index] &&
                !cheng_seed_expr_can_bind_var_arg(locals, local_count, args[arg_index])) {
                score = -1;
                break;
            }
            if (strcmp(args[arg_index], "nil") == 0) {
                snprintf(normalized_arg_type, sizeof(normalized_arg_type), "%s", "nil");
            } else if (cheng_seed_expr_matches_fixed_array_param_type(plan,
                                                              lowering,
                                                              current_function,
                                                              aliases,
                                                              alias_count,
                                                              locals,
                                                              local_count,
                                                              args[arg_index],
                                                              candidate->owner_module_path,
                                                              candidate->param_types[arg_index],
                                                              generic_names,
                                                              generic_types,
                                                              &generic_count,
                                                              &score,
                                                              0U)) {
                snprintf(normalized_arg_type,
                         sizeof(normalized_arg_type),
                         "%s",
                         candidate->param_types[arg_index]);
                exact_score += 1;
                continue;
            } else if (strcmp(args[arg_index], "[]") == 0) {
                snprintf(normalized_arg_type, sizeof(normalized_arg_type), "%s", "[]");
            } else if (!cheng_seed_infer_expr_type(plan,
                                           lowering,
                                           current_function,
                                           aliases,
                                           alias_count,
                                           locals,
                                           local_count,
                                           args[arg_index],
                                           arg_type,
                                           sizeof(arg_type),
                                           arg_abi,
                                           sizeof(arg_abi)) ||
                       !cheng_seed_normalize_type_text(lowering,
                                               current_function->owner_module_path,
                                               aliases,
                                               alias_count,
                                               arg_type,
                                               normalized_arg_type,
                                               sizeof(normalized_arg_type))) {
                score = -1;
                break;
            }
            if (strcmp(normalized_arg_type, "[]") == 0) {
                if (!(strlen(candidate->param_types[arg_index]) > 2U &&
                      strcmp(candidate->param_types[arg_index] +
                                 strlen(candidate->param_types[arg_index]) - 2U,
                             "[]") == 0)) {
                    score = -1;
                    break;
                }
                score += 1;
                exact_score += 1;
                continue;
            }
            if (!cheng_seed_overload_match_type(lowering,
                                        candidate->owner_module_path,
                                        candidate->param_types[arg_index],
                                        normalized_arg_type,
                                        generic_names,
                                        generic_types,
                                        &generic_count,
                                        &score,
                                        0U)) {
                score = -1;
                break;
            }
            if (strcmp(candidate->param_types[arg_index], normalized_arg_type) == 0) {
                exact_score += 2;
            }
        }
        if (score < 0) {
            continue;
        }
        if (trace_overload &&
            trace_overload[0] != '\0' &&
            (strcmp(trace_overload, "1") == 0 ||
             strstr(current_function->symbol_text, trace_overload) != NULL ||
             strstr(function_name, trace_overload) != NULL)) {
            char signature[1024];
            size_t sig_used = 0U;
            size_t sig_i;
            signature[0] = '\0';
            sig_used = (size_t)snprintf(signature,
                                        sizeof(signature),
                                        "%s(",
                                        candidate->function_name);
            for (sig_i = 0U; sig_i < candidate->param_count && sig_used + 8U < sizeof(signature); ++sig_i) {
                sig_used += (size_t)snprintf(signature + sig_used,
                                             sizeof(signature) - sig_used,
                                             "%s%s%s",
                                             sig_i == 0U ? "" : ", ",
                                             candidate->param_is_var[sig_i] ? "var " : "",
                                             candidate->param_types[sig_i]);
            }
            if (sig_used + 8U < sizeof(signature)) {
                snprintf(signature + sig_used,
                         sizeof(signature) - sig_used,
                         "): %s",
                         candidate->return_type);
            }
            fprintf(stderr,
                    "[cheng_seed] overload match caller=%s callee=%s candidate=%s signature=%s source=%s:%zu score=%d exact=%d generic_count=%zu\n",
                    current_function->symbol_text,
                    function_name,
                    candidate->symbol_text,
                    signature,
                    candidate->source_path,
                    candidate->signature_line_number,
                    score,
                    exact_score,
                    generic_count);
        }
        if (score > best_score) {
            best_index = (int32_t)i;
            best_score = score;
            best_exact_score = exact_score;
            ambiguous = false;
            best_generic_count = generic_count;
            memcpy(best_generic_names, generic_names, sizeof(best_generic_names));
            memcpy(best_generic_types, generic_types, sizeof(best_generic_types));
        } else if (score == best_score && exact_score > best_exact_score) {
            best_index = (int32_t)i;
            best_exact_score = exact_score;
            ambiguous = false;
            best_generic_count = generic_count;
            memcpy(best_generic_names, generic_names, sizeof(best_generic_names));
            memcpy(best_generic_types, generic_types, sizeof(best_generic_types));
        } else if (score == best_score &&
                   exact_score == best_exact_score &&
                   generic_count < best_generic_count) {
            best_index = (int32_t)i;
            ambiguous = false;
            best_generic_count = generic_count;
            memcpy(best_generic_names, generic_names, sizeof(best_generic_names));
            memcpy(best_generic_types, generic_types, sizeof(best_generic_types));
        } else if (score == best_score && exact_score == best_exact_score) {
            ambiguous = true;
        }
    }
    if (best_index < 0 || ambiguous) {
        if (trace_overload &&
            trace_overload[0] != '\0' &&
            (strcmp(trace_overload, "1") == 0 ||
             strstr(current_function->symbol_text, trace_overload) != NULL ||
             strstr(function_name, trace_overload) != NULL)) {
            fprintf(stderr,
                    "[cheng_seed] overload unresolved caller=%s callee=%s best_index=%d ambiguous=%d\n",
                    current_function->symbol_text,
                    function_name,
                    best_index,
                    ambiguous ? 1 : 0);
        }
        return false;
    }
    if (trace_overload &&
        trace_overload[0] != '\0' &&
        (strcmp(trace_overload, "1") == 0 ||
         strstr(current_function->symbol_text, trace_overload) != NULL ||
         strstr(function_name, trace_overload) != NULL)) {
        fprintf(stderr,
                "[cheng_seed] overload pick caller=%s callee=%s winner=%s score=%d exact=%d\n",
                current_function->symbol_text,
                function_name,
                lowering->functions[best_index].symbol_text,
                best_score,
                best_exact_score);
    }
    if (!cheng_seed_ensure_specialized_function(lowering,
                                        &lowering->functions[best_index],
                                        best_generic_names,
                                        best_generic_types,
                                        best_generic_count,
                                        out,
                                        cap)) {
        return false;
    }
    if (selected_index_out != NULL) {
        int32_t resolved_index = cheng_seed_find_lowered_function_index_by_symbol(lowering, out);
        *selected_index_out = resolved_index >= 0 ? resolved_index : best_index;
    }
    return true;
}

static bool cheng_seed_resolve_call_target_with_args(const ChengSeedSystemLinkPlanStub *plan,
                                             const ChengSeedLoweringPlanStub *lowering,
                                             const ChengSeedLoweredFunctionStub *current_function,
                                             const ChengSeedImportAlias *aliases,
                                             size_t alias_count,
                                             const ChengSeedAsmLocalSlot *locals,
                                             size_t local_count,
                                             const char *callee,
                                             const char args[][4096],
                                             size_t arg_count,
                                             ChengSeedAsmCallTarget *target) {
    char trimmed_callee[PATH_MAX];
    char canonical_callee[PATH_MAX];
    char symbol_text[PATH_MAX];
    int32_t function_index;
    int32_t selected_function_index = -1;
    int32_t char_value = 0;
    bool resolved = false;
    if (!plan || !lowering || !current_function || !callee || !target) {
        return false;
    }
    cheng_seed_trim_copy_text(callee, trimmed_callee, sizeof(trimmed_callee));
    if (trimmed_callee[0] == '\0') {
        return false;
    }
    if (cheng_seed_parse_int_literal_text(trimmed_callee, NULL) ||
        cheng_seed_parse_char_literal_text(trimmed_callee, &char_value) ||
        strcmp(trimmed_callee, "true") == 0 ||
        strcmp(trimmed_callee, "false") == 0 ||
        strcmp(trimmed_callee, "nil") == 0 ||
        (trimmed_callee[0] == '"' &&
         trimmed_callee[strlen(trimmed_callee) - 1U] == '"')) {
        return false;
    }
    callee = trimmed_callee;
    snprintf(canonical_callee, sizeof(canonical_callee), "%s", callee);
    if (current_function != NULL &&
        !cheng_seed_canonicalize_static_str_join_call(current_function->owner_module_path,
                                              aliases,
                                              alias_count,
                                              canonical_callee,
                                              sizeof(canonical_callee),
                                              args,
                                              &arg_count,
                                              NULL)) {
        return false;
    }
    callee = canonical_callee;
    symbol_text[0] = '\0';
    if (strchr(callee, '.') == NULL &&
        cheng_seed_is_strformat_join_name(callee) &&
        cheng_seed_resolve_strformat_join_call_target(plan, callee, target)) {
        if (args != NULL && arg_count != target->param_count) {
            return false;
        }
        return true;
    }
    if (strchr(callee, '.') != NULL) {
        char callee_copy[PATH_MAX];
        char *dot;
        const char *module_path;
        const char *function_name;
        snprintf(callee_copy, sizeof(callee_copy), "%s", callee);
        dot = strchr(callee_copy, '.');
        *dot = '\0';
        module_path = cheng_seed_alias_module_path_exported_member(aliases,
                                                           alias_count,
                                                           current_function->owner_module_path,
                                                           callee_copy,
                                                           dot + 1,
                                                           sizeof(callee_copy) - (size_t)((dot + 1) - callee_copy));
        if (module_path) {
            function_name = dot + 1;
            if (cheng_seed_resolve_intrinsic_module_call_target(module_path, plan, function_name, target)) {
                return true;
            }
            if (args != NULL &&
                cheng_seed_select_overloaded_function_symbol(plan,
                                                     lowering,
                                                     current_function,
                                                     aliases,
                                                     alias_count,
                                                     locals,
                                                     local_count,
                                                     module_path,
                                                     function_name,
                                                     args,
                                                     arg_count,
                                                     &selected_function_index,
                                                     symbol_text,
                                                     sizeof(symbol_text))) {
                resolved = true;
            } else {
                int32_t unique_index =
                    cheng_seed_find_unique_lowered_function_index_by_module_and_name(lowering,
                                                                            module_path,
                                                                            function_name);
                if (unique_index >= 0) {
                    snprintf(symbol_text,
                             sizeof(symbol_text),
                             "%s",
                             lowering->functions[unique_index].symbol_text);
                    resolved = true;
                } else if (cheng_seed_resolve_importc_call_target_from_module_path(plan,
                                                                           lowering,
                                                                           module_path,
                                                                           function_name,
                                                                           target)) {
                    return true;
                }
            }
        }
    } else if (!cheng_seed_is_intrinsic_call_name(callee) &&
               ((args != NULL &&
                 cheng_seed_select_visible_overloaded_function_symbol(plan,
                                                              lowering,
                                                              current_function,
                                                              aliases,
                                                              alias_count,
                                                              locals,
                                                              local_count,
                                                              callee,
                                                              args,
                                                              arg_count,
                                                              &selected_function_index,
                                                              symbol_text,
                                                              sizeof(symbol_text))) ||
                cheng_seed_resolve_bare_call_symbol(lowering,
                                            current_function->owner_module_path,
                                            aliases,
                                            alias_count,
                                            callee,
                                            symbol_text,
                                            sizeof(symbol_text)))) {
        resolved = true;
    } else if (!cheng_seed_is_intrinsic_call_name(callee) &&
               cheng_seed_resolve_importc_call_target_from_aliases(plan,
                                                           lowering,
                                                           current_function,
                                                           aliases,
                                                           alias_count,
                                                           callee,
                                                           target)) {
        return true;
    } else if (cheng_seed_const_resolve_call_symbol(aliases,
                                            alias_count,
                                            current_function,
                                            callee,
                                            symbol_text,
                                            sizeof(symbol_text))) {
        resolved = true;
    }
    if (resolved) {
        function_index = -1;
        /* Prefer the resolved symbol text so generic overload picks bind to the
         * specialized clone instead of falling back to the template index. */
        if (symbol_text[0] != '\0') {
            function_index = cheng_seed_find_lowered_function_index_by_symbol(lowering, symbol_text);
        }
        if (function_index < 0 && selected_function_index >= 0) {
            function_index = selected_function_index;
        }
        if (function_index >= 0) {
            const ChengSeedLoweredFunctionStub *callee_function = &lowering->functions[function_index];
            ChengSeedImportAlias callee_aliases[CHENG_MAX_IMPORT_ALIASES];
            size_t callee_alias_count = 0U;
            size_t i;
            if (!cheng_seed_load_import_aliases_from_source_path(callee_function->source_path,
                                                         callee_aliases,
                                                         &callee_alias_count,
                                                         CHENG_MAX_IMPORT_ALIASES)) {
                fprintf(stderr,
                        "[cheng_seed] callee alias load failed: %s\n",
                        callee_function->source_path);
                return false;
            }
            memset(target, 0, sizeof(*target));
            target->ffi_handle_consume_index = -1;
            target->external = false;
            target->lowered_function = callee_function;
            snprintf(target->callee_name, sizeof(target->callee_name), "%s", callee_function->function_name);
            cheng_seed_primary_symbol_name(plan, callee_function, target->symbol_name, sizeof(target->symbol_name));
            {
                char normalized_return_type[CHENG_MAX_TYPE_TEXT];
                char normalized_param_type_texts[CHENG_MAX_CALL_ARGS][CHENG_MAX_TYPE_TEXT];
                const char *normalized_param_types[CHENG_MAX_CALL_ARGS] = {0};
                normalized_return_type[0] = '\0';
                if (!cheng_seed_normalize_type_text_for_function(lowering,
                                                         callee_function,
                                                         callee_aliases,
                                                         callee_alias_count,
                                                         callee_function->return_type,
                                                         normalized_return_type,
                                                         sizeof(normalized_return_type))) {
                    fprintf(stderr,
                            "[cheng_seed] callee return type normalize failed function=%s type=%s\n",
                            callee_function->symbol_text,
                            callee_function->return_type);
                    return false;
                }
                for (i = 0; i < callee_function->param_count && i < CHENG_MAX_CALL_ARGS; ++i) {
                    target->param_is_var[i] = callee_function->param_is_var[i];
                    if (!cheng_seed_normalize_type_text_for_function(lowering,
                                                             callee_function,
                                                             callee_aliases,
                                                             callee_alias_count,
                                                             callee_function->param_types[i],
                                                             normalized_param_type_texts[i],
                                                             sizeof(normalized_param_type_texts[i]))) {
                        fprintf(stderr,
                                "[cheng_seed] callee param type normalize failed function=%s param=%s type=%s\n",
                                callee_function->symbol_text,
                                callee_function->param_names[i],
                                callee_function->param_types[i]);
                        return false;
                    }
                    normalized_param_types[i] = normalized_param_type_texts[i];
                }
                if (!cheng_seed_call_target_set_signature(target,
                                                  normalized_return_type,
                                                  callee_function->param_count,
                                                  normalized_param_types)) {
                    return false;
                }
            }
            return true;
        }
        {
            char symbol_copy[PATH_MAX];
            char *scope;
            char module_path[PATH_MAX];
            char source_path[PATH_MAX];
            snprintf(symbol_copy, sizeof(symbol_copy), "%s", symbol_text);
            scope = strrchr(symbol_copy, ':');
            if (scope && scope != symbol_copy && scope[-1] == ':') {
                scope[-1] = '\0';
                snprintf(module_path, sizeof(module_path), "%s", symbol_copy);
                cheng_seed_module_path_to_source_path(plan->workspace_root,
                                              plan->package_root,
                                              plan->package_id,
                                              module_path,
                                              source_path,
                                              sizeof(source_path));
                if (source_path[0] != '\0' &&
                    cheng_seed_resolve_importc_call_target_from_source_path(plan,
                                                                    lowering,
                                                                    source_path,
                                                                    scope + 1,
                                                                    target)) {
                    return true;
                }
            }
        }
    }
    if (cheng_seed_resolve_importc_call_target_from_source_path(plan,
                                                        lowering,
                                                        current_function->source_path,
                                                        callee,
                                                        target)) {
        return true;
    }
    return cheng_seed_external_call_signature(plan, callee, target);
}

static bool cheng_seed_resolve_return_call_noarg_i32_target(const ChengSeedSystemLinkPlanStub *plan,
                                                    const ChengSeedLoweringPlanStub *lowering,
                                                    const ChengSeedLoweredFunctionStub *current_function,
                                                    ChengSeedAsmCallTarget *target) {
    ChengSeedImportAlias aliases[CHENG_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    if (current_function == NULL || target == NULL ||
        current_function->body_call_target[0] == '\0') {
        return false;
    }
    if (!cheng_seed_load_import_aliases_from_source_path(current_function->source_path,
                                                 aliases,
                                                 &alias_count,
                                                 CHENG_MAX_IMPORT_ALIASES)) {
        fprintf(stderr,
                "[cheng_seed] owner alias load failed: %s\n",
                current_function->source_path);
        return false;
    }
    if (!cheng_seed_resolve_call_target(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                current_function->body_call_target,
                                target)) {
        return false;
    }
    return target->param_count == 0U;
}

static bool cheng_seed_resolve_return_call_arg0_i32_target(const ChengSeedSystemLinkPlanStub *plan,
                                                   const ChengSeedLoweringPlanStub *lowering,
                                                   const ChengSeedLoweredFunctionStub *current_function,
                                                   ChengSeedAsmCallTarget *target) {
    ChengSeedImportAlias aliases[CHENG_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    if (current_function == NULL || target == NULL ||
        current_function->body_call_target[0] == '\0' ||
        current_function->param_count != 1U ||
        strcmp(current_function->param_abi_classes[0], "i32") != 0 ||
        strcmp(current_function->body_call_arg0_name, current_function->param_names[0]) != 0) {
        return false;
    }
    if (!cheng_seed_load_import_aliases_from_source_path(current_function->source_path,
                                                 aliases,
                                                 &alias_count,
                                                 CHENG_MAX_IMPORT_ALIASES)) {
        fprintf(stderr,
                "[cheng_seed] owner alias load failed: %s\n",
                current_function->source_path);
        return false;
    }
    if (!cheng_seed_resolve_call_target(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                current_function->body_call_target,
                                target)) {
        char wasm_symbol[PATH_MAX];
        wasm_symbol[0] = '\0';
        if (!cheng_seed_wasm_resolve_external_arg0_i32_from_source_path(plan,
                                                                current_function->source_path,
                                                                current_function->body_call_target,
                                                                wasm_symbol,
                                                                sizeof(wasm_symbol))) {
            return false;
        }
        memset(target, 0, sizeof(*target));
        target->ffi_handle_consume_index = -1;
        target->external = true;
        snprintf(target->symbol_name, sizeof(target->symbol_name), "%s", wasm_symbol);
        if (!cheng_seed_call_target_set_signature(target, "int32", 1U, (const char *const[]){"int32"})) {
            return false;
        }
    }
    return target->param_count == 1U &&
           strcmp(target->return_abi_class, "i32") == 0 &&
           strcmp(target->param_abi_classes[0], "i32") == 0;
}

static bool cheng_seed_wasm_resolve_external_i32_params_from_source_path(const ChengSeedSystemLinkPlanStub *plan,
                                                                 const char *source_path,
                                                                 const char *callee,
                                                                 size_t expected_argc,
                                                                 char *symbol_name_out,
                                                                 size_t symbol_name_cap);

static bool cheng_seed_resolve_return_call_params_i32_target(const ChengSeedSystemLinkPlanStub *plan,
                                                     const ChengSeedLoweringPlanStub *lowering,
                                                     const ChengSeedLoweredFunctionStub *current_function,
                                                     ChengSeedAsmCallTarget *target) {
    ChengSeedImportAlias aliases[CHENG_MAX_IMPORT_ALIASES];
    size_t alias_count = 0U;
    size_t arg_index;
    if (current_function == NULL || target == NULL ||
        current_function->body_call_target[0] == '\0' ||
        current_function->body_call_arg_count < 2U ||
        current_function->body_call_arg_count > CHENG_MAX_CALL_ARGS ||
        current_function->param_count != current_function->body_call_arg_count ||
        strcmp(current_function->return_abi_class, "i32") != 0) {
        return false;
    }
    for (arg_index = 0U; arg_index < current_function->body_call_arg_count; ++arg_index) {
        if (strcmp(current_function->param_abi_classes[arg_index], "i32") != 0 ||
            strcmp(current_function->body_call_arg_names[arg_index], current_function->param_names[arg_index]) != 0) {
            return false;
        }
    }
    if (!cheng_seed_load_import_aliases_from_source_path(current_function->source_path,
                                                 aliases,
                                                 &alias_count,
                                                 CHENG_MAX_IMPORT_ALIASES)) {
        fprintf(stderr,
                "[cheng_seed] owner alias load failed: %s\n",
                current_function->source_path);
        return false;
    }
    if (!cheng_seed_resolve_call_target(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                current_function->body_call_target,
                                target)) {
        char wasm_symbol[PATH_MAX];
        wasm_symbol[0] = '\0';
        if (!cheng_seed_wasm_resolve_external_i32_params_from_source_path(plan,
                                                                  current_function->source_path,
                                                                  current_function->body_call_target,
                                                                  current_function->body_call_arg_count,
                                                                  wasm_symbol,
                                                                  sizeof(wasm_symbol))) {
            return false;
        }
        memset(target, 0, sizeof(*target));
        target->ffi_handle_consume_index = -1;
        target->external = true;
        snprintf(target->symbol_name, sizeof(target->symbol_name), "%s", wasm_symbol);
        target->c_abi = !cheng_seed_symbol_uses_cheng_internal_abi(wasm_symbol);
        {
            const char *param_types[CHENG_MAX_CALL_ARGS];
            target->param_count = current_function->body_call_arg_count;
            for (arg_index = 0U; arg_index < target->param_count; ++arg_index) {
                param_types[arg_index] = "int32";
            }
            if (!cheng_seed_call_target_set_signature(target,
                                              "int32",
                                              current_function->body_call_arg_count,
                                              param_types)) {
                return false;
            }
        }
    }
    if (strcmp(target->return_abi_class, "i32") != 0 ||
        target->param_count != current_function->body_call_arg_count) {
        return false;
    }
    for (arg_index = 0U; arg_index < target->param_count; ++arg_index) {
        if (strcmp(target->param_abi_classes[arg_index], "i32") != 0) {
            return false;
        }
    }
    return true;
}

static void cheng_seed_emit_call_arg_spill_store(char *out,
                                         size_t cap,
                                         int32_t call_arg_base,
                                         int call_depth,
                                         size_t arg_index,
                                         const char *abi_class,
                                         int src_reg_index) {
    int32_t offset = call_arg_base + call_depth * CHENG_CALL_ARG_SPILL_STRIDE + (int32_t)arg_index * 8;
    cheng_seed_note_emit_spill_call_depth(call_depth);
    if (!cheng_seed_emit_frame_store_reg(out, cap, offset, abi_class, src_reg_index)) {
        abort();
    }
}

