static bool cheng_seed_emit_cstring_literal_label(const ChengSeedSystemLinkPlanStub *plan,
                                          const ChengSeedLoweredFunctionStub *current_function,
                                          const char *literal_text,
                                          int32_t *string_label_index_io,
                                          char *label_out,
                                          size_t label_cap,
                                          char *out,
                                          size_t cap) {
    char safe_name[80];
    char *escaped;
    int32_t label_id = 0;
    const char *label_prefix = "L_cheng_strlit";
    uint64_t symbol_hash = cheng_seed_fnv1a64(current_function->symbol_text);
    cheng_seed_sanitize_path_part(current_function->symbol_text, safe_name, sizeof(safe_name));
    if (string_label_index_io) {
        label_id = *string_label_index_io;
        *string_label_index_io += 1;
    } else {
        label_id = cheng_seed_next_expr_label_id();
        label_prefix = "L_cheng_expr_strlit";
    }
    snprintf(label_out,
             label_cap,
             "%s_%s_%016llx_%d",
             label_prefix,
             safe_name,
             (unsigned long long)symbol_hash,
             label_id);
    escaped = cheng_seed_c_escape(literal_text);
    if (!escaped) {
        return false;
    }
    cheng_seed_append_cstring_section_for_target(plan, out, cap);
    cheng_seed_text_appendf(out, cap,
                    "%s:\n"
                    "  .asciz \"%s\"\n"
                    ".text\n"
                    ".p2align 2\n",
                    label_out,
                    escaped);
    free(escaped);
    return true;
}

