static bool cheng_seed_native_call_arg_memory_copy_target_supported(const ChengSeedSystemLinkPlanStub *plan,
                                                            const ChengSeedAsmCallTarget *target,
                                                            const ChengSeedNativeCallLoweringRule *rule,
                                                            size_t arg_index) {
    return ((plan != NULL && cheng_seed_target_is_linux_x86_64(plan->target_triple)) ||
            cheng_seed_active_target_is_linux_x86_64()) &&
           target != NULL &&
           rule != NULL &&
           arg_index < rule->param_count &&
           rule->import_kind != ChengSeed_NATIVE_IMPORT_NONE &&
           target->external &&
           target->c_abi &&
           arg_index < target->param_count &&
           cheng_seed_call_signature_needs_address_temp(target->param_types[arg_index],
                                               target->param_abi_classes[arg_index]);
}

static bool cheng_seed_native_call_arg_memory_copy_layout_supported(const ChengSeedTypeLayoutStub *layout) {
    return layout != NULL &&
           layout->size > 0 &&
           layout->align > 0 &&
           layout->align <= 8;
}

static bool cheng_seed_native_call_arg_layout_requires_small_aggregate_register_abi(const ChengSeedTypeLayoutStub *layout) {
    return layout != NULL &&
           cheng_seed_native_call_arg_memory_copy_layout_supported(layout) &&
           layout->size <= 16;
}

static bool cheng_seed_native_call_arg_layout_requires_memory_copy_stack(const ChengSeedTypeLayoutStub *layout) {
    return layout != NULL && layout->size > 16;
}

static int32_t cheng_seed_native_call_arg_memory_copy_stack_bytes_for_layout(const ChengSeedTypeLayoutStub *layout) {
    if (layout == NULL) {
        return 0;
    }
    return cheng_seed_align_up_i32(layout->size, 8);
}

static bool cheng_seed_resolve_native_call_arg_memory_copy_stack_bytes(const ChengSeedSystemLinkPlanStub *plan,
                                                               const ChengSeedLoweringPlanStub *lowering,
                                                               const ChengSeedLoweredFunctionStub *current_function,
                                                               const ChengSeedImportAlias *aliases,
                                                               size_t alias_count,
                                                               const ChengSeedAsmCallTarget *target,
                                                               const ChengSeedNativeCallLoweringRule *rule,
                                                               size_t arg_index,
                                                               int32_t *stack_bytes_out) {
    char normalized_type[256];
    ChengSeedTypeLayoutStub layout;
    if (!stack_bytes_out) {
        return false;
    }
    *stack_bytes_out = 0;
    if (!cheng_seed_native_call_arg_memory_copy_target_supported(plan, target, rule, arg_index)) {
        return true;
    }
    if (!lowering ||
        !current_function ||
        !cheng_seed_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                target->param_types[arg_index],
                                normalized_type,
                                sizeof(normalized_type)) ||
        !cheng_seed_compute_type_layout_impl(lowering, normalized_type, &layout, 0U)) {
        fprintf(stderr,
                "[cheng_seed] native abi memory-copy arg layout failed caller=%s callee=%s arg_index=%zu type=%s\n",
                current_function ? current_function->symbol_text : "<nil>",
                target ? target->callee_name : "<nil>",
                arg_index,
                target ? target->param_types[arg_index] : "<nil>");
        return false;
    }
    if (!cheng_seed_native_call_arg_memory_copy_layout_supported(&layout)) {
        fprintf(stderr,
                "[cheng_seed] native abi memory-copy arg invalid layout caller=%s callee=%s arg_index=%zu type=%s size=%d align=%d\n",
                current_function->symbol_text,
                target->callee_name,
                arg_index,
                normalized_type,
                layout.size,
                layout.align);
        return false;
    }
    if (cheng_seed_native_call_arg_layout_requires_small_aggregate_register_abi(&layout)) {
        fprintf(stderr,
                "[cheng_seed] native abi small aggregate register arg unsupported caller=%s callee=%s arg_index=%zu type=%s size=%d\n",
                current_function->symbol_text,
                target->callee_name,
                arg_index,
                normalized_type,
                layout.size);
        return false;
    }
    if (!cheng_seed_native_call_arg_layout_requires_memory_copy_stack(&layout)) {
        return true;
    }
    *stack_bytes_out = cheng_seed_native_call_arg_memory_copy_stack_bytes_for_layout(&layout);
    return true;
}

static void cheng_seed_emit_native_stack_arg_store_from_reg(char *out,
                                                    size_t cap,
                                                    int32_t stack_offset,
                                                    const char *abi_class,
                                                    int src_reg) {
    if (cheng_seed_active_target_is_linux_x86_64()) {
        if (strcmp(abi_class, "i32") == 0 || strcmp(abi_class, "bool") == 0) {
            cheng_seed_text_appendf(out, cap, "  movl %s, %d(%%rsp)\n",
                            cheng_seed_x64_dreg_name(src_reg),
                            stack_offset);
        } else {
            cheng_seed_text_appendf(out, cap, "  movq %s, %d(%%rsp)\n",
                            cheng_seed_x64_qreg_name(src_reg),
                            stack_offset);
        }
        return;
    }
    if (strcmp(abi_class, "i32") == 0 || strcmp(abi_class, "bool") == 0) {
        cheng_seed_text_appendf(out, cap, "  str w%d, [sp, #%d]\n", src_reg, stack_offset);
    } else {
        cheng_seed_text_appendf(out, cap, "  str x%d, [sp, #%d]\n", src_reg, stack_offset);
    }
}

static void cheng_seed_native_call_stack_layout_init(ChengSeedNativeCallStackLayout *layout) {
    size_t i;
    if (layout == NULL) {
        return;
    }
    memset(layout, 0, sizeof(*layout));
    for (i = 0U; i < CHENG_MAX_CALL_ARGS; ++i) {
        layout->arg_reg_ordinals[i] = -1;
        layout->arg_stack_offsets[i] = -1;
        layout->arg_load_abis[i] = NULL;
    }
    layout->supported = false;
}

static void cheng_seed_native_call_arg_stack_placement_init(ChengSeedNativeCallArgStackPlacement *placement) {
    if (placement == NULL) {
        return;
    }
    memset(placement, 0, sizeof(*placement));
}

static bool cheng_seed_resolve_native_call_arg_stack_placement(const ChengSeedSystemLinkPlanStub *plan,
                                                       const ChengSeedLoweringPlanStub *lowering,
                                                       const ChengSeedLoweredFunctionStub *current_function,
                                                       const ChengSeedImportAlias *aliases,
                                                       size_t alias_count,
                                                       const ChengSeedAsmCallTarget *target,
                                                       const ChengSeedNativeCallLoweringRule *rule,
                                                       size_t arg_index,
                                                       ChengSeedNativeCallArgStackPlacement *placement) {
    int32_t external_memory_stack_bytes = 0;
    if (target == NULL || rule == NULL || placement == NULL ||
        arg_index >= target->param_count || arg_index >= rule->param_count) {
        return false;
    }
    cheng_seed_native_call_arg_stack_placement_init(placement);
    if (!cheng_seed_resolve_native_call_arg_memory_copy_stack_bytes(plan,
                                                            lowering,
                                                            current_function,
                                                            aliases,
                                                            alias_count,
                                                            target,
                                                            rule,
                                                            arg_index,
                                                            &external_memory_stack_bytes)) {
        return false;
    }
    if (external_memory_stack_bytes <= 0) {
        return true;
    }
    placement->stack_bytes = external_memory_stack_bytes;
    placement->copy_from_ptr = true;
    placement->force_stack = true;
    placement->consumes_reg_ordinal = false;
    return true;
}

static bool cheng_seed_build_native_call_stack_layout(const ChengSeedSystemLinkPlanStub *plan,
                                              const ChengSeedLoweringPlanStub *lowering,
                                              const ChengSeedLoweredFunctionStub *current_function,
                                              const ChengSeedImportAlias *aliases,
                                              size_t alias_count,
                                              const ChengSeedAsmCallTarget *target,
                                              const ChengSeedNativeCallLoweringRule *rule,
                                              int call_reg_count,
                                              ChengSeedNativeCallStackLayout *layout) {
    size_t i;
    int gp_arg_index = 0;
    int32_t raw_stack_bytes = 0;
    if (target == NULL || rule == NULL || layout == NULL ||
        target->param_count > CHENG_MAX_CALL_ARGS ||
        rule->param_count != target->param_count) {
        return false;
    }
    cheng_seed_native_call_stack_layout_init(layout);
    layout->param_count = target->param_count;
    for (i = 0U; i < target->param_count; ++i) {
        ChengSeedNativeCallArgStackPlacement placement;
        const char *arg_load_abi = cheng_seed_native_call_rule_arg_load_abi(target, rule, i);
        if (!cheng_seed_resolve_native_call_arg_stack_placement(plan,
                                                        lowering,
                                                        current_function,
                                                        aliases,
                                                        alias_count,
                                                        target,
                                                        rule,
                                                        i,
                                                        &placement)) {
            return false;
        }
        layout->arg_load_abis[i] = arg_load_abi;
        if (placement.force_stack) {
            layout->arg_stack_offsets[i] = raw_stack_bytes;
            layout->arg_stack_bytes[i] = placement.stack_bytes;
            layout->arg_stack_copy_from_ptr[i] = placement.copy_from_ptr;
            raw_stack_bytes += placement.stack_bytes;
            if (placement.consumes_reg_ordinal) {
                gp_arg_index += 1;
            }
            continue;
        }
        if (gp_arg_index < call_reg_count) {
            layout->arg_reg_ordinals[i] = gp_arg_index;
            gp_arg_index += 1;
            continue;
        }
        layout->arg_stack_offsets[i] = raw_stack_bytes;
        layout->arg_stack_bytes[i] = 8;
        raw_stack_bytes += 8;
        gp_arg_index += 1;
    }
    layout->total_stack_bytes = cheng_seed_align_up_i32(raw_stack_bytes, 16);
    layout->supported = true;
    (void)plan;
    return true;
}

static int cheng_seed_call_arg_virtual_reg_for_target(const ChengSeedSystemLinkPlanStub *plan,
                                              size_t arg_index,
                                              bool composite_return) {
    if ((plan != NULL && cheng_seed_target_is_linux_x86_64(plan->target_triple)) ||
        cheng_seed_active_target_is_linux_x86_64()) {
        return cheng_seed_x64_call_arg_virtual_reg(arg_index, composite_return);
    }
    return (int)arg_index;
}

static int cheng_seed_call_result_address_virtual_reg_for_target(const ChengSeedSystemLinkPlanStub *plan) {
    if ((plan != NULL && cheng_seed_target_is_linux_x86_64(plan->target_triple)) ||
        cheng_seed_active_target_is_linux_x86_64()) {
        return 14;
    }
    return 8;
}

static bool cheng_seed_emit_stack_call_args_from_spills(const ChengSeedSystemLinkPlanStub *plan,
                                                const ChengSeedNativeCallStackLayout *layout,
                                                int32_t call_arg_base,
                                                int call_depth,
                                                char *out,
                                                size_t cap) {
    size_t i;
    if (layout == NULL || out == NULL) {
        return false;
    }
    for (i = 0U; i < layout->param_count; ++i) {
        const char *arg_abi;
        int32_t stack_bytes = layout->arg_stack_bytes[i];
        int32_t stack_offset = layout->arg_stack_offsets[i];
        if (stack_bytes <= 0) {
            continue;
        }
        arg_abi = layout->arg_load_abis[i];
        if (arg_abi == NULL || arg_abi[0] == '\0') {
            return false;
        }
        if (layout->arg_stack_copy_from_ptr[i]) {
            cheng_seed_emit_call_arg_spill_load_adjusted(out,
                                                 cap,
                                                 call_arg_base,
                                                 call_depth,
                                                 i,
                                                 9,
                                                 "ptr",
                                                 layout->total_stack_bytes);
            if (plan == NULL ||
                !cheng_seed_emit_sp_offset_address(out, cap, 14, stack_offset) ||
                !cheng_seed_emit_copy_address_to_address(plan,
                                                 out,
                                                 cap,
                                                 14,
                                                 9,
                                                 stack_bytes)) {
                return false;
            }
            continue;
        }
        cheng_seed_emit_call_arg_spill_load_adjusted(out,
                                             cap,
                                             call_arg_base,
                                             call_depth,
                                             i,
                                             9,
                                             arg_abi,
                                             layout->total_stack_bytes);
        cheng_seed_emit_native_stack_arg_store_from_reg(out, cap, stack_offset, arg_abi, 9);
    }
    return true;
}

static void cheng_seed_emit_call_register_args_from_spills(const ChengSeedSystemLinkPlanStub *plan,
                                                   const ChengSeedNativeCallStackLayout *layout,
                                                   bool composite_return,
                                                   int32_t call_arg_base,
                                                   int call_depth,
                                                   char *out,
                                                   size_t cap) {
    size_t i;
    if (layout == NULL || out == NULL) {
        return;
    }
    for (i = 0U; i < layout->param_count; ++i) {
        const char *arg_abi = layout->arg_load_abis[i];
        if (layout->arg_reg_ordinals[i] < 0) {
            continue;
        }
        if (arg_abi == NULL || arg_abi[0] == '\0') {
            return;
        }
        cheng_seed_emit_call_arg_spill_load_adjusted(out,
                                             cap,
                                             call_arg_base,
                                             call_depth,
                                             i,
                                             cheng_seed_call_arg_virtual_reg_for_target(plan,
                                                                                (size_t)layout->arg_reg_ordinals[i],
                                                                                composite_return),
                                             arg_abi,
                                             layout->total_stack_bytes);
    }
}

static bool cheng_seed_resolve_native_call_post_result_kind(const ChengSeedNativeCallLoweringRule *rule,
                                                    ChengSeedNativeCompositeResultKind composite_result_kind,
                                                    ChengSeedNativeCallPostResultKind *kind_out) {
    if (kind_out == NULL) {
        return false;
    }
    *kind_out = ChengSeed_NATIVE_CALL_POST_RESULT_NONE;
    if (rule == NULL || !rule->supported) {
        return false;
    }
    if (rule->result_kind != ChengSeed_CALL_RESULT_ADDRESS) {
        return composite_result_kind == ChengSeed_NATIVE_COMPOSITE_RESULT_UNSUPPORTED;
    }
    if (composite_result_kind == ChengSeed_NATIVE_COMPOSITE_RESULT_DEST_ADDRESS) {
        *kind_out = ChengSeed_NATIVE_CALL_POST_RESULT_DEST_ADDRESS;
        return true;
    }
    if (composite_result_kind == ChengSeed_NATIVE_COMPOSITE_RESULT_IMPORT_BUFFER) {
        *kind_out = ChengSeed_NATIVE_CALL_POST_RESULT_IMPORT_BUFFER;
        return true;
    }
    return false;
}

static bool cheng_seed_native_call_post_result_requires_hidden_result_address(ChengSeedNativeCallPostResultKind kind) {
    return kind == ChengSeed_NATIVE_CALL_POST_RESULT_DEST_ADDRESS ||
           kind == ChengSeed_NATIVE_CALL_POST_RESULT_IMPORT_BUFFER;
}

static bool cheng_seed_emit_call_hidden_result_address_preload_from_spills(const ChengSeedSystemLinkPlanStub *plan,
                                                                   ChengSeedNativeCallPostResultKind post_result_kind,
                                                                   int32_t call_arg_base,
                                                                   int call_depth,
                                                                   const ChengSeedNativeCallStackLayout *layout,
                                                                   char *out,
                                                                   size_t cap) {
    if (plan == NULL || layout == NULL || out == NULL) {
        return false;
    }
    if (cheng_seed_native_call_post_result_requires_hidden_result_address(post_result_kind)) {
        cheng_seed_emit_call_dest_spill_load_adjusted(out,
                                              cap,
                                              call_arg_base,
                                              call_depth,
                                              cheng_seed_call_result_address_virtual_reg_for_target(plan),
                                              layout->total_stack_bytes);
        return true;
    }
    return post_result_kind == ChengSeed_NATIVE_CALL_POST_RESULT_NONE;
}

static bool cheng_seed_emit_call_post_result_finalize_from_spills(const ChengSeedSystemLinkPlanStub *plan,
                                                          const ChengSeedAsmCallTarget *target,
                                                          const ChengSeedNativeCallLoweringRule *rule,
                                                          ChengSeedNativeCallPostResultKind post_result_kind,
                                                          int32_t call_arg_base,
                                                          int call_depth,
                                                          const ChengSeedNativeCallStackLayout *layout,
                                                          char *out,
                                                          size_t cap) {
    if (plan == NULL || target == NULL || layout == NULL || out == NULL) {
        return false;
    }
    if (post_result_kind != ChengSeed_NATIVE_CALL_POST_RESULT_NONE &&
        post_result_kind != ChengSeed_NATIVE_CALL_POST_RESULT_DEST_ADDRESS &&
        post_result_kind != ChengSeed_NATIVE_CALL_POST_RESULT_IMPORT_BUFFER) {
        return false;
    }
    if (post_result_kind == ChengSeed_NATIVE_CALL_POST_RESULT_NONE &&
        cheng_seed_call_needs_ffi_handle_return_fixups(target, rule)) {
        cheng_seed_emit_call_ffi_handle_return_fixups(plan,
                                              target,
                                              rule,
                                              call_arg_base,
                                              call_depth,
                                              out,
                                              cap);
    }
    return true;
}

static bool cheng_seed_emit_call_finish_from_spills(const ChengSeedSystemLinkPlanStub *plan,
                                            const ChengSeedAsmCallTarget *target,
                                            const ChengSeedNativeCallLoweringRule *rule,
                                            ChengSeedNativeCallPostResultKind post_result_kind,
                                            int32_t call_arg_base,
                                            int call_depth,
                                            const ChengSeedNativeCallStackLayout *layout,
                                            char *out,
                                            size_t cap) {
    if (plan == NULL || target == NULL || layout == NULL || out == NULL) {
        return false;
    }
    if (!cheng_seed_emit_call_hidden_result_address_preload_from_spills(plan,
                                                                post_result_kind,
                                                                call_arg_base,
                                                                call_depth,
                                                                layout,
                                                                out,
                                                                cap)) {
        return false;
    }
    cheng_seed_emit_call_target_symbol_text(plan, out, cap, target->symbol_name);
    if (layout->total_stack_bytes > 0) {
        if (!cheng_seed_emit_sp_adjust(out, cap, false, layout->total_stack_bytes)) {
            return false;
        }
    }
    return cheng_seed_emit_call_post_result_finalize_from_spills(plan,
                                                         target,
                                                         rule,
                                                         post_result_kind,
                                                         call_arg_base,
                                                         call_depth,
                                                         layout,
                                                         out,
                                                         cap);
}

static bool cheng_seed_emit_call_capture_hidden_result_address_from_dest_reg(int dest_addr_reg,
                                                                     int32_t call_arg_base,
                                                                     int call_depth,
                                                                     char *out,
                                                                     size_t cap) {
    if (dest_addr_reg < 0 || out == NULL) {
        return false;
    }
    cheng_seed_emit_call_dest_spill_store(out,
                                  cap,
                                  call_arg_base,
                                  call_depth,
                                  dest_addr_reg);
    return true;
}

static bool cheng_seed_emit_call_prepare_result_address_from_dest_reg(int dest_addr_reg,
                                                              int32_t call_arg_base,
                                                              int call_depth,
                                                              char *out,
                                                              size_t cap) {
    return cheng_seed_emit_call_capture_hidden_result_address_from_dest_reg(dest_addr_reg,
                                                                    call_arg_base,
                                                                    call_depth,
                                                                    out,
                                                                    cap);
}

static bool cheng_seed_emit_call_from_spills(const ChengSeedSystemLinkPlanStub *plan,
                                     const ChengSeedLoweringPlanStub *lowering,
                                     const ChengSeedLoweredFunctionStub *current_function,
                                     const ChengSeedImportAlias *aliases,
                                     size_t alias_count,
                                     const ChengSeedAsmCallTarget *target,
                                     const ChengSeedNativeCallLoweringRule *rule,
                                     ChengSeedNativeCompositeResultKind composite_result_kind,
                                     int32_t call_arg_base,
                                     int call_depth,
                                     char *out,
                                     size_t cap) {
    ChengSeedNativeCallStackLayout layout;
    ChengSeedNativeCallPostResultKind post_result_kind;
    bool result_address_call;
    if (!target || rule == NULL || !rule->supported ||
        rule->param_count != target->param_count) {
        return false;
    }
    if (!cheng_seed_resolve_native_call_post_result_kind(rule,
                                                 composite_result_kind,
                                                 &post_result_kind)) {
        return false;
    }
    result_address_call =
        cheng_seed_native_call_post_result_requires_hidden_result_address(post_result_kind);
    if (!cheng_seed_build_native_call_stack_layout(plan,
                                           lowering,
                                           current_function,
                                           aliases,
                                           alias_count,
                                           target,
                                           rule,
                                           cheng_seed_call_arg_reg_count_for_target(plan, result_address_call),
                                           &layout)) {
        return false;
    }
    if (layout.total_stack_bytes > 0) {
        if (!cheng_seed_emit_sp_adjust(out, cap, true, layout.total_stack_bytes)) {
            return false;
        }
    }
    if (!cheng_seed_emit_stack_call_args_from_spills(plan,
                                             &layout,
                                             call_arg_base,
                                             call_depth,
                                             out,
                                             cap)) {
        return false;
    }
    cheng_seed_emit_call_register_args_from_spills(plan,
                                           &layout,
                                           result_address_call,
                                           call_arg_base,
                                           call_depth,
                                           out,
                                           cap);
    return cheng_seed_emit_call_finish_from_spills(plan,
                                           target,
                                           rule,
                                           post_result_kind,
                                           call_arg_base,
                                           call_depth,
                                           &layout,
                                           out,
                                           cap);
}

static bool cheng_seed_emit_copy_slot_to_address(const ChengSeedSystemLinkPlanStub *plan,
                                         const ChengSeedLoweringPlanStub *lowering,
                                         const ChengSeedLoweredFunctionStub *current_function,
                                         const ChengSeedImportAlias *aliases,
                                         size_t alias_count,
                                         int32_t call_arg_base,
                                         int call_depth,
                                         char *out,
                                         size_t cap,
                                         const ChengSeedAsmLocalSlot *src_slot,
                                         int dst_reg) {
    ChengSeedTypeLayoutStub layout;
    char value_type[256];
    int32_t copy_size;
    int src_reg;
    (void)current_function;
    (void)aliases;
    (void)alias_count;
    (void)call_arg_base;
    (void)call_depth;
    if (!src_slot || src_slot->stack_size < 0) {
        return false;
    }
    if (src_slot->indirect_value) {
        if (!lowering) {
            return false;
        }
        cheng_seed_strip_var_type_text(src_slot->type_text, value_type, sizeof(value_type));
        if (!cheng_seed_compute_type_layout_impl(lowering, value_type, &layout, 0U)) {
            return false;
        }
        copy_size = layout.size;
        src_reg = dst_reg == 14 ? 15 : 14;
        if (!cheng_seed_emit_local_value_address(out, cap, src_slot, src_reg)) {
            return false;
        }
        return cheng_seed_emit_copy_address_to_address(plan, out, cap, dst_reg, src_reg, copy_size);
    }
    copy_size = src_slot->stack_size;
    src_reg = dst_reg == 14 ? 15 : 14;
    if (!cheng_seed_emit_local_value_address(out, cap, src_slot, src_reg)) {
        return false;
    }
    return cheng_seed_emit_copy_address_to_address(plan, out, cap, dst_reg, src_reg, copy_size);
}

static bool cheng_seed_emit_clone_slot_to_address_for_assignment(const ChengSeedSystemLinkPlanStub *plan,
                                                         const ChengSeedLoweringPlanStub *lowering,
                                                         const ChengSeedLoweredFunctionStub *current_function,
                                                         const ChengSeedImportAlias *aliases,
                                                         size_t alias_count,
                                                         int32_t call_arg_base,
                                                         int call_depth,
                                                         char *out,
                                                         size_t cap,
                                                         const ChengSeedAsmLocalSlot *src_slot,
                                                         int frame_base_reg,
                                                         int dst_reg) {
    ChengSeedTypeLayoutStub layout;
    char value_type[256];
    int32_t copy_size;
    int src_reg;
    if (!src_slot || src_slot->stack_size < 0 || !lowering || !current_function) {
        return false;
    }
    if (src_slot->indirect_value) {
        cheng_seed_strip_var_type_text(src_slot->type_text, value_type, sizeof(value_type));
        if (!cheng_seed_compute_type_layout_impl(lowering, value_type, &layout, 0U)) {
            return false;
        }
        copy_size = layout.size;
        src_reg = dst_reg == 14 ? 15 : 14;
        if (!((frame_base_reg >= 0) ?
                  cheng_seed_emit_local_value_address_from_base(out,
                                                        cap,
                                                        src_slot,
                                                        frame_base_reg,
                                                        src_reg) :
                  cheng_seed_emit_local_value_address(out, cap, src_slot, src_reg))) {
            return false;
        }
        if (cheng_seed_type_needs_bytes_orc_lifecycle(lowering,
                                              aliases,
                                              alias_count,
                                              current_function->owner_module_path,
                                              value_type,
                                              0U)) {
            if (!cheng_seed_emit_sp_adjust(out, cap, true, 16) ||
                !cheng_seed_emit_sp_store_reg(out, cap, 0, "ptr", src_reg) ||
                !cheng_seed_emit_sp_store_reg(out, cap, 8, "ptr", dst_reg) ||
                !cheng_seed_emit_bytes_orc_lifecycle_at_address(plan,
                                                        lowering,
                                                        current_function,
                                                        aliases,
                                                        alias_count,
                                                        current_function->owner_module_path,
                                                        value_type,
                                                        src_reg,
                                                        call_arg_base + 32,
                                                        call_depth,
                                                        true,
                                                        out,
                                                        cap,
                                                        0U) ||
                !cheng_seed_emit_sp_load_reg(out, cap, 0, "ptr", src_reg) ||
                !cheng_seed_emit_sp_load_reg(out, cap, 8, "ptr", dst_reg) ||
                !cheng_seed_emit_sp_adjust(out, cap, false, 16)) {
                return false;
            }
        }
        return cheng_seed_emit_copy_address_to_address(plan, out, cap, dst_reg, src_reg, copy_size);
    }
    copy_size = src_slot->stack_size;
    src_reg = dst_reg == 14 ? 15 : 14;
    if (!((frame_base_reg >= 0) ?
              cheng_seed_emit_local_value_address_from_base(out,
                                                    cap,
                                                    src_slot,
                                                    frame_base_reg,
                                                    src_reg) :
              cheng_seed_emit_local_value_address(out, cap, src_slot, src_reg))) {
        return false;
    }
    if (cheng_seed_type_needs_bytes_orc_lifecycle(lowering,
                                          aliases,
                                          alias_count,
                                          current_function->owner_module_path,
                                          src_slot->type_text,
                                          0U)) {
        if (!cheng_seed_emit_sp_adjust(out, cap, true, 16) ||
            !cheng_seed_emit_sp_store_reg(out, cap, 0, "ptr", src_reg) ||
            !cheng_seed_emit_sp_store_reg(out, cap, 8, "ptr", dst_reg) ||
            !cheng_seed_emit_bytes_orc_lifecycle_at_address(plan,
                                                    lowering,
                                                    current_function,
                                                    aliases,
                                                    alias_count,
                                                    current_function->owner_module_path,
                                                    src_slot->type_text,
                                                    src_reg,
                                                    call_arg_base + 32,
                                                    call_depth,
                                                    true,
                                                    out,
                                                    cap,
                                                    0U) ||
            !cheng_seed_emit_sp_load_reg(out, cap, 0, "ptr", src_reg) ||
            !cheng_seed_emit_sp_load_reg(out, cap, 8, "ptr", dst_reg) ||
            !cheng_seed_emit_sp_adjust(out, cap, false, 16)) {
            return false;
        }
    }
    return cheng_seed_emit_copy_address_to_address(plan, out, cap, dst_reg, src_reg, copy_size);
}

static bool cheng_seed_emit_mov_imm(char *out, size_t cap, int reg_index, int64_t value) {
    if (cheng_seed_active_target_is_linux_x86_64()) {
        if (value >= INT32_MIN && value <= INT32_MAX) {
            cheng_seed_text_appendf(out, cap,
                            "  movq $%lld, %s\n",
                            (long long)value,
                            cheng_seed_x64_qreg_name(reg_index));
            return true;
        }
        cheng_seed_text_appendf(out, cap,
                        "  movabsq $%lld, %s\n",
                        (long long)value,
                        cheng_seed_x64_qreg_name(reg_index));
        return true;
    }
    uint64_t bits = (uint64_t)value;
    bool emitted = false;
    int shift;
    if (value >= -65535 && value <= 65535) {
        cheng_seed_text_appendf(out, cap, "  mov x%d, #%lld\n", reg_index, (long long)value);
        return true;
    }
    for (shift = 0; shift <= 48; shift += 16) {
        uint16_t part = (uint16_t)((bits >> shift) & 0xffffU);
        if (!emitted) {
            if (part == 0U && shift < 48) {
                continue;
            }
            cheng_seed_text_appendf(out,
                            cap,
                            "  movz x%d, #%u, lsl #%d\n",
                            reg_index,
                            (unsigned)part,
                            shift);
            emitted = true;
            continue;
        }
        if (part != 0U) {
            cheng_seed_text_appendf(out,
                            cap,
                            "  movk x%d, #%u, lsl #%d\n",
                            reg_index,
                            (unsigned)part,
                            shift);
        }
    }
    if (!emitted) {
        cheng_seed_text_appendf(out, cap, "  mov x%d, #0\n", reg_index);
    }
    return true;
}

static bool cheng_seed_parse_member_access_expr(const char *expr_text,
                                        char *base_out,
                                        size_t base_cap,
                                        char *field_out,
                                        size_t field_cap) {
    char expr[4096];
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t last_sep = -1;
    int32_t sep_len = 0;
    size_t i;
    size_t len;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    len = strlen(expr);
    if (len <= 0U) {
        return false;
    }
    for (i = 0; i < len; ++i) {
        char ch = expr[i];
        if (ch == '"' && !cheng_seed_quote_is_escaped(expr, i)) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            if (paren_depth < 0) {
                return false;
            }
            continue;
        }
        if (ch == '[') {
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            if (bracket_depth < 0) {
                return false;
            }
            continue;
        }
        if (ch == '.' && paren_depth == 0 && bracket_depth == 0) {
            last_sep = (int32_t)i;
            sep_len = 1;
            continue;
        }
        if (ch == '-' &&
            paren_depth == 0 &&
            bracket_depth == 0 &&
            i + 1U < len &&
            expr[i + 1U] == '>') {
            last_sep = (int32_t)i;
            sep_len = 2;
        }
    }
    if (in_string || paren_depth != 0 || bracket_depth != 0 || last_sep <= 0 || (size_t)last_sep + (size_t)sep_len >= len) {
        return false;
    }
    snprintf(base_out, base_cap, "%.*s", last_sep, expr);
    cheng_seed_trim_copy_text(base_out, base_out, base_cap);
    snprintf(field_out, field_cap, "%s", expr + last_sep + sep_len);
    cheng_seed_trim_copy_text(field_out, field_out, field_cap);
    if (base_out[0] == '\0' ||
        field_out[0] == '\0' ||
        strchr(field_out, '.') != NULL ||
        strstr(field_out, "->") != NULL ||
        strchr(field_out, '[') != NULL ||
        strchr(field_out, ']') != NULL ||
        strchr(field_out, '(') != NULL ||
        strchr(field_out, ')') != NULL ||
        strchr(field_out, ' ') != NULL) {
        return false;
    }
    return true;
}

static bool cheng_seed_parse_index_access_expr(const char *expr_text,
                                       char *base_out,
                                       size_t base_cap,
                                       char *index_out,
                                       size_t index_cap) {
    char expr[4096];
    bool in_string = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t top_open = -1;
    size_t i;
    size_t len;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    len = strlen(expr);
    if (len < 3U || expr[len - 1U] != ']') {
        return false;
    }
    for (i = 0; i < len; ++i) {
        char ch = expr[i];
        if (ch == '"' && !cheng_seed_quote_is_escaped(expr, i)) {
            in_string = !in_string;
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            if (paren_depth < 0) {
                return false;
            }
            continue;
        }
        if (ch == '[') {
            if (paren_depth == 0 && bracket_depth == 0) {
                top_open = (int32_t)i;
            }
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            if (bracket_depth < 0) {
                return false;
            }
            continue;
        }
    }
    if (in_string || paren_depth != 0 || bracket_depth != 0 || top_open <= 0) {
        return false;
    }
    snprintf(base_out, base_cap, "%.*s", top_open, expr);
    cheng_seed_trim_copy_text(base_out, base_out, base_cap);
    snprintf(index_out, index_cap, "%.*s", (int)(len - (size_t)top_open - 2U), expr + top_open + 1);
    cheng_seed_trim_copy_text(index_out, index_out, index_cap);
    return base_out[0] != '\0' && index_out[0] != '\0';
}

static bool cheng_seed_find_type_def_by_normalized(const ChengSeedLoweringPlanStub *lowering,
                                           const char *normalized_type,
                                           int32_t *index_out) {
    char stripped[PATH_MAX];
    char inner[256];
    char owner_module[PATH_MAX];
    char type_instance_name[128];
    char type_args[CHENG_MAX_TYPE_PARAMS][256];
    int32_t fixed_len = 0;
    size_t type_arg_count = 0U;
    if (index_out) {
        *index_out = -1;
    }
    cheng_seed_strip_internal_ref_type(normalized_type, stripped, sizeof(stripped));
    if (stripped[0] == '\0' ||
        cheng_seed_is_tuple_type_text(stripped) ||
        cheng_seed_type_text_strip_one_pointer_suffix(stripped, inner, sizeof(inner)) ||
        (strlen(stripped) > 2U && strcmp(stripped + strlen(stripped) - 2U, "[]") == 0) ||
        cheng_seed_startswith(stripped, "Result[") ||
        cheng_seed_parse_fixed_array_type(stripped, inner, sizeof(inner), &fixed_len)) {
        return false;
    }
    if (!cheng_seed_split_qualified_type_text(stripped,
                                      owner_module,
                                      sizeof(owner_module),
                                      type_instance_name,
                                      sizeof(type_instance_name)) ||
        !cheng_seed_parse_type_instance_text(type_instance_name,
                                     type_instance_name,
                                     sizeof(type_instance_name),
                                     type_args,
                                     &type_arg_count,
                                     CHENG_MAX_TYPE_PARAMS)) {
        return false;
    }
    if (index_out) {
        *index_out = cheng_seed_find_type_def_index_by_symbol(lowering, owner_module, type_instance_name);
    }
    return index_out && *index_out >= 0;
}

static bool cheng_seed_resolve_field_meta_impl(const ChengSeedLoweringPlanStub *lowering,
                                       const char *normalized_type,
                                       const char *field_name,
                                       char *field_type_out,
                                       size_t field_type_cap,
                                       char *field_abi_out,
                                       size_t field_abi_cap,
                                       int32_t *field_offset_out,
                                       unsigned depth) {
    char pointer_base[256];
    int32_t type_index = -1;
    size_t i;
    if (depth > 8U) {
        return false;
    }
    if (cheng_seed_type_text_strip_one_pointer_suffix(normalized_type, pointer_base, sizeof(pointer_base))) {
        return cheng_seed_resolve_field_meta_impl(lowering,
                                          pointer_base,
                                          field_name,
                                          field_type_out,
                                          field_type_cap,
                                          field_abi_out,
                                          field_abi_cap,
                                          field_offset_out,
                                          depth + 1U);
    }
    if (strcmp(normalized_type, "Bytes") == 0) {
        if (strcmp(field_name, "data") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "ptr");
            snprintf(field_abi_out, field_abi_cap, "%s", "ptr");
            *field_offset_out = 0;
            return true;
        }
        if (strcmp(field_name, "len") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = cheng_seed_active_target_bytes_len_offset_i32();
            return true;
        }
        return false;
    }
    if (strcmp(normalized_type, "str") == 0) {
        if (strcmp(field_name, "data") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "ptr");
            snprintf(field_abi_out, field_abi_cap, "%s", "ptr");
            *field_offset_out = 0;
            return true;
        }
        if (strcmp(field_name, "len") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = cheng_seed_active_target_str_len_offset_i32();
            return true;
        }
        if (strcmp(field_name, "storeId") == 0 || strcmp(field_name, "store_id") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = cheng_seed_active_target_str_store_id_offset_i32();
            return true;
        }
        if (strcmp(field_name, "flags") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = cheng_seed_active_target_str_flags_offset_i32();
            return true;
        }
        return false;
    }
    if (strlen(normalized_type) > 2U &&
        strcmp(normalized_type + strlen(normalized_type) - 2U, "[]") == 0) {
        if (strcmp(field_name, "len") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = 0;
            return true;
        }
        if (strcmp(field_name, "cap") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "int32");
            snprintf(field_abi_out, field_abi_cap, "%s", "i32");
            *field_offset_out = 4;
            return true;
        }
        if (strcmp(field_name, "buffer") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "ptr");
            snprintf(field_abi_out, field_abi_cap, "%s", "ptr");
            *field_offset_out = cheng_seed_active_target_seq_buffer_offset_i32();
            return true;
        }
        return false;
    }
    if (cheng_seed_startswith(normalized_type, "Result[") && normalized_type[strlen(normalized_type) - 1U] == ']') {
        ChengSeedTypeLayoutStub value_layout;
        ChengSeedTypeLayoutStub err_layout;
        char value_type[256];
        int32_t value_offset;
        snprintf(value_type,
                 sizeof(value_type),
                 "%.*s",
                 (int)(strlen(normalized_type) - 8U),
                 normalized_type + 7);
        if (!cheng_seed_compute_type_layout_impl(lowering, value_type, &value_layout, depth + 1U) ||
            !cheng_seed_compute_type_layout_impl(lowering, "std/result::ErrorInfo", &err_layout, depth + 1U)) {
            return false;
        }
        value_offset = cheng_seed_align_up_i32(1, value_layout.align);
        if (strcmp(field_name, "ok") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "bool");
            snprintf(field_abi_out, field_abi_cap, "%s", "bool");
            *field_offset_out = 0;
            return true;
        }
        if (strcmp(field_name, "value") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", value_type);
            snprintf(field_abi_out, field_abi_cap, "%s", cheng_seed_type_abi_class(value_type));
            *field_offset_out = value_offset;
            return true;
        }
        if (strcmp(field_name, "err") == 0) {
            snprintf(field_type_out, field_type_cap, "%s", "std/result::ErrorInfo");
            snprintf(field_abi_out, field_abi_cap, "%s", cheng_seed_type_abi_class(field_type_out));
            *field_offset_out = cheng_seed_align_up_i32(value_offset + value_layout.size, err_layout.align);
            return true;
        }
        return false;
    }
    if (cheng_seed_is_tuple_type_text(normalized_type)) {
        char (*items)[4096] = NULL;
        ChengSeedTypeFieldDef *field = NULL;
        size_t item_count = 0U;
        int32_t offset = 0;
        bool ok = false;
        items = (char (*)[4096])cheng_seed_xmalloc(sizeof(*items) * CHENG_MAX_TYPE_FIELDS);
        field = (ChengSeedTypeFieldDef *)cheng_seed_xmalloc(sizeof(*field));
        if (!cheng_seed_parse_tuple_type_items(normalized_type,
                                       items,
                                       &item_count,
                                       CHENG_MAX_TYPE_FIELDS)) {
            goto tuple_field_meta_cleanup;
        }
        for (i = 0; i < item_count; ++i) {
            ChengSeedTypeLayoutStub field_layout;
            int32_t field_align;
            if (!cheng_seed_parse_type_field_spec(items[i], true, field) ||
                !cheng_seed_compute_type_layout_impl(lowering,
                                             field->type_text,
                                             &field_layout,
                                             depth + 1U)) {
                goto tuple_field_meta_cleanup;
            }
            field_align = field_layout.align > 0 ? field_layout.align : 1;
            offset = cheng_seed_align_up_i32(offset, field_align);
            if (field->has_explicit_name &&
                strcmp(field->name, field_name) == 0) {
                snprintf(field_type_out, field_type_cap, "%s", field->type_text);
                snprintf(field_abi_out, field_abi_cap, "%s", cheng_seed_type_abi_class(field->type_text));
                *field_offset_out = offset;
                ok = true;
                goto tuple_field_meta_cleanup;
            }
            offset += field_layout.size;
        }
tuple_field_meta_cleanup:
        free(field);
        free(items);
        return ok;
    }
    {
        char stripped[PATH_MAX];
        char owner_module[PATH_MAX];
        char type_instance_name[128];
        char type_name[128];
        char type_args[CHENG_MAX_TYPE_PARAMS][256];
        size_t type_arg_count = 0U;
        ChengSeedImportAlias *type_aliases = NULL;
        size_t type_alias_count = 0U;
        const ChengSeedTypeDefStub *type_def;
        bool ok = false;
        cheng_seed_strip_internal_ref_type(normalized_type, stripped, sizeof(stripped));
        if (!cheng_seed_split_qualified_type_text(stripped,
                                          owner_module,
                                          sizeof(owner_module),
                                          type_instance_name,
                                          sizeof(type_name)) ||
            !cheng_seed_parse_type_instance_text(type_instance_name,
                                         type_name,
                                         sizeof(type_name),
                                         type_args,
                                         &type_arg_count,
                                         CHENG_MAX_TYPE_PARAMS)) {
            goto field_meta_cleanup;
        }
        type_index = cheng_seed_find_type_def_index_by_symbol(lowering, owner_module, type_instance_name);
        if (type_index < 0) {
            goto field_meta_cleanup;
        }
        type_def = &lowering->type_defs[type_index];
        if (type_def->kind == ChengSeed_TYPE_DEF_ALIAS) {
            char alias_target[256];
            if (type_def->generic_param_count > 0U) {
                type_aliases = (ChengSeedImportAlias *)cheng_seed_xmalloc(sizeof(*type_aliases) * CHENG_MAX_IMPORT_ALIASES);
                if (!cheng_seed_load_import_aliases_from_source_path(type_def->source_path,
                                                             type_aliases,
                                                             &type_alias_count,
                                                             CHENG_MAX_IMPORT_ALIASES) ||
                    !cheng_seed_normalize_type_text_with_params(lowering,
                                                        type_def->owner_module_path,
                                                        type_aliases,
                                                        type_alias_count,
                                                        type_def->generic_param_names,
                                                        type_args,
                                                        type_arg_count,
                                                        type_def->alias_target,
                                                        alias_target,
                                                        sizeof(alias_target))) {
                    goto field_meta_cleanup;
                }
            } else {
                snprintf(alias_target, sizeof(alias_target), "%s", type_def->alias_target);
            }
            ok = cheng_seed_resolve_field_meta_impl(lowering,
                                            alias_target,
                                            field_name,
                                            field_type_out,
                                            field_type_cap,
                                            field_abi_out,
                                            field_abi_cap,
                                            field_offset_out,
                                            depth + 1U);
            goto field_meta_cleanup;
        }
        if (type_def->kind != ChengSeed_TYPE_DEF_RECORD) {
            goto field_meta_cleanup;
        }
        if (type_def->generic_param_count > 0U &&
            ((type_aliases = (ChengSeedImportAlias *)cheng_seed_xmalloc(sizeof(*type_aliases) * CHENG_MAX_IMPORT_ALIASES)) == NULL ||
             !cheng_seed_load_import_aliases_from_source_path(type_def->source_path,
                                                      type_aliases,
                                                      &type_alias_count,
                                                      CHENG_MAX_IMPORT_ALIASES) ||
             type_def->generic_param_count != type_arg_count)) {
            goto field_meta_cleanup;
        }
        {
            int32_t offset = 0;
            int32_t i;
            for (i = 0; i < (int32_t)type_def->field_count; ++i) {
                ChengSeedTypeLayoutStub field_layout;
                int32_t field_align;
                char resolved_field_type[256];
                if (type_def->generic_param_count > 0U) {
                    if (!cheng_seed_normalize_type_text_with_params(lowering,
                                                            type_def->owner_module_path,
                                                            type_aliases,
                                                            type_alias_count,
                                                            type_def->generic_param_names,
                                                            type_args,
                                                            type_arg_count,
                                                            type_def->fields[i].type_text,
                                                            resolved_field_type,
                                                            sizeof(resolved_field_type))) {
                        goto field_meta_cleanup;
                    }
                } else {
                    snprintf(resolved_field_type, sizeof(resolved_field_type), "%s", type_def->fields[i].type_text);
                }
                if (!cheng_seed_compute_type_layout_impl(lowering,
                                                 resolved_field_type,
                                                 &field_layout,
                                                 depth + 1U)) {
                    goto field_meta_cleanup;
                }
                field_align = field_layout.align > 0 ? field_layout.align : 1;
                offset = cheng_seed_align_up_i32(offset, field_align);
                if (strcmp(type_def->fields[i].name, field_name) == 0) {
                    snprintf(field_type_out, field_type_cap, "%s", resolved_field_type);
                    snprintf(field_abi_out, field_abi_cap, "%s", cheng_seed_type_abi_class(resolved_field_type));
                    *field_offset_out = offset;
                    ok = true;
                    goto field_meta_cleanup;
                }
                offset += field_layout.size;
            }
        }
field_meta_cleanup:
        free(type_aliases);
        return ok;
    }
    return false;
}

static bool cheng_seed_resolve_index_access_call_target(const ChengSeedSystemLinkPlanStub *plan,
                                                const ChengSeedLoweringPlanStub *lowering,
                                                const ChengSeedLoweredFunctionStub *current_function,
                                                const ChengSeedImportAlias *aliases,
                                                size_t alias_count,
                                                const ChengSeedAsmLocalSlot *locals,
                                                size_t local_count,
                                                const char *base_expr,
                                                const char *index_expr,
                                                ChengSeedAsmCallTarget *target) {
    char (*args)[4096] = cheng_seed_alloc_call_arg_scratch();
    bool ok;
    if (args == NULL || base_expr == NULL || index_expr == NULL || target == NULL) {
        free(args);
        return false;
    }
    snprintf(args[0], sizeof(args[0]), "%s", base_expr);
    snprintf(args[1], sizeof(args[1]), "%s", index_expr);
    ok = cheng_seed_resolve_call_target_with_args(plan,
                                          lowering,
                                          current_function,
                                          aliases,
                                          alias_count,
                                          locals,
                                          local_count,
                                          "[]",
                                          (const char (*)[4096])args,
                                          2U,
                                          target);
    free(args);
    return ok;
}

static bool cheng_seed_resolve_call_target(const ChengSeedSystemLinkPlanStub *plan,
                                   const ChengSeedLoweringPlanStub *lowering,
                                   const ChengSeedLoweredFunctionStub *current_function,
                                   const ChengSeedImportAlias *aliases,
                                   size_t alias_count,
                                   const char *callee,
                                   ChengSeedAsmCallTarget *target) {
    return cheng_seed_resolve_call_target_with_args(plan,
                                            lowering,
                                            current_function,
                                            aliases,
                                            alias_count,
                                            NULL,
                                            0U,
                                            callee,
                                            NULL,
                                            0U,
                                            target);
}

static bool cheng_seed_resolve_field_meta(const ChengSeedLoweringPlanStub *lowering,
                                  const char *base_type_text,
                                  const char *field_name,
                                  char *field_type_out,
                                  size_t field_type_cap,
                                  char *field_abi_out,
                                  size_t field_abi_cap,
                                  int32_t *field_offset_out) {
    char normalized_type[256];
    cheng_seed_strip_var_prefix(base_type_text, normalized_type, sizeof(normalized_type));
    return cheng_seed_resolve_field_meta_impl(lowering,
                                      normalized_type,
                                      field_name,
                                      field_type_out,
                                      field_type_cap,
                                      field_abi_out,
                                      field_abi_cap,
                                      field_offset_out,
                                      0U);
}

static bool cheng_seed_resolve_field_path_expr(const ChengSeedLoweringPlanStub *lowering,
                                       const ChengSeedAsmLocalSlot *locals,
                                       size_t local_count,
                                       const char *expr_text,
                                       int32_t *base_local_index_out,
                                       char *field_type_out,
                                       size_t field_type_cap,
                                       char *field_abi_out,
                                       size_t field_abi_cap,
                                       int32_t *field_offset_out) {
    char expr[4096];
    char *segments[32];
    size_t segment_count = 0U;
    char *cursor;
    char current_type[256];
    int32_t local_index;
    int32_t total_offset = 0;
    size_t i;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0' ||
        strchr(expr, '(') != NULL ||
        strchr(expr, '[') != NULL ||
        strchr(expr, ' ') != NULL) {
        return false;
    }
    cursor = expr;
    segments[segment_count++] = cursor;
    while (*cursor != '\0') {
        if (*cursor == '.') {
            *cursor = '\0';
            if (segment_count >= 32U || cursor[1] == '\0') {
                return false;
            }
            segments[segment_count++] = cursor + 1;
        }
        cursor += 1;
    }
    if (segment_count < 2U) {
        return false;
    }
    local_index = cheng_seed_find_local_slot(locals, local_count, segments[0]);
    if (local_index < 0) {
        return false;
    }
    snprintf(current_type, sizeof(current_type), "%s", locals[local_index].type_text);
    for (i = 1; i < segment_count; ++i) {
        int32_t current_offset = 0;
        char next_type[256];
        char next_abi[32];
        if (!cheng_seed_resolve_field_meta(lowering,
                                   current_type,
                                   segments[i],
                                   next_type,
                                   sizeof(next_type),
                                   next_abi,
                                   sizeof(next_abi),
                                   &current_offset)) {
            return false;
        }
        total_offset += current_offset;
        snprintf(current_type, sizeof(current_type), "%s", next_type);
        snprintf(field_abi_out, field_abi_cap, "%s", next_abi);
    }
    if (base_local_index_out) {
        *base_local_index_out = local_index;
    }
    if (field_type_out) {
        snprintf(field_type_out, field_type_cap, "%s", current_type);
    }
    if (field_offset_out) {
        *field_offset_out = total_offset;
    }
    return true;
}

static bool cheng_seed_emit_index_access_address(const ChengSeedSystemLinkPlanStub *plan,
                                         const ChengSeedLoweringPlanStub *lowering,
                                         const ChengSeedLoweredFunctionStub *current_function,
                                         const ChengSeedImportAlias *aliases,
                                         size_t alias_count,
                                         const ChengSeedAsmLocalSlot *locals,
                                         size_t local_count,
                                         const char *expr_text,
                                         char *field_type_out,
                                         size_t field_type_cap,
                                         char *field_abi_out,
                                         size_t field_abi_cap,
                                         int addr_reg,
                                         int32_t call_arg_base,
                                         int32_t string_temp_base,
                                         int32_t string_temp_stride,
                                         int call_depth,
                                         char *out,
                                         size_t cap);
static bool cheng_seed_infer_expr_type(const ChengSeedSystemLinkPlanStub *plan,
                               const ChengSeedLoweringPlanStub *lowering,
                               const ChengSeedLoweredFunctionStub *current_function,
                               const ChengSeedImportAlias *aliases,
                               size_t alias_count,
                               const ChengSeedAsmLocalSlot *locals,
                               size_t local_count,
                               const char *expr_text,
                               char *type_out,
                               size_t type_cap,
                               char *abi_out,
                               size_t abi_cap);

static bool cheng_seed_emit_field_path_address(char *out,
                                       size_t cap,
                                       const ChengSeedAsmLocalSlot *locals,
                                       size_t local_count,
                                       const ChengSeedLoweringPlanStub *lowering,
                                       const char *expr_text,
                                       char *field_type_out,
                                       size_t field_type_cap,
                                       char *field_abi_out,
                                       size_t field_abi_cap,
                                       int addr_reg) {
    char expr[4096];
    char *segments[32];
    size_t segment_count = 0U;
    char *cursor;
    char current_type[256];
    int32_t local_index;
    size_t i;
    cheng_seed_trim_copy_text(expr_text, expr, sizeof(expr));
    if (expr[0] == '\0' ||
        strchr(expr, '(') != NULL ||
        strchr(expr, '[') != NULL ||
        strchr(expr, ' ') != NULL) {
        return false;
    }
    cursor = expr;
    segments[segment_count++] = cursor;
    while (*cursor != '\0') {
        if (*cursor == '.') {
            *cursor = '\0';
            if (segment_count >= 32U || cursor[1] == '\0') {
                return false;
            }
            segments[segment_count++] = cursor + 1;
        }
        cursor += 1;
    }
    if (segment_count < 2U) {
        return false;
    }
    local_index = cheng_seed_find_local_slot(locals, local_count, segments[0]);
    if (local_index < 0 ||
        !cheng_seed_emit_local_value_address(out, cap, &locals[local_index], addr_reg)) {
        return false;
    }
    snprintf(current_type, sizeof(current_type), "%s", locals[local_index].type_text);
    for (i = 1; i < segment_count; ++i) {
        int32_t field_offset = 0;
        char next_type[256];
        char next_abi[32];
        if (cheng_seed_is_internal_ref_type(current_type)) {
            cheng_seed_emit_load_scalar_from_address(out, cap, addr_reg, 0, "ptr", addr_reg);
        }
        if (!cheng_seed_resolve_field_meta(lowering,
                                   current_type,
                                   segments[i],
                                   next_type,
                                   sizeof(next_type),
                                   next_abi,
                                   sizeof(next_abi),
                                   &field_offset)) {
            return false;
        }
        if (field_offset != 0 &&
            !cheng_seed_emit_add_address_offset(out, cap, addr_reg, addr_reg, field_offset)) {
            return false;
        }
        snprintf(current_type, sizeof(current_type), "%s", next_type);
        snprintf(field_abi_out, field_abi_cap, "%s", next_abi);
    }
    snprintf(field_type_out, field_type_cap, "%s", current_type);
    return true;
}

static bool cheng_seed_emit_result_field_address(const ChengSeedSystemLinkPlanStub *plan,
                                         const ChengSeedLoweringPlanStub *lowering,
                                         const ChengSeedLoweredFunctionStub *current_function,
                                         const ChengSeedImportAlias *aliases,
                                         size_t alias_count,
                                         const ChengSeedAsmLocalSlot *locals,
                                         size_t local_count,
                                         const char *arg_expr,
                                         const char *field_name,
                                         int addr_reg,
                                         int32_t call_arg_base,
                                         int32_t string_temp_base,
                                         int32_t string_temp_stride,
                                         int32_t *string_label_index_io,
                                         int call_depth,
                                         char *out,
                                         size_t cap,
                                         char *field_type_out,
                                         size_t field_type_cap,
                                         char *field_abi_out,
                                         size_t field_abi_cap);

static bool cheng_seed_emit_member_access_address(const ChengSeedSystemLinkPlanStub *plan,
                                          const ChengSeedLoweringPlanStub *lowering,
                                          const ChengSeedLoweredFunctionStub *current_function,
                                          const ChengSeedImportAlias *aliases,
                                          size_t alias_count,
                                          const ChengSeedAsmLocalSlot *locals,
                                          size_t local_count,
                                          const char *expr_text,
                                          char *field_type_out,
                                          size_t field_type_cap,
                                          char *field_abi_out,
                                          size_t field_abi_cap,
                                          int addr_reg,
                                          int32_t call_arg_base,
                                          int32_t string_temp_base,
                                          int32_t string_temp_stride,
                                          int call_depth,
                                          char *out,
                                          size_t cap) {
    char base_expr[4096];
    char field_name[128];
    char base_type[256];
    char base_abi[32];
    char normalized_base_type[256];
    char nested_type[256];
    char nested_abi[32];
    char result_callee[PATH_MAX];
    char result_arg_text[4096] = {0};
    char result_value_expr[4096] = {0};
    size_t result_arg_count = 0U;
    int32_t field_offset = 0;
    int32_t local_index = -1;
    if (!cheng_seed_parse_member_access_expr(expr_text,
                                     base_expr,
                                     sizeof(base_expr),
                                     field_name,
                                     sizeof(field_name)) ||
        !cheng_seed_infer_expr_type(plan,
                            lowering,
                            current_function,
                            aliases,
                            alias_count,
                            locals,
                            local_count,
                            base_expr,
                            base_type,
                            sizeof(base_type),
                            base_abi,
                            sizeof(base_abi)) ||
        !cheng_seed_normalize_type_text(lowering,
                                current_function->owner_module_path,
                                aliases,
                                alias_count,
                                base_type,
                                normalized_base_type,
                                sizeof(normalized_base_type)) ||
        !cheng_seed_resolve_field_meta(lowering,
                               base_type,
                               field_name,
                               field_type_out,
                               field_type_cap,
                               field_abi_out,
                               field_abi_cap,
                               &field_offset)) {
        return false;
    }
    local_index = cheng_seed_find_local_slot(locals, local_count, base_expr);
    if (local_index >= 0) {
        if (!cheng_seed_emit_local_value_address(out, cap, &locals[local_index], addr_reg)) {
            return false;
        }
    } else if (cheng_seed_emit_owner_global_var_address(plan,
                                                lowering,
                                                current_function,
                                                base_expr,
                                                nested_type,
                                                sizeof(nested_type),
                                                nested_abi,
                                                sizeof(nested_abi),
                                                addr_reg,
                                                out,
                                                cap)) {
    } else {
        bool result_value_base = false;
        char (*result_args)[4096] = cheng_seed_alloc_call_arg_scratch();
        if ((cheng_seed_parse_call_text(base_expr,
                                result_callee,
                                sizeof(result_callee),
                                result_args,
                                &result_arg_count,
                                CHENG_MAX_CALL_ARGS) ||
             cheng_seed_parse_prefix_single_arg_call(base_expr,
                                             result_callee,
                                             sizeof(result_callee),
                                             result_arg_text,
                                             sizeof(result_arg_text))) &&
            ((result_arg_count == 1U) || (result_arg_count == 0U && result_arg_text[0] != '\0')) &&
            cheng_seed_resolve_result_intrinsic_kind(lowering,
                                            current_function->owner_module_path,
                                            aliases,
                                            alias_count,
                                            result_callee) == ChengSeed_RESULT_INTRINSIC_VALUE) {
            if (result_arg_count == 0U) {
                snprintf(result_value_expr, sizeof(result_value_expr), "%s", result_arg_text);
            } else {
                snprintf(result_value_expr, sizeof(result_value_expr), "%s", result_args[0]);
            }
            result_value_base = true;
        }
        free(result_args);
        if (result_value_base) {
            if (!cheng_seed_emit_result_field_address(plan,
                                              lowering,
                                              current_function,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              result_value_expr,
                                              "value",
                                              addr_reg,
                                              call_arg_base,
                                              string_temp_base,
                                              string_temp_stride,
                                              NULL,
                                              call_depth,
                                              out,
                                              cap,
                                              nested_type,
                                              sizeof(nested_type),
                                              nested_abi,
                                              sizeof(nested_abi))) {
                return false;
            }
        } else if (!cheng_seed_emit_index_access_address(plan,
                                                 lowering,
                                                 current_function,
                                                 aliases,
                                                 alias_count,
                                                 locals,
                                                 local_count,
                                                 base_expr,
                                                 nested_type,
                                                 sizeof(nested_type),
                                                 nested_abi,
                                                 sizeof(nested_abi),
                                                 addr_reg,
                                                 call_arg_base,
                                                 string_temp_base,
                                                 string_temp_stride,
                                                 call_depth + 1,
                                                 out,
                                                 cap) &&
                   !cheng_seed_emit_member_access_address(plan,
                                                  lowering,
                                                  current_function,
                                                  aliases,
                                                  alias_count,
                                                  locals,
                                                  local_count,
                                                  base_expr,
                                                  nested_type,
                                                  sizeof(nested_type),
                                                  nested_abi,
                                                  sizeof(nested_abi),
                                                  addr_reg,
                                                  call_arg_base,
                                                  string_temp_base,
                                                  string_temp_stride,
                                                  call_depth + 1,
                                                  out,
                                                  cap) &&
                   !cheng_seed_emit_field_path_address(out,
                                               cap,
                                               locals,
                                               local_count,
                                               lowering,
                                               base_expr,
                                               nested_type,
                                               sizeof(nested_type),
                                               nested_abi,
                                               sizeof(nested_abi),
                                               addr_reg)) {
            return false;
        }
    }
    if (cheng_seed_is_internal_ref_type(base_type) ||
        (strcmp(base_abi, "ptr") == 0 &&
         (strcmp(normalized_base_type, "ptr") == 0 ||
          strcmp(normalized_base_type, "cstring") == 0 ||
          cheng_seed_type_text_strip_one_pointer_suffix(normalized_base_type, nested_type, sizeof(nested_type))))) {
        cheng_seed_emit_load_scalar_from_address(out, cap, addr_reg, 0, "ptr", addr_reg);
    }
    if (!cheng_seed_emit_add_address_offset(out, cap, addr_reg, addr_reg, field_offset)) {
        return false;
    }
    return true;
}

