typedef enum ChengSeedNativeSeqRuntimeKind {
    ChengSeed_NATIVE_SEQ_RUNTIME_INVALID = 0,
    ChengSeed_NATIVE_SEQ_RUNTIME_LEN_GET = 1,
    ChengSeed_NATIVE_SEQ_RUNTIME_GROW_INST = 2,
    ChengSeed_NATIVE_SEQ_RUNTIME_BUFFER_GET = 3,
    ChengSeed_NATIVE_SEQ_RUNTIME_ZERO_TAIL_RAW = 4,
    ChengSeed_NATIVE_SEQ_RUNTIME_LEN_SET = 5,
    ChengSeed_NATIVE_SEQ_RUNTIME_SET_GROW = 6
} ChengSeedNativeSeqRuntimeKind;

static bool cheng_seed_build_native_seq_runtime_target(const ChengSeedSystemLinkPlanStub *plan,
                                               ChengSeedNativeSeqRuntimeKind kind,
                                               ChengSeedAsmCallTarget *target) {
    const char *symbol = NULL;
    const char *return_type = NULL;
    size_t param_count = 0U;
    const char *param_types[5] = {0};
    if (plan == NULL || target == NULL) {
        return false;
    }
    memset(target, 0, sizeof(*target));
    target->external = true;
    switch (kind) {
        case ChengSeed_NATIVE_SEQ_RUNTIME_LEN_GET:
            symbol = "cheng_seq_header_len_get";
            return_type = "int32";
            param_count = 1U;
            param_types[0] = "ptr";
            break;
        case ChengSeed_NATIVE_SEQ_RUNTIME_GROW_INST:
            symbol = "cheng_seq_grow_inst";
            return_type = "void";
            param_count = 3U;
            param_types[0] = "ptr";
            param_types[1] = "int32";
            param_types[2] = "int32";
            break;
        case ChengSeed_NATIVE_SEQ_RUNTIME_BUFFER_GET:
            symbol = "cheng_seq_header_buffer_get";
            return_type = "ptr";
            param_count = 1U;
            param_types[0] = "ptr";
            break;
        case ChengSeed_NATIVE_SEQ_RUNTIME_ZERO_TAIL_RAW:
            symbol = "cheng_seq_zero_tail_raw";
            return_type = "void";
            param_count = 5U;
            param_types[0] = "ptr";
            param_types[1] = "int32";
            param_types[2] = "int32";
            param_types[3] = "int32";
            param_types[4] = "int32";
            break;
        case ChengSeed_NATIVE_SEQ_RUNTIME_LEN_SET:
            symbol = "cheng_seq_header_len_set";
            return_type = "void";
            param_count = 2U;
            param_types[0] = "ptr";
            param_types[1] = "int32";
            break;
        case ChengSeed_NATIVE_SEQ_RUNTIME_SET_GROW:
            symbol = "cheng_seq_set_grow";
            return_type = "ptr";
            param_count = 3U;
            param_types[0] = "ptr";
            param_types[1] = "int32";
            param_types[2] = "int32";
            break;
        default:
            return false;
    }
    snprintf(target->callee_name, sizeof(target->callee_name), "%s", symbol);
    cheng_seed_copy_target_symbol_name(plan, symbol, target->symbol_name, sizeof(target->symbol_name));
    return cheng_seed_call_target_set_signature(target, return_type, param_count, param_types);
}

