static bool cheng_seed_try_emit_builtin_statement_impl(const ChengSeedSystemLinkPlanStub *plan,
                                               const ChengSeedLoweringPlanStub *lowering,
                                               const ChengSeedLoweredFunctionStub *current_function,
                                               const ChengSeedImportAlias *aliases,
                                               size_t alias_count,
                                               const ChengSeedAsmLocalSlot *locals,
                                               size_t local_count,
                                               const char *callee,
                                               char args[][4096],
                                               size_t arg_count,
                                               int32_t call_arg_base,
                                               int32_t string_temp_base,
                                               int32_t string_temp_stride,
                                               int32_t *string_label_index_io,
                                               int32_t *control_label_index_io,
                                               char *out,
                                               size_t cap,
                                               bool *handled_out) {
    (void)control_label_index_io;
    *handled_out = false;
    if (strcmp(callee, "store") == 0 && arg_count == 2U) {
        char value_type[256];
        char value_abi[32];
        *handled_out = true;
        if (!cheng_seed_codegen_expr_scalar(plan,
                                    lowering,
                                    current_function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    args[0],
                                    "ptr",
                                    14,
                                    call_arg_base,
                                    string_temp_base,
                                    string_temp_stride,
                                    0,
                                    out,
                                    cap) ||
            !cheng_seed_infer_expr_type(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                locals,
                                local_count,
                                args[1],
                                value_type,
                                sizeof(value_type),
                                value_abi,
                                sizeof(value_abi))) {
            return false;
        }
        if (!cheng_seed_expr_materializes_to_address(value_type, value_abi)) {
            if (!cheng_seed_codegen_expr_scalar(plan,
                                        lowering,
                                        current_function,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        args[1],
                                        value_abi,
                                        9,
                                        call_arg_base,
                                        string_temp_base,
                                        string_temp_stride,
                                        0,
                                        out,
                                        cap)) {
                return false;
            }
            cheng_seed_emit_address_spill_load(out, cap, call_arg_base, 0, 14);
            cheng_seed_emit_store_scalar_to_address(out, cap, 14, 0, value_abi, 9);
            return true;
        }
        return cheng_seed_materialize_composite_expr_into_address(plan,
                                                          lowering,
                                                          current_function,
                                                          aliases,
                                                          alias_count,
                                                          locals,
                                                          local_count,
                                                          args[1],
                                                          value_type,
                                                          14,
                                                          call_arg_base,
                                                          string_temp_base,
                                                          string_temp_stride,
                                                          string_label_index_io,
                                                          0,
                                                          out,
                                                          cap);
    }
    if (strcmp(callee, "add") == 0 && arg_count == 2U) {
        char seq_type[256];
        char seq_abi[32];
        char elem_type[256];
        char elem_abi[32];
        int32_t elem_size = 0;
        ChengSeedTypeLayoutStub elem_layout;
        *handled_out = true;
        if (!cheng_seed_infer_expr_type(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                locals,
                                local_count,
                                args[0],
                                seq_type,
                                sizeof(seq_type),
                                seq_abi,
                                sizeof(seq_abi)) ||
            !cheng_seed_expr_materializes_to_address(seq_type, seq_abi) ||
            strlen(seq_type) <= 2U ||
            strcmp(seq_type + strlen(seq_type) - 2U, "[]") != 0) {
            return false;
        }
        snprintf(elem_type, sizeof(elem_type), "%.*s", (int)(strlen(seq_type) - 2U), seq_type);
        snprintf(elem_abi, sizeof(elem_abi), "%s", cheng_seed_type_abi_class(elem_type));
        if (strcmp(elem_abi, "i8") == 0 ||
            strcmp(elem_abi, "u8") == 0 ||
            strcmp(elem_abi, "bool") == 0) {
            elem_size = 1;
        } else if (strcmp(elem_abi, "i16") == 0 ||
                   strcmp(elem_abi, "u16") == 0) {
            elem_size = 2;
        } else if (strcmp(elem_abi, "i32") == 0) {
            elem_size = 4;
        } else if (strcmp(elem_abi, "i64") == 0 || strcmp(elem_abi, "ptr") == 0) {
            elem_size = 8;
        } else if (!cheng_seed_compute_type_layout_impl(lowering, elem_type, &elem_layout, 0U)) {
            return false;
        } else {
            elem_size = elem_layout.size;
        }
        if (elem_size <= 0) {
            return false;
        }
        if (!cheng_seed_emit_lvalue_address(plan,
                                    lowering,
                                    current_function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    args[0],
                                    seq_type,
                                    sizeof(seq_type),
                                    seq_abi,
                                    sizeof(seq_abi),
                                    15,
                                    call_arg_base,
                                    string_temp_base,
                                    string_temp_stride,
                                    0,
                                    out,
                                    cap) ||
            !cheng_seed_expr_materializes_to_address(seq_type, seq_abi)) {
            return false;
        }
        if (cheng_seed_active_target_is_linux_x86_64()) {
            cheng_seed_emit_load_scalar_from_address(out, cap, 15, 0, "i32", 10);
        } else {
            cheng_seed_text_appendf(out, cap, "  ldrsw x10, [x15, #0]\n");
        }
        if (!cheng_seed_emit_mov_imm(out, cap, 2, elem_size)) {
            return false;
        }
        if (!cheng_seed_emit_native_seq_runtime_call_ptr_i32_i32(plan,
                                                         ChengSeed_NATIVE_SEQ_RUNTIME_SET_GROW,
                                                         15,
                                                         10,
                                                         2,
                                                         out,
                                                         cap)) {
            return false;
        }
        cheng_seed_emit_address_spill_store(out, cap, call_arg_base, 0, 0);
        if (!cheng_seed_expr_materializes_to_address(elem_type, elem_abi)) {
            if (!cheng_seed_codegen_expr_scalar(plan,
                                        lowering,
                                        current_function,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        args[1],
                                        elem_abi,
                                        9,
                                        call_arg_base,
                                        string_temp_base,
                                        string_temp_stride,
                                        1,
                                        out,
                                        cap)) {
                return false;
            }
            cheng_seed_emit_address_spill_load(out, cap, call_arg_base, 0, 0);
            cheng_seed_emit_store_scalar_to_address(out, cap, 0, 0, elem_abi, 9);
            return true;
        }
        cheng_seed_emit_address_spill_load(out, cap, call_arg_base, 0, 15);
        return cheng_seed_materialize_composite_expr_into_address(plan,
                                                          lowering,
                                                          current_function,
                                                          aliases,
                                                          alias_count,
                                                          locals,
                                                          local_count,
                                                          args[1],
                                                          elem_type,
                                                          15,
                                                          call_arg_base,
                                                          string_temp_base,
                                                          string_temp_stride,
                                                          string_label_index_io,
                                                          1,
                                                          out,
                                                          cap);
    }
    if (strcmp(callee, "setLen") == 0 && arg_count == 2U) {
        char seq_type[256];
        char seq_abi[32];
        char elem_type[256];
        char elem_abi[32];
        int32_t elem_size = 0;
        int32_t clamp_label_id = 0;
        ChengSeedTypeLayoutStub elem_layout;
        *handled_out = true;
        if (!cheng_seed_infer_expr_type(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                locals,
                                local_count,
                                args[0],
                                seq_type,
                                sizeof(seq_type),
                                seq_abi,
                                sizeof(seq_abi)) ||
            !cheng_seed_expr_materializes_to_address(seq_type, seq_abi) ||
            strlen(seq_type) <= 2U ||
            strcmp(seq_type + strlen(seq_type) - 2U, "[]") != 0 ||
            !cheng_seed_emit_lvalue_address(plan,
                                    lowering,
                                    current_function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    args[0],
                                    seq_type,
                                    sizeof(seq_type),
                                    seq_abi,
                                    sizeof(seq_abi),
                                    15,
                                    call_arg_base,
                                    string_temp_base,
                                    string_temp_stride,
                                    0,
                                    out,
                                    cap) ||
            !cheng_seed_codegen_expr_scalar(plan,
                                    lowering,
                                    current_function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    args[1],
                                    "i32",
                                    10,
                                    call_arg_base,
                                    string_temp_base,
                                    string_temp_stride,
                                    1,
                                    out,
                                    cap)) {
            return false;
        }
        snprintf(elem_type, sizeof(elem_type), "%.*s", (int)(strlen(seq_type) - 2U), seq_type);
        snprintf(elem_abi, sizeof(elem_abi), "%s", cheng_seed_type_abi_class(elem_type));
        if (strcmp(elem_abi, "i8") == 0 ||
            strcmp(elem_abi, "u8") == 0 ||
            strcmp(elem_abi, "bool") == 0) {
            elem_size = 1;
        } else if (strcmp(elem_abi, "i16") == 0 ||
                   strcmp(elem_abi, "u16") == 0) {
            elem_size = 2;
        } else if (strcmp(elem_abi, "i32") == 0 ||
                   strcmp(elem_abi, "u32") == 0) {
            elem_size = 4;
        } else if (strcmp(elem_abi, "i64") == 0 || strcmp(elem_abi, "ptr") == 0) {
            elem_size = 8;
        } else if (!cheng_seed_compute_type_layout_impl(lowering, elem_type, &elem_layout, 0U)) {
            return false;
        } else {
            elem_size = elem_layout.size;
        }
        if (elem_size <= 0) {
            return false;
        }
        clamp_label_id = control_label_index_io != NULL
                         ? (*control_label_index_io)++
                         : cheng_seed_next_expr_label_id();
        if (cheng_seed_active_target_is_linux_x86_64()) {
            cheng_seed_text_appendf(out, cap,
                            "  cmpl $0, %s\n"
                            "  jge L_cheng_setlen_nonneg_%d\n"
                            "  xorl %s, %s\n"
                            "L_cheng_setlen_nonneg_%d:\n",
                            cheng_seed_x64_dreg_name(10),
                            clamp_label_id,
                            cheng_seed_x64_dreg_name(10),
                            cheng_seed_x64_dreg_name(10),
                            clamp_label_id);
        } else {
            cheng_seed_text_appendf(out, cap,
                            "  cmp w10, #0\n"
                            "  b.ge L_cheng_setlen_nonneg_%d\n"
                            "  mov w10, wzr\n"
                            "L_cheng_setlen_nonneg_%d:\n",
                            clamp_label_id,
                            clamp_label_id);
        }
        cheng_seed_emit_address_spill_store(out, cap, call_arg_base, 0, 15);
        cheng_seed_emit_call_arg_spill_store(out, cap, call_arg_base, 0, 1U, "i32", 10);

        cheng_seed_emit_address_spill_load(out, cap, call_arg_base, 0, 15);
        if (!cheng_seed_emit_native_seq_runtime_call_ptr(plan,
                                                 ChengSeed_NATIVE_SEQ_RUNTIME_LEN_GET,
                                                 15,
                                                 out,
                                                 cap)) {
            return false;
        }
        cheng_seed_emit_call_arg_spill_store(out, cap, call_arg_base, 0, 2U, "i32", 0);

        cheng_seed_emit_address_spill_load(out, cap, call_arg_base, 0, 15);
        cheng_seed_emit_call_arg_spill_load(out, cap, call_arg_base, 0, 1U, 10, "i32");
        if (!cheng_seed_emit_mov_imm(out, cap, 11, elem_size)) {
            return false;
        }
        if (!cheng_seed_emit_native_seq_runtime_call_ptr_i32_i32(plan,
                                                         ChengSeed_NATIVE_SEQ_RUNTIME_GROW_INST,
                                                         15,
                                                         10,
                                                         11,
                                                         out,
                                                         cap)) {
            return false;
        }

        cheng_seed_emit_address_spill_load(out, cap, call_arg_base, 0, 15);
        if (!cheng_seed_emit_native_seq_runtime_call_ptr(plan,
                                                 ChengSeed_NATIVE_SEQ_RUNTIME_BUFFER_GET,
                                                 15,
                                                 out,
                                                 cap)) {
            return false;
        }
        cheng_seed_emit_address_spill_store(out, cap, call_arg_base, 1, 0);

        cheng_seed_emit_address_spill_load(out, cap, call_arg_base, 1, 15);
        cheng_seed_emit_call_arg_spill_load(out, cap, call_arg_base, 0, 2U, 10, "i32");
        cheng_seed_emit_call_arg_spill_load(out, cap, call_arg_base, 0, 1U, 11, "i32");
        if (!cheng_seed_emit_mov_imm(out, cap, 12, elem_size) ||
            !cheng_seed_emit_mov_imm(out, cap, 9, 0)) {
            return false;
        }
        if (!cheng_seed_emit_native_seq_runtime_call_ptr_i32_i32_i32_i32(plan,
                                                                 ChengSeed_NATIVE_SEQ_RUNTIME_ZERO_TAIL_RAW,
                                                                 15,
                                                                 9,
                                                                 10,
                                                                 11,
                                                                 12,
                                                                 out,
                                                                 cap)) {
            return false;
        }

        cheng_seed_emit_address_spill_load(out, cap, call_arg_base, 0, 15);
        cheng_seed_emit_call_arg_spill_load(out, cap, call_arg_base, 0, 1U, 10, "i32");
        if (!cheng_seed_emit_native_seq_runtime_call_ptr_i32(plan,
                                                     ChengSeed_NATIVE_SEQ_RUNTIME_LEN_SET,
                                                     15,
                                                     10,
                                                     out,
                                                     cap)) {
            return false;
        }
        return true;
    }
    if ((strcmp(callee, "panic") == 0 || strcmp(callee, "system.panic") == 0) && arg_count == 1U) {
        char literal[4096];
        char label[128];
        char arg_type[256];
        char arg_abi[32];
        *handled_out = true;
        if (cheng_seed_parse_string_literal_text(args[0], literal, sizeof(literal))) {
            if (!cheng_seed_emit_cstring_literal_label(plan,
                                               current_function,
                                               literal,
                                               string_label_index_io,
                                               label,
                                               sizeof(label),
                                               out,
                                               cap)) {
                return false;
            }
            if (!cheng_seed_emit_symbol_address_for_target(plan, out, cap, 0, label)) {
                return false;
            }
            return cheng_seed_emit_native_panic_cstring_reg0_call(plan, out, cap);
        }
        if (!cheng_seed_infer_expr_type(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                locals,
                                local_count,
                                args[0],
                                arg_type,
                                sizeof(arg_type),
                                arg_abi,
                                sizeof(arg_abi))) {
            return false;
        }
        if (strcmp(arg_abi, "ptr") == 0) {
            if (!cheng_seed_codegen_expr_scalar(plan,
                                        lowering,
                                        current_function,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        args[0],
                                        "ptr",
                                        0,
                                        call_arg_base,
                                        string_temp_base,
                                        string_temp_stride,
                                        0,
                                        out,
                                        cap)) {
                return false;
            }
            return cheng_seed_emit_native_panic_cstring_reg0_call(plan, out, cap);
        }
        if (strcmp(arg_type, "str") != 0 ||
            !cheng_seed_expr_materializes_to_address(arg_type, arg_abi)) {
            return false;
        }
        if (!cheng_seed_emit_builtin_str_expr_address(plan,
                                              lowering,
                                              current_function,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              args[0],
                                              "__cheng_panic_str_tmp",
                                              15,
                                              call_arg_base,
                                              string_temp_base,
                                              string_temp_stride,
                                              string_label_index_io,
                                              0,
                                              out,
                                              cap) ||
            !cheng_seed_emit_builtin_str_to_cstring_bridge(plan,
                                                   lowering,
                                                   current_function,
                                                   aliases,
                                                   alias_count,
                                                   15,
                                                   call_arg_base,
                                                   0,
                                                   out,
                                                   cap)) {
            return false;
        }
        return cheng_seed_emit_native_panic_cstring_reg0_call(plan, out, cap);
    }
    if (strcmp(callee, "echo") == 0) {
        char literal[4096];
        char label[128];
        char arg_type[256];
        char arg_abi[32];
        *handled_out = true;
        if (arg_count != 1U) {
            return false;
        }
        if (cheng_seed_parse_string_literal_text(args[0], literal, sizeof(literal))) {
            if (!cheng_seed_emit_cstring_literal_label(plan,
                                               current_function,
                                               literal,
                                               string_label_index_io,
                                               label,
                                               sizeof(label),
                                               out,
                                               cap)) {
                return false;
            }
            if (!cheng_seed_emit_symbol_address_for_target(plan, out, cap, 0, label)) {
                return false;
            }
            return cheng_seed_emit_native_puts_reg0_call(plan, out, cap);
        }
        if (!cheng_seed_infer_expr_type(plan,
                                lowering,
                                current_function,
                                aliases,
                                alias_count,
                                locals,
                                local_count,
                                args[0],
                                arg_type,
                                sizeof(arg_type),
                                arg_abi,
                                sizeof(arg_abi)) ||
            strcmp(arg_type, "str") != 0 ||
            !cheng_seed_expr_materializes_to_address(arg_type, arg_abi)) {
            return false;
        }
        if (!cheng_seed_emit_builtin_str_expr_address(plan,
                                              lowering,
                                              current_function,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              args[0],
                                              "__cheng_echo_str_tmp",
                                              15,
                                              call_arg_base,
                                              string_temp_base,
                                              string_temp_stride,
                                              string_label_index_io,
                                              0,
                                              out,
                                              cap) ||
            !cheng_seed_emit_builtin_str_to_cstring_bridge(plan,
                                                   lowering,
                                                   current_function,
                                                   aliases,
                                                   alias_count,
                                                   15,
                                                   call_arg_base,
                                                   0,
                                                   out,
                                                   cap)) {
            return false;
        }
        return cheng_seed_emit_native_puts_reg0_call(plan, out, cap);
    }
    if (strcmp(callee, "assert") == 0) {
        char ok_label[128];
        int32_t label_id = cheng_seed_next_expr_label_id();
        char literal[4096];
        char label[128];
        char arg_type[256];
        char arg_abi[32];
        *handled_out = true;
        if ((arg_count != 1U && arg_count != 2U) ||
            !cheng_seed_codegen_expr_scalar(plan,
                                    lowering,
                                    current_function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    args[0],
                                    "bool",
                                    9,
                                    call_arg_base,
                                    string_temp_base,
                                    string_temp_stride,
                                    0,
                                    out,
                                    cap)) {
            return false;
        }
        snprintf(ok_label, sizeof(ok_label), "L_cheng_assert_ok_%d", label_id);
        cheng_seed_emit_branch_nonzero(out, cap, 9, false, ok_label);
        if (arg_count == 2U) {
            if (!cheng_seed_parse_string_literal_text(args[1], literal, sizeof(literal))) {
                if (!cheng_seed_infer_expr_type(plan,
                                        lowering,
                                        current_function,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        args[1],
                                        arg_type,
                                        sizeof(arg_type),
                                        arg_abi,
                                        sizeof(arg_abi))) {
                    return false;
                }
                if (strcmp(arg_abi, "ptr") == 0) {
                    if (!cheng_seed_codegen_expr_scalar(plan,
                                                lowering,
                                                current_function,
                                                aliases,
                                                alias_count,
                                                locals,
                                                local_count,
                                                args[1],
                                                "ptr",
                                                0,
                                                call_arg_base,
                                                string_temp_base,
                                                string_temp_stride,
                                                0,
                                                out,
                                                cap) ||
                        !cheng_seed_emit_native_panic_cstring_reg0_call(plan, out, cap)) {
                        return false;
                    }
                    cheng_seed_text_appendf(out, cap, "%s:\n", ok_label);
                    return true;
                }
                if (strcmp(arg_type, "str") != 0 ||
                    !cheng_seed_expr_materializes_to_address(arg_type, arg_abi) ||
                    !cheng_seed_emit_builtin_str_expr_address(plan,
                                                      lowering,
                                                      current_function,
                                                      aliases,
                                                      alias_count,
                                                      locals,
                                                      local_count,
                                                      args[1],
                                                      "__cheng_assert_str_tmp",
                                                      15,
                                                      call_arg_base,
                                                      string_temp_base,
                                                      string_temp_stride,
                                                      string_label_index_io,
                                                      0,
                                                      out,
                                                      cap) ||
                    !cheng_seed_emit_builtin_str_to_cstring_bridge(plan,
                                                           lowering,
                                                           current_function,
                                                           aliases,
                                                           alias_count,
                                                           15,
                                                           call_arg_base,
                                                           0,
                                                           out,
                                                           cap) ||
                    !cheng_seed_emit_native_panic_cstring_reg0_call(plan, out, cap)) {
                    return false;
                }
                cheng_seed_text_appendf(out, cap, "%s:\n", ok_label);
                return true;
            }
        } else {
            snprintf(literal, sizeof(literal), "%s", "assert failed");
        }
        if (!cheng_seed_emit_cstring_literal_label(plan,
                                           current_function,
                                           literal,
                                           string_label_index_io,
                                           label,
                                           sizeof(label),
                                           out,
                                           cap)) {
            return false;
        }
        if (!cheng_seed_emit_symbol_address_for_target(plan, out, cap, 0, label)) {
            return false;
        }
        if (!cheng_seed_emit_native_panic_cstring_reg0_call(plan, out, cap)) {
            return false;
        }
        cheng_seed_text_appendf(out, cap, "%s:\n", ok_label);
        return true;
    }
    return true;
}

static const char *cheng_seed_statement_effective_call_text(const char *statement) {
    return statement;
}

static bool cheng_seed_try_emit_builtin_statement(const ChengSeedSystemLinkPlanStub *plan,
                                          const ChengSeedLoweringPlanStub *lowering,
                                          const ChengSeedLoweredFunctionStub *current_function,
                                          const ChengSeedImportAlias *aliases,
                                          size_t alias_count,
                                          const ChengSeedAsmLocalSlot *locals,
                                          size_t local_count,
                                          const char *statement,
                                          int32_t call_arg_base,
                                          int32_t string_temp_base,
                                          int32_t string_temp_stride,
                                          int32_t *string_label_index_io,
                                          int32_t *control_label_index_io,
                                          char *out,
                                          size_t cap,
                                          bool *handled_out) {
    const char *call_text = cheng_seed_statement_effective_call_text(statement);
    char callee[PATH_MAX];
    char arg_text[4096];
    size_t arg_count = 0U;
    char (*args)[4096] = cheng_seed_alloc_call_arg_scratch();
    bool ok = true;
    callee[0] = '\0';
    arg_text[0] = '\0';
    *handled_out = false;
    if (cheng_seed_parse_call_text(call_text, callee, sizeof(callee), args, &arg_count, CHENG_MAX_CALL_ARGS)) {
        ok = cheng_seed_try_emit_builtin_statement_impl(plan,
                                                lowering,
                                                current_function,
                                                aliases,
                                                alias_count,
                                                locals,
                                                local_count,
                                                callee,
                                                args,
                                                arg_count,
                                                call_arg_base,
                                                string_temp_base,
                                                string_temp_stride,
                                                string_label_index_io,
                                                control_label_index_io,
                                                out,
                                                cap,
                                                handled_out);
    } else if (cheng_seed_parse_prefix_single_arg_call(call_text,
                                               callee,
                                               sizeof(callee),
                                               arg_text,
                                               sizeof(arg_text))) {
        snprintf(args[0], sizeof(args[0]), "%s", arg_text);
        ok = cheng_seed_try_emit_builtin_statement_impl(plan,
                                                lowering,
                                                current_function,
                                                aliases,
                                                alias_count,
                                                locals,
                                                local_count,
                                                callee,
                                                args,
                                                1U,
                                                call_arg_base,
                                                string_temp_base,
                                                string_temp_stride,
                                                string_label_index_io,
                                                control_label_index_io,
                                                out,
                                                cap,
                                                handled_out);
    }
    free(args);
    return ok;
}

static int32_t cheng_seed_find_top_level_colon(const char *text) {
    bool in_string = false;
    bool in_char = false;
    int32_t paren_depth = 0;
    int32_t bracket_depth = 0;
    int32_t brace_depth = 0;
    size_t i;
    for (i = 0; text && text[i] != '\0'; ++i) {
        char ch = text[i];
        bool escaped = false;
        size_t slash = i;
        while (slash > 0U && text[slash - 1U] == '\\') {
            escaped = !escaped;
            slash -= 1U;
        }
        if (!in_char && ch == '"' && !escaped) {
            in_string = !in_string;
            continue;
        }
        if (!in_string && ch == '\'' && !escaped) {
            in_char = !in_char;
            continue;
        }
        if (in_char) {
            continue;
        }
        if (in_string) {
            continue;
        }
        if (ch == '(') {
            paren_depth += 1;
            continue;
        }
        if (ch == ')') {
            paren_depth -= 1;
            continue;
        }
        if (ch == '[') {
            bracket_depth += 1;
            continue;
        }
        if (ch == ']') {
            bracket_depth -= 1;
            continue;
        }
        if (ch == '{') {
            brace_depth += 1;
            continue;
        }
        if (ch == '}') {
            brace_depth -= 1;
            continue;
        }
        if (paren_depth == 0 && bracket_depth == 0 && brace_depth == 0 && ch == ':') {
            return (int32_t)i;
        }
    }
    return -1;
}

static bool cheng_seed_parse_if_like_header(const char *statement,
                                    const char *keyword,
                                    char *cond_out,
                                    size_t cond_cap,
                                    char *inline_stmt_out,
                                    size_t inline_stmt_cap) {
    char trimmed[8192];
    int32_t colon;
    size_t keyword_len = strlen(keyword);
    if (!cheng_seed_startswith(statement, keyword)) {
        return false;
    }
    cheng_seed_trim_copy_text(statement, trimmed, sizeof(trimmed));
    colon = cheng_seed_find_top_level_colon(trimmed);
    if (colon < 0) {
        return false;
    }
    snprintf(cond_out, cond_cap, "%.*s", colon - (int32_t)keyword_len, trimmed + keyword_len);
    cheng_seed_trim_copy_text(cond_out, cond_out, cond_cap);
    snprintf(inline_stmt_out, inline_stmt_cap, "%s", trimmed + colon + 1);
    cheng_seed_trim_copy_text(inline_stmt_out, inline_stmt_out, inline_stmt_cap);
    return cond_out[0] != '\0';
}

static bool cheng_seed_parse_if_header(const char *statement,
                               char *cond_out,
                               size_t cond_cap,
                               char *inline_stmt_out,
                               size_t inline_stmt_cap) {
    return cheng_seed_parse_if_like_header(statement,
                                   "if ",
                                   cond_out,
                                   cond_cap,
                                   inline_stmt_out,
                                   inline_stmt_cap);
}

static bool cheng_seed_parse_elif_header(const char *statement,
                                 char *cond_out,
                                 size_t cond_cap,
                                 char *inline_stmt_out,
                                 size_t inline_stmt_cap) {
    return cheng_seed_parse_if_like_header(statement,
                                   "elif ",
                                   cond_out,
                                   cond_cap,
                                   inline_stmt_out,
                                   inline_stmt_cap);
}

static bool cheng_seed_parse_else_header(const char *statement,
                                 char *inline_stmt_out,
                                 size_t inline_stmt_cap) {
    char trimmed[8192];
    int32_t colon;
    if (!cheng_seed_startswith(statement, "else")) {
        return false;
    }
    cheng_seed_trim_copy_text(statement, trimmed, sizeof(trimmed));
    colon = cheng_seed_find_top_level_colon(trimmed);
    if (colon < 0) {
        return false;
    }
    snprintf(inline_stmt_out, inline_stmt_cap, "%s", trimmed + colon + 1);
    cheng_seed_trim_copy_text(inline_stmt_out, inline_stmt_out, inline_stmt_cap);
    return true;
}

static bool cheng_seed_parse_case_header(const char *statement,
                                 char *expr_out,
                                 size_t expr_cap) {
    if (!cheng_seed_startswith(statement, "case ")) {
        return false;
    }
    cheng_seed_trim_copy_text(statement + 5, expr_out, expr_cap);
    return expr_out[0] != '\0';
}

static bool cheng_seed_parse_case_arm_header(const char *statement,
                                     bool *is_else_out,
                                     int64_t *match_value_out,
                                     char *inline_stmt_out,
                                     size_t inline_stmt_cap) {
    char trimmed[8192];
    int32_t colon;
    char value_text[128];
    *is_else_out = false;
    *match_value_out = 0;
    inline_stmt_out[0] = '\0';
    cheng_seed_trim_copy_text(statement, trimmed, sizeof(trimmed));
    colon = cheng_seed_find_top_level_colon(trimmed);
    if (colon < 0) {
        return false;
    }
    if (cheng_seed_startswith(trimmed, "of ")) {
        snprintf(value_text, sizeof(value_text), "%.*s", colon - 3, trimmed + 3);
        cheng_seed_trim_copy_text(value_text, value_text, sizeof(value_text));
        if (value_text[0] == '\0') {
            return false;
        }
        *match_value_out = strtoll(value_text, NULL, 0);
    } else if (cheng_seed_startswith(trimmed, "else")) {
        *is_else_out = true;
    } else {
        return false;
    }
    snprintf(inline_stmt_out, inline_stmt_cap, "%s", trimmed + colon + 1);
    cheng_seed_trim_copy_text(inline_stmt_out, inline_stmt_out, inline_stmt_cap);
    return inline_stmt_out[0] != '\0';
}

static bool cheng_seed_parse_while_header(const char *statement,
                                  char *cond_out,
                                  size_t cond_cap,
                                  char *inline_stmt_out,
                                  size_t inline_stmt_cap) {
    char trimmed[8192];
    int32_t colon;
    if (!cheng_seed_startswith(statement, "while ")) {
        return false;
    }
    cheng_seed_trim_copy_text(statement, trimmed, sizeof(trimmed));
    colon = cheng_seed_find_top_level_colon(trimmed);
    if (colon < 0) {
        return false;
    }
    snprintf(cond_out, cond_cap, "%.*s", colon - 6, trimmed + 6);
    cheng_seed_trim_copy_text(cond_out, cond_out, cond_cap);
    snprintf(inline_stmt_out, inline_stmt_cap, "%s", trimmed + colon + 1);
    cheng_seed_trim_copy_text(inline_stmt_out, inline_stmt_out, inline_stmt_cap);
    return cond_out[0] != '\0';
}

static bool cheng_seed_parse_for_header(const char *statement,
                                char *iter_name_out,
                                size_t iter_name_cap,
                                char *start_expr_out,
                                size_t start_expr_cap,
                                char *end_expr_out,
                                size_t end_expr_cap,
                                bool *end_inclusive_out,
                                char *inline_stmt_out,
                                size_t inline_stmt_cap) {
    char trimmed[8192];
    int32_t colon;
    char header[8192];
    char *in_sep;
    char *range_text;
    if (!cheng_seed_startswith(statement, "for ")) {
        return false;
    }
    cheng_seed_trim_copy_text(statement, trimmed, sizeof(trimmed));
    colon = cheng_seed_find_top_level_colon(trimmed);
    if (colon < 0) {
        return false;
    }
    snprintf(header, sizeof(header), "%.*s", colon - 4, trimmed + 4);
    cheng_seed_trim_copy_text(header, header, sizeof(header));
    in_sep = strstr(header, " in ");
    if (!in_sep) {
        return false;
    }
    *in_sep = '\0';
    range_text = in_sep + 4;
    cheng_seed_trim_copy_text(header, iter_name_out, iter_name_cap);
    if (!cheng_seed_parse_range_expr(range_text,
                             start_expr_out,
                             start_expr_cap,
                             end_expr_out,
                             end_expr_cap,
                             end_inclusive_out)) {
        return false;
    }
    snprintf(inline_stmt_out, inline_stmt_cap, "%s", trimmed + colon + 1);
    cheng_seed_trim_copy_text(inline_stmt_out, inline_stmt_out, inline_stmt_cap);
    if (iter_name_out[0] == '\0' || start_expr_out[0] == '\0' || end_expr_out[0] == '\0') {
        return false;
    }
    return true;
}

static bool cheng_seed_prepare_if_statement_state(const ChengSeedSystemLinkPlanStub *plan,
                                          const ChengSeedLoweringPlanStub *lowering,
                                          const ChengSeedLoweredFunctionStub *function,
                                          const ChengSeedImportAlias *aliases,
                                          size_t alias_count,
                                          ChengSeedAsmLocalSlot *locals,
                                          size_t *local_count,
                                          size_t local_cap,
                                          int32_t *next_offset_io,
                                          char **lines,
                                          size_t line_count,
                                          size_t *index_io,
                                          int32_t parent_indent,
                                          const char *statement,
                                          int32_t *max_call_depth_io,
                                          int32_t *max_string_literal_temps_io);
static bool cheng_seed_prepare_while_statement_state(const ChengSeedSystemLinkPlanStub *plan,
                                             const ChengSeedLoweringPlanStub *lowering,
                                             const ChengSeedLoweredFunctionStub *function,
                                             const ChengSeedImportAlias *aliases,
                                             size_t alias_count,
                                             ChengSeedAsmLocalSlot *locals,
                                             size_t *local_count,
                                             size_t local_cap,
                                             int32_t *next_offset_io,
                                             char **lines,
                                             size_t line_count,
                                             size_t *index_io,
                                             int32_t parent_indent,
                                             const char *statement,
                                             int32_t *max_call_depth_io,
                                             int32_t *max_string_literal_temps_io);
static bool cheng_seed_prepare_for_statement_state(const ChengSeedSystemLinkPlanStub *plan,
                                           const ChengSeedLoweringPlanStub *lowering,
                                           const ChengSeedLoweredFunctionStub *function,
                                           const ChengSeedImportAlias *aliases,
                                           size_t alias_count,
                                           ChengSeedAsmLocalSlot *locals,
                                           size_t *local_count,
                                           size_t local_cap,
                                           int32_t *next_offset_io,
                                           char **lines,
                                           size_t line_count,
                                           size_t *index_io,
                                           int32_t parent_indent,
                                           const char *statement,
                                           int32_t *max_call_depth_io,
                                           int32_t *max_string_literal_temps_io);
static bool cheng_seed_prepare_case_const_table_statement(const ChengSeedSystemLinkPlanStub *plan,
                                                  const ChengSeedLoweringPlanStub *lowering,
                                                  const ChengSeedLoweredFunctionStub *function,
                                                  const ChengSeedImportAlias *aliases,
                                                  size_t alias_count,
                                                  ChengSeedAsmLocalSlot *locals,
                                                  size_t *local_count,
                                                  size_t local_cap,
                                                  int32_t *next_offset_io,
                                                  char **lines,
                                                  size_t line_count,
                                                  size_t *index_io,
                                                  int32_t parent_indent,
                                                  const char *statement,
                                                  int32_t *max_call_depth_io,
                                                  int32_t *max_string_literal_temps_io);

static bool cheng_seed_prepare_non_if_statement_state(const ChengSeedSystemLinkPlanStub *plan,
                                              const ChengSeedLoweringPlanStub *lowering,
                                              const ChengSeedLoweredFunctionStub *function,
                                              const ChengSeedImportAlias *aliases,
                                              size_t alias_count,
                                              ChengSeedAsmLocalSlot *locals,
                                              size_t *local_count,
                                              size_t local_cap,
                                              int32_t *next_offset_io,
                                              const char *statement,
                                              int32_t *max_call_depth_io,
                                              int32_t *max_string_literal_temps_io) {
    char name[128];
    char type_text[CHENG_MAX_TYPE_TEXT];
    char expr[4096];
    if (cheng_seed_tuple_binding_expr_omits_items(statement)) {
        fprintf(stderr,
                "[cheng_seed] tuple literal omission unsupported function=%s stmt=%s\n",
                function->symbol_text,
                statement);
        return false;
    }
    if ((cheng_seed_startswith(statement, "let ") || cheng_seed_startswith(statement, "var ")) &&
        cheng_seed_parse_binding_decl_meta(statement,
                                   cheng_seed_startswith(statement, "let ") ? "let " : "var ",
                                   name,
                                   sizeof(name),
                                   type_text,
                                   sizeof(type_text))) {
        char normalized_type[256];
        const char *abi_class = cheng_seed_resolved_type_abi_class(lowering,
                                                           function->owner_module_path,
                                                           aliases,
                                                           alias_count,
                                                           type_text,
                                                           normalized_type,
                                                           sizeof(normalized_type));
        if (cheng_seed_find_local_slot(locals, *local_count, name) < 0) {
            return cheng_seed_add_local_slot_for_type(lowering,
                                              function->owner_module_path,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              local_cap,
                                              name,
                                              type_text,
                                              abi_class,
                                              false,
                                              next_offset_io);
        }
        return true;
    }
    if ((cheng_seed_startswith(statement, "let ") || cheng_seed_startswith(statement, "var ")) &&
        cheng_seed_parse_binding_meta(statement,
                              cheng_seed_startswith(statement, "let ") ? "let " : "var ",
                              name,
                              sizeof(name),
                              type_text,
                              sizeof(type_text),
                              expr,
                              sizeof(expr))) {
        const char *abi_class;
        char inferred_type[CHENG_MAX_TYPE_TEXT];
        char inferred_abi[32];
        char prepared_expr[8192];
        if (type_text[0] == '\0') {
            if (!cheng_seed_infer_expr_type(plan,
                                    lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    *local_count,
                                    expr,
                                    inferred_type,
                                    sizeof(inferred_type),
                                    inferred_abi,
                                    sizeof(inferred_abi))) {
                fprintf(stderr,
                        "[cheng_seed] infer binding type failed function=%s name=%s expr=%s\n",
                        function->symbol_text,
                        name,
                        expr);
                return false;
            }
            snprintf(type_text, sizeof(type_text), "%s", inferred_type);
        }
        abi_class = cheng_seed_type_abi_class(type_text);
        if (type_text[0] == '\0' || strcmp(abi_class, "void") == 0) {
            return false;
        }
        if (!cheng_seed_rewrite_expr_for_expected_str(lowering,
                                              function,
                                              aliases,
                                              alias_count,
                                              type_text,
                                              expr,
                                              prepared_expr,
                                              sizeof(prepared_expr))) {
            return false;
        }
        if (cheng_seed_find_local_slot(locals, *local_count, name) < 0 &&
            !cheng_seed_add_local_slot_for_type(lowering,
                                        function->owner_module_path,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        local_cap,
                                        name,
                                        type_text,
                                        abi_class,
                                        false,
                                        next_offset_io)) {
            fprintf(stderr,
                    "[cheng_seed] add binding slot failed function=%s name=%s type=%s abi=%s expr=%s\n",
                    function->symbol_text,
                    name,
                    type_text,
                    abi_class,
                    expr);
            return false;
        }
        if (!cheng_seed_tuple_binding_expr_complete(type_text, expr)) {
            fprintf(stderr,
                    "[cheng_seed] tuple literal omission unsupported function=%s name=%s type=%s expr=%s\n",
                    function->symbol_text,
                    name,
                    type_text,
                    expr);
            return false;
        }
        if (cheng_seed_call_expr_string_literal_count(prepared_expr) > *max_string_literal_temps_io) {
            *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(prepared_expr);
        }
        if (!cheng_seed_prepare_expr_call_state(plan,
                                        lowering,
                                        function,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        local_cap,
                                        next_offset_io,
                                        prepared_expr,
                                        1,
                                        max_call_depth_io)) {
            fprintf(stderr,
                    "[cheng_seed] prepare binding expr failed function=%s name=%s type=%s abi=%s expr=%s prepared=%s\n",
                    function->symbol_text,
                    name,
                    type_text,
                    abi_class,
                    expr,
                    prepared_expr);
            return false;
        }
        return true;
    }
    if (strcmp(statement, "continue") == 0 || strcmp(statement, "break") == 0) {
        return true;
    }
    if (strcmp(statement, "return") == 0) {
        return true;
    }
    if (cheng_seed_startswith(statement, "panic ")) {
        if (cheng_seed_call_expr_string_literal_count(statement + 6) > *max_string_literal_temps_io) {
            *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(statement + 6);
        }
        if (!cheng_seed_prepare_expr_call_state(plan,
                                        lowering,
                                        function,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        local_cap,
                                        next_offset_io,
                                        statement + 6,
                                        0,
                                        max_call_depth_io)) {
            fprintf(stderr,
                    "[cheng_seed] prepare panic expr failed function=%s expr=%s\n",
                    function->symbol_text,
                    statement + 6);
            return false;
        }
        return true;
    }
    if (cheng_seed_startswith(statement, "return ")) {
        char prepared_expr[8192];
        if (!cheng_seed_rewrite_expr_for_expected_str(lowering,
                                              function,
                                              aliases,
                                              alias_count,
                                              function->return_type,
                                              statement + 7,
                                              prepared_expr,
                                              sizeof(prepared_expr))) {
            return false;
        }
        if (cheng_seed_call_expr_string_literal_count(prepared_expr) > *max_string_literal_temps_io) {
            *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(prepared_expr);
        }
        if (!cheng_seed_prepare_expr_call_state(plan,
                                        lowering,
                                        function,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        local_cap,
                                        next_offset_io,
                                        prepared_expr,
                                        0,
                                        max_call_depth_io)) {
            fprintf(stderr,
                    "[cheng_seed] prepare return expr failed function=%s expr=%s prepared=%s\n",
                    function->symbol_text,
                    statement + 7,
                    prepared_expr);
            return false;
        }
        return true;
    }
    if (cheng_seed_parse_assignment_meta(statement,
                                 name,
                                 sizeof(name),
                                 expr,
                                 sizeof(expr))) {
        char target_type[256];
        char target_abi[32];
        char prepared_expr[8192];
        int32_t string_literal_count = 0;
        bool handled = false;
        if (!cheng_seed_try_prepare_index_assignment_call_state(plan,
                                                        lowering,
                                                        function,
                                                        aliases,
                                                        alias_count,
                                                        locals,
                                                        local_count,
                                                        local_cap,
                                                        next_offset_io,
                                                        name,
                                                        expr,
                                                        0,
                                                        max_call_depth_io,
                                                        &handled)) {
            fprintf(stderr,
                    "[cheng_seed] prepare index assignment call state failed function=%s target=%s expr=%s stmt=%s\n",
                    function->symbol_text,
                    name,
                    expr,
                    statement);
            return false;
        }
        if (handled) {
            return true;
        }
        if (!cheng_seed_infer_lvalue_expr_type(plan,
                                       lowering,
                                       function,
                                       aliases,
                                       alias_count,
                                       locals,
                                       *local_count,
                                       name,
                                       target_type,
                                       sizeof(target_type),
                                       target_abi,
                                       sizeof(target_abi)) ||
            !cheng_seed_rewrite_expr_for_expected_str(lowering,
                                              function,
                                              aliases,
                                              alias_count,
                                              target_type,
                                              expr,
                                              prepared_expr,
                                              sizeof(prepared_expr))) {
            return false;
        }
        string_literal_count = cheng_seed_assignment_string_literal_count(name, prepared_expr);
        if (string_literal_count > *max_string_literal_temps_io) {
            *max_string_literal_temps_io = string_literal_count;
        }
        if (!cheng_seed_prepare_expr_call_state(plan,
                                        lowering,
                                        function,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        local_cap,
                                        next_offset_io,
                                        prepared_expr,
                                        0,
                                        max_call_depth_io)) {
            fprintf(stderr,
                    "[cheng_seed] prepare assignment expr failed function=%s lhs=%s expr=%s prepared=%s\n",
                    function->symbol_text,
                    name,
                    expr,
                    prepared_expr);
            return false;
        }
        return true;
    }
    {
        char callee[PATH_MAX];
        char arg_text[4096];
        char (*call_args)[4096] = cheng_seed_alloc_call_arg_scratch();
        size_t call_arg_count = 0U;
        const char *call_text = cheng_seed_statement_effective_call_text(statement);
        bool parsed_call =
            cheng_seed_parse_call_text(call_text,
                               callee,
                               sizeof(callee),
                               call_args,
                               &call_arg_count,
                               CHENG_MAX_CALL_ARGS) ||
            cheng_seed_parse_prefix_single_arg_call(call_text,
                                            callee,
                                            sizeof(callee),
                                            arg_text,
                                            sizeof(arg_text));
        free(call_args);
        if (parsed_call) {
            if (cheng_seed_call_expr_string_literal_count(call_text) > *max_string_literal_temps_io) {
                *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(call_text);
            }
            if (!cheng_seed_prepare_expr_call_state(plan,
                                            lowering,
                                            function,
                                            aliases,
                                            alias_count,
                                            locals,
                                            local_count,
                                            local_cap,
                                            next_offset_io,
                                            call_text,
                                            0,
                                            max_call_depth_io)) {
                fprintf(stderr,
                        "[cheng_seed] prepare stmt call state failed function=%s stmt=%s\n",
                        function->symbol_text,
                        statement);
                return false;
            }
            return true;
        }
    }
    if (strchr(statement, '(') != NULL) {
        if (cheng_seed_call_expr_string_literal_count(statement) > *max_string_literal_temps_io) {
            *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(statement);
        }
        if (!cheng_seed_prepare_expr_call_state(plan,
                                        lowering,
                                        function,
                                        aliases,
                                        alias_count,
                                        locals,
                                        local_count,
                                        local_cap,
                                        next_offset_io,
                                        statement,
                                        0,
                                        max_call_depth_io)) {
            fprintf(stderr,
                    "[cheng_seed] prepare stmt call state failed function=%s stmt=%s\n",
                    function->symbol_text,
                    statement);
            return false;
        }
        return true;
    }
    {
        char expr_type[256];
        char expr_abi[32];
        if (cheng_seed_infer_expr_type(plan,
                               lowering,
                               function,
                               aliases,
                               alias_count,
                               locals,
                               *local_count,
                               statement,
                               expr_type,
                               sizeof(expr_type),
                               expr_abi,
                               sizeof(expr_abi)) &&
            !cheng_seed_expr_materializes_to_address(expr_type, expr_abi)) {
            if (cheng_seed_call_expr_string_literal_count(statement) > *max_string_literal_temps_io) {
                *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(statement);
            }
            return cheng_seed_prepare_expr_call_state(plan,
                                              lowering,
                                              function,
                                              aliases,
                                              alias_count,
                                              locals,
                                              local_count,
                                              local_cap,
                                              next_offset_io,
                                              statement,
                                              0,
                                              max_call_depth_io);
        }
    }
    return false;
}

static bool cheng_seed_prepare_if_statement_state(const ChengSeedSystemLinkPlanStub *plan,
                                          const ChengSeedLoweringPlanStub *lowering,
                                          const ChengSeedLoweredFunctionStub *function,
                                          const ChengSeedImportAlias *aliases,
                                          size_t alias_count,
                                          ChengSeedAsmLocalSlot *locals,
                                          size_t *local_count,
                                          size_t local_cap,
                                          int32_t *next_offset_io,
                                          char **lines,
                                          size_t line_count,
                                          size_t *index_io,
                                          int32_t parent_indent,
                                          const char *statement,
                                          int32_t *max_call_depth_io,
                                          int32_t *max_string_literal_temps_io) {
    char current_stmt[8192];
    snprintf(current_stmt, sizeof(current_stmt), "%s", statement);
    for (;;) {
        size_t clause_local_start = *local_count;
        size_t clause_line = cheng_seed_current_source_line();
        size_t clause_end_line = clause_line;
        char cond[4096];
        char inline_stmt[8192];
        char next_clause[8192];
        bool is_else = false;
        bool has_next_clause = false;
        if (cheng_seed_startswith(current_stmt, "if ")) {
            if (!cheng_seed_parse_if_header(current_stmt, cond, sizeof(cond), inline_stmt, sizeof(inline_stmt))) {
                fprintf(stderr,
                        "[cheng_seed] parse if header failed function=%s stmt=%s\n",
                        function->symbol_text,
                        current_stmt);
                return false;
            }
        } else if (cheng_seed_startswith(current_stmt, "elif ")) {
            if (!cheng_seed_parse_elif_header(current_stmt, cond, sizeof(cond), inline_stmt, sizeof(inline_stmt))) {
                fprintf(stderr,
                        "[cheng_seed] parse elif header failed function=%s stmt=%s\n",
                        function->symbol_text,
                        current_stmt);
                return false;
            }
        } else {
            is_else = true;
            if (!cheng_seed_parse_else_header(current_stmt, inline_stmt, sizeof(inline_stmt))) {
                fprintf(stderr,
                        "[cheng_seed] parse else header failed function=%s stmt=%s\n",
                        function->symbol_text,
                        current_stmt);
                return false;
            }
            cond[0] = '\0';
        }
        if (!is_else) {
            if (cheng_seed_call_expr_string_literal_count(cond) > *max_string_literal_temps_io) {
                *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(cond);
            }
            if (!cheng_seed_prepare_expr_call_state(plan,
                                            lowering,
                                            function,
                                            aliases,
                                            alias_count,
                                            locals,
                                            local_count,
                                            local_cap,
                                            next_offset_io,
                                            cond,
                                            0,
                                            max_call_depth_io)) {
                fprintf(stderr,
                        "[cheng_seed] prepare if cond failed function=%s cond=%s\n",
                        function->symbol_text,
                        cond);
                return false;
            }
        }
        if (inline_stmt[0] != '\0') {
            if (cheng_seed_startswith(inline_stmt, "if ") ||
                cheng_seed_startswith(inline_stmt, "while ") ||
                cheng_seed_startswith(inline_stmt, "for ") ||
                cheng_seed_startswith(inline_stmt, "case ")) {
                return false;
            }
            if (!cheng_seed_prepare_non_if_statement_state(plan,
                                                   lowering,
                                                   function,
                                                   aliases,
                                                   alias_count,
                                                   locals,
                                                   local_count,
                                                   local_cap,
                                                   next_offset_io,
                                                   inline_stmt,
                                                   max_call_depth_io,
                                                   max_string_literal_temps_io)) {
                return false;
            }
            cheng_seed_limit_local_scope_end(locals, clause_local_start, *local_count, clause_line);
        } else {
            while (*index_io < line_count) {
                char raw_copy[4096];
                char *trimmed;
                int32_t indent;
                char nested_stmt[8192];
                snprintf(raw_copy, sizeof(raw_copy), "%s", lines[*index_io]);
                trimmed = cheng_seed_trim_inplace(raw_copy);
                if (*trimmed == '\0') {
                    *index_io += 1U;
                    continue;
                }
                indent = cheng_seed_line_indent(lines[*index_io]);
                if (indent < parent_indent) {
                    break;
                }
                if (indent == parent_indent &&
                    (cheng_seed_startswith(trimmed, "elif ") || cheng_seed_startswith(trimmed, "else"))) {
                    size_t next_clause_line = *index_io + 1U;
                    if (!cheng_seed_collect_statement_from_lines(lines,
                                                         line_count,
                                                         index_io,
                                                         next_clause,
                                                         sizeof(next_clause))) {
                        return false;
                    }
                    has_next_clause = true;
                    clause_end_line = next_clause_line > 0U ? next_clause_line - 1U : 0U;
                    break;
                }
                if (indent <= parent_indent) {
                    clause_end_line = *index_io;
                    break;
                }
                if (!cheng_seed_collect_statement_from_lines(lines, line_count, index_io, nested_stmt, sizeof(nested_stmt))) {
                    return false;
                }
                if (cheng_seed_startswith(nested_stmt, "if ")) {
                if (!cheng_seed_prepare_if_statement_state(plan,
                                                   lowering,
                                                   function,
                                                   aliases,
                                                       alias_count,
                                                       locals,
                                                       local_count,
                                                       local_cap,
                                                       next_offset_io,
                                                       lines,
                                                       line_count,
                                                       index_io,
                                                       indent,
                                                   nested_stmt,
                                                   max_call_depth_io,
                                                   max_string_literal_temps_io)) {
                    fprintf(stderr,
                            "[cheng_seed] prepare if child if failed function=%s parent=%s nested=%s\n",
                            function->symbol_text,
                            current_stmt,
                            nested_stmt);
                    return false;
                }
                continue;
            }
            if (cheng_seed_startswith(nested_stmt, "while ")) {
                    if (!cheng_seed_prepare_while_statement_state(plan,
                                                          lowering,
                                                          function,
                                                          aliases,
                                                          alias_count,
                                                          locals,
                                                          local_count,
                                                          local_cap,
                                                          next_offset_io,
                                                          lines,
                                                          line_count,
                                                          index_io,
                                                          indent,
                                                      nested_stmt,
                                                      max_call_depth_io,
                                                      max_string_literal_temps_io)) {
                    fprintf(stderr,
                            "[cheng_seed] prepare if child while failed function=%s parent=%s nested=%s\n",
                            function->symbol_text,
                            current_stmt,
                            nested_stmt);
                    return false;
                }
                continue;
            }
            if (cheng_seed_startswith(nested_stmt, "for ")) {
                    if (!cheng_seed_prepare_for_statement_state(plan,
                                                        lowering,
                                                        function,
                                                        aliases,
                                                        alias_count,
                                                        locals,
                                                        local_count,
                                                        local_cap,
                                                        next_offset_io,
                                                        lines,
                                                        line_count,
                                                        index_io,
                                                        indent,
                                                    nested_stmt,
                                                    max_call_depth_io,
                                                    max_string_literal_temps_io)) {
                    fprintf(stderr,
                            "[cheng_seed] prepare if child for failed function=%s parent=%s nested=%s\n",
                            function->symbol_text,
                            current_stmt,
                            nested_stmt);
                    return false;
                }
                continue;
            }
                if (!cheng_seed_prepare_non_if_statement_state(plan,
                                                       lowering,
                                                       function,
                                                       aliases,
                                                       alias_count,
                                                       locals,
                                                       local_count,
                                                       local_cap,
                                                       next_offset_io,
                                                       nested_stmt,
                                                       max_call_depth_io,
                                                       max_string_literal_temps_io)) {
                    fprintf(stderr,
                            "[cheng_seed] prepare if nested stmt failed function=%s parent=%s nested=%s\n",
                            function->symbol_text,
                            current_stmt,
                            nested_stmt);
                    return false;
                }
            }
            if (!has_next_clause) {
                clause_end_line = *index_io;
            }
            cheng_seed_limit_local_scope_end(locals, clause_local_start, *local_count, clause_end_line);
        }
        if (!has_next_clause) {
            break;
        }
        snprintf(current_stmt, sizeof(current_stmt), "%s", next_clause);
    }
    return true;
}

static bool cheng_seed_prepare_case_const_table_statement(const ChengSeedSystemLinkPlanStub *plan,
                                                  const ChengSeedLoweringPlanStub *lowering,
                                                  const ChengSeedLoweredFunctionStub *function,
                                                  const ChengSeedImportAlias *aliases,
                                                  size_t alias_count,
                                                  ChengSeedAsmLocalSlot *locals,
                                                  size_t *local_count,
                                                  size_t local_cap,
                                                  int32_t *next_offset_io,
                                                  char **lines,
                                                  size_t line_count,
                                                  size_t *index_io,
                                                  int32_t parent_indent,
                                                  const char *statement,
                                                  int32_t *max_call_depth_io,
                                                  int32_t *max_string_literal_temps_io) {
    char case_expr[4096];
    if (!cheng_seed_parse_case_header(statement, case_expr, sizeof(case_expr)) ||
        !cheng_seed_prepare_expr_call_state(plan,
                                    lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    local_cap,
                                    next_offset_io,
                                    case_expr,
                                    0,
                                    max_call_depth_io)) {
        return false;
    }
    while (*index_io < line_count) {
        char raw_copy[4096];
        char *trimmed;
        int32_t indent;
        char arm_stmt[8192];
        bool is_else = false;
        int64_t match_value = 0;
        char inline_stmt[8192];
        snprintf(raw_copy, sizeof(raw_copy), "%s", lines[*index_io]);
        trimmed = cheng_seed_trim_inplace(raw_copy);
        if (*trimmed == '\0') {
            *index_io += 1U;
            continue;
        }
        indent = cheng_seed_line_indent(lines[*index_io]);
        if (indent < parent_indent) {
            break;
        }
        if (indent == parent_indent &&
            !cheng_seed_startswith(trimmed, "of ") &&
            !cheng_seed_startswith(trimmed, "else")) {
            break;
        }
        if (!cheng_seed_collect_statement_from_lines(lines, line_count, index_io, arm_stmt, sizeof(arm_stmt)) ||
            !cheng_seed_parse_case_arm_header(arm_stmt,
                                      &is_else,
                                      &match_value,
                                      inline_stmt,
                                      sizeof(inline_stmt))) {
            return false;
        }
        if (cheng_seed_startswith(inline_stmt, "if ") ||
            cheng_seed_startswith(inline_stmt, "while ") ||
            cheng_seed_startswith(inline_stmt, "for ") ||
            cheng_seed_startswith(inline_stmt, "case ")) {
            return false;
        }
        if (cheng_seed_call_expr_string_literal_count(inline_stmt) > *max_string_literal_temps_io) {
            *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(inline_stmt);
        }
        {
            size_t arm_local_start = *local_count;
            size_t arm_line = cheng_seed_current_source_line();
            if (!cheng_seed_prepare_non_if_statement_state(plan,
                                                   lowering,
                                                   function,
                                                   aliases,
                                                   alias_count,
                                                   locals,
                                                   local_count,
                                                   local_cap,
                                                   next_offset_io,
                                                   inline_stmt,
                                                   max_call_depth_io,
                                                   max_string_literal_temps_io)) {
                return false;
            }
            cheng_seed_limit_local_scope_end(locals, arm_local_start, *local_count, arm_line);
        }
    }
    return true;
}

static bool cheng_seed_prepare_while_statement_state(const ChengSeedSystemLinkPlanStub *plan,
                                             const ChengSeedLoweringPlanStub *lowering,
                                             const ChengSeedLoweredFunctionStub *function,
                                             const ChengSeedImportAlias *aliases,
                                             size_t alias_count,
                                             ChengSeedAsmLocalSlot *locals,
                                             size_t *local_count,
                                             size_t local_cap,
                                             int32_t *next_offset_io,
                                             char **lines,
                                             size_t line_count,
                                             size_t *index_io,
                                             int32_t parent_indent,
                                             const char *statement,
                                             int32_t *max_call_depth_io,
                                             int32_t *max_string_literal_temps_io) {
    size_t block_local_start = *local_count;
    size_t block_line = cheng_seed_current_source_line();
    size_t block_end_line = block_line;
    char cond[4096];
    char inline_stmt[8192];
    if (!cheng_seed_parse_while_header(statement, cond, sizeof(cond), inline_stmt, sizeof(inline_stmt))) {
        fprintf(stderr,
                "[cheng_seed] parse while header failed function=%s stmt=%s\n",
                function->symbol_text,
                statement);
        return false;
    }
    if (cheng_seed_call_expr_string_literal_count(cond) > *max_string_literal_temps_io) {
        *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(cond);
    }
    if (!cheng_seed_prepare_expr_call_state(plan,
                                    lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    local_cap,
                                    next_offset_io,
                                    cond,
                                    0,
                                    max_call_depth_io)) {
        fprintf(stderr,
                "[cheng_seed] prepare while cond failed function=%s cond=%s\n",
                function->symbol_text,
                cond);
        return false;
    }
    if (inline_stmt[0] != '\0') {
        if (cheng_seed_startswith(inline_stmt, "if ") ||
            cheng_seed_startswith(inline_stmt, "while ") ||
            cheng_seed_startswith(inline_stmt, "for ")) {
            return false;
        }
        if (!cheng_seed_prepare_non_if_statement_state(plan,
                                               lowering,
                                               function,
                                               aliases,
                                               alias_count,
                                               locals,
                                               local_count,
                                               local_cap,
                                               next_offset_io,
                                               inline_stmt,
                                               max_call_depth_io,
                                               max_string_literal_temps_io)) {
            fprintf(stderr,
                    "[cheng_seed] prepare while inline stmt failed function=%s stmt=%s inline=%s\n",
                    function->symbol_text,
                    statement,
                    inline_stmt);
            return false;
        }
        cheng_seed_limit_local_scope_end(locals, block_local_start, *local_count, block_line);
        return true;
    }
    while (*index_io < line_count) {
        char raw_copy[4096];
        char *trimmed;
        int32_t indent;
        char nested_stmt[8192];
        snprintf(raw_copy, sizeof(raw_copy), "%s", lines[*index_io]);
        trimmed = cheng_seed_trim_inplace(raw_copy);
        if (*trimmed == '\0') {
            *index_io += 1U;
            continue;
        }
        indent = cheng_seed_line_indent(lines[*index_io]);
        if (indent <= parent_indent) {
            block_end_line = *index_io;
            break;
        }
        if (!cheng_seed_collect_statement_from_lines(lines, line_count, index_io, nested_stmt, sizeof(nested_stmt))) {
            return false;
        }
        if (cheng_seed_startswith(nested_stmt, "if ")) {
            if (!cheng_seed_prepare_if_statement_state(plan,
                                               lowering,
                                               function,
                                               aliases,
                                               alias_count,
                                               locals,
                                               local_count,
                                               local_cap,
                                               next_offset_io,
                                               lines,
                                               line_count,
                                               index_io,
                                               indent,
                                               nested_stmt,
                                               max_call_depth_io,
                                               max_string_literal_temps_io)) {
                fprintf(stderr,
                        "[cheng_seed] prepare while child if failed function=%s parent=%s nested=%s\n",
                        function->symbol_text,
                        statement,
                        nested_stmt);
                return false;
            }
            continue;
        }
        if (cheng_seed_startswith(nested_stmt, "while ")) {
            if (!cheng_seed_prepare_while_statement_state(plan,
                                                  lowering,
                                                  function,
                                                  aliases,
                                                  alias_count,
                                                  locals,
                                                  local_count,
                                                  local_cap,
                                                  next_offset_io,
                                                  lines,
                                                  line_count,
                                                  index_io,
                                                  indent,
                                                  nested_stmt,
                                                  max_call_depth_io,
                                                  max_string_literal_temps_io)) {
                fprintf(stderr,
                        "[cheng_seed] prepare while child while failed function=%s parent=%s nested=%s\n",
                        function->symbol_text,
                        statement,
                        nested_stmt);
                return false;
            }
            continue;
        }
        if (cheng_seed_startswith(nested_stmt, "for ")) {
            if (!cheng_seed_prepare_for_statement_state(plan,
                                                lowering,
                                                function,
                                                aliases,
                                                alias_count,
                                                locals,
                                                local_count,
                                                local_cap,
                                                next_offset_io,
                                                lines,
                                                line_count,
                                                index_io,
                                                indent,
                                                nested_stmt,
                                                max_call_depth_io,
                                                max_string_literal_temps_io)) {
                fprintf(stderr,
                        "[cheng_seed] prepare while child for failed function=%s parent=%s nested=%s\n",
                        function->symbol_text,
                        statement,
                        nested_stmt);
                return false;
            }
            continue;
        }
        if (!cheng_seed_prepare_non_if_statement_state(plan,
                                               lowering,
                                               function,
                                               aliases,
                                               alias_count,
                                               locals,
                                               local_count,
                                               local_cap,
                                               next_offset_io,
                                               nested_stmt,
                                               max_call_depth_io,
                                               max_string_literal_temps_io)) {
            fprintf(stderr,
                    "[cheng_seed] prepare while nested stmt failed function=%s parent=%s nested=%s\n",
                    function->symbol_text,
                    statement,
                    nested_stmt);
            return false;
        }
    }
    if (block_end_line < *index_io) {
        block_end_line = *index_io;
    }
    cheng_seed_limit_local_scope_end(locals, block_local_start, *local_count, block_end_line);
    return true;
}

static bool cheng_seed_prepare_for_statement_state(const ChengSeedSystemLinkPlanStub *plan,
                                           const ChengSeedLoweringPlanStub *lowering,
                                           const ChengSeedLoweredFunctionStub *function,
                                           const ChengSeedImportAlias *aliases,
                                           size_t alias_count,
                                           ChengSeedAsmLocalSlot *locals,
                                           size_t *local_count,
                                           size_t local_cap,
                                           int32_t *next_offset_io,
                                           char **lines,
                                           size_t line_count,
                                           size_t *index_io,
                                           int32_t parent_indent,
                                           const char *statement,
                                           int32_t *max_call_depth_io,
                                           int32_t *max_string_literal_temps_io) {
    size_t block_local_start = *local_count;
    size_t block_line = cheng_seed_current_source_line();
    size_t block_end_line = block_line;
    char iter_name[128];
    char start_expr[4096];
    char end_expr[4096];
    bool end_inclusive = false;
    char inline_stmt[8192];
    if (!cheng_seed_parse_for_header(statement,
                             iter_name,
                             sizeof(iter_name),
                             start_expr,
                             sizeof(start_expr),
                             end_expr,
                             sizeof(end_expr),
                             &end_inclusive,
                             inline_stmt,
                             sizeof(inline_stmt))) {
        fprintf(stderr,
                "[cheng_seed] parse for header failed function=%s stmt=%s\n",
                function->symbol_text,
                statement);
        return false;
    }
    if (cheng_seed_find_local_slot(locals, *local_count, iter_name) < 0 &&
        !cheng_seed_add_local_slot_for_type(lowering,
                                    function->owner_module_path,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    local_cap,
                                    iter_name,
                                    "int32",
                                    "i32",
                                    false,
                                    next_offset_io)) {
        return false;
    }
    if (cheng_seed_call_expr_string_literal_count(start_expr) > *max_string_literal_temps_io) {
        *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(start_expr);
    }
    if (cheng_seed_call_expr_string_literal_count(end_expr) > *max_string_literal_temps_io) {
        *max_string_literal_temps_io = cheng_seed_call_expr_string_literal_count(end_expr);
    }
    if (!cheng_seed_prepare_expr_call_state(plan,
                                    lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    local_cap,
                                    next_offset_io,
                                    start_expr,
                                    0,
                                    max_call_depth_io) ||
        !cheng_seed_prepare_expr_call_state(plan,
                                    lowering,
                                    function,
                                    aliases,
                                    alias_count,
                                    locals,
                                    local_count,
                                    local_cap,
                                    next_offset_io,
                                    end_expr,
                                    0,
                                    max_call_depth_io)) {
        fprintf(stderr,
                "[cheng_seed] prepare for range failed function=%s start=%s end=%s\n",
                function->symbol_text,
                start_expr,
                end_expr);
        return false;
    }
    if (inline_stmt[0] != '\0') {
        if (cheng_seed_startswith(inline_stmt, "if ") ||
            cheng_seed_startswith(inline_stmt, "while ") ||
            cheng_seed_startswith(inline_stmt, "for ")) {
            return false;
        }
        if (!cheng_seed_prepare_non_if_statement_state(plan,
                                               lowering,
                                               function,
                                               aliases,
                                               alias_count,
                                               locals,
                                               local_count,
                                               local_cap,
                                               next_offset_io,
                                               inline_stmt,
                                               max_call_depth_io,
                                               max_string_literal_temps_io)) {
            fprintf(stderr,
                    "[cheng_seed] prepare for inline stmt failed function=%s stmt=%s inline=%s\n",
                    function->symbol_text,
                    statement,
                    inline_stmt);
            return false;
        }
        cheng_seed_limit_local_scope_end(locals, block_local_start, *local_count, block_line);
        return true;
    }
    while (*index_io < line_count) {
        char raw_copy[4096];
        char *trimmed;
        int32_t indent;
        char nested_stmt[8192];
        snprintf(raw_copy, sizeof(raw_copy), "%s", lines[*index_io]);
        trimmed = cheng_seed_trim_inplace(raw_copy);
        if (*trimmed == '\0') {
            *index_io += 1U;
            continue;
        }
        indent = cheng_seed_line_indent(lines[*index_io]);
        if (indent <= parent_indent) {
            block_end_line = *index_io;
            break;
        }
        if (!cheng_seed_collect_statement_from_lines(lines, line_count, index_io, nested_stmt, sizeof(nested_stmt))) {
            return false;
        }
        if (cheng_seed_startswith(nested_stmt, "if ")) {
            if (!cheng_seed_prepare_if_statement_state(plan,
                                               lowering,
                                               function,
                                               aliases,
                                               alias_count,
                                               locals,
                                               local_count,
                                               local_cap,
                                               next_offset_io,
                                               lines,
                                               line_count,
                                               index_io,
                                               indent,
                                               nested_stmt,
                                               max_call_depth_io,
                                               max_string_literal_temps_io)) {
                fprintf(stderr,
                        "[cheng_seed] prepare for child if failed function=%s parent=%s nested=%s\n",
                        function->symbol_text,
                        statement,
                        nested_stmt);
                return false;
            }
            continue;
        }
        if (cheng_seed_startswith(nested_stmt, "while ")) {
            if (!cheng_seed_prepare_while_statement_state(plan,
                                                  lowering,
                                                  function,
                                                  aliases,
                                                  alias_count,
                                                  locals,
                                                  local_count,
                                                  local_cap,
                                                  next_offset_io,
                                                  lines,
                                                  line_count,
                                                  index_io,
                                                  indent,
                                                  nested_stmt,
                                                  max_call_depth_io,
                                                  max_string_literal_temps_io)) {
                fprintf(stderr,
                        "[cheng_seed] prepare for child while failed function=%s parent=%s nested=%s\n",
                        function->symbol_text,
                        statement,
                        nested_stmt);
                return false;
            }
            continue;
        }
        if (cheng_seed_startswith(nested_stmt, "for ")) {
            if (!cheng_seed_prepare_for_statement_state(plan,
                                                lowering,
                                                function,
                                                aliases,
                                                alias_count,
                                                locals,
                                                local_count,
                                                local_cap,
                                                next_offset_io,
                                                lines,
                                                line_count,
                                                index_io,
                                                indent,
                                                nested_stmt,
                                                max_call_depth_io,
                                                max_string_literal_temps_io)) {
                fprintf(stderr,
                        "[cheng_seed] prepare for child for failed function=%s parent=%s nested=%s\n",
                        function->symbol_text,
                        statement,
                        nested_stmt);
                return false;
            }
            continue;
        }
        if (!cheng_seed_prepare_non_if_statement_state(plan,
                                               lowering,
                                               function,
                                               aliases,
                                               alias_count,
                                               locals,
                                               local_count,
                                               local_cap,
                                               next_offset_io,
                                               nested_stmt,
                                               max_call_depth_io,
                                               max_string_literal_temps_io)) {
            fprintf(stderr,
                    "[cheng_seed] prepare for nested stmt failed function=%s parent=%s nested=%s\n",
                    function->symbol_text,
                    statement,
                    nested_stmt);
            return false;
        }
    }
    if (block_end_line < *index_io) {
        block_end_line = *index_io;
    }
    cheng_seed_limit_local_scope_end(locals, block_local_start, *local_count, block_end_line);
    return true;
}

