static bool cheng_seed_wasm_emit_seq_set_grow_into_local_address(const ChengSeedSystemLinkPlanStub *plan,
                                                         const ChengSeedLoweringPlanStub *lowering,
                                                         uint32_t seq_addr_local_index,
                                                         bool index_from_seq_len,
                                                         int32_t seq_len_field_offset,
                                                         int32_t seq_index,
                                                         int32_t elem_size,
                                                         uint32_t dest_addr_local_index,
                                                         const ChengSeedWasmImportStub *imports,
                                                         size_t import_count,
                                                         ChengSeedWasmBuffer *body) {
    ChengSeedAsmCallTarget target;
    if (plan == NULL || lowering == NULL || seq_addr_local_index == 0U ||
        elem_size <= 0 || dest_addr_local_index == 0U || body == NULL ||
        !cheng_seed_wasm_build_seq_set_grow_target(plan, &target) ||
        !cheng_seed_wasm_emit_local_get(body, seq_addr_local_index)) {
        return false;
    }
    if (index_from_seq_len) {
        if (seq_len_field_offset < 0 ||
            !cheng_seed_wasm_emit_local_get(body, seq_addr_local_index) ||
            !cheng_seed_wasm_emit_field_access_from_base(body, "i32", seq_len_field_offset)) {
            return false;
        }
    } else if (!cheng_seed_wasm_emit_i32_const(body, seq_index)) {
        return false;
    }
    return cheng_seed_wasm_emit_i32_const(body, elem_size) &&
           cheng_seed_wasm_emit_call_target(lowering, &target, imports, import_count, body) &&
           cheng_seed_wasm_emit_local_set(body, dest_addr_local_index);
}

