static ChengSeedWasmBuiltinMessagePtrKind cheng_seed_wasm_builtin_message_ptr_kind(const ChengSeedSystemLinkPlanStub *plan,
                                                                    const ChengSeedLoweringPlanStub *lowering,
                                                                    const ChengSeedLoweredFunctionStub *function,
                                                                    const ChengSeedWasmFunctionContext *ctx,
                                                                    const char *expr_text,
                                                                    char *literal,
                                                                    size_t literal_cap,
                                                                    char *arg_type,
                                                                    size_t arg_type_cap,
                                                                    char *arg_abi,
                                                                    size_t arg_abi_cap) {
    if (plan == NULL || lowering == NULL || function == NULL || ctx == NULL ||
        expr_text == NULL || literal == NULL || literal_cap == 0U ||
        arg_type == NULL || arg_type_cap == 0U ||
        arg_abi == NULL || arg_abi_cap == 0U) {
        return ChengSeed_WASM_BUILTIN_MESSAGE_PTR_INVALID;
    }
    literal[0] = '\0';
    arg_type[0] = '\0';
    arg_abi[0] = '\0';
    if (cheng_seed_parse_string_literal_text(expr_text, literal, literal_cap)) {
        return ChengSeed_WASM_BUILTIN_MESSAGE_PTR_LITERAL_BRIDGE;
    }
    if (!cheng_seed_infer_expr_type(plan,
                            lowering,
                            function,
                            ctx->aliases,
                            ctx->alias_count,
                            ctx->locals,
                            ctx->local_count,
                            expr_text,
                            arg_type,
                            arg_type_cap,
                            arg_abi,
                            arg_abi_cap)) {
        return ChengSeed_WASM_BUILTIN_MESSAGE_PTR_INVALID;
    }
    if (strcmp(arg_abi, "ptr") == 0) {
        return ChengSeed_WASM_BUILTIN_MESSAGE_PTR_POINTER_VALUE;
    }
    if (strcmp(arg_type, "str") == 0 &&
        cheng_seed_expr_materializes_to_address(arg_type, arg_abi)) {
        return ChengSeed_WASM_BUILTIN_MESSAGE_PTR_STR_ADDRESS_BRIDGE;
    }
    return ChengSeed_WASM_BUILTIN_MESSAGE_PTR_INVALID;
}

