static bool cheng_seed_wasm_emit_builtin_message_sink_call(const ChengSeedSystemLinkPlanStub *plan,
                                                   const ChengSeedLoweringPlanStub *lowering,
                                                   ChengSeedWasmBuiltinMessageSinkKind kind,
                                                   bool drop_result,
                                                   const ChengSeedWasmImportStub *imports,
                                                   size_t import_count,
                                                   ChengSeedWasmBuffer *body) {
    ChengSeedAsmCallTarget target;
    if (plan == NULL || lowering == NULL || body == NULL ||
        !cheng_seed_wasm_build_builtin_message_sink_target(plan, kind, &target) ||
        !cheng_seed_wasm_emit_call_target(lowering, &target, imports, import_count, body)) {
        return false;
    }
    if (drop_result && kind == ChengSeed_WASM_BUILTIN_MESSAGE_SINK_PUTS) {
        return cheng_seed_wasm_append_u8(body, 0x1aU);
    }
    return true;
}

static bool cheng_seed_wasm_analyze_builtin_message_ptr(const ChengSeedSystemLinkPlanStub *plan,
                                                const ChengSeedLoweringPlanStub *lowering,
                                                const ChengSeedLoweredFunctionStub *function,
                                                ChengSeedWasmFunctionContext *ctx,
                                                const char *expr_text,
                                                ChengSeedWasmImportStub *imports,
                                                size_t *import_count) {
    char literal[4096];
    char arg_type[256];
    char arg_abi[32];
    ChengSeedWasmBuiltinMessagePtrKind kind;
    if (plan == NULL || lowering == NULL || function == NULL || ctx == NULL ||
        expr_text == NULL || imports == NULL || import_count == NULL) {
        return false;
    }
    kind = cheng_seed_wasm_builtin_message_ptr_kind(plan,
                                            lowering,
                                            function,
                                            ctx,
                                            expr_text,
                                            literal,
                                            sizeof(literal),
                                            arg_type,
                                            sizeof(arg_type),
                                            arg_abi,
                                            sizeof(arg_abi));
    if (kind == ChengSeed_WASM_BUILTIN_MESSAGE_PTR_POINTER_VALUE) {
        return cheng_seed_wasm_analyze_expr(plan, lowering, function, ctx, expr_text, imports, import_count);
    }
    if (kind == ChengSeed_WASM_BUILTIN_MESSAGE_PTR_LITERAL_BRIDGE) {
        return cheng_seed_wasm_register_str_to_cstring_bridge_import(plan, function, imports, import_count);
    }
    if (kind == ChengSeed_WASM_BUILTIN_MESSAGE_PTR_STR_ADDRESS_BRIDGE) {
        return cheng_seed_wasm_prepare_composite_expr(plan,
                                              lowering,
                                              function,
                                              ctx,
                                              expr_text,
                                              "str",
                                              imports,
                                              import_count) &&
               cheng_seed_wasm_register_str_to_cstring_bridge_import(plan, function, imports, import_count);
    }
    return false;
}

static bool cheng_seed_wasm_emit_builtin_message_ptr(const ChengSeedSystemLinkPlanStub *plan,
                                             const ChengSeedLoweringPlanStub *lowering,
                                             const ChengSeedLoweredFunctionStub *function,
                                             const ChengSeedWasmFunctionContext *ctx,
                                             const char *expr_text,
                                             const ChengSeedWasmImportStub *imports,
                                             size_t import_count,
                                             ChengSeedWasmBuffer *body) {
    char literal[4096];
    char arg_type[256];
    char arg_abi[32];
    uint32_t temp_local_index = 0U;
    ChengSeedWasmBuiltinMessagePtrKind kind;
    if (plan == NULL || lowering == NULL || function == NULL || ctx == NULL ||
        expr_text == NULL || body == NULL || !ctx->has_scratch_locals) {
        return false;
    }
    kind = cheng_seed_wasm_builtin_message_ptr_kind(plan,
                                            lowering,
                                            function,
                                            ctx,
                                            expr_text,
                                            literal,
                                            sizeof(literal),
                                            arg_type,
                                            sizeof(arg_type),
                                            arg_abi,
                                            sizeof(arg_abi));
    if (kind == ChengSeed_WASM_BUILTIN_MESSAGE_PTR_POINTER_VALUE) {
        return cheng_seed_wasm_emit_expr(plan, lowering, function, ctx, expr_text, imports, import_count, body);
    }
    temp_local_index = cheng_seed_wasm_pick_builtin_message_ptr_temp_local(ctx);
    if (temp_local_index == 0U) {
        return false;
    }
    if (kind == ChengSeed_WASM_BUILTIN_MESSAGE_PTR_LITERAL_BRIDGE) {
        return cheng_seed_wasm_emit_str_literal_into_local_address(ctx,
                                                           body,
                                                           temp_local_index,
                                                           literal) &&
               cheng_seed_wasm_emit_str_to_cstring_bridge_call(plan,
                                                       lowering,
                                                       temp_local_index,
                                                       imports,
                                                       import_count,
                                                       body);
    }
    if (kind == ChengSeed_WASM_BUILTIN_MESSAGE_PTR_STR_ADDRESS_BRIDGE) {
        return cheng_seed_wasm_emit_composite_expr_into_local_address(plan,
                                                              lowering,
                                                              function,
                                                              ctx,
                                                              expr_text,
                                                              "str",
                                                              temp_local_index,
                                                              imports,
                                                              import_count,
                                                              body) &&
               cheng_seed_wasm_emit_str_to_cstring_bridge_call(plan,
                                                       lowering,
                                                       temp_local_index,
                                                       imports,
                                                       import_count,
                                                       body);
    }
    return false;
}

static bool cheng_seed_wasm_prepare_composite_expr(const ChengSeedSystemLinkPlanStub *plan,
                                           const ChengSeedLoweringPlanStub *lowering,
                                           const ChengSeedLoweredFunctionStub *function,
                                           ChengSeedWasmFunctionContext *ctx,
                                           const char *expr_text,
                                           const char *dest_type_text,
                                           ChengSeedWasmImportStub *imports,
                                           size_t *import_count) {
    char expr[4096];
    char normalized_dest_type[CHENG_MAX_TYPE_TEXT];
    if (plan == NULL || lowering == NULL || function == NULL || ctx == NULL ||
        expr_text == NULL || dest_type_text == NULL) {
        return false;
    }
    cheng_seed_wasm_trim_wrapping_parens(expr_text, expr, sizeof(expr));
    if (!cheng_seed_normalize_type_text(lowering,
                                function->owner_module_path,
                                ctx->aliases,
                                ctx->alias_count,
                                dest_type_text,
                                normalized_dest_type,
                                sizeof(normalized_dest_type))) {
        return false;
    }
    if (strcmp(expr, "nil") == 0 ||
        (strcmp(expr, "[]") == 0 && cheng_seed_is_seq_type_text(normalized_dest_type)) ||
        (strcmp(expr, "\"\"") == 0 && strcmp(normalized_dest_type, "str") == 0)) {
        return true;
    }
    if (strcmp(expr, "[]") != 0 && cheng_seed_is_list_literal_text(expr, NULL)) {
        return cheng_seed_wasm_prepare_list_literal_expr(plan,
                                                 lowering,
                                                 function,
                                                 ctx,
                                                 expr,
                                                 normalized_dest_type,
                                                 imports,
                                                 import_count);
    }
    if (strcmp(normalized_dest_type, "str") == 0) {
        char expanded_expr[32768];
        char fmt_error[256];
        bool changed = false;
        char literal[4096];
        int32_t plus_index = -1;
        if (!cheng_seed_expand_strformat_fmt_expr(expr,
                                          expanded_expr,
                                          sizeof(expanded_expr),
                                          &changed,
                                          fmt_error,
                                          sizeof(fmt_error))) {
            return false;
        }
        if (changed) {
            return cheng_seed_wasm_prepare_composite_expr(plan,
                                                  lowering,
                                                  function,
                                                  ctx,
                                                  expanded_expr,
                                                  "str",
                                                  imports,
                                                  import_count);
        }
        if (cheng_seed_parse_string_literal_text(expr, literal, sizeof(literal))) {
            return true;
        }
        plus_index = cheng_seed_find_top_level_binary_op_last(expr, "+");
        if (plus_index >= 0) {
            char rewritten_concat_expr[8192];
            char concat_error[256];
            if (!cheng_seed_build_str_concat_fmt_call(expr,
                                              rewritten_concat_expr,
                                              sizeof(rewritten_concat_expr),
                                              concat_error,
                                              sizeof(concat_error))) {
                return false;
            }
            return cheng_seed_wasm_prepare_composite_expr(plan,
                                                  lowering,
                                                  function,
                                                  ctx,
                                                  rewritten_concat_expr,
                                                  "str",
                                                  imports,
                                                  import_count);
        }
    }
    return cheng_seed_wasm_analyze_expr(plan, lowering, function, ctx, expr, imports, import_count);
}

static bool cheng_seed_wasm_emit_str_literal_into_local_address(const ChengSeedWasmFunctionContext *ctx,
                                                        ChengSeedWasmBuffer *body,
                                                        uint32_t dest_addr_local_index,
                                                        const char *literal_text) {
    int32_t object_addr = 0;
    if (ctx == NULL || body == NULL || literal_text == NULL ||
        !cheng_seed_wasm_register_string_literal_object(literal_text, &object_addr, NULL, NULL)) {
        return false;
    }
    return cheng_seed_wasm_emit_i32_const(body, object_addr) &&
           cheng_seed_wasm_emit_local_set(body, ctx->scratch3_local_index) &&
           cheng_seed_wasm_emit_composite_copy_into_local_address(ctx,
                                                          ChengSeed_WASM_COMPOSITE_COPY_FROM_LOCAL_ADDRESS,
                                                          dest_addr_local_index,
                                                          ctx->scratch3_local_index,
                                                          cheng_seed_active_target_str_size_i32(),
                                                          body);
}

static bool cheng_seed_wasm_emit_str_literal_expr(ChengSeedWasmBuffer *body,
                                          const char *literal_text) {
    int32_t object_addr = 0;
    if (body == NULL || literal_text == NULL ||
        !cheng_seed_wasm_register_string_literal_object(literal_text, &object_addr, NULL, NULL)) {
        return false;
    }
    return cheng_seed_wasm_emit_i32_const(body, object_addr);
}

static bool cheng_seed_wasm_compute_static_return_slot_offset(const ChengSeedLoweringPlanStub *lowering,
                                                      const ChengSeedLoweredFunctionStub *function,
                                                      int32_t *offset_out,
                                                      int32_t *size_out) {
    size_t i;
    int32_t offset = 0;
    if (lowering == NULL || function == NULL || offset_out == NULL || size_out == NULL) {
        return false;
    }
    for (i = 0U; i < lowering->function_count; ++i) {
        const ChengSeedLoweredFunctionStub *it = &lowering->functions[i];
        ChengSeedWasmFunctionLoweringRule rule;
        if (!cheng_seed_build_wasm_function_lowering_rule(it, &rule)) {
            return false;
        }
        if (cheng_seed_wasm_function_rule_uses_static_return_slot(&rule)) {
            ChengSeedTypeLayoutStub layout;
            if (!cheng_seed_compute_type_layout_impl(lowering, it->return_type, &layout, 0U)) {
                return false;
            }
            offset = cheng_seed_align_up_i32(offset, layout.align > 0 ? layout.align : 8);
            if (it == function) {
                *offset_out = offset;
                *size_out = layout.size;
                return true;
            }
            offset += cheng_seed_align_up_i32(layout.size, 8);
        }
    }
    return false;
}

static int32_t cheng_seed_wasm_total_static_return_bytes(const ChengSeedLoweringPlanStub *lowering) {
    size_t i;
    int32_t offset = 0;
    if (lowering == NULL) {
        return 0;
    }
    for (i = 0U; i < lowering->function_count; ++i) {
        const ChengSeedLoweredFunctionStub *it = &lowering->functions[i];
        ChengSeedWasmFunctionLoweringRule rule;
        if (!cheng_seed_build_wasm_function_lowering_rule(it, &rule)) {
            return 0;
        }
        if (cheng_seed_wasm_function_rule_uses_static_return_slot(&rule)) {
            ChengSeedTypeLayoutStub layout;
            if (!cheng_seed_compute_type_layout_impl(lowering, it->return_type, &layout, 0U)) {
                return 0;
            }
            offset = cheng_seed_align_up_i32(offset, layout.align > 0 ? layout.align : 8);
            offset += cheng_seed_align_up_i32(layout.size, 8);
        }
    }
    return offset;
}

static bool cheng_seed_wasm_prepare_static_return_slot(const ChengSeedLoweringPlanStub *lowering,
                                               const ChengSeedLoweredFunctionStub *function,
                                               int32_t *return_slot_addr_out,
                                               int32_t *return_slot_size_out) {
    int32_t return_slot_offset = 0;
    int32_t return_slot_size = 0;
    ChengSeedWasmFunctionLoweringRule rule;
    if (lowering == NULL || function == NULL ||
        return_slot_addr_out == NULL || return_slot_size_out == NULL ||
        !cheng_seed_build_wasm_function_lowering_rule(function, &rule) ||
        !cheng_seed_wasm_function_rule_uses_static_return_slot(&rule) ||
        !cheng_seed_wasm_compute_static_return_slot_offset(lowering,
                                                   function,
                                                   &return_slot_offset,
                                                   &return_slot_size)) {
        return false;
    }
    *return_slot_addr_out = CHENG_WASM_STATIC_BASE_I32 + return_slot_offset;
    *return_slot_size_out = return_slot_size;
    return true;
}

static bool cheng_seed_wasm_emit_static_return_address(const ChengSeedWasmFunctionContext *ctx,
                                               int32_t return_slot_addr,
                                               ChengSeedWasmBuffer *body) {
    if (ctx == NULL || body == NULL) {
        return false;
    }
    if (!cheng_seed_wasm_emit_restore_frame_base(ctx, body)) {
        return false;
    }
    return cheng_seed_wasm_emit_i32_const(body, return_slot_addr) &&
           cheng_seed_wasm_append_u8(body, 0x0fU);
}

static bool cheng_seed_wasm_context_init(const ChengSeedSystemLinkPlanStub *plan,
                                 const ChengSeedLoweringPlanStub *lowering,
                                 const ChengSeedLoweredFunctionStub *function,
                                 ChengSeedWasmFunctionContext *ctx) {
    size_t i;
    uint32_t type_index = 0U;
    (void)plan;
    (void)lowering;
    memset(ctx, 0, sizeof(*ctx));
    if (!cheng_seed_load_import_aliases_from_source_path(function->source_path,
                                                 ctx->aliases,
                                                 &ctx->alias_count,
                                                 CHENG_MAX_IMPORT_ALIASES)) {
        fprintf(stderr, "[cheng_seed] wasm alias load failed: %s\n", function->source_path);
        return false;
    }
    if (!cheng_seed_wasm_function_type_index(function, &type_index)) {
        return false;
    }
    for (i = 0U; i < function->param_count; ++i) {
        if (cheng_seed_wasm_param_slot_kind(function->param_abi_classes[i]) != ChengSeed_WASM_SLOT_I32 ||
            !cheng_seed_wasm_context_add_local(ctx,
                                       function->param_names[i],
                                       function->param_types[i],
                                       function->param_abi_classes[i],
                                       (uint32_t)i,
                                       -1,
                                       0,
                                       0)) {
            fprintf(stderr,
                    "[cheng_seed] wasm param local init failed function=%s param=%s type=%s abi=%s\n",
                    function->symbol_text,
                    function->param_names[i],
                    function->param_types[i],
                    function->param_abi_classes[i]);
            return false;
        }
    }
    ctx->param_count = function->param_count;
    return true;
}

static bool cheng_seed_wasm_register_import(const char *function_symbol,
                                    const ChengSeedAsmCallTarget *target,
                                    ChengSeedWasmImportStub *imports,
                                    size_t *import_count) {
    uint32_t type_index = 0U;
    ChengSeedWasmCallLoweringRule rule;
    if (target == NULL || !target->external) {
        return true;
    }
    if (!cheng_seed_wasm_build_call_lowering_rule(target, &rule) ||
        !cheng_seed_wasm_call_target_type_index(target, &type_index)) {
        fprintf(stderr,
                "[cheng_seed] wasm unsupported external call signature function=%s symbol=%s ret=%s argc=%zu\n",
                function_symbol,
                target->symbol_name,
                target->return_abi_class,
                target->param_count);
        return false;
    }
    if (imports == NULL || import_count == NULL) {
        return true;
    }
    if (cheng_seed_wasm_find_import_index(imports, *import_count, target->symbol_name, type_index) >= 0) {
        return true;
    }
    if (*import_count >= CHENG_MAX_PLAN_FUNCTIONS) {
        fprintf(stderr, "[cheng_seed] wasm import table overflow\n");
        return false;
    }
    snprintf(imports[*import_count].symbol_name,
             sizeof(imports[*import_count].symbol_name),
             "%s",
             target->symbol_name);
    imports[*import_count].type_index = type_index;
    *import_count += 1U;
    return true;
}

static bool cheng_seed_wasm_call_target_type_index(const ChengSeedAsmCallTarget *target,
                                           uint32_t *type_index_out) {
    ChengSeedWasmCallLoweringRule rule;
    if (target == NULL || type_index_out == NULL || target->param_count > CHENG_MAX_CALL_ARGS) {
        return false;
    }
    if (!cheng_seed_wasm_build_call_lowering_rule(target, &rule) || !rule.supported) {
        return false;
    }
    *type_index_out = cheng_seed_wasm_signature_type_slot(rule.param_count,
                                                  rule.import_kind != ChengSeed_WASM_IMPORT_VOID);
    return true;
}

static bool cheng_seed_wasm_resolve_call_target_callee_index(const char *function_symbol,
                                                     const ChengSeedLoweringPlanStub *lowering,
                                                     const ChengSeedAsmCallTarget *target,
                                                     const ChengSeedWasmImportStub *imports,
                                                     size_t import_count,
                                                     uint32_t *callee_index_out) {
    if (target == NULL || callee_index_out == NULL) {
        return false;
    }
    if (target->external) {
        uint32_t type_index = 0U;
        int32_t import_index;
        if (!cheng_seed_wasm_call_target_type_index(target, &type_index)) {
            fprintf(stderr,
                    "[cheng_seed] wasm import signature resolve failed symbol=%s function=%s\n",
                    target->symbol_name,
                    function_symbol ? function_symbol : "<nil>");
            return false;
        }
        import_index = cheng_seed_wasm_find_import_index(imports, import_count, target->symbol_name, type_index);
        if (import_index < 0) {
            fprintf(stderr,
                    "[cheng_seed] wasm import index missing symbol=%s function=%s\n",
                    target->symbol_name,
                    function_symbol ? function_symbol : "<nil>");
            return false;
        }
        *callee_index_out = (uint32_t)import_index;
        return true;
    }
    {
        int32_t local_index = cheng_seed_find_lowered_function_index_by_symbol(lowering,
                                                                       target->lowered_function->symbol_text);
        if (local_index < 0) {
            fprintf(stderr,
                    "[cheng_seed] wasm local callee missing symbol=%s function=%s\n",
                    target->lowered_function != NULL ? target->lowered_function->symbol_text : "<nil>",
                    function_symbol ? function_symbol : "<nil>");
            return false;
        }
        *callee_index_out = (uint32_t)import_count + (uint32_t)local_index;
        return true;
    }
}

