static bool cheng_seed_wasm_resolve_len_expr_meta(const ChengSeedSystemLinkPlanStub *plan,
                                          const ChengSeedLoweringPlanStub *lowering,
                                          const ChengSeedLoweredFunctionStub *function,
                                          const ChengSeedWasmFunctionContext *ctx,
                                          const char *expr_text,
                                          char *base_type_out,
                                          size_t base_type_cap,
                                          char *base_abi_out,
                                          size_t base_abi_cap,
                                          char *field_abi_out,
                                          size_t field_abi_cap,
                                          int32_t *field_offset_out) {
    if (plan == NULL || lowering == NULL || function == NULL || ctx == NULL || expr_text == NULL ||
        base_type_out == NULL || base_abi_out == NULL || field_abi_out == NULL || field_offset_out == NULL) {
        return false;
    }
    if (!cheng_seed_infer_expr_type(plan,
                            lowering,
                            function,
                            ctx->aliases,
                            ctx->alias_count,
                            ctx->locals,
                            ctx->local_count,
                            expr_text,
                            base_type_out,
                            base_type_cap,
                            base_abi_out,
                            base_abi_cap)) {
        return false;
    }
    return cheng_seed_resolve_field_meta(lowering,
                                 base_type_out,
                                 "len",
                                 NULL,
                                 0U,
                                 field_abi_out,
                                 field_abi_cap,
                                 field_offset_out);
}

