static bool cheng_seed_wasm_build_bounds_check_target(const ChengSeedSystemLinkPlanStub *plan,
                                              ChengSeedAsmCallTarget *target) {
    static const char *const param_types[] = { "int32", "int32" };
    if (plan == NULL || target == NULL) {
        return false;
    }
    memset(target, 0, sizeof(*target));
    target->external = true;
    snprintf(target->callee_name, sizeof(target->callee_name), "%s", "cheng_bounds_check");
    cheng_seed_copy_target_symbol_name(plan,
                               "cheng_bounds_check",
                               target->symbol_name,
                               sizeof(target->symbol_name));
    return cheng_seed_call_target_set_signature(target, "void", 2U, param_types);
}

static bool cheng_seed_wasm_register_bounds_check_import(const ChengSeedSystemLinkPlanStub *plan,
                                                 const ChengSeedLoweredFunctionStub *function,
                                                 ChengSeedWasmImportStub *imports,
                                                 size_t *import_count) {
    ChengSeedAsmCallTarget target;
    return plan != NULL &&
           function != NULL &&
           imports != NULL &&
           import_count != NULL &&
           cheng_seed_wasm_build_bounds_check_target(plan, &target) &&
           cheng_seed_wasm_register_import(function->symbol_text, &target, imports, import_count);
}

