static bool cheng_seed_load_contract_from_cli(int argc, char **argv, ChengSeedBootstrapContract *contract) {
    const char *in_path = cheng_seed_flag_value(argc, argv, "--in");
    if (in_path && *in_path != '\0') {
        return cheng_seed_parse_contract_file(contract, in_path);
    }
    if (CHENG_EMBEDDED_CONTRACT_TEXT[0] != '\0') {
        return cheng_seed_parse_contract_text(contract,
                                      CHENG_EMBEDDED_SOURCE_PATH[0] != '\0' ? CHENG_EMBEDDED_SOURCE_PATH : "<embedded>",
                                      CHENG_EMBEDDED_CONTRACT_TEXT);
    }
    fprintf(stderr, "[cheng_seed] missing --in:<path>\n");
    return false;
}

static bool cheng_seed_load_runtime_contract(int argc, char **argv, ChengSeedBootstrapContract *contract) {
    const char *contract_path = cheng_seed_flag_value(argc, argv, "--contract-in");
    if (contract_path && *contract_path != '\0') {
        return cheng_seed_parse_contract_file(contract, contract_path);
    }
    if (CHENG_EMBEDDED_CONTRACT_TEXT[0] != '\0') {
        return cheng_seed_parse_contract_text(contract,
                                      CHENG_EMBEDDED_SOURCE_PATH[0] != '\0' ? CHENG_EMBEDDED_SOURCE_PATH : "<embedded>",
                                      CHENG_EMBEDDED_CONTRACT_TEXT);
    }
    fprintf(stderr, "[cheng_seed] missing embedded bootstrap contract\n");
    return false;
}

static int cheng_seed_cmd_print_contract(int argc, char **argv) {
    ChengSeedBootstrapContract contract;
    char *normalized;
    if (!cheng_seed_load_contract_from_cli(argc, argv, &contract)) {
        return 1;
    }
    if (!cheng_seed_validate_contract(&contract)) {
        cheng_seed_contract_free(&contract);
        return 1;
    }
    normalized = cheng_seed_contract_normalized_text(&contract);
    if (!normalized) {
        cheng_seed_contract_free(&contract);
        return 1;
    }
    fputs(normalized, stdout);
    free(normalized);
    cheng_seed_contract_free(&contract);
    return 0;
}

static int cheng_seed_cmd_self_check(int argc, char **argv) {
    ChengSeedBootstrapContract contract;
    char *normalized;
    char manifest_path[PATH_MAX];
    uint64_t hash;
    if (!cheng_seed_load_contract_from_cli(argc, argv, &contract)) {
        return 1;
    }
    if (!cheng_seed_validate_contract(&contract)) {
        cheng_seed_contract_free(&contract);
        return 1;
    }
    normalized = cheng_seed_contract_normalized_text(&contract);
    if (!normalized) {
        cheng_seed_contract_free(&contract);
        return 1;
    }
    hash = cheng_seed_fnv1a64(normalized);
    printf("bootstrap_name=%s\n", cheng_seed_contract_get(&contract, "bootstrap_name"));
    printf("target=%s\n", cheng_seed_contract_get(&contract, "target"));
    if (cheng_seed_contract_manifest_path(&contract, manifest_path, sizeof(manifest_path))) {
        printf("bootstrap_manifest=%s\n", manifest_path);
    }
    if (cheng_seed_contract_get(&contract, "compiler_parallel_model") != NULL) {
        printf("compiler_parallel_model=%s\n", cheng_seed_contract_get(&contract, "compiler_parallel_model"));
    }
    if (cheng_seed_contract_get(&contract, "program_parallel_model") != NULL) {
        printf("program_parallel_model=%s\n", cheng_seed_contract_get(&contract, "program_parallel_model"));
    }
    printf("contract_hash=%016llx\n", (unsigned long long)hash);
    puts("cheng_bootstrap_self_check=ok");
    free(normalized);
    cheng_seed_contract_free(&contract);
    return 0;
}

static int cheng_seed_cmd_compile_bootstrap(int argc, char **argv) {
    ChengSeedBootstrapContract contract;
    const char *out_path = cheng_seed_flag_value(argc, argv, "--out");
    const char *report_path = cheng_seed_flag_value(argc, argv, "--report-out");
    char *normalized;
    char wrapper_path[PATH_MAX];
    if (!out_path || *out_path == '\0') {
        fprintf(stderr, "[cheng_seed] missing --out:<path>\n");
        return 1;
    }
    if (!cheng_seed_load_contract_from_cli(argc, argv, &contract)) {
        return 1;
    }
    if (!cheng_seed_validate_contract(&contract)) {
        cheng_seed_contract_free(&contract);
        return 1;
    }
    normalized = cheng_seed_contract_normalized_text(&contract);
    if (!normalized) {
        cheng_seed_contract_free(&contract);
        return 1;
    }
    snprintf(wrapper_path, sizeof(wrapper_path), "%s.generated.c", out_path);
    if (!cheng_seed_write_wrapper_source(wrapper_path, contract.source_path, normalized)) {
        free(normalized);
        cheng_seed_contract_free(&contract);
        return 1;
    }
    if (!cheng_seed_ensure_parent_dir(out_path) || !cheng_seed_compile_wrapper(wrapper_path, out_path)) {
        free(normalized);
        cheng_seed_contract_free(&contract);
        return 1;
    }
    if (report_path && *report_path != '\0') {
        if (!cheng_seed_write_compile_report(report_path, &contract, contract.source_path, out_path, normalized)) {
            free(normalized);
            cheng_seed_contract_free(&contract);
            return 1;
        }
    }
    printf("compiled=%s\n", out_path);
    printf("contract_hash=%016llx\n", (unsigned long long)cheng_seed_fnv1a64(normalized));
    free(normalized);
    cheng_seed_contract_free(&contract);
    return 0;
}

static int cheng_seed_cmd_status(int argc, char **argv) {
    ChengSeedBootstrapContract contract;
    char compiler_entry[PATH_MAX];
    char manifest_path[PATH_MAX];
    const char *target;
    if (!cheng_seed_load_runtime_contract(argc, argv, &contract)) {
        return 1;
    }
    if (!cheng_seed_validate_contract(&contract)) {
        cheng_seed_contract_free(&contract);
        return 1;
    }
    target = cheng_seed_contract_get(&contract, "target");
    cheng_seed_resolve_contract_path(&contract, "compiler_entry_source", compiler_entry, sizeof(compiler_entry));
    puts("cheng");
    puts("version=cheng.compiler_runtime.v1");
    puts("execution=argv_control_plane");
    puts("bootstrap_mode=selfhost");
    printf("contract_target=%s\n", target);
    printf("supported_targets=%s\n", cheng_seed_supported_seed_target_csv());
    printf("target_support=%s\n", cheng_seed_target_support_state(target));
    printf("target_support_detail=%s\n", cheng_seed_target_support_detail(target));
    if (cheng_seed_contract_source_value(&contract, "compiler_entry_source") != NULL) {
        printf("compiler_entry=%s\n", compiler_entry);
    }
    if (cheng_seed_contract_manifest_path(&contract, manifest_path, sizeof(manifest_path))) {
        printf("bootstrap_manifest=%s\n", manifest_path);
    }
    if (cheng_seed_contract_get(&contract, "ordinary_command") != NULL) {
        printf("ordinary_command=%s\n", cheng_seed_contract_get(&contract, "ordinary_command"));
    }
    if (cheng_seed_contract_get(&contract, "ordinary_pipeline_state") != NULL) {
        printf("ordinary_pipeline=%s\n", cheng_seed_contract_get(&contract, "ordinary_pipeline_state"));
    }
    cheng_seed_contract_free(&contract);
    return 0;
}

