static int cheng_seed_cmd_print_bootstrap(int argc, char **argv) {
    ChengSeedBootstrapPaths paths;
    char *snapshot_text;
    (void)argc;
    (void)argv;
    cheng_seed_bootstrap_paths_init(&paths);
    if (!cheng_seed_bootstrap_artifacts_ready(&paths)) {
        if (cheng_seed_cmd_bootstrap_bridge(0, NULL) != 0) {
            return 1;
        }
        cheng_seed_bootstrap_paths_init(&paths);
    }
    snapshot_text = cheng_seed_read_file(paths.snapshot_path);
    if (snapshot_text == NULL) {
        fprintf(stderr, "[cheng_seed] missing bootstrap snapshot: %s\n", paths.snapshot_path);
        return 1;
    }
    fputs(snapshot_text, stdout);
    free(snapshot_text);
    return 0;
}

static int cheng_seed_cmd_bootstrap_bridge(int argc, char **argv) {
    ChengSeedBootstrapPaths paths;
    char lock_path[PATH_MAX];
    char bootstrap_compiler[PATH_MAX];
    char stage0_candidate[PATH_MAX];
    char in_flag[PATH_MAX + 16];
    char out_flag[PATH_MAX + 16];
    bool lock_held = false;
    int rc = 1;
    (void)argc;
    (void)argv;
    cheng_seed_bootstrap_paths_init(&paths);
    if (paths.root[0] == '\0') {
        fprintf(stderr, "[cheng_seed] bootstrap root detect failed\n");
        return 1;
    }
    if (!cheng_seed_mkdir_p(paths.out_dir)) {
        return 1;
    }
    cheng_seed_join_path(stage0_candidate, sizeof(stage0_candidate), paths.out_dir, "cheng.stage0.next");
    cheng_seed_join_path(lock_path, sizeof(lock_path), paths.out_dir, ".bootstrap_bridge.lock");
    if (cheng_seed_bootstrap_artifacts_fresh(&paths)) {
        printf("bootstrap bridge ok: %s\n", paths.stage2);
        return 0;
    }
    if (!cheng_seed_acquire_pid_lock(lock_path, &lock_held, cheng_seed_bootstrap_ready_check, &paths, "bootstrap-bridge")) {
        return 1;
    }
    if (cheng_seed_bootstrap_artifacts_fresh(&paths)) {
        rc = 0;
        goto done;
    }
    if (access(paths.stage1_source, R_OK) != 0 ||
        access(paths.compiler_entry_source, R_OK) != 0 ||
        access(paths.compiler_runtime_source, R_OK) != 0 ||
        access(paths.compiler_request_source, R_OK) != 0 ||
        access(paths.tooling_gate_source, R_OK) != 0) {
        fprintf(stderr, "[cheng_seed] bootstrap-bridge missing source input under %s\n", paths.root);
        goto done;
    }
    if (!cheng_seed_bootstrap_current_bootstrap_compiler_path(&paths,
                                                      bootstrap_compiler,
                                                      sizeof(bootstrap_compiler))) {
        fprintf(stderr,
                "[cheng_seed] bootstrap-bridge bootstrap inputs newer than live bootstrap compiler; rebuild stage0 and rerun bootstrap-bridge\n");
        goto done;
    }
    if (!cheng_seed_bootstrap_materialize_stage0(&paths, bootstrap_compiler, stage0_candidate)) {
        fprintf(stderr, "[cheng_seed] bootstrap-bridge failed to materialize stage0 candidate from %s\n",
                bootstrap_compiler);
        goto done;
    }
    if (access(stage0_candidate, X_OK) != 0) {
        fprintf(stderr, "[cheng_seed] bootstrap-bridge missing stage0 candidate: %s\n", stage0_candidate);
        goto done;
    }

    snprintf(in_flag, sizeof(in_flag), "--in:%s", paths.stage1_source);
    if (!cheng_seed_run_command_logged_argv(3U,
                                    (const char *[3]){ stage0_candidate, "self-check", in_flag },
                                    paths.stage0_self_check_log,
                                    "bootstrap-bridge stage0_self_check")) {
        goto done;
    }

    snprintf(out_flag, sizeof(out_flag), "--out:%s", paths.stage1);
    if (!cheng_seed_run_command_logged_argv(4U,
                                    (const char *[4]){ stage0_candidate,
                                                       "compile-bootstrap",
                                                       in_flag,
                                                       out_flag },
                                    paths.stage1_build_log,
                                    "bootstrap-bridge stage1_compile")) {
        goto done;
    }

    if (!cheng_seed_run_command_logged_argv(3U,
                                    (const char *[3]){ paths.stage1, "self-check", in_flag },
                                    paths.stage1_self_check_log,
                                    "bootstrap-bridge stage1_self_check")) {
        goto done;
    }

    snprintf(out_flag, sizeof(out_flag), "--out:%s", paths.stage2);
    if (!cheng_seed_run_command_logged_argv(4U,
                                    (const char *[4]){ paths.stage1,
                                                       "compile-bootstrap",
                                                       in_flag,
                                                       out_flag },
                                    paths.stage2_build_log,
                                    "bootstrap-bridge stage2_compile")) {
        goto done;
    }

    if (!cheng_seed_run_command_logged_argv(3U,
                                    (const char *[3]){ paths.stage2, "self-check", in_flag },
                                    paths.stage2_self_check_log,
                                    "bootstrap-bridge stage2_self_check")) {
        goto done;
    }

    snprintf(out_flag, sizeof(out_flag), "--out:%s", paths.stage3);
    if (!cheng_seed_run_command_logged_argv(4U,
                                    (const char *[4]){ paths.stage2,
                                                       "compile-bootstrap",
                                                       in_flag,
                                                       out_flag },
                                    paths.stage3_build_log,
                                    "bootstrap-bridge stage3_compile")) {
        goto done;
    }

    if (!cheng_seed_run_command_logged_argv(3U,
                                    (const char *[3]){ paths.stage3, "self-check", in_flag },
                                    paths.stage3_self_check_log,
                                    "bootstrap-bridge stage3_self_check")) {
        goto done;
    }

    if (!cheng_seed_run_command_logged_argv(3U,
                                    (const char *[3]){ paths.stage2, "print-contract", in_flag },
                                    paths.stage2_contract_log,
                                    "bootstrap-bridge stage2_contract")) {
        goto done;
    }

    if (!cheng_seed_run_command_logged_argv(3U,
                                    (const char *[3]){ paths.stage3, "print-contract", in_flag },
                                    paths.stage3_contract_log,
                                    "bootstrap-bridge stage3_contract")) {
        goto done;
    }

    if (!cheng_seed_file_text_equal(paths.stage2_contract_log, paths.stage3_contract_log)) {
        fprintf(stderr, "[cheng_seed] bootstrap-bridge fixed point mismatch stage2/stage3\n");
        goto done;
    }
    if (strcmp(bootstrap_compiler, paths.stage0) != 0) {
        if (rename(stage0_candidate, paths.stage0) != 0) {
            perror("rename");
            goto done;
        }
        stage0_candidate[0] = '\0';
    } else {
        if (unlink(stage0_candidate) != 0 && errno != ENOENT) {
            perror("unlink");
            goto done;
        }
        stage0_candidate[0] = '\0';
    }
    if (!cheng_seed_bootstrap_write_env_and_snapshot(&paths)) {
        fprintf(stderr, "[cheng_seed] bootstrap-bridge failed to write snapshot/env\n");
        goto done;
    }
    rc = 0;
done:
    if (stage0_candidate[0] != '\0') {
        unlink(stage0_candidate);
    }
    cheng_seed_release_pid_lock(lock_path, &lock_held);
    if (rc == 0) {
        printf("bootstrap bridge ok: %s\n", paths.stage2);
    }
    return rc;
}

