static bool cheng_seed_crash_report_raw_line_allowed(const char *line) {
    if (line == NULL || line[0] == '\0') {
        return false;
    }
    if (strncmp(line, "reason=", 7) == 0) return true;
    if (strncmp(line, "regs pc=", 8) == 0) return true;
    if (strncmp(line, "m#", 2) == 0) return true;
    if (line[0] == '#' && line[1] >= '0' && line[1] <= '9') return true;
    if (strncmp(line, "source_frames=", 14) == 0) return true;
    return false;
}

static bool cheng_seed_crash_report_transform_raw(const char *raw_log_path,
                                          const char *report_path,
                                          const char *log_path) {
    char *raw_text = NULL;
    char *cursor = NULL;
    char *line = NULL;
    char *report = NULL;
    size_t report_cap = 1024U;
    size_t report_used = 0U;
    char line_buf[PATH_MAX * 2];
    bool header_seen = false;
    bool saw_reason = false;
    bool saw_regs = false;
    bool saw_machine = false;
    bool ok = false;
    if (!cheng_seed_path_exists_nonempty(raw_log_path)) {
        cheng_seed_crash_log_error(log_path, "cheng crash report: missing raw log\n");
        return false;
    }
    if (!cheng_seed_ensure_parent_dir(report_path) || !cheng_seed_ensure_parent_dir(log_path)) {
        return false;
    }
    raw_text = cheng_seed_read_file(raw_log_path);
    if (raw_text == NULL) {
        cheng_seed_crash_log_error(log_path, "cheng crash report: failed to read raw log\n");
        goto done;
    }
    report = (char *)cheng_seed_xmalloc(report_cap);
    report[0] = '\0';
    cursor = raw_text;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        cheng_seed_profile_trim_line(line);
        if (line[0] == '\0') {
            continue;
        }
        if (!header_seen) {
            if (strcmp(line, "cheng_crash_raw_v1") != 0) {
                continue;
            }
            header_seen = true;
            cheng_seed_report_append(&report, &report_cap, &report_used, "[cheng] cheng_crash_report_v1");
            continue;
        }
        if (!cheng_seed_crash_report_raw_line_allowed(line)) {
            continue;
        }
        snprintf(line_buf, sizeof(line_buf), "[cheng] %s", line);
        cheng_seed_report_append(&report, &report_cap, &report_used, line_buf);
        if (strncmp(line, "reason=", 7) == 0) {
            saw_reason = true;
        } else if (strncmp(line, "regs pc=", 8) == 0) {
            saw_regs = true;
        } else if (strncmp(line, "m#", 2) == 0) {
            saw_machine = true;
        }
    }
    if (!header_seen || !saw_reason || !saw_regs || !saw_machine) {
        cheng_seed_crash_log_error(log_path, "cheng crash report: invalid raw log\n");
        goto done;
    }
    if (!cheng_seed_write_text_file(report_path, report)) {
        cheng_seed_crash_log_error(log_path, "cheng crash report: failed to write report\n");
        goto done;
    }
    ok = true;
done:
    free(report);
    free(raw_text);
    return ok;
}

static int cheng_seed_cmd_bootstrap_bridge(int argc, char **argv);

static bool cheng_seed_profile_report_live_compiler_bin(const ChengSeedBootstrapPaths *paths,
                                                char *out,
                                                size_t cap) {
    if (paths == NULL || out == NULL || cap == 0U) {
        return false;
    }
    out[0] = '\0';
    if (cheng_seed_backend_driver_ready(paths)) {
        cheng_seed_copy_text(out, cap, paths->backend_driver_out);
        return true;
    }
    if (cheng_seed_bootstrap_artifacts_fresh(paths) && cheng_seed_path_exists_nonempty(paths->stage3)) {
        cheng_seed_copy_text(out, cap, paths->stage3);
        return true;
    }
    if (cheng_seed_cmd_bootstrap_bridge(0, NULL) == 0) {
        if (cheng_seed_backend_driver_ready(paths)) {
            cheng_seed_copy_text(out, cap, paths->backend_driver_out);
            return true;
        }
        if (cheng_seed_bootstrap_artifacts_fresh(paths) && cheng_seed_path_exists_nonempty(paths->stage3)) {
            cheng_seed_copy_text(out, cap, paths->stage3);
            return true;
        }
    }
    return false;
}

typedef struct {
    char *key;
    uint32_t count;
} ChengSeedProfileCount;

static int cheng_seed_profile_count_cmp(const void *left, const void *right) {
    const ChengSeedProfileCount *a = (const ChengSeedProfileCount *)left;
    const ChengSeedProfileCount *b = (const ChengSeedProfileCount *)right;
    if (a->count != b->count) {
        return a->count < b->count ? 1 : -1;
    }
    if (a->key == NULL && b->key == NULL) return 0;
    if (a->key == NULL) return 1;
    if (b->key == NULL) return -1;
    return strcmp(a->key, b->key);
}

static bool cheng_seed_profile_count_add(ChengSeedProfileCount **items,
                                 int32_t *len,
                                 int32_t *cap,
                                 const char *key) {
    int32_t i;
    int32_t next_cap;
    ChengSeedProfileCount *grown = NULL;
    const char *safe_key = (key != NULL && key[0] != '\0') ? key : "?";
    for (i = 0; i < *len; i += 1) {
        if ((*items)[i].key != NULL && strcmp((*items)[i].key, safe_key) == 0) {
            (*items)[i].count += 1U;
            return true;
        }
    }
    if (*len >= *cap) {
        next_cap = *cap > 0 ? *cap * 2 : 16;
        grown = (ChengSeedProfileCount *)realloc(*items, (size_t)next_cap * sizeof(ChengSeedProfileCount));
        if (grown == NULL) {
            return false;
        }
        *items = grown;
        *cap = next_cap;
    }
    (*items)[*len].key = cheng_seed_strdup(safe_key);
    if ((*items)[*len].key == NULL) {
        return false;
    }
    (*items)[*len].count = 1U;
    *len += 1;
    return true;
}

static void cheng_seed_profile_counts_free(ChengSeedProfileCount *items, int32_t len) {
    int32_t i;
    if (items == NULL) return;
    for (i = 0; i < len; i += 1) {
        free(items[i].key);
    }
    free(items);
}

static void cheng_seed_profile_trim_line(char *line) {
    size_t len;
    if (line == NULL) return;
    len = strlen(line);
    while (len > 0U && (line[len - 1U] == '\r' || line[len - 1U] == '\n')) {
        line[len - 1U] = '\0';
        len -= 1U;
    }
}

static bool cheng_seed_profile_report_transform_raw(const char *raw_report_path,
                                            const char *report_path,
                                            const char *log_path) {
    char *raw_text = NULL;
    char *cursor = NULL;
    char *line = NULL;
    bool header_seen = false;
    int32_t total_samples = 0;
    int32_t dropped_samples = 0;
    int32_t sample_count = 0;
    ChengSeedProfileCount *function_counts = NULL;
    ChengSeedProfileCount *source_counts = NULL;
    ChengSeedProfileCount *pc_counts = NULL;
    int32_t function_len = 0;
    int32_t source_len = 0;
    int32_t pc_len = 0;
    int32_t function_cap = 0;
    int32_t source_cap = 0;
    int32_t pc_cap = 0;
    char *report = NULL;
    size_t report_cap = 1024U;
    size_t report_used = 0U;
    char line_buf[PATH_MAX * 2];
    bool ok = false;
    int32_t i;
    (void)log_path;
    if (!cheng_seed_path_exists_nonempty(raw_report_path)) {
        cheng_seed_profile_log_error(log_path, "cheng profile report: missing raw profile\n");
        return false;
    }
    if (!cheng_seed_ensure_parent_dir(report_path) || !cheng_seed_ensure_parent_dir(log_path)) {
        return false;
    }
    raw_text = cheng_seed_read_file(raw_report_path);
    if (raw_text == NULL) {
        cheng_seed_profile_log_error(log_path, "cheng profile report: failed to read raw profile\n");
        goto done;
    }
    cursor = raw_text;
    while ((line = strsep(&cursor, "\n")) != NULL) {
        char *rest;
        char *pc_key;
        char *function_key;
        char *source_key;
        cheng_seed_profile_trim_line(line);
        if (line[0] == '\0') {
            continue;
        }
        if (!header_seen) {
            header_seen = true;
            if (strcmp(line, "cheng_profile_raw_v1") != 0) {
                cheng_seed_profile_log_error(log_path, "cheng profile report: invalid raw header\n");
                goto done;
            }
            continue;
        }
        if (strncmp(line, "total_samples=", 14) == 0) {
            cheng_seed_parse_i32_text(line + 14, &total_samples);
            continue;
        }
        if (strncmp(line, "dropped_samples=", 16) == 0) {
            cheng_seed_parse_i32_text(line + 16, &dropped_samples);
            continue;
        }
        if (strncmp(line, "sample\t", 7) != 0) {
            continue;
        }
        rest = line + 7;
        pc_key = strsep(&rest, "\t");
        function_key = strsep(&rest, "\t");
        source_key = strsep(&rest, "\t");
        if (!cheng_seed_profile_count_add(&pc_counts, &pc_len, &pc_cap, pc_key) ||
            !cheng_seed_profile_count_add(&function_counts, &function_len, &function_cap, function_key) ||
            !cheng_seed_profile_count_add(&source_counts, &source_len, &source_cap, source_key)) {
            cheng_seed_profile_log_error(log_path, "cheng profile report: out of memory while counting samples\n");
            goto done;
        }
        sample_count += 1;
    }
    if (!header_seen) {
        cheng_seed_profile_log_error(log_path, "cheng profile report: invalid raw header\n");
        goto done;
    }
    if (total_samples <= 0) {
        total_samples = sample_count;
    }
    if (function_len > 1) {
        qsort(function_counts, (size_t)function_len, sizeof(ChengSeedProfileCount), cheng_seed_profile_count_cmp);
    }
    if (source_len > 1) {
        qsort(source_counts, (size_t)source_len, sizeof(ChengSeedProfileCount), cheng_seed_profile_count_cmp);
    }
    if (pc_len > 1) {
        qsort(pc_counts, (size_t)pc_len, sizeof(ChengSeedProfileCount), cheng_seed_profile_count_cmp);
    }
    report = (char *)cheng_seed_xmalloc(report_cap);
    report[0] = '\0';
    cheng_seed_report_append(&report, &report_cap, &report_used, "cheng_profile_v1");
    snprintf(line_buf, sizeof(line_buf), "total_samples=%d", total_samples);
    cheng_seed_report_append(&report, &report_cap, &report_used, line_buf);
    snprintf(line_buf, sizeof(line_buf), "dropped_samples=%d", dropped_samples);
    cheng_seed_report_append(&report, &report_cap, &report_used, line_buf);
    for (i = 0; i < function_len && i < 8; i += 1) {
        snprintf(line_buf,
                 sizeof(line_buf),
                 "hot_function[%d]=%u|%s",
                 i,
                 function_counts[i].count,
                 function_counts[i].key != NULL ? function_counts[i].key : "?");
        cheng_seed_report_append(&report, &report_cap, &report_used, line_buf);
    }
    for (i = 0; i < source_len && i < 8; i += 1) {
        snprintf(line_buf,
                 sizeof(line_buf),
                 "hot_source[%d]=%u|%s",
                 i,
                 source_counts[i].count,
                 source_counts[i].key != NULL ? source_counts[i].key : "?");
        cheng_seed_report_append(&report, &report_cap, &report_used, line_buf);
    }
    for (i = 0; i < pc_len && i < 8; i += 1) {
        snprintf(line_buf,
                 sizeof(line_buf),
                 "hot_pc[%d]=%u|%s",
                 i,
                 pc_counts[i].count,
                 pc_counts[i].key != NULL ? pc_counts[i].key : "?");
        cheng_seed_report_append(&report, &report_cap, &report_used, line_buf);
    }
    if (!cheng_seed_write_text_file(report_path, report)) {
        cheng_seed_profile_log_error(log_path, "cheng profile report: failed to write report\n");
        goto done;
    }
    ok = true;
done:
    free(report);
    free(raw_text);
    cheng_seed_profile_counts_free(function_counts, function_len);
    cheng_seed_profile_counts_free(source_counts, source_len);
    cheng_seed_profile_counts_free(pc_counts, pc_len);
    return ok;
}

static bool cheng_seed_compile_fixture_with_backend_driver_emit_target(const char *compiler_bin,
                                                               const char *root_cheng,
                                                               const char *src_path,
                                                               const char *emit_kind,
                                                               const char *target,
                                                               const char *out_path,
                                                               const char *log_path,
                                                               const char *report_path) {
    char contract_path[PATH_MAX];
    char root_arg[PATH_MAX + 32];
    char contract_arg[PATH_MAX + 32];
    char in_arg[PATH_MAX + 32];
    char emit_arg[128];
    char target_arg[256];
    char out_arg[PATH_MAX + 32];
    char report_arg[PATH_MAX + 32];
    const char *args[9];
    size_t arg_count = 0U;
    bool ok;
    cheng_seed_join_path(contract_path, sizeof(contract_path), root_cheng, cheng_seed_bootstrap_stage1_source_relpath_from_cheng_root());
    snprintf(root_arg, sizeof(root_arg), "--root:%s", root_cheng);
    snprintf(contract_arg, sizeof(contract_arg), "--contract-in:%s", contract_path);
    snprintf(in_arg, sizeof(in_arg), "--in:%s", src_path);
    snprintf(emit_arg, sizeof(emit_arg), "--emit:%s", emit_kind);
    snprintf(target_arg, sizeof(target_arg), "--target:%s", target);
    snprintf(out_arg, sizeof(out_arg), "--out:%s", out_path);
    args[arg_count++] = compiler_bin;
    args[arg_count++] = "system-link-exec";
    args[arg_count++] = root_arg;
    args[arg_count++] = contract_arg;
    args[arg_count++] = in_arg;
    args[arg_count++] = emit_arg;
    args[arg_count++] = target_arg;
    args[arg_count++] = out_arg;
    if (report_path != NULL && report_path[0] != '\0') {
        snprintf(report_arg, sizeof(report_arg), "--report-out:%s", report_path);
        args[arg_count++] = report_arg;
    }
    ok = cheng_seed_run_command_logged_argv(arg_count, args, log_path, "ordinary fixture compile");
    if (ok && !cheng_seed_path_exists_nonempty(out_path)) {
        fprintf(stderr, "[cheng_seed] ordinary fixture compile missing output: %s\n", out_path);
        ok = false;
    }
    return ok;
}

static bool cheng_seed_compile_fixture_with_backend_driver_target(const char *compiler_bin,
                                                          const char *root_cheng,
                                                          const char *src_path,
                                                          const char *target,
                                                          const char *out_bin,
                                                          const char *log_path) {
    return cheng_seed_compile_fixture_with_backend_driver_emit_target(compiler_bin,
                                                              root_cheng,
                                                              src_path,
                                                              "exe",
                                                              target,
                                                              out_bin,
                                                              log_path,
                                                              NULL);
}

